// Auto-generated translations for réseau entity descriptions
// Keyed by locale, then by entity slug

export const reseauDescriptionTranslations: Record<string, Record<string, string>> = {
  en: {
    "emmanuel-macron": "Emmanuel Macron was selected as a Young Leader in the 2012 cohort, one year after Édouard Philippe. Their shared mentor, Alain Juppé, belonged to the founding 1982 cohort — three generations of Young Leaders linked by the same political godfather. Macron appointed Philippe as Prime Minister on May 15, 2017, despite Philippe's earlier criticisms (calling Macron a \"former Rothschild banker\" and displaying the \"cynicism of an old hand\"). This post-criticism rally illustrates the strength of network ties over public positions. Macron came from the Inspection des finances, then Rothschild bank, before being appointed deputy secretary-general of the Élysée under Hollande (himself a Young Leader 1996). The chain Hollande (YL 1996) → Macron (YL 2012) → Philippe (YL 2011) at the summit of the state is unique in FAF history. Tensions between the two men have grown since 2020: Philippe criticized Macron's 2024 dissolution (\"a fatal and absurd decision\") and called on him to resign at the end of 2025. Macron's 2012 cohort also included Fleur Pellerin and Cédric Villani, both of whom became political figures. The fact that a president and his Prime Minister came from consecutive cohorts of the same transatlantic program is unprecedented and raises questions about American influence in the formation of France's ruling elite.",
    "alain-juppe": "Alain Juppé is the godfather of the entire ecosystem. Prime Minister under Chirac (1995-1997), convicted in 2004 (RPR ghost jobs), Young Leader of the founding FAF cohort (1982), Mayor of Bordeaux (2006-2019), member of the Conseil constitutionnel since March 2019 (mandate until 2028), and president of the Institut Georges-Pompidou since February 2025. It was Juppé who launched Philippe in politics (as UMP director-general in 2002), and Villepin had worked alongside him since the \"groupe J\" (1979) before being appointed chief of staff at the Quai d'Orsay by Juppé (1993). The triangle Juppé (YL 1982) → Philippe (YL 2011) → Macron (YL 2012) is the most spectacular case of power transmission within the FAF. Today neutralized by the constraints of the Conseil constitutionnel (duty of restraint, ban on any partisan responsibility, incompatibility with any mandate), he can neither support Philippe, nor comment on political matters, nor play any role in Horizons. But his residual power is threefold: institutional (he participates in constitutional decisions, sits alongside Richard Ferrand YL 2005), symbolic (his legacy permeates Horizons: pragmatism, Europeanism, tempered liberalism), and reticular (the \"Juppéie\" — his informal network of loyalists — forms the backbone of Horizons). Publication of L'heure du choix (Tallandier, 2025) on European independence. \"Alain Juppé lost but the Juppéists won: they are everywhere in ministerial cabinets\" (Julien Miro).",
    "cma-cgm": "CMA CGM is the largest French shipping company and the third largest in the world, founded in Marseille by Jacques Saadé in 1978. The group owns more than 600 vessels and serves 420 ports worldwide. Yann Le Goff, CMA CGM's regional security manager, was selected for the 2011 Young Leaders cohort alongside Édouard Philippe. The port of Le Havre, Philippe's political stronghold since 2010, is one of CMA CGM's main European hubs — the group's vessels represent a significant share of containerized traffic there. Le Havre is the primary entry point for cocaine into Europe according to Europol, with 18 tonnes seized in 2023. The question of port security — a domain where CMA CGM (via Le Goff), the mayor's responsibilities (Philippe), and transatlantic networks (FAF) intersect — is a critical nexus. CMA CGM has been run by Rodolphe Saadé since 2017, and the group has diversified into media (acquisition of La Tribune, La Provence) and logistics. The France China Foundation, of which Ribadeau-Dumas (Philippe's chief of staff) is a member, is embedded in the same Sino-maritime influence circuits. CMA CGM's commercial routes to Asia transit massively through Le Havre, making the port a convergence point for commercial, diplomatic and political interests.",
    "yann-le-goff": "Yann Le Goff is regional security manager at CMA CGM, France's largest shipping company, at the time of his selection as a Young Leader in 2011 alongside Édouard Philippe. His role at CMA CGM places him at the heart of maritime transport security issues — a domain that includes combating drug trafficking in ports. The port of Le Havre, Philippe's political stronghold, is the primary entry point for cocaine into Europe according to Europol. CMA CGM vessels represent a major share of containerized traffic at Le Havre, meaning that CMA CGM security and Le Havre port security are intimately linked. Le Goff and Philippe spent time together during two five-day seminars in 2011-2012, forging personal ties in an informal and confidential setting. The presence in the same Young Leaders cohort of a future mayor/Prime Minister and a security manager from the main shipping company operating in his port creates a direct channel of influence. This connection is all the more significant given that the issue of port drug trafficking has become a major political issue in France, with record seizures at Le Havre (18 tonnes of cocaine in 2023). Le Goff represents the CMA CGM node in Philippe's Young Leaders network. The convergence between his position (maritime security), Philippe's territory (Le Havre) and the structural problem (drug trafficking) warrants thorough examination.",
    "atos": "Atos is a French IT group specializing in digital transformation, cybersecurity and cloud computing. Édouard Philippe was appointed as an independent director in 2020, immediately after leaving Matignon, for a remunerated mandate worth approximately 70,000 euros per year. Atos is at the forefront of processing computerized data from traffic offenses, notably speed cameras, a market that directly benefited from the 80 km/h measure imposed by Philippe in 2018. Boulevard Voltaire and Blast highlighted this potential conflict of interest: the Prime Minister who imposed a massively unpopular road measure then joined the board of the company that processes the data generated by that same measure. Links between Philippe and Atos date back to 2006, well before his appointment to Matignon. The company experienced serious financial difficulties from 2022 onwards, with a spectacular share price collapse and massive restructuring. Atos also manages strategic activities for the French state (supercomputers, defense, Paris 2024 Olympics), making it a sensitive actor whose board member is also a presidential candidate. The timeline — 80 km/h in 2018, departure from Matignon in 2020, appointment at Atos in 2020 — raises questions about the porosity between public decisions and private interests. Philippe has never publicly commented on this potential conflict of interest.",
    "areva": "Areva (renamed Orano in 2018) is the French multinational of the nuclear industry, covering the entire fuel cycle. Édouard Philippe held the position of Director of Public Affairs from October 2007 to October 2010, a lobbying and elected official relations role that kept him at the heart of the decision-making sphere. This period coincided with his selection as a Young Leader in 2011, when he was presented as \"Mayor of Le Havre and Director of Public Affairs at Areva.\" Nuclear lobbying is one of the most powerful in France, where the industry accounts for approximately 70% of electricity production. As Director of Public Affairs, Philippe was tasked with defending Areva's interests before parliamentarians and the government — the very institutions he would later lead as Prime Minister. His trajectory Conseil d'État → Debevoise & Plimpton (business lawyer) → Areva (lobbying) → Le Havre mayoralty → Matignon illustrates a classic revolving-door career between public and private sectors. Areva experienced a major scandal with the disastrous acquisition of UraMin in 2007 (3.6 billion euros in losses), an affair that broke out during the period when Philippe worked there. The group had to be restructured and recapitalized by the state to the tune of 5 billion euros in 2017 — under the Philippe government. The Prime Minister who bails out the company that employed him as a lobbyist is a textbook case of potential conflict of interest.",
    "debevoise-plimpton": "Debevoise & Plimpton LLP is an American law firm founded in 1931 in New York, specializing in international business law, mergers and acquisitions, private equity and international arbitration. The firm has approximately 800 lawyers and offices in New York, Washington, London, Paris, Frankfurt, Hong Kong and Shanghai. Édouard Philippe worked there as a lawyer from 2004 to 2007, in the Paris branch, after leaving his role as UMP director-general and taking a leave of absence from the Conseil d'État. This stint at a top Anglo-Saxon firm illustrates the classic revolving-door trajectory: senior civil service (ENA, Conseil d'État), political party leadership (UMP), then the international private sector, before returning to politics. Debevoise represents Fortune 500 companies and investment funds, which allowed Philippe to build a network in international business circles. The firm is present in Hong Kong and Shanghai, nerve centers of Asian commerce — a detail that becomes meaningful in light of Philippe's entourage's subsequent Sino-French connections. After Debevoise, Philippe joined Areva as Director of Public Affairs (lobbying), confirming his embeddedness in economic influence circles. The sequence Conseil d'État → UMP → Debevoise → Areva → mayoralty → Matignon traces a path where each step enriches the contact book for the next. The Debevoise stint is the Anglo-Saxon parenthesis in this essentially French career. The fees and mandates he handled at Debevoise have never been made public.",
    "antoine-rufenacht": "Antoine Rufenacht was Mayor of Le Havre from 1995 to 2010, a former énarque and figure of the Norman right. It was he who identified Édouard Philippe as a potential successor and brought him into politics in 2001, integrating him into his municipal slate as deputy in charge of legal affairs. Rufenacht then recommended Philippe to Alain Juppé for the UMP directorship in 2002, thereby launching his national career. When Rufenacht resigned from the mayoralty in 2010, the municipal council elected Philippe to succeed him — a perfectly orchestrated local power transfer. Christine Poyer-Rufenacht, a lawyer bearing the same surname as the former mayor, was selected for the 2011 FAF Young Leaders cohort alongside Philippe — a coincidence that has never been publicly explained. Rufenacht led Le Havre for fifteen years, shaping the local political and economic network that Philippe inherited. Under Rufenacht, Le Havre undertook an urban transformation centered on the port and the Perret architecture classified by UNESCO. The Rufenacht-Philippe relationship is a textbook case of local political succession: the mentor identifies, grooms and installs his protégé at the head of the city. Philippe's Le Havre anchoring — town hall, port, urban community — is directly inherited from the Rufenacht network. The fact that the local mentor and the transatlantic network (FAF) converge around the same surname raises questions about the mechanisms of co-optation among French elites.",
    "french-american-foundation": "The French-American Foundation (FAF) is an organization founded in 1976 under the auspices of Presidents Gerald Ford and Valéry Giscard d'Estaing. Its Young Leaders program, created in 1981, selects ten French and ten American participants aged 30 to 40 each year, drawn from senior civil service, business, media, the military and research. Participants attend two five-day seminars over two consecutive years, alternating between France and the United States. The seminar content is not published — the FAF does not disclose the agendas of past editions. Upon completing the program, participants join an alumni network of more than 600 members. The program is regularly described as an instrument of American soft power, even though the FAF presents itself as being \"neither a think tank, nor a lobby, nor a parliamentary friendship group.\" The presence of Young Leaders in the French government is remarkable and transcends political alternations. Édouard Philippe belongs to the 2011 cohort, Emmanuel Macron to the 2012 cohort, Alain Juppé to the founding 1982 cohort, and François Hollande to the 1996 cohort. Richard Ferrand, minister in the Philippe government, was a Young Leader 2005. More than 400 leaders have benefited from the program since 1981, and the fact that a president and his Prime Minister came from consecutive cohorts is unprecedented in the FAF's history. The program's sponsors include Airbus, J.P. Morgan and Sodexo.",
    "david-barroux": "David Barroux is a journalist and editor-in-chief at the economic daily Les Échos, one of France's main business newspapers. He was part of the 2011 Young Leaders cohort of the French-American Foundation, alongside Édouard Philippe. His position at the helm of a benchmark economic media outlet gives him significant influence over coverage of French economic policy. Les Échos belongs to Bernard Arnault's LVMH group, which places Barroux within a media ecosystem tied to major French fortunes. As a Young Leader, he shared two five-day seminars with Philippe between 2011 and 2012, forging lasting personal and professional ties. The convergence of a future Prime Minister and an editor-in-chief of a major daily newspaper within the same transatlantic network is worth noting. Les Échos generally gave favorable coverage to the Philippe government's reforms, notably on the Labor Code and the PACTE law. This proximity illustrates the intertwining of French political and media elites within the same influence networks. Barroux represents the media pillar of the 2011 cohort. The FAF does not publish the exchanges that took place between these future leaders during the seminars.",
    "yohann-benard": "Yohann Bénard is Director of Public Affairs at Amazon France at the time of his selection as a Young Leader in 2011. He shares the FAF cohort with Édouard Philippe, then Mayor of Le Havre and Director of Public Affairs at Areva. The two men thus hold similar roles — lobbying and institutional relations — one for the nuclear giant, the other for the American e-commerce giant. Amazon is one of the most controversial companies in France for its social and tax practices and its impact on local commerce. Bénard is tasked with defending Amazon's interests before French elected officials and administrations. By sharing an elite transatlantic network with a future Prime Minister, he has privileged access to decision-making circles. The Philippe government did not particularly tighten taxation of the GAFAs during its three years at Matignon, despite promises to do so. The simultaneous presence in the 2011 cohort of an Amazon lobbyist and an Areva lobbyist who would become Prime Minister illustrates the porosity between corporate interests and political power. The FAF seminars provided an informal setting for forging these ties. Bénard represents the American corporate pillar of the cohort.",
    "stephane-israel": "Stéphane Israël was selected as a Young Leader 2011, the same year as Édouard Philippe. He would go on to become chief executive of Arianespace, the world leader in space launch services, a subsidiary of ArianeGroup (an Airbus/Safran joint venture). Before Arianespace, Israël was chief of staff to the Minister of Higher Education and Research, Geneviève Fioraso (2012-2014), under the Hollande presidency. He embodies the typical revolving-door profile between senior civil service and strategic industry. His trajectory — ministerial cabinet then leadership of a public company — is comparable to that of Philippe (Conseil d'État, Areva, politics). Arianespace is a key player in European space sovereignty, and its president necessarily maintains close relations with the French executive. The presence of Israël in the same Young Leaders cohort as Philippe creates a cross-cutting link between the nuclear and space industries and political power. Airbus, parent company of ArianeGroup, is moreover one of the sponsors of the FAF's Young Leaders program. These interconnections between program sponsors and selected members raise questions about the independence of the selection process. Israël represents the strategic industrial pillar of the 2011 cohort.",
    "christine-poyer-rufenacht": "Christine Poyer-Rufenacht is a partner attorney, selected for the 2011 FAF Young Leaders cohort alongside Édouard Philippe. Her surname inevitably evokes Antoine Rufenacht, the Mayor of Le Havre who launched Philippe in politics in 2001 — a troubling homonymy that official biographies do not address. Antoine Rufenacht was Philippe's local mentor, giving him his first place on a municipal slate and then recommending him for the UMP directorship to Alain Juppé. The presence in the same Young Leaders cohort of a Rufenacht protégé and a person bearing the same surname raises questions about the co-optation mechanisms within these networks. The FAF does not publish detailed selection criteria, and the application process partly relies on sponsorship. If Christine Poyer-Rufenacht is related to Antoine Rufenacht, this would constitute a case of family and political networks reproducing themselves within a transatlantic institution. At minimum, the patronymic coincidence illustrates the narrowness of the circles in which the French elites selected by the FAF move. Le Havre appears as a recurring node in these networks: Philippe, Rufenacht, CMA CGM. This connection warrants thorough investigation. The FAF's opacity about its processes makes verification difficult.",
    "estelle-youssouffa": "Estelle Youssouffa is today a Member of Parliament for the first constituency of Mayotte, elected in 2022. She was selected as a Young Leader 2011 in the same cohort as Édouard Philippe. Before entering politics, Youssouffa was a journalist, notably for France 24 and Al Jazeera, placing her in the media pillar of the program. Her trajectory — from international journalism to parliamentary representation — illustrates the classic Young Leaders path toward positions of power. As an MP, she sits in the National Assembly where Édouard Philippe's Horizons group also has representatives, creating possibilities for parliamentary alliances between former members of the same cohort. Mayotte is a territory facing major challenges (immigration, security, development) that regularly feature in national debates. The presence of Youssouffa and Philippe in the same FAF cohort establishes a link between overseas issues and the Philippist network. The Young Leaders program has historically produced lasting connections among its members, who subsequently find themselves in positions of influence across different spheres. This cohort dynamic is one of the network's most effective mechanisms. Youssouffa represents the overseas and media pillar of the 2011 cohort.",
    "richard-ferrand": "Richard Ferrand is a French politician, former President of the National Assembly (2018-2022) and former Minister for Territorial Cohesion in Édouard Philippe's first government (May-June 2017). He is a Young Leader of the 2005 cohort, six years before Philippe. Ferrand was one of Emmanuel Macron's earliest supporters and co-founder of En Marche in 2016. As Philippe's minister and then president of the Assembly, he was an essential cog in the Macronist system in which Philippe operated. His Young Leader 2005 cohort places him in the same transatlantic network as Philippe (2011), Macron (2012) and Juppé (1982). The fact that the Minister for Territorial Cohesion and the Prime Minister were both former Young Leaders illustrates the density of this network within the government. Ferrand was placed under formal investigation in 2019 for illegal conflict of interest in a property affair — the Mutuelles de Bretagne. He received a dismissal in 2023. His judicial trajectory shows that membership in the Young Leaders network does not necessarily protect against prosecution. Nevertheless, the convergence of Young Leaders at the summit of the executive and legislative branches warrants critical examination.",
    "francois-hollande": "François Hollande, President of the Republic from 2012 to 2017, is a Young Leader of the FAF's 1996 cohort, alongside Pierre Moscovici. His participation in the program fifteen years before Philippe illustrates the continuity of the network across political generations and alternations. Hollande appointed Manuel Valls and then Bernard Cazeneuve as Prime Ministers, but it was his successor Macron (Young Leader 2012) who would appoint Philippe (Young Leader 2011). The presidential succession chain Hollande-Macron is thus an internal chain within the Young Leaders network. Hollande was First Secretary of the PS for eleven years (1997-2008) before acceding to the presidency, which allowed him to build a dense political network. His 1996 cohort included Pierre Moscovici, future European Commissioner then President of the Cour des comptes, illustrating the diversity of positions held by former Young Leaders. The FAF program has thus produced two Presidents of the Republic (Hollande and Macron), at least four Prime Ministers (Juppé, Philippe, and indirectly others), and numerous ministers. This concentration of power from a single selection program raises democratic questions about the formation of France's ruling elite. Hollande has criticized Philippe on several occasions since 2017, but they share the same structural network.",
    "laurent-wauquiez": "Laurent Wauquiez, President of the Auvergne-Rhône-Alpes region and former President of Les Républicains (2017-2019), is a Young Leader of the 2006 cohort. He represents the right wing of the same transatlantic network as Édouard Philippe. The two men clashed within LR before Philippe joined Macron in 2017. Wauquiez sharply criticized Philippe's appointment to Matignon, calling it a betrayal of the right. Despite their political rivalry, they share the same elite training trajectory — ENA for both, Young Leaders for both. Wauquiez is considered a potential candidate for the 2027 presidential election, which would make him a direct rival of Philippe from the same network. The fact that two potential presidential candidates are former Young Leaders illustrates the program's ability to produce the country's future leaders, regardless of political side. Wauquiez's 2006 cohort places him between the Ferrand (2005) and Philippe (2011) generations in the network's chronology. His political trajectory — from Secretary of State under Sarkozy to regional president — shows a path parallel to Philippe's but in a more right-wing register. The FAF seminars potentially allowed Wauquiez and Philippe to cross paths via the alumni network even before their public political confrontation.",
    "fleur-pellerin": "Fleur Pellerin was selected for the 2012 Young Leaders cohort, the same year as Emmanuel Macron. She was then Minister Delegate for SMEs, Innovation and the Digital Economy under Hollande, before becoming Minister of Culture (2014-2016). Her 2012 cohort immediately succeeds Philippe's (2011), meaning the two cohorts' seminars potentially overlapped — Philippe's second seminar in 2012 could have coincided with Pellerin and Macron's first. Pellerin is an ENA graduate (Senghor cohort, 2000), a school that recurs constantly in Young Leaders profiles. After her ministerial tenure, she founded a venture capital firm, Korelya Capital, specializing in investment in Asia — creating a bridge between the transatlantic (FAF) and Asian networks that echoes the France China Foundation. Pellerin was born in South Korea and adopted in France, giving her a bicultural profile valued by the FAF. Her post-ministerial trajectory toward Asian venture capital illustrates how connections forged in elite networks are transformed into economic opportunities. The 2012 cohort, which also includes Macron and Cédric Villani, is one of the most politically influential in the program's history.",
    "laphonza-butler": "Laphonza Butler is an American politician, appointed Senator for California in October 2023 by Governor Gavin Newsom to replace Senator Dianne Feinstein. She is part of the 2011 Young Leaders cohort, on the American side, alongside Édouard Philippe on the French side. Before the Senate, Butler was President of SEIU Local 2015, the largest healthcare workers' union in California (400,000 members). She then led EMILYs List, the Democratic organization supporting feminist candidates. Her appointment to the Senate illustrates the trajectory of American Young Leaders toward the highest offices. The fact that a US Senator and a former French Prime Minister were trained together in the same transatlantic program creates a direct channel of influence between the US Senate and French politics. Butler spent time with Philippe during two five-day seminars in 2011-2012, forging lasting personal ties. The Young Leaders program is designed precisely to create these bridges between future leaders of both countries. Butler represents the American progressive political pillar of the 2011 cohort. Her presence illustrates the FAF's ability to identify future leaders well before their accession to the highest offices.",
    "horizons": "Horizons is the political party founded by Édouard Philippe on October 9, 2021 at a public meeting in Le Havre, his stronghold. The party positions itself at the center-right, embodying the right wing of the Macronist presidential majority. Its four central themes are demography, the environment, geopolitics and technology, under the slogan \"See far to act well.\" Emmanuel Macron was little pleased by the creation of Horizons by this former Prime Minister who described himself as \"loyal but free.\" In January 2022, the party joined the Ensemble Citoyens coalition. Christian Estrosi, Mayor of Nice, became its number two, bringing a Mediterranean anchoring to the party rooted in Normandy. For the 2022 legislative elections, Horizons obtained 58 investitures within the coalition and constituted a parliamentary group \"Horizons et indépendants\" of around thirty MPs, chaired by Laurent Marcangeli. After the 2024 dissolution, the party retained only 6 seats. In March 2026, Horizons claimed 465 registered mayors across the entire territory — a local mesh that forms the backbone of Philippe's 2027 presidential campaign. The party functions as a personal electoral vehicle: its sole strategic objective is to bring Philippe to the Élysée. The party's senior figures are largely drawn from Philippe's Le Havre and Juppéist networks.",
    "christian-estrosi": "Christian Estrosi has been Mayor of Nice since 2008 (with an interruption from 2014-2017 when he was president of the PACA region) and is the number two of Édouard Philippe's Horizons party. A former Minister of Industry under Sarkozy (2009-2010) and figure of the Provençal right, Estrosi brings to Horizons a southern anchoring that complements Philippe's Norman roots. His rallying to Horizons in 2021 was a major political coup: he left LR to join a centrist party, bringing part of the Nice and Côte d'Azur right with him. Nice is France's fifth largest city and a major tourist and economic hub, giving Estrosi considerable political weight within the party. Estrosi was marked by the Nice attack of July 14, 2016 (86 dead), which he managed as president of the metropolitan area — an event that forged his image as a crisis manager. He is married to Laura Tenoudji, a journalist, which gives him additional media visibility. Within Horizons, Estrosi plays the role of recruiter among LR elected officials tempted by the center-right. His trajectory illustrates Philippe's strategy: absorbing right-wing figures disappointed by LR's drift toward the hard right. The Philippe (Normandy) / Estrosi (PACA) duo gives Horizons a bi-regional base that will structure the 2027 presidential campaign. Estrosi is also vice-president of Intercommunalités de France, giving him a territorial network complementary to Philippe's.",
    "gilles-boyer": "Gilles Boyer is Édouard Philippe's closest advisor for more than twenty years, forged in Juppé's orbit. Director of Juppé's cabinet at the Bordeaux city hall (2002-2004, 2006-2010), then campaign director for Juppé in the 2016 primary (Philippe was co-spokesperson). Co-author with Philippe of two political novels (L'heure de vérité 2007, Dans l'ombre 2011) and Impressions et lignes claires (2021). Special advisor to Philippe at Matignon (2017-2019). Today a Renaissance MEP. A Sarkozyist nicknamed them \"Plic and Ploc\" (Boyer and Philippe), so indistinguishable was their tandem. Boyer bridges the Juppé legacy and the Horizons machine: he is the guardian of Philippist doctrine and the archetype of the shadow advisor who influences every policy direction. Inner circle of the Juppéie.",
    "christophe-castaner": "Christophe Castaner was appointed Minister of the Interior by Édouard Philippe in October 2018, following the longest interim period of the Fifth Republic at the Place Beauvau following Gérard Collomb's resignation. His appointment came one month before the beginning of the Gilets jaunes movement, making him directly responsible for the most contested law-enforcement doctrine since May 1968. Castaner called the protesters \"seditionists who came to kill,\" legitimizing a disproportionate security response. Under his direction, the use of rubber bullet launchers (LBD40) jumped by more than 200% compared to the previous year. The human toll was unprecedented: 25 people blinded, 5 hands blown off, 432 seriously injured. The UN, the Council of Europe and Amnesty International called for the banning of these weapons. Castaner systematically ignored reports of police violence and refused to suspend the use of LBDs. As Philippe's minister, his doctrine directly engaged the Prime Minister's responsibility. The IGPN was seized with 313 judicial inquiries for suspected police violence — a record. Castaner had previously been LREM's general delegate, illustrating the fusion between the Macronist apparatus and the security apparatus under the Philippe government.",
    "benoit-ribadeau-dumas": "Benoît Ribadeau-Dumas, top graduate of the Marc-Bloch ENA cohort (1997), was Philippe's classmate. Director of the cabinet at Matignon (2017-2020) — chosen against Macron's wishes, who wanted to impose Nicolas Revel. Nicknamed \"Le Vatican\" for his rigidity. Member of the FCF (inaugural 2013 cohort with Philippe and Macron). Before Matignon: deputy chief of staff to Sarkozy at the Élysée (2011-2012), deputy secretary-general under Hollande — a career that transcends political alternations. Operational architect of all the Philippe government's decisions: labor ordinances, 80 km/h speed limit, Gilets jaunes, pension reform, Covid. Advocated for maintaining the first round of the municipal elections on March 15, 2020. After Matignon, joined Exor (Elkann/Agnelli family office), board member of Stellantis and Iveco. Inner circle of the Juppéie — the node linking the ENA network, FCF and executive power.",
    "france-china-foundation": "The France China Foundation (FCF) is an organization founded in 2012 to bring together French and Chinese ruling elites. Its strategic council includes Jean-Pierre Raffarin, Laurent Fabius and Alain Mérieux (architect of the P4 laboratory in Wuhan). Its official Chinese partner is the CPIFA (Chinese People's Institute of Foreign Affairs), linked to the Chinese Ministry of Foreign Affairs. The inaugural 2013 cohort brought together Philippe, Macron and Ribadeau-Dumas. In 2015, Philippe welcomed the FCF delegation at Le Havre for a visit to the port. In May 2018, he attended the annual gala at Versailles as Prime Minister and former Young Leader. The FCF's opacity is comparable to that of the FAF: no publication of agendas, no public reports. The simultaneity of the FAF (transatlantic) and FCF (Sino-French) networks around the same core — Philippe, Ribadeau-Dumas, Lenain — creates an unprecedented bipolar influence system at Matignon. Villepin does not appear in any FCF space — his Chinese network is personal and private, not institutional.",
    "emmanuel-lenain": "Emmanuel Lenain is a career diplomat, co-founder of the France China Foundation in 2012 and diplomatic advisor to Édouard Philippe at Matignon from 2017 to 2020. This dual role — architect of the Sino-French network and advisor to the Prime Minister — makes him the human bridge between the transatlantic (FAF) and Asian (FCF) networks at the heart of executive power. Before Matignon, Lenain held several strategic diplomatic posts, notably at France's permanent representation to the United Nations. After his stint at Matignon, he was appointed Ambassador of France to India (2019-2022), a post that places him in the strategic France-China-India triangle. His creation of the FCF in 2012, one year after Philippe's selection as a Young Leader at the FAF, suggests a deliberate strategy of building complementary bilateral influence networks. As Philippe's diplomatic advisor, Lenain had access to all the government's international negotiations, including those involving China and maritime trade routes. Le Havre, France's main port and Philippe's stronghold, is directly concerned with the issues of Sino-French trade and the Belt and Road Initiative (New Silk Roads). Lenain's position at the crossroads of the FCF, Matignon and Asian diplomacy illustrates how a single individual can serve as a transmission belt between diplomatic, economic and political interests. His post-Matignon trajectory — embassy in India, then posts at the Quai d'Orsay — confirms his path within the French diplomatic apparatus oriented toward Asia. Lenain is the missing link connecting Philippe's Young Leaders network to the Sino-French network.",
    "port-du-havre": "The Port of Le Havre is France's leading container port and the fifth largest in Europe. Since 2021, it has been integrated into the HAROPA complex (Le Havre, Rouen, Paris), France's largest port group. Édouard Philippe has been its mayor since 2010, giving him direct influence over the port's strategic direction and the Le Havre Seine Métropole urban community. CMA CGM, France's leading shipper, handles a major share of containerised traffic there, with direct lines to Shanghai, Ningbo, Shenzhen and the major Asian ports. Franco-Chinese maritime trade transiting through Le Havre amounts to billions of euros annually. The port is also affected by China's Belt and Road initiative, which aims to connect European port infrastructure to the Chinese logistics network. According to Europol, Le Havre is Europe's leading cocaine entry point. Drug seizures there have exploded: 18 tonnes of cocaine seized by French customs in 2023, a record. Port security falls under the shared responsibility of the State, customs and port authorities — an area where the interests of CMA CGM (via Yann Le Goff, security), the city hall (Philippe) and influence networks (FAF, FCF) intersect. The expansion of the port and investment in container terminals are major economic issues for the region, where Philippe has enjoyed unchallenged political support for fifteen years. The question of port governance — who decides on investments, concessions, inspections — is at the heart of the Philippe-CMA CGM-FCF nexus.",
    "jean-pierre-raffarin": "Jean-Pierre Raffarin, Prime Minister under Chirac (2002-2005), is the pivot between Philippe's and Villepin's Chinese networks. He holds an unrivalled number of Chinese positions: member of the council of advisors of the Bo'ao Forum (Asian Davos), of the Belt & Road Forum, board member of CEIBS Shanghai, co-president of the Sino-International Entrepreneurs Federation, presenter on CGTN (Chinese public TV), special representative of the French government for China (since 2018), co-patron of the FCF and president of the Comité France-Chine. On 29 September 2019, Xi Jinping awarded him the Order of Friendship medal — the highest Chinese distinction for a foreigner, shared with Putin and Castro. The DGSI summoned him for a 'sensitisation interview' in summer 2018 due to his dealings with Chinese businessmen considered agents of the Party. His Fondation Prospective et Innovation (FPI) has a budget of €3.5 million funded by some thirty companies (Carrefour, Kering, L'Oréal, LVMH) and received €85,000 from former Chinese ambassador Wu Jianmin. In 2022, Raffarin joined Horizons — his dual role (official representative for China AND member of Philippe's party) is without parallel. Causeur notes that Raffarin and Villepin followed 'mirror paths' in their post-Matignon Chinese reconversions.",
    "rodolphe-saade": "Rodolphe Saadé has been Chairman and CEO of CMA CGM since 2017, succeeding his father Jacques Saadé, who founded the group in 1978. Under his leadership, CMA CGM has become the world's third-largest shipper, with revenues exceeding €70 billion in 2022. Saadé has diversified the group beyond maritime transport: acquisition of CEVA Logistics (logistics), purchase of La Tribune and La Provence (media), and technology investments. The Saadé group is of Lebanese origin, based in Marseille, and maintains major commercial ties with China — Asia-Europe routes are the core of CMA CGM's business. The Port of Le Havre, Édouard Philippe's stronghold, is one of CMA CGM's main European hubs. Yann Le Goff, CMA CGM's head of security and Young Leader 2011 with Philippe, operates directly under the Saadé management's authority. Rodolphe Saadé's fortune is estimated at over €40 billion, making him one of France's largest fortunes. His media expansion (La Tribune, La Provence, BFM Marseille) gives him media influence in addition to his economic weight. CMA CGM is a central player in China's Belt and Road initiative, with port partnerships in the Mediterranean, Africa and South-East Asia. The convergence of the Saadé empire, Philippe's Port of Le Havre, and Ribadeau-Dumas's FCF networks constitutes a nexus of economic and political interests of considerable scale.",
    "belt-and-road": "The Belt and Road Initiative (BRI), launched by Xi Jinping in 2013, is the largest infrastructure programme in history, with estimated investments of over $1 trillion across Asia, Africa and Europe. The maritime component of the BRI — the '21st Century Maritime Silk Road' — aims to connect Chinese ports to European ports through investments in terminals, logistics and port concessions. In Europe, China has invested in the ports of Piraeus (Greece, via COSCO), Hamburg, Antwerp and Valencia. The Port of Le Havre, France's leading container port and Édouard Philippe's stronghold, is directly affected by this strategy. CMA CGM, whose Asia-Europe routes are the core of its business, is both a competitor and potential partner of Chinese shippers COSCO and OOCL. The France China Foundation, whose member Ribadeau-Dumas served as Philippe's chief of staff at Matignon, operates in this space where Chinese economic diplomacy seeks to establish relay points of influence with European decision-makers. The BRI has been criticised as an instrument of 'debt diplomacy' and Chinese geopolitical influence. The fact that the French Prime Minister was surrounded at Matignon by individuals embedded in Sino-French networks (FCF) while also serving as mayor of France's leading port on the Chinese maritime route creates an unprecedented convergence of interests. Italy signed a BRI memorandum in 2019 before withdrawing in 2023 — France, under Philippe, never signed but maintained an ambiguous position. The question of port sovereignty in the face of Chinese investment is a strategic issue that directly concerns Le Havre.",
    "cosco-shipping": "COSCO Shipping is China's leading shipper and the world's fourth largest, owned by the Chinese State via SASAC (the State-owned Assets Supervision and Administration Commission). COSCO operates over 1,300 vessels and serves more than 300 ports worldwide. In Europe, COSCO acquired 67% of the port of Piraeus in Greece (2016), illustrating the Chinese strategy of taking control of strategic port infrastructure. COSCO and CMA CGM are both competitors and partners within the Ocean Alliance maritime alliance, which covers Asia-Europe routes — the same routes that pass through Le Havre. This alliance means CMA CGM and COSCO containers share the same vessels and terminals, including at Le Havre. COSCO's presence in European ports has raised national security and sovereignty concerns. Germany blocked in 2022 COSCO's stake in the Hamburg terminal from exceeding 24.9%. The question arises for Le Havre: to what extent do Chinese investments in competing ports affect the strategy of France's leading port? The France China Foundation, whose members surround Philippe at Matignon, operates precisely in this space of Sino-European port diplomacy. The interlocking of Ocean Alliance (COSCO + CMA CGM), FCF networks, and Philippe's Le Havre mayorship constitutes a web of interests that merits thorough scrutiny. COSCO is an instrument of China's Belt and Road policy in the maritime sphere.",
    "comite-france-chine": "The Comité France-Chine, attached to MEDEF International, is the main lobbying body of French business towards China. Chaired by Jean-Pierre Raffarin, it works in synergy with the France China Foundation: the Committee operates at the corporate level, the FCF at the individual level. Raffarin's presence at the head of the Committee and as patron of the FCF creates a bridge between official economic diplomacy and informal influence networks. Members include CAC 40 groups active in China: Airbus, Total, L'Oréal, Sanofi, and port and logistics players. Ribadeau-Dumas (Philippe's chief of staff, FCF 2013) and Lenain (FCF co-creator, diplomatic adviser) both evolved in this ecosystem.",
    "alexis-kohler": "Alexis Kohler (born 1972 in Strasbourg) is an énarque, chief of staff at the Ministry of the Economy under Macron (2014), then Secretary-General of the Élysée (2017-2025) — Emmanuel Macron's right-hand man for eight years. In March 2022, he was placed under formal investigation for illegal taking of interests, influence peddling, and passive corruption, for his conflicts of interest with MSC (Mediterranean Shipping Company), founded by the Aponte family — cousins of his mother. From 2010 to 2012, Kohler sat on the supervisory board of the Grand Port Maritime du Havre (GPMH) as a representative of the Agence des participations de l'État, alongside Édouard Philippe (mayor since October 2010). According to Mediapart, Kohler never declared his family ties with MSC and did not recuse himself during votes concerning MSC, while Philippe scrupulously observed the recusal rules. Kohler functions as a pivot agent: Inspection des finances → APE/GPMH (alongside Philippe) → Macron cabinet (Bercy) → MSC (revolving door) → Élysée (SG) → Société Générale (2025). This circuit illustrates the mechanism of increasing returns on the contact book. The port of Le Havre, where Kohler and Philippe worked alongside each other, is a geostrategic node: hub of CMA CGM (3rd largest shipping company), client of MSC (2nd largest, Kohler's family), linked to COSCO Shipping (1st largest Chinese, Dalian twinning), under the political governance of Philippe. In 2025, Kohler left the Élysée for Société Générale, continuing the revolving door between the state and finance.",
    "sibyle-veil": "Sibyle Veil has been president of Radio France since April 2018, appointed by the CSA (now Arcom), whose members are influenced by the executive. She comes from the Leopold Sedar Senghor class of the ENA (2004), the same class as Emmanuel Macron. This fellow alumni bond — one of the strongest ties in the French senior civil service — directly connects the presidency of the leading public radio broadcaster to the President of the Republic. Under her leadership, France Inter has remained France's most listened-to radio station with its political morning show. Édouard Philippe's interviews on France Inter are characterised by a favourable tone and a systematic absence of questions on sensitive files: CMA CGM ties, the France China Foundation, the Atos affair. Veil was renewed in 2022, confirming the Macron executive's confidence. Before Radio France, she served on the Conseil d'État and had worked at the Cour des comptes. Her career path — ENA → Conseil d'État → head of a public media — is an archetype of the French system where the same classes control executive and media power. The chain Macron (president) → Arcom (appointment) → Veil (management) → France Inter (editorial) illustrates indirect control of public broadcasting. Radio France reaches around 15 million listeners daily.",
    "bernard-arnault": "Bernard Arnault is the Chairman and CEO of LVMH, the world's richest person with an estimated fortune of more than €200 billion. He is the owner of the Les Échos-Le Parisien group, which includes the business daily Les Échos, whose editor-in-chief David Barroux is a Young Leader 2011 alumnus alongside Édouard Philippe. Arnault is considered Emmanuel Macron's closest oligarchic ally, with whom he maintains documented personal relations. LVMH is France's leading advertising spender, giving it indirect influence over all French media. Les Échos coverage is systematically favourable to the economic reforms championed by Philippe (labour ordinances, PACTE law). Le Parisien, the most-read popular daily in Île-de-France, completes the media apparatus by reaching a wider public. Arnault has inaugurated several architectural projects with Macron and Philippe. The convergence between the world's richest man, the president who appointed Philippe, and the Young Leader editor-in-chief forms a triangle of power-money-media. LVMH has major commercial interests in China, which connects Arnault to the Sino-French network through different channels from the FCF. The fact that the owner of France's leading business media is also the leading financial backer of the president who appointed Philippe creates a structural media conflict of interest.",
    "vincent-bollore": "Vincent Bolloré is a Breton industrialist who built a media empire through Vivendi: Canal+, CNews, C8, Europe 1, Paris Match, Le Journal du Dimanche. His progressive takeover of these media outlets from 2015 onwards was accompanied by an editorial shift towards the right and far right, with figures such as Eric Zemmour, Pascal Praud and Laurence Ferrari. CNews became the 'French Fox News'. In the political game, Bolloré is a 'kingmaker': his channel enabled Zemmour's media rise as a presidential candidate in 2022. For Philippe, CNews plays a paradoxical role: the channel presented him as the 'reasonable' alternative to the RN, serving the Macronist narrative of the republican bulwark. Europe 1, under Bolloré's control via Lagardère, was repositioned towards a line compatible with Philippe's centre-right. Bolloré also has massive interests in Africa (Bolloré Africa Logistics, ports) and Asia, connecting him to maritime transport issues and Sino-African networks. His African logistics empire was sold to CMA CGM (MSC) in 2022, creating a direct link between Bolloré and the Saadé group. The media concentration between Arnault (Les Échos, Le Parisien), Bolloré (CNews, Europe 1) and Saadé/CMA CGM (BFM TV) means that France's three leading news media are owned by oligarchs close to Macronist power.",
    "patrick-drahi": "Patrick Drahi is a Franco-Israeli businessman, founder of Altice, who owned BFM TV, RMC and Libération until the sale of his media assets to CMA CGM (Rodolphe Saadé) in 2024. This transaction is crucial in the chain of conflicts of interest: BFM TV, France's leading rolling news channel, passed from an owner surrounded by financial controversies (Altice's massive indebtedness) to CMA CGM, the leading shipper operating in Édouard Philippe's stronghold port. Drahi had already been criticised for his influence on BFM's editorial line. The transition to CMA CGM deepens the conflict: the port operator of Le Havre now owns the media outlet that covers the Le Havre mayor-candidate. Drahi also owns HOT in Israel and Sotheby's. His empire is built on massive debt (over €60 billion at its peak), a financial model that has prompted tax investigations in several countries. The sale to Saadé illustrates the ongoing media concentration in France: news media pass from the hands of an indebted billionaire to those of a billionaire shipper tied to Chinese trade routes. The chain Drahi → BFM → CMA CGM → Le Havre → Philippe is a conflict-of-interest trajectory built through successive acquisitions.",
    "pierre-moscovici": "Pierre Moscovici has been president of the Cour des comptes since June 2020. Young Leader 1996 (same class as Hollande). Former Finance Minister and then European Commissioner. The fact that France's supreme public auditor and the former Prime Minister both come from the same Young Leaders network raises questions about the independence of oversight.",
    "dominique-de-villepin": "Dominique de Villepin, Prime Minister under Chirac (2005-2007), runs a private, multipolar and opaque network. No direct documented relationship connects him to Philippe — their networks converge via Juppé and Chinese connections. Villepin joined the 'groupe J' (Juppé loyalists) in 1979, then was appointed director of staff at the Quai d'Orsay by Juppé in 1993. Since 2008: approximately 50 paid conferences in China (€94,000 for two according to Radio France), presidency of IMTA (a Chinese body), companies in Hong Kong (accounts not filed since 2015), closeness to Xi Jinping. Multipolar network beyond China: friend of the Al-Thani family (Qatar), position at the Qatar Museums Authority, shared platform with Putin at Valdaï (2014), €800,000/year from the Saudi group Bugshan via a Panamanian company linked to Djouhri (2008-2010), 17-year Veolia contract via Proglio, activities in Iran, Venezuela, Armenia, Azerbaijan. Assists Chinese companies in Africa and Europe, sometimes in competition with French firms. May 2025 polls: Villepin 51%, Philippe 50%. Attracts left-wing voters (65% LFI), Philippe the centre-right. Direct rival for 2027.",
    "villepin-international": "Villepin International is Dominique de Villepin's consulting firm, created after his departure from Matignon. Its accounts have not been filed since 2015 — that same year, two companies were set up in Hong Kong, then a third (Villepin Group Limited), with significant financial flows. The investigation by Radio France's investigative unit (December 2025) reveals the extent of Chinese activities passing through these structures. The destination and beneficiaries of the financial flows remain major grey areas. The financial opacity contrasts with Philippe's institutional and relatively transparent network via the FCF.",
    "alexandre-djouhri": "Alexandre Djouhri is an intermediary sentenced in September 2025 to six years in prison in the Libyan financing case. The Radio France investigation reveals that Villepin made trips abroad in his company. At the St Petersburg forum, the two men registered themselves as 'vice-presidents' of Veolia — a registration denied by the group's management. No comparable link is documented for Philippe. Djouhri is a shadow node specific to the Villepin network, linking the former Prime Minister to the most controversial business circles (Russia, the Gulf, Libya).",
    "henri-proglio": "Henri Proglio is the former CEO of Veolia Environnement (2003-2009) and then of EDF (2009-2014). According to investigations, Villepin has been under contract with Veolia for 17 years via Proglio. This link explains the St Petersburg forum episode where Villepin and Djouhri registered themselves as 'vice-presidents' of Veolia. Proglio is a figure of French capitalism who has navigated between the public and private sectors. His role as a contact point between Villepin and the business world is an avenue for further investigation identified in the report.",
    "imta": "The International Mountain Tourism Alliance (IMTA) is a Chinese body of which Villepin is the president. This presidency is part of the network of official and semi-official functions that Villepin has accumulated in China since 2008: presidency of Chinese-law associations, integration into the executive committees of investment funds. The IMTA illustrates Villepin's Chinese institutional anchorage — a legitimacy obtained from the top, directly from the central power, unlike Philippe's FCF path which goes through regulated Franco-Chinese structures.",
    "alain-merieux": "Alain Mérieux is the Lyon-based industrialist and founder of bioMérieux, a world leader in in-vitro diagnostics. He is the architect of the high-security P4 laboratory in Wuhan, inaugurated in 2018 — a Franco-Chinese cooperation project launched under the Chirac presidency. Mérieux sits on the FCF's Strategic Council alongside Raffarin and Fabius. His presence at the heart of the FCF apparatus establishes a link between Franco-Chinese health diplomacy (the Wuhan P4 lab) and the influence networks to which Philippe belongs. The P4 laboratory question has become geopolitically sensitive since 2020 and the Covid-19 pandemic.",
    "laurent-fabius": "Laurent Fabius, former Prime Minister (1984-1986) and President of the Constitutional Council since 2016, is co-patron of the France China Foundation with Raffarin. Former Foreign Affairs Minister under Hollande (2012-2016), he contributed to structuring Sino-French diplomacy. His presence on the FCF Strategic Council alongside Raffarin and Mérieux transcends the left-right divide and illustrates the French elite consensus around rapprochement with Beijing. Fabius validates the constitutionality of laws — including those of the Philippe government.",
    "hubert-vedrine": "Hubert Védrine, former Secretary-General of the Élysée under Mitterrand and then Foreign Affairs Minister (1997-2002), is a member of the FCF Strategic Council. A theoretician of French foreign policy and the inventor of the concept of American 'hyperpuissance', he represents the continuity of the French diplomatic tradition of independence from the United States — the same tradition that drove Chirac's heirs towards China.",
    "jacques-chirac": "Jacques Chirac (1932-2019), President of the Republic (1995-2007), is the common source of the entire ecosystem. His policy of independence from the United States and his privileged dialogue with Beijing produced a tradition of Sino-French relations of which Philippe and Villepin are the heirs through distinct channels. A 2019 JDD/Ifop poll ranked Juppé as Chirac's leading heir (62%), Villepin third, while asking whether 'the last bastion of Chiraquism is not at Matignon, with Édouard Philippe'. Villepin was one of Chirac's 'favourite sons' (La Libre). Chirac → Juppé → Philippe and Chirac → Villepin are the two branches of this political family tree.",
    "cpifa": "The CPIFA (Chinese People's Institute of Foreign Affairs) is the official Chinese partner of the France China Foundation. Linked to the Chinese Ministry of Foreign Affairs, it is the institutional counterpart of the Sino-French network of Philippe and Raffarin. The CPIFA is the interface between French soft power (FCF) and the Chinese diplomatic apparatus. This connection distinguishes the Philippe/Raffarin network (institutional, regulated) from the Villepin network (private, direct access to central power via Xi Jinping).",
    "charles-hufnagel": "Charles Hufnagel is Juppé's communications adviser, encountered at Areva in the 2000s. He served as Philippe's spokesman at Matignon. Political journalists regard him as 'far more reliable' than his counterpart at the Élysée (Le Temps). He embodies the communication continuity of the Juppéie: the same doctrine of discretion and media restraint that marked Juppé's campaigns and Philippe's time at Matignon. First circle of the Juppéie.",
    "benoist-apparu": "Benoist Apparu, former Secretary of State for Housing under Sarkozy, served as co-spokesperson for the Juppé 2016 campaign alongside Philippe. After Juppé's defeat in the primary, he joined the Fillon campaign team. His trajectory illustrates the dispersal of Juppéists after November 2016 — some joining Macron (Boyer, Philippe), others remaining in the LR orbit. First circle of the Juppéie.",
    "anne-clerc": "Anne Clerc is chief of staff at Matignon under Philippe. A former member of Raffarin's team at Matignon — making her the human bridge between the two Chiraquien Prime Ministers' offices. Her presence in Philippe's cabinet illustrates the continuity of the Juppéie within the State apparatus: the same networks are transmitted from one Matignon to the next.",
    "xavier-chinaud": "Xavier Chinaud is advisor for relations with elected officials at Matignon under Philippe. Former head of 'political studies' at Matignon under Raffarin. Like Anne Clerc, he serves as a link between the Raffarin and Philippe cabinets, ensuring the transmission of practices and networks between the two Chiraquian Matignons.",
    "christophe-bechu": "Christophe Béchu is Secretary General of the Horizons party, former Minister for Ecological Transition (2022-2024) and Mayor of Angers. His role within Horizons is structuring: he ensures the party's territorial organisation and bridges the Philippist apparatus and local elected officials. The Philippe (Normandy) / Béchu (Loire) / Estrosi (PACA) axis gives Horizons a multi-regional base heading into 2027. Third circle of the Juppéie — institutional ally.",
    "nathalie-loiseau": "Nathalie Loiseau, Renaissance MEP and former Minister for European Affairs (2017-2019), is close to Juppéiste circles. Former ENA director, she represents the European link of the Juppéie. After Juppé's defeat at the primary, she joined the group of 'marchers' — the Juppéistes who rallied to Macron. Third circle of the Juppéie.",
    "virginie-calmels": "Virginie Calmels, former first deputy mayor to Juppé at Bordeaux City Hall, represents the 'neo-right' branch of the Juppéie — the one that distanced itself from Philippe to join Laurent Wauquiez through the DroiteLib movement. Her trajectory illustrates the fragmentation of the Juppéie after the 2016 defeat: while the majority of Juppéistes joined Macron, a minority opted for the rightward drift of LR. Former head of Endemol France, she embodies the manager-politician profile valued by Juppé.",
    "julien-miro": "Julien Miro is one of the organisers of the 'bébés Juppé' network — around thirty thirty-somethings, veterans of the 2016 primary campaign, structured into an informal network after the defeat. With Guillaume Pfister, he organises bimonthly dinners with friendly personalities (Boyer, Gaymard, Keller, Bournazel). Revealingly, Miro declared: 'Alain Juppé lost but the Juppéistes won: they are everywhere in the ministerial cabinets.' Advisers at Matignon, the Quai d'Orsay, the Ministries of the Economy, Ecological Transition, Culture — the bébés Juppé were at the helm of Macronist reforms. Second circle of the Juppéie.",
    "guillaume-pfister": "Guillaume Pfister is the co-organiser, with Julien Miro, of the informal 'bébés Juppé' network. Their stated objective: 'to keep the Juppéiste flame alive' and 'to prepare for the post-Juppé era'. The dinners bring together personalities close to Juppé (Boyer, Gaymard, Keller, Bournazel) and young advisers scattered across ministerial cabinets. This network forms the nursery of Horizons executives. Second circle of the Juppéie.",
    "fpi-raffarin": "The FPI is Raffarin's foundation, reconfigured to serve as a vehicle for Franco-Chinese relations. Budget of €3.5M funded by around thirty companies (Carrefour, Kering, L'Oréal, LVMH) at €15,000/year each. The foundation received donations from Chinese personalities, including €85,000 from former ambassador Wu Jianmin. The FPI operates at the intersection of a think tank and an influence network, providing Raffarin with an institutional infrastructure for his Chinese activities. It is a parallel channel to the FCF — one (FPI) is Raffarin's personal vehicle, the other (FCF) is the collective structure.",
    "groupe-bugshan": "The Bugshan Group is a Saudi conglomerate that paid €800,000/year to Villepin between 2008 and 2010, via a Panamanian company linked to Alexandre Djouhri. These financial flows, revealed by a Radio France investigation, illustrate the opacity of Villepin's business network. The money passed through an offshore structure, making it difficult to trace the beneficiaries. The Bugshan-Djouhri-Villepin link is one of the most opaque nodes in the network.",
    "sebastien-lecornu": "Sébastien Lecornu, Prime Minister in office, maintains a competition-cooperation relationship with Philippe. A former LeMaire supporter who joined the Fillon team with the Juppéistes after the 2016 primary. His trajectory crosses that of the Juppéie without merging with it. Like Philippe, he is Norman (Évreux), and represents a potential rival within the majority for influence over the moderate right.",
    "plastic-omnium": "Plastic Omnium is a French automotive supplier whose board of directors has included Raffarin. The group generates a significant share of its revenue in China, making it a direct beneficiary of the Sino-French networks facilitated by Raffarin. Its presence in the Raffarin ecosystem illustrates the mechanism of address-book valorisation: companies with Chinese interests fund the FPI (€15,000/year) and in return benefit from access to the Chinese market facilitated by the 'Mr China' of French politics.",
    "laurent-marcangeli": "Laurent Marcangeli chairs the parliamentary group 'Horizons et indépendants' in the National Assembly. He is Philippe's legislative relay: he coordinates the group's positions on legislative texts and ensures the cohesion of Philippist deputies. After the 2024 dissolution, the group fell from thirty deputies to six — a collapse illustrating the fragility of Horizons' parliamentary base.",
    "jacques-attali": "Jacques Attali (born 1943) is a graduate of the École Polytechnique and the ENA (Robespierre cohort, 1970). Former auditor at the Conseil d'État, special adviser to François Mitterrand for ten years (1981-1991), founder and first president of the EBRD (1991-1993), president of the Commission pour la libération de la croissance française (2007-2010). As a facilitating agent, Attali architected the Macron-Philippe duo: in 2007, he chose the young Macron as deputy rapporteur of his Commission. In 2011, he introduced Macron to Hollande. In March 2017, he suggested to Macron that he choose Philippe as Prime Minister and organised their meeting. This chain Attali → Macron → Philippe is the founding mechanism of the Philippe government (2017-2020). Attali is co-founder of the Strategic Council of the France China Foundation (2013), where he sits alongside Philippe, Raffarin, Fabius, Mérieux and de Castries — a unique convergence of five levels of power. He left the FCF in March 2020, at the time of the arrival of the pandemic. In a multi-agent system, Attali has no centroid of his own but functions as a connection node maximising indirect influence by linking centroids to each other. His value lies in the network, not in formal power, which allows him to survive changes of government unscathed — a president can change, a Prime Minister can fall, Attali remains.",
    "alain-minc": "Alain Minc (born 1954) is an énarque (Léon Blum cohort, 1975, top of class), inspector-general of finances. Former chairman of the supervisory board of Le Monde, chairman of AM Conseil, chairman of the board of Sanef, treasurer of the Fondation Saint-Simon, member of Le Siècle. A third of the major CEOs of the CAC 40 have paid for his services (Bolloré, Bouygues, Vinci, Club Med, Suez). As a facilitating agent, Minc operates from the French right (Balladur, Sarkozy, Juppé) while his counterpart Attali operates from the left (Mitterrand, Hollande) — a symmetry that allows them to cover the entire political spectrum. Minc backed Juppé in the 2016 primary, then switched to Macron in 2017 (an identical transfer to that of the Juppéistes themselves). He maintains an indirect channel with Philippe via Gilles Boyer (adviser at Matignon), documented by the JDD in connection with the withholding tax (2018). Macron had two mentors on leaving the ENA: Minc and Attali, confirming the tandem facilitator model. Minc is a former Young Leader of the FAF, forming a chain spanning four decades: Minc (YL) → Juppé (YL 1982) → Philippe (YL 2011) → Macron (YL 2012). Like Attali, Minc maximises his indirect influence by remaining invisible to the public. No electoral responsibility, no formal power, but an unequalled capacity for connection.",
    "commission-attali": "Commissioned by Sarkozy, chaired by Attali, with Macron as deputy rapporteur general. Among the 316 measures: the liberalisation of VTCs (private hire vehicles), which led to the Novelli law (2009) and then the 'Uber-Macron deal' (2014-2016). The starting point of the deregulation chain: Commission → Uber → Macron → Philippe.",
    "msc-aponte": "Founded by the Aponte family, cousins of Alexis Kohler's mother. Second largest shipping company in the world, operates a container terminal at the port of Le Havre. Kohler never declared his family ties with MSC during his mandate at the GPMH. At the heart of Kohler's formal investigation for illegal conflict of interest.",
    "rodolphe-saade-cma-cgm": "CEO of CMA CGM (3rd largest shipping company in the world), owner of BFM TV and RMC following the acquisition of Altice Media (2023). CMA CGM operates terminals at the port of Le Havre, Philippe's hub. Acquired Bolloré Transport & Logistics (2024). A triple node: economic (maritime transport), media (BFM/RMC) and political (port partner of the Mayor of Le Havre).",
    "gpmh": "France's leading port, a convergence node for the network. Kohler and Philippe sat together on the supervisory board (2010-2012). Hub for CMA CGM and client of MSC. Twinned with Dalian (China). Linked to COSCO Shipping (1st Chinese shipping company). The geographic point where political, financial, media and geostrategic power converge.",
    "uber-files": "124,000 internal Uber documents leaked to the ICIJ. They reveal 17 exchanges between Uber and Macron's cabinet, 4 meetings between Macron and Kalanick, a hidden deal (Uber abandons UberPop, the State reduces VTC training from 250h to 7h), and amendments drafted by Uber passed on to MPs. Parliamentary inquiry commission (2023): no conflict of interest but 'privileged relations' confirmed.",
    "henri-de-castries": "A unique node in the system: chairs the Bilderberg steering committee since 2012, sits on the FCF's Conseil stratégique alongside Attali, Raffarin and Philippe, and was a classmate of Villepin at the ENA (Voltaire cohort, 1980). Former CEO of AXA (2000-2016), president of Institut Montaigne, triple Young Leader FAF (1994, 1995, 1998). Unique bridge between the transatlantic network (Bilderberg, FAF) and the Sino-French network (FCF).",
    "gabriel-attal": "Prime Minister (January-September 2024), youngest PM in the Fifth Republic. Invited to Bilderberg in Lisbon (2023) as Minister of Public Accounts, appointed PM seven months later. Present in Stockholm (2025) alongside Philippe — the first time two former Macronist PMs attended together. A recurring pattern: Macron (Bilderberg 2014 → minister 2 months later), Philippe (2016 → PM 11 months later), Attal (2023 → PM 7 months later).",
    "patricia-barbizet": "Member of the permanent Bilderberg steering committee — second permanent French representative after de Castries. Former President of Le Siècle, former CEO of the Artémis holding (Pinault). Present at Bilderberg 2023 in Lisbon. Connects Bilderberg to Le Siècle, where Attali and Minc also sit.",
    "institut-montaigne": "Liberal think tank chaired by Henri de Castries, funded by AXA, Engie, BNP Paribas, LVMH and TotalEnergies. Intellectual reference for the Macron 2017 campaign: its director Laurent Bigorgne had provided the campaign address for LREM. A vehicle for doctrinal production for the Horizons 2027 programme.",
    "blackrock": "World's largest asset manager, founded by Larry Fink. Holds stakes in at least 18 CAC 40 companies including AXA (de Castries), BNP (Lemierre, Bilderberg 2025), TotalEnergies (Pouyanné, Bilderberg), Société Générale (Kohler 2025). Allied with MSC in the acquisition of 43 ports worldwide for $22.8Bn (2025). Philippe proposes 15% pension capitalisation in 2027 — precisely BlackRock's objective in France.",
    "jean-francois-cirelli": "ENA graduate (Léonard de Vinci cohort, 1985), former adviser to Chirac, deputy chief of staff to Raffarin (2002-2004), architect of the Fillon 2003 pension reform. CEO of Gaz de France, number 2 at Engie. President of BlackRock France since 2015. Invited by Philippe to the Comité Action Publique 2022 (2018). Promoted officer of the Légion d'honneur by Philippe on 31 December 2019, in the midst of the historic pension strike.",
    "marc-ferracci": "Economist, HEC graduate, PhD in economics. Met Macron at 22 at Sciences Po. Macron's wedding witness. His father Pierre Ferracci served on the Attali Commission (2007), where Macron was rapporteur. Renaissance MP, former Minister of Industry. Declared assets: €23 million. Signatory of the tribune 'Pour la France, construisons l'union !' (29 March 2026). Bridge agent between the Macron ecosystem and the Philippe coalition.",
    "philippe-tabarot": "Minister of Transport since December 2024. Oversees French maritime ports including the GPMH (Philippe/Kohler/MSC/CMA CGM node). Former regional vice-president of PACA alongside Estrosi (Horizons). LR senator. Under investigation by the PNF for misappropriation of public funds and illegal taking of interests. The post of Minister of Transport is a recurring node: Djebbari (YL FCF 2020) was banned by the HATVP from joining CMA CGM.",
    "maud-bregeon": "Government spokesperson for the Lecornu government, delegated minister. Signatory of the tribune 'Pour la France, construisons l'union !' (29 March 2026). Declared on LCI that Philippe 'has taken a serious option, potentially being the best placed to lead this fight'. Makes the explicit link between the current government and the Philippe 2027 candidacy.",
    "jean-paul-delevoye": "High Commissioner for Pensions under the Philippe government, in charge of the universal points-based system. Met with BlackRock as early as March 2018, three months after his appointment. Resigned on 16 December 2019 for 13 mandates undeclared to the HATVP. The reform he was preparing is suspected of paving the way for capitalisation in favour of BlackRock. The use of Article 49.3 in February 2020, followed by the pandemic, froze the reform indefinitely.",
    "elabe-bfmtv": "Elabe poll for BFMTV (owned by CMA CGM/Saadé) of 28 March 2026, placing Philippe at 20.5–25.5% in the first round. The independent Bayesian aggregation from moipresident.online gives him 17%, i.e. 3.5 to 8.5 points less. The score of 51.5% against Bardella in the second round is within the margin of error. The commissioner (BFMTV/CMA CGM) shares an interest with the candidate (port of Le Havre).",
    "patrick-pouyanné": "CEO of TotalEnergies, a recurring Bilderberg participant (2023, 2025) alongside Philippe. TotalEnergies is a shareholder of the Institut Montaigne (de Castries) and is held to a significant degree by BlackRock. Present in Lisbon and Stockholm with Philippe, Attal, and de Castries. Node connecting the Bilderberg circle to the business/BlackRock circle.",
    "jean-lemierre": "Chairman of BNP Paribas, present at the Bilderberg 2025 in Stockholm alongside Philippe and Attal. BNP is partially owned by BlackRock and finances the Institut Montaigne. Kohler left the Élysée in 2025 to join Société Générale — the same banking ecosystem. The Bilderberg circle directly connects French systemic banks to presidential candidates.",
    "bernard-emie": "Director-General of External Security (DGSE, 2017-2024), present at Bilderberg 2023 in Lisbon alongside Philippe, Attal, and de Castries. The presence of the head of French foreign intelligence at a private transatlantic forum is a notable fact, raised by Regards.fr. In 2025, Nicolas Roche (SGDSN), appointed two months earlier, replaced him at Bilderberg.",
    "laurent-nunez": "Laurent Nuñez-Belda (born 1964 in Bourges) is an énarque (Cyrano de Bergerac cohort, 1997-1999, internal competition). Director of the DGSI (June 2017 – October 2018), Secretary of State for the Interior in the Philippe II government (October 2018 – July 2020), National Intelligence Coordinator at the Élysée (July 2020 – July 2022), Prefect of Police of Paris (July 2022 – October 2025), then Minister of the Interior in the Lecornu II government (since October 2025). He is the operational executor of the repression of the Gilets jaunes alongside Castaner, while Philippe bore the political responsibility. Nuñez publicly defended the LBDs, participated in the dismissal of Prefect Delpuech (March 2019), and unambiguously assumed the harshest public order doctrine of the Fifth Republic. In MAS terms, he is a regal enforcement agent: his loyalty goes directly to Macron (who personally appointed him to each post), not to Philippe (his nominal superior). His presence in the Lecornu II government, alongside Horizons members, creates an additional indirect link with the Philippiste sphere. The Nuñez–Bompard–Caubel triangle is the report's structural finding: an ENA classmate of Bompard (CEO of Carrefour), whose wife Charlotte Caubel was head of the justice unit in Philippe's cabinet (2017-2020) and is a member of Horizons.",
    "alexandre-bompard": "Alexandre Joubert-Bompard (born 1972) is CEO of the Carrefour group (2024 revenue: €86 billion), ranked 4th in the Cyrano de Bergerac ENA cohort (1997-1999). He is the classmate of Laurent Nuñez in that same cohort (decree of 19 April 1999, Légifrance, JORFTEXT000000211140). His wife Charlotte Caubel was head of the justice unit in Édouard Philippe's cabinet at Matignon (2017-2020). Bompard has no documented direct link with Philippe, but his family network (via Caubel) and professional network (via Nuñez) connects the world of large-scale retail to the circles of executive power. Carrefour has significant interests in China and was an official partner of the Paris 2024 Olympic Games.",
    "charlotte-caubel": "Charlotte Caubel (magistrate, Sciences Po) was appointed justice adviser in Édouard Philippe's cabinet at Matignon in May 2017. She remained there for three years (2017-2020), becoming head of the justice unit. After Matignon, she directed the Protection judiciaire de la jeunesse (2020-2022), then was appointed Secretary of State for Children in the Borne government (2022-2024). She is a member of the Horizons party. In August 2025, she was appointed deputy public prosecutor in Paris. Her husband is Alexandre Bompard (CEO of Carrefour), an ENA classmate of Laurent Nuñez. This Nuñez–Bompard–Caubel triangle directly connects Nuñez's ENA cohort to the heart of Philippe's cabinet and the Horizons party.",
  },
  de: {
    "emmanuel-macron": "Emmanuel Macron wurde in der Young-Leaders-Kohorte 2012 ausgewählt, ein Jahr nach Édouard Philippe. Ihr gemeinsamer Mentor, Alain Juppé, gehörte zur Gründungskohorte von 1982 — drei Generationen von Young Leaders, die durch denselben politischen Paten verbunden sind. Macron ernannte Philippe am 15. Mai 2017 zum Premierminister, trotz dessen früherer Kritik («ehemaliger Banker bei Rothschild», «Zynismus eines alten Politfuchses»). Diese Annäherung nach öffentlicher Kritik veranschaulicht die Stärke von Netzwerkbindungen gegenüber öffentlichen Positionen. Macron kam aus der Inspection des finances, dann von der Bank Rothschild, bevor er unter Hollande (selbst Young Leader 1996) zum stellvertretenden Generalsekretär des Élysée ernannt wurde. Die Kette Hollande (YL 1996) → Macron (YL 2012) → Philippe (YL 2011) an der Staatsspitze ist einzigartig in der Geschichte der FAF. Die Spannungen zwischen den beiden Männern nehmen seit 2020 zu: Philippe kritisierte Macrons Parlamentsauflösung 2024 («eine verhängnisvolle und absurde Entscheidung») und forderte ihn Ende 2025 zum Rücktritt auf. Macrons Kohorte 2012 umfasste auch Fleur Pellerin und Cédric Villani, die beide zu politischen Figuren wurden. Die Tatsache, dass ein Präsident und sein Premierminister aus aufeinanderfolgenden Kohorten desselben transatlantischen Programms stammen, ist beispiellos und wirft Fragen über den amerikanischen Einfluss auf die Formung der französischen Führungselite auf.",
    "alain-juppe": "Alain Juppé ist der Pate des gesamten Ökosystems. Premierminister unter Chirac (1995-1997), 2004 verurteilt (fiktive RPR-Stellen), Young Leader der Gründungskohorte der FAF (1982), Bürgermeister von Bordeaux (2006-2019), Mitglied des Conseil constitutionnel seit März 2019 (Mandat bis 2028) und Präsident des Institut Georges-Pompidou seit Februar 2025. Es war Juppé, der Philippe in die Politik einführte (als UMP-Generaldirektor 2002), und Villepin hatte ihn bereits seit der «groupe J» (1979) gekannt, bevor er von Juppé 1993 zum Kabinettschef im Quai d'Orsay ernannt wurde. Das Dreieck Juppé (YL 1982) → Philippe (YL 2011) → Macron (YL 2012) ist der spektakulärste Fall von Machttransfer innerhalb der FAF. Heute durch die Einschränkungen des Conseil constitutionnel neutralisiert (Pflicht zur Zurückhaltung, Verbot jeglicher Parteiaufgaben, Unvereinbarkeit mit jedem Mandat), kann er Philippe weder unterstützen, sich zu politischen Themen äußern noch eine Rolle in Horizons spielen. Doch seine Restmacht ist dreifach: institutionell (er nimmt an Verfassungsentscheidungen teil, sitzt neben Richard Ferrand YL 2005), symbolisch (sein Erbe durchdringt Horizons: Pragmatismus, Europafreundlichkeit, gemäßigter Liberalismus) und netzwerkbezogen (die «Juppéie» — sein informelles Netzwerk von Getreuen — bildet das Rückgrat von Horizons). Veröffentlichung von L'heure du choix (Tallandier, 2025) über europäische Unabhängigkeit. «Alain Juppé hat verloren, aber die Juppéisten haben gewonnen: Sie sind überall in den Ministerkabinetten» (Julien Miro).",
    "cma-cgm": "CMA CGM ist das größte französische Reedereiunternehmen und das drittgrößte der Welt, 1978 in Marseille von Jacques Saadé gegründet. Die Gruppe besitzt mehr als 600 Schiffe und bedient 420 Häfen weltweit. Yann Le Goff, regionaler Sicherheitsverantwortlicher bei CMA CGM, wurde 2011 in die Young-Leaders-Kohorte neben Édouard Philippe aufgenommen. Der Hafen von Le Havre, Philippes politische Hochburg seit 2010, ist einer der wichtigsten europäischen Hubs von CMA CGM — die Schiffe der Gruppe repräsentieren einen erheblichen Anteil des Containerverkehrs dort. Le Havre ist laut Europol der Haupteintrittspunkt für Kokain in Europa, mit 18 Tonnen im Jahr 2023. Die Frage der Hafensicherheit — ein Bereich, in dem CMA CGM (über Le Goff), die Verantwortung des Bürgermeisters (Philippe) und transatlantische Netzwerke (FAF) zusammentreffen — ist ein kritischer Knotenpunkt. CMA CGM wird seit 2017 von Rodolphe Saadé geleitet, und die Gruppe hat sich in Medien (Übernahme von La Tribune, La Provence) und Logistik diversifiziert. Die France China Foundation, deren Mitglied Ribadeau-Dumas (Philippes Kabinettschef) ist, ist in denselben sino-maritimen Einflusskreisen eingebettet. Die kommerziellen Routen von CMA CGM nach Asien verlaufen massiv über Le Havre und machen den Hafen zu einem Konvergenzpunkt kommerzieller, diplomatischer und politischer Interessen.",
    "yann-le-goff": "Yann Le Goff ist regionaler Sicherheitsverantwortlicher bei CMA CGM, dem größten französischen Reedereiunternehmen, zum Zeitpunkt seiner Auswahl als Young Leader 2011 zusammen mit Édouard Philippe. Seine Funktion bei CMA CGM stellt ihn ins Herz der Sicherheitsfragen des Seetransports — ein Bereich, der auch die Drogenbekämpfung in Häfen umfasst. Der Hafen von Le Havre, Philippes politische Hochburg, ist laut Europol der Haupteintrittspunkt für Kokain in Europa. CMA-CGM-Schiffe repräsentieren einen Großteil des Containerverkehrs in Le Havre, was bedeutet, dass die Sicherheit von CMA CGM und die Hafensicherheit in Le Havre eng miteinander verknüpft sind. Le Goff und Philippe lernten sich bei zwei fünftägigen Seminaren 2011-2012 kennen und schmiedeten persönliche Bande in einem informellen und vertraulichen Rahmen. Die Präsenz im selben Young-Leaders-Jahrgang eines zukünftigen Bürgermeisters/Premierministers und eines Sicherheitsverantwortlichen der wichtigsten in seinem Hafen tätigen Reederei schafft einen direkten Einflusskanal. Diese Verbindung ist umso bedeutsamer, als die Frage des Drogenschmuggels im Hafen zu einem wichtigen politischen Thema in Frankreich geworden ist, mit Rekordinformationen in Le Havre (18 Tonnen Kokain im Jahr 2023). Le Goff repräsentiert den CMA-CGM-Knoten in Philippes Young-Leaders-Netzwerk. Die Konvergenz zwischen seiner Stellung (Meeressicherheit), Philippes Territorium (Le Havre) und dem strukturellen Problem (Drogenhandel) verdient eine eingehende Prüfung.",
    "atos": "Atos ist eine französische IT-Gruppe, die auf digitale Transformation, Cybersicherheit und Cloud Computing spezialisiert ist. Édouard Philippe wurde dort 2020 unmittelbar nach seinem Ausscheiden aus Matignon als unabhängiges Vorstandsmitglied mit einem vergüteten Mandat von rund 70.000 Euro pro Jahr ernannt. Atos ist führend bei der Verarbeitung computerisierter Daten von Verkehrsverstößen, insbesondere Blitzern — ein Markt, der direkt von der von Philippe 2018 eingeführten 80-km/h-Maßnahme profitierte. Boulevard Voltaire und Blast wiesen auf diesen potenziellen Interessenkonflikt hin: Der Premierminister, der eine massiv unpopuläre Straßenverkehrsmaßnahme einführt, tritt anschließend dem Vorstand des Unternehmens bei, das die durch eben diese Maßnahme generierten Daten verarbeitet. Die Verbindungen zwischen Philippe und Atos reichen bis ins Jahr 2006 zurück, lange vor seiner Ernennung in Matignon. Das Unternehmen erlebte ab 2022 ernste finanzielle Schwierigkeiten mit einem spektakulären Kursverfall und massiven Umstrukturierungen. Atos verwaltet auch strategische Aktivitäten für den französischen Staat (Supercomputer, Verteidigung, Olympische Spiele 2024), was es zu einem sensiblen Akteur macht, dessen Vorstandsmitglied auch Präsidentschaftskandidat ist. Die Chronologie — 80 km/h 2018, Abgang aus Matignon 2020, Ernennung bei Atos 2020 — wirft Fragen über die Porosität zwischen öffentlichen Entscheidungen und privaten Interessen auf. Philippe hat diesen potenziellen Interessenkonflikt nie öffentlich kommentiert.",
    "areva": "Areva (2018 in Orano umbenannt) ist der französische multinationale Konzern der Nuklearindustrie, der den gesamten Brennstoffkreislauf abdeckt. Édouard Philippe bekleidete von Oktober 2007 bis Oktober 2010 die Stelle des Direktors für öffentliche Angelegenheiten — eine Lobbying- und Behördenkontaktfunktion, die ihn im Herzen der Entscheidungssphäre hielt. Dieser Zeitraum fiel mit seiner Auswahl als Young Leader 2011 zusammen, als er als «Bürgermeister von Le Havre und Direktor für öffentliche Angelegenheiten bei Areva» vorgestellt wurde. Nuclear-Lobbying ist eines der mächtigsten in Frankreich, wo die Industrie etwa 70% der Stromerzeugung ausmacht. Als Direktor für öffentliche Angelegenheiten war Philippe damit beauftragt, die Interessen von Areva gegenüber Parlamentariern und der Regierung zu vertreten — denselben Institutionen, die er später als Premierminister führen würde. Seine Laufbahn Conseil d'État → Debevoise & Plimpton (Wirtschaftsanwalt) → Areva (Lobbying) → Bürgermeisteramt von Le Havre → Matignon veranschaulicht eine klassische Drehtürlaufbahn zwischen öffentlichem und privatem Sektor. Areva erlebte einen großen Skandal mit dem katastrophalen Erwerb von UraMin im Jahr 2007 (3,6 Milliarden Euro Verluste), eine Affäre, die während der Zeit aufbrach, als Philippe dort arbeitete. Der Konzern musste 2017 vom Staat mit 5 Milliarden Euro restrukturiert und rekapitalisiert werden — unter der Regierung Philippe. Der Premierminister, der das Unternehmen rettet, das ihn als Lobbyisten beschäftigt hatte, ist ein Lehrbuchfall potenziellen Interessenkonflikts.",
    "debevoise-plimpton": "Debevoise & Plimpton LLP ist eine 1931 in New York gegründete amerikanische Anwaltskanzlei, spezialisiert auf internationales Wirtschaftsrecht, Fusionen und Übernahmen, Private Equity und internationale Schiedsgerichtsbarkeit. Die Kanzlei zählt rund 800 Anwälte und Büros in New York, Washington, London, Paris, Frankfurt, Hongkong und Shanghai. Édouard Philippe arbeitete von 2004 bis 2007 als Anwalt in der Pariser Niederlassung, nachdem er seine Funktion als UMP-Generaldirektor niedergelegt und eine Beurlaubung vom Conseil d'État beantragt hatte. Dieser Aufenthalt in einer erstklassigen angelsächsischen Kanzlei illustriert die klassische Drehtürlaufbahn: höherer Staatsdienst (ENA, Conseil d'État), Parteileitung (UMP), dann internationaler Privatsektor, vor der Rückkehr in die Politik. Debevoise vertritt Fortune-500-Unternehmen und Investmentfonds, was Philippe ermöglichte, ein Netzwerk in internationalen Geschäftskreisen aufzubauen. Die Kanzlei ist in Hongkong und Shanghai präsent — Nervenzentren des asiatischen Handels —, ein Detail, das angesichts der späteren sino-französischen Verbindungen in Philippes Umfeld bedeutsam wird. Nach Debevoise wechselte Philippe zu Areva als Direktor für öffentliche Angelegenheiten (Lobbying) und bestätigte damit seine Verwurzelung in wirtschaftlichen Einflusskreisen. Die Abfolge Conseil d'État → UMP → Debevoise → Areva → Bürgermeisteramt → Matignon zeichnet eine Laufbahn, in der jede Stufe das Netzwerk für die nächste bereichert. Der Aufenthalt bei Debevoise ist die angelsächsische Klammer in dieser im Wesentlichen französischen Karriere. Die Honorare und Mandate, die er bei Debevoise betreut hat, wurden nie öffentlich gemacht.",
    "antoine-rufenacht": "Antoine Rufenacht war von 1995 bis 2010 Bürgermeister von Le Havre, ehemaliger Énarque und Persönlichkeit der normannischen Rechten. Es war er, der Édouard Philippe als potenziellen Nachfolger identifizierte und ihn 2001 in die Politik brachte, indem er ihn als Beigeordneten für Rechtsfragen in seine Gemeinderatsliste aufnahm. Rufenacht empfahl Philippe dann Alain Juppé für die UMP-Leitung im Jahr 2002 und lancierte damit seine nationale Karriere. Als Rufenacht 2010 vom Bürgermeisteramt zurücktrat, wählte der Gemeinderat Philippe zu seinem Nachfolger — eine perfekt orchestrierte lokale Machtübertragung. Christine Poyer-Rufenacht, Anwältin mit demselben Nachnamen wie der ehemalige Bürgermeister, wurde 2011 in die FAF-Young-Leaders-Kohorte neben Philippe aufgenommen — eine Koinzidenz, die öffentlich nie erklärt wurde. Rufenacht führte Le Havre fünfzehn Jahre lang und prägte das lokale politische und wirtschaftliche Netzwerk, das Philippe erbte. Unter Rufenacht initiierte Le Havre einen Stadterneuerungsprozess rund um den Hafen und die von der UNESCO klassierte Perret-Architektur. Die Beziehung Rufenacht-Philippe ist ein Lehrbuchfall lokaler politischer Nachfolge: Der Mentor identifiziert, formt und installiert seinen Schützling an der Stadtspitze. Philippes Verankerung in Le Havre — Rathaus, Hafen, städtische Gemeinschaft — ist direkt vom Netzwerk Rufenacht geerbt. Die Tatsache, dass der lokale Mentor und das transatlantische Netzwerk (FAF) um denselben Nachnamen konvergieren, wirft Fragen zu den Kooptationsmechanismen in der französischen Elite auf.",
    "french-american-foundation": "Die French-American Foundation (FAF) ist eine Organisation, die 1976 unter der Schirmherrschaft der Präsidenten Gerald Ford und Valéry Giscard d'Estaing gegründet wurde. Ihr Young-Leaders-Programm, das 1981 ins Leben gerufen wurde, wählt jedes Jahr zehn Franzosen und zehn Amerikaner im Alter von 30 bis 40 Jahren aus, die aus dem höheren Staatsdienst, der Wirtschaft, den Medien, dem Militär und der Forschung stammen. Die Teilnehmer besuchen zwei fünftägige Seminare über zwei aufeinanderfolgende Jahre, abwechselnd in Frankreich und den USA. Der Seminarinhalt wird nicht veröffentlicht — die FAF gibt die Tagesordnungen vergangener Ausgaben nicht bekannt. Nach Abschluss des Programms treten die Teilnehmer einem Alumni-Netzwerk von mehr als 600 Mitgliedern bei. Das Programm wird regelmäßig als Instrument des amerikanischen Soft Power beschrieben, obwohl die FAF sich selbst als «weder Think Tank noch Lobby noch parlamentarische Freundschaftsgruppe» darstellt. Die Präsenz von Young Leaders in der französischen Regierung ist bemerkenswert und überschreitet politische Wechsel. Édouard Philippe gehört der Kohorte 2011 an, Emmanuel Macron der Kohorte 2012, Alain Juppé der Gründungskohorte 1982 und François Hollande der Kohorte 1996. Richard Ferrand, Minister in der Regierung Philippe, war Young Leader 2005. Mehr als 400 Führungspersönlichkeiten haben das Programm seit 1981 durchlaufen, und die Tatsache, dass ein Präsident und sein Premierminister aus aufeinanderfolgenden Kohorten stammen, ist in der Geschichte der FAF beispiellos. Zu den Sponsoren des Programms gehören Airbus, J.P. Morgan und Sodexo.",
    "david-barroux": "David Barroux ist Journalist und Chefredakteur der Wirtschaftstageszeitung Les Échos, einer der wichtigsten französischen Wirtschaftszeitungen. Er war Teil der Young-Leaders-Kohorte 2011 der French-American Foundation neben Édouard Philippe. Seine Position an der Spitze eines Referenzmediums für Wirtschaftsfragen verleiht ihm erheblichen Einfluss auf die Berichterstattung über die französische Wirtschaftspolitik. Les Échos gehört zur LVMH-Gruppe von Bernard Arnault, was Barroux in ein Medienökosystem einbettet, das mit den großen französischen Vermögen verbunden ist. Als Young Leader teilte er mit Philippe zwei fünftägige Seminare zwischen 2011 und 2012 und knüpfte dauerhafte persönliche und berufliche Beziehungen. Das Zusammentreffen eines zukünftigen Premierministers und eines Chefredakteurs einer großen Tageszeitung im selben transatlantischen Netzwerk ist bemerkenswert. Les Échos berichtete im Allgemeinen positiv über die Reformen der Regierung Philippe, insbesondere zum Arbeitsgesetzbuch und dem PACTE-Gesetz. Diese Nähe veranschaulicht das Ineinandergreifen der politischen und medialen Eliten Frankreichs innerhalb derselben Einflussnetze. Barroux repräsentiert die Mediensäule der Kohorte 2011. Die FAF veröffentlicht nicht den Austausch, der während der Seminare zwischen diesen zukünftigen Führungspersönlichkeiten stattgefunden hat.",
    "yohann-benard": "Yohann Bénard ist Direktor für öffentliche Angelegenheiten bei Amazon France zum Zeitpunkt seiner Auswahl als Young Leader 2011. Er teilt die FAF-Kohorte mit Édouard Philippe, damals Bürgermeister von Le Havre und Direktor für öffentliche Angelegenheiten bei Areva. Die beiden Männer üben also ähnliche Funktionen aus — Lobbying und institutionelle Beziehungen — einer für den Atomgiganten, der andere für den amerikanischen E-Commerce-Giganten. Amazon ist eines der umstrittensten Unternehmen in Frankreich wegen seiner sozialen und steuerlichen Praktiken und seiner Auswirkungen auf den Einzelhandel. Bénard ist damit beauftragt, die Interessen von Amazon gegenüber französischen Mandatsträgern und Behörden zu vertreten. Durch die Teilhabe an einem elitären transatlantischen Netzwerk mit einem zukünftigen Premierminister hat er privilegierten Zugang zu Entscheidungskreisen. Die Regierung Philippe hat die Besteuerung der GAFAs während ihrer drei Jahre in Matignon nicht besonders verschärft, trotz entsprechender Versprechen. Die gleichzeitige Präsenz in der Kohorte 2011 eines Amazon-Lobbyisten und eines Areva-Lobbyisten, der Premierminister werden sollte, verdeutlicht die Porosität zwischen Unternehmensinteressen und politischer Macht. Die FAF-Seminare boten einen informellen Rahmen für die Knüpfung dieser Bande. Bénard repräsentiert die amerikanische Unternehmensachse des Jahrgangs.",
    "stephane-israel": "Stéphane Israël wurde 2011 als Young Leader ausgewählt, im selben Jahr wie Édouard Philippe. Er sollte Vorstandsvorsitzender von Arianespace werden, dem Weltmarktführer im Bereich der kommerziellen Raumfahrtdienste, einer Tochtergesellschaft von ArianeGroup (ein Gemeinschaftsunternehmen von Airbus/Safran). Vor Arianespace war Israël Kabinettschef der Ministerin für Hochschulbildung und Forschung, Geneviève Fioraso (2012-2014), unter der Präsidentschaft Hollande. Er verkörpert das typische Drehtür-Profil zwischen höherem Staatsdienst und strategischer Industrie. Seine Laufbahn — Ministerkabinett, dann Leitung eines öffentlichen Unternehmens — ist vergleichbar mit der von Philippe (Conseil d'État, Areva, Politik). Arianespace ist ein Schlüsselakteur der europäischen Weltraumsouveränität, und sein Präsident unterhält notwendigerweise enge Beziehungen zur französischen Exekutive. Die Präsenz von Israël in derselben Young-Leaders-Kohorte wie Philippe schafft eine querschnittliche Verbindung zwischen der Atom- und Raumfahrtindustrie und der politischen Macht. Airbus, die Muttergesellschaft von ArianeGroup, ist zudem einer der Sponsoren des Young-Leaders-Programms der FAF. Diese Verflechtungen zwischen Programmsponsoren und ausgewählten Mitgliedern werfen Fragen zur Unabhängigkeit des Auswahlverfahrens auf. Israël repräsentiert die strategische Industriesäule der Kohorte 2011.",
    "christine-poyer-rufenacht": "Christine Poyer-Rufenacht ist Rechtsanwältin, die 2011 in die FAF-Young-Leaders-Kohorte neben Édouard Philippe aufgenommen wurde. Ihr Nachname evoziert unweigerlich Antoine Rufenacht, den Bürgermeister von Le Havre, der Philippe 2001 in die Politik einführte — eine beunruhigende Namensgleichheit, auf die offizielle Biografien nicht eingehen. Antoine Rufenacht war Philippes lokaler Mentor, der ihm seinen ersten Platz auf einer Gemeinderatsliste verschaffte und ihn Alain Juppé für die UMP-Leitung empfahl. Die Präsenz in derselben Young-Leaders-Kohorte eines Rufenacht-Schützlings und einer Person mit demselben Nachnamen wirft Fragen zu den Kooptationsmechanismen in diesen Netzwerken auf. Die FAF veröffentlicht keine detaillierten Auswahlkriterien, und der Bewerbungsprozess beruht zum Teil auf Förderung. Wenn Christine Poyer-Rufenacht mit Antoine Rufenacht verwandt ist, würde dies einen Fall darstellen, in dem sich familiäre und politische Netzwerke innerhalb einer transatlantischen Institution reproduzieren. Zumindest veranschaulicht die patronymische Koinzidenz die Enge der Kreise, in denen sich die von der FAF ausgewählten französischen Eliten bewegen. Le Havre erscheint als wiederkehrender Knoten in diesen Netzwerken: Philippe, Rufenacht, CMA CGM. Diese Verbindung verdient eine eingehende Untersuchung. Die Intransparenz der FAF über ihre Prozesse erschwert die Überprüfung.",
    "estelle-youssouffa": "Estelle Youssouffa ist heute Abgeordnete des ersten Wahlkreises von Mayotte, gewählt 2022. Sie wurde 2011 als Young Leader in derselben Kohorte wie Édouard Philippe ausgewählt. Vor ihrem Eintritt in die Politik war Youssouffa Journalistin, u.a. für France 24 und Al Jazeera, was sie der Mediensäule des Programms zuordnet. Ihre Laufbahn — vom internationalen Journalismus zur parlamentarischen Repräsentation — illustriert den klassischen Young-Leaders-Weg zu Machtpositionen. Als Abgeordnete sitzt sie in der Nationalversammlung, wo Édouard Philippes Gruppe Horizons ebenfalls Vertreter hat, was parlamentarische Allianzmöglichkeiten zwischen ehemaligen Mitgliedern derselben Kohorte schafft. Mayotte ist ein Gebiet mit großen Herausforderungen (Einwanderung, Sicherheit, Entwicklung), die regelmäßig in nationalen Debatten thematisiert werden. Die Präsenz von Youssouffa und Philippe in derselben FAF-Kohorte stellt eine Verbindung zwischen den Fragen der Überseegebiete und dem Philippisten-Netzwerk her. Das Young-Leaders-Programm hat historisch dauerhafte Verbindungen unter seinen Mitgliedern geschaffen, die sich später in Einflussposten in verschiedenen Bereichen wiederfinden. Diese Kohortendynamik ist einer der wirksamsten Mechanismen des Netzwerks. Youssouffa repräsentiert die überseeische und Mediensäule der Kohorte 2011.",
    "richard-ferrand": "Richard Ferrand ist ein französischer Politiker, ehemaliger Präsident der Nationalversammlung (2018-2022) und ehemaliger Minister für territoriale Kohäsion in Édouard Philippes erstem Kabinett (Mai-Juni 2017). Er ist Young Leader der Kohorte 2005, sechs Jahre vor Philippe. Ferrand war einer der ersten Unterstützer von Emmanuel Macron und Mitbegründer von En Marche 2016. Als Philippes Minister und dann Präsident der Nationalversammlung war er ein wesentliches Rädchen im macronistischen System, in dem Philippe operierte. Seine Young-Leader-Kohorte 2005 ordnet ihn in dasselbe transatlantische Netzwerk wie Philippe (2011), Macron (2012) und Juppé (1982) ein. Die Tatsache, dass der Minister für territoriale Kohäsion und der Premierminister beide ehemalige Young Leaders waren, verdeutlicht die Dichte dieses Netzwerks innerhalb der Regierung. Ferrand wurde 2019 wegen unerlaubter Interessenkollision in einer Immobilienaffäre — den Mutuelles de Bretagne — unter förmliche Ermittlung gestellt. Er erhielt 2023 eine Einstellung des Verfahrens. Seine justizielle Laufbahn zeigt, dass die Mitgliedschaft im Young-Leaders-Netzwerk nicht unbedingt vor Strafverfolgung schützt. Dennoch verdient die Konvergenz von Young Leaders an der Spitze von Exekutive und Legislative eine kritische Betrachtung.",
    "francois-hollande": "François Hollande, Staatspräsident von 2012 bis 2017, ist Young Leader der FAF-Kohorte 1996 neben Pierre Moscovici. Seine Teilnahme am Programm fünfzehn Jahre vor Philippe veranschaulicht die Kontinuität des Netzwerks über politische Generationen und Wechsel hinaus. Hollande ernannte Manuel Valls und dann Bernard Cazeneuve zu Premierministern, aber es war sein Nachfolger Macron (Young Leader 2012), der Philippe (Young Leader 2011) ernennen würde. Die Kette der präsidentiellen Nachfolge Hollande-Macron ist also eine interne Kette innerhalb des Young-Leaders-Netzwerks. Hollande war elf Jahre lang Erster Sekretär der PS (1997-2008), bevor er das Präsidentenamt anstrebte, was ihm ermöglichte, ein dichtes politisches Netzwerk aufzubauen. Seine Kohorte 1996 umfasste Pierre Moscovici, zukünftiger EU-Kommissar und dann Präsident des Cour des comptes, was die Vielfalt der von ehemaligen Young Leaders besetzten Stellen verdeutlicht. Das FAF-Programm hat damit zwei Staatspräsidenten (Hollande und Macron), mindestens vier Premierminister (Juppé, Philippe und indirekt andere) und zahlreiche Minister hervorgebracht. Diese Machtkonzentration aus einem einzigen Auswahlprogramm wirft demokratische Fragen zur Bildung der französischen Führungselite auf. Hollande hat Philippe nach 2017 mehrfach kritisiert, teilt aber dasselbe strukturelle Netzwerk.",
    "laurent-wauquiez": "Laurent Wauquiez, Präsident der Region Auvergne-Rhône-Alpes und ehemaliger Präsident der Républicains (2017-2019), ist Young Leader der Kohorte 2006. Er repräsentiert den rechten Flügel desselben transatlantischen Netzwerks wie Édouard Philippe. Die beiden Männer standen sich innerhalb der LR gegenüber, bevor Philippe 2017 zu Macron wechselte. Wauquiez kritisierte Philippes Ernennung in Matignon scharf und bezeichnete sie als Verrat an der Rechten. Trotz ihrer politischen Rivalität teilen sie denselben elitären Bildungsweg — ENA für beide, Young Leaders für beide. Wauquiez gilt als potenzieller Kandidat für die Präsidentschaftswahl 2027, was ihn zu einem direkten Rivalen aus demselben Netzwerk machen würde. Die Tatsache, dass zwei potenzielle Präsidentschaftskandidaten ehemalige Young Leaders sind, verdeutlicht die Fähigkeit des Programms, die zukünftigen Führungspersönlichkeiten des Landes zu produzieren, unabhängig von der politischen Seite. Wauquiez' Kohorte 2006 platziert ihn zwischen den Generationen Ferrand (2005) und Philippe (2011) in der Netzwerkchronologie. Seine politische Laufbahn — vom Staatssekretär unter Sarkozy zum Regionalpräsidenten — zeigt einen Weg parallel zu dem von Philippe, aber in einem rechtslastigeren Register. Die FAF-Seminare ermöglichten es Wauquiez und Philippe möglicherweise, über das Alumni-Netzwerk in Kontakt zu kommen, noch bevor ihre öffentliche politische Konfrontation begann.",
    "fleur-pellerin": "Fleur Pellerin wurde in die Young-Leaders-Kohorte 2012 aufgenommen, im selben Jahr wie Emmanuel Macron. Sie war damals Staatssekretärin für KMU, Innovation und die digitale Wirtschaft unter Hollande, bevor sie Kulturministerin wurde (2014-2016). Ihre Kohorte 2012 folgt unmittelbar auf die von Philippe (2011), was bedeutet, dass sich die Seminare der beiden Kohorten potenziell überschnitten — Philippes zweites Seminar 2012 könnte mit dem ersten von Pellerin und Macron zusammengefallen sein. Pellerin ist ENA-Absolventin (Promotion Senghor, 2000), eine Schule, die in den Young-Leaders-Profilen immer wieder auftaucht. Nach ihrer Ministerzeit gründete sie eine Risikokapitalgesellschaft, Korelya Capital, spezialisiert auf Investitionen in Asien — und schuf damit eine Brücke zwischen den transatlantischen (FAF) und asiatischen Netzwerken, die an die France China Foundation erinnert. Pellerin wurde in Südkorea geboren und in Frankreich adoptiert, was ihr ein bikulturelles Profil verleiht, das von der FAF geschätzt wird. Ihre Post-Ministerkarriere in Richtung asiatisches Risikokapital verdeutlicht, wie die in Elitenetzwerken geknüpften Verbindungen in wirtschaftliche Chancen umgewandelt werden. Die Kohorte 2012, die auch Macron und Cédric Villani umfasst, ist eine der politisch einflussreichsten in der Geschichte des Programms.",
    "laphonza-butler": "Laphonza Butler ist eine amerikanische Politikerin, die im Oktober 2023 von Gouverneur Gavin Newsom zur Senatorin von Kalifornien ernannt wurde, um Senatorin Dianne Feinstein zu ersetzen. Sie gehört der Young-Leaders-Kohorte 2011 auf amerikanischer Seite an, neben Édouard Philippe auf französischer Seite. Vor dem Senat war Butler Präsidentin der SEIU Local 2015, der größten Gesundheitsarbeitergewerkschaft Kaliforniens (400.000 Mitglieder). Anschließend leitete sie EMILYs List, die demokratische Organisation zur Unterstützung feministischer Kandidatinnen. Ihre Ernennung in den Senat verdeutlicht die Laufbahn amerikanischer Young Leaders hin zu den höchsten Funktionen. Die Tatsache, dass eine US-Senatorin und ein ehemaliger französischer Premierminister gemeinsam im selben transatlantischen Programm ausgebildet wurden, schafft einen direkten Einflusskanal zwischen dem US-Senat und der französischen Politik. Butler verbrachte Zeit mit Philippe während zweier fünftägiger Seminare 2011-2012 und knüpfte dauerhafte persönliche Bande. Das Young-Leaders-Programm wurde genau dazu konzipiert, diese Brücken zwischen zukünftigen Führungspersönlichkeiten beider Länder zu schaffen. Butler repräsentiert die progressive amerikanische Politiksäule der Kohorte 2011. Ihre Präsenz verdeutlicht die Fähigkeit der FAF, zukünftige Führungspersönlichkeiten lange vor ihrer Übernahme der höchsten Ämter zu identifizieren.",
    "horizons": "Horizons ist die politische Partei, die Édouard Philippe am 9. Oktober 2021 bei einer öffentlichen Versammlung in Le Havre, seiner Hochburg, gründete. Die Partei positioniert sich in der Mitte-Rechts und verkörpert den rechten Flügel der macronistischen Präsidiumsmehrheit. Ihre vier zentralen Themen sind Demografie, Umwelt, Geopolitik und Technologie, unter dem Slogan «Weit blicken, um gut zu handeln». Emmanuel Macron schätzte die Gründung von Horizons durch diesen ehemaligen Premierminister, der sich «loyal, aber frei» bezeichnete, wenig. Im Januar 2022 trat die Partei der Koalition Ensemble Citoyens bei. Christian Estrosi, Bürgermeister von Nizza, wurde ihre Nummer zwei und brachte eine mediterrane Verankerung in die in der Normandie verwurzelte Partei. Für die Parlamentswahlen 2022 erhielt Horizons 58 Aufstellungen innerhalb der Koalition und bildete eine parlamentarische Gruppe «Horizons et indépendants» von etwa dreißig Abgeordneten unter dem Vorsitz von Laurent Marcangeli. Nach der Auflösung 2024 behielt die Partei nur 6 Sitze. Im März 2026 beanspruchte Horizons 465 eingeschriebene Bürgermeister im gesamten Gebiet — ein lokales Netz, das das Rückgrat von Philippes Präsidentschaftskampagne 2027 bildet. Die Partei fungiert als persönliches Wahlvehikel: Ihr einziges strategisches Ziel ist es, Philippe in den Élysée zu bringen. Die führenden Kader der Partei stammen größtenteils aus Philippes Netzwerken in Le Havre und dem Juppé-Umfeld.",
    "christian-estrosi": "Christian Estrosi ist seit 2008 Bürgermeister von Nizza (mit einer Unterbrechung 2014-2017, als er Präsident der Region PACA war) und die Nummer zwei der Partei Horizons von Édouard Philippe. Ehemaliger Industrieminister unter Sarkozy (2009-2010) und Persönlichkeit der provenzalischen Rechten bringt Estrosi Horizons eine südfranzösische Verankerung, die Philippes normannisches Profil ergänzt. Seine Annäherung an Horizons 2021 war ein großer politischer Coup: Er verließ LR, um einer zentristischen Partei beizutreten, und brachte einen Teil der rechten Wählerschaft aus Nizza und der Côte d'Azur mit. Nizza ist Frankreichs fünftgrößte Stadt und ein führender Touristik- und Wirtschaftsstandort, was Estrosi innerhalb der Partei ein beachtliches politisches Gewicht verleiht. Estrosi wurde durch den Anschlag von Nizza am 14. Juli 2016 (86 Tote) geprägt, den er als Präsident der Metropolregion bewältigte — ein Ereignis, das sein Bild als Krisenmanager prägte. Er ist mit Laura Tenoudji, einer Journalistin, verheiratet, was ihm zusätzliche Medienpräsenz verschafft. Innerhalb von Horizons übernimmt Estrosi die Rolle des Werbers unter LR-Mandatsträgern, die vom Mitte-Rechts-Kurs verlockt werden. Seine Laufbahn illustriert Philippes Strategie: die Aufnahme rechter Kader, die von der Entwicklung der LR zur harten Rechten enttäuscht sind. Das Duo Philippe (Normandie) / Estrosi (PACA) gibt Horizons eine bi-regionale Basis, die die Präsidentschaftskampagne 2027 strukturieren wird. Estrosi ist auch Vizepräsident von Intercommunalités de France, was ihm ein ergänzendes territoriales Netzwerk zu dem von Philippe verleiht.",
    "gilles-boyer": "Gilles Boyer ist seit mehr als zwanzig Jahren Édouard Philippes engster Berater, geformt in der Umlaufbahn von Juppé. Kabinettsdirektor von Juppé im Rathaus von Bordeaux (2002-2004, 2006-2010), dann Wahlkampfleiter von Juppé bei der Vorwahl 2016 (Philippe war Ko-Sprecher). Ko-Autor mit Philippe von zwei politischen Romanen (L'heure de vérité 2007, Dans l'ombre 2011) und Impressions et lignes claires (2021). Sonderberater von Philippe in Matignon (2017-2019). Heute Renaissance-Europaabgeordneter. Ein Sarkozyist nannte sie «Plic und Ploc» (Boyer und Philippe), so untrennbar war ihr Tandem. Boyer verbindet das Erbe Juppés mit der Horizons-Maschine: Er ist der Hüter der philippistischen Doktrin und der Archetyp des Schattenberaters, der jede politische Ausrichtung beeinflusst. Innerer Kreis der Juppéie.",
    "christophe-castaner": "Christophe Castaner wurde im Oktober 2018 von Édouard Philippe zum Innenminister ernannt, nach der längsten Interimszeit der Fünften Republik auf dem Place Beauvau nach dem Rücktritt von Gérard Collomb. Seine Ernennung erfolgte einen Monat vor dem Beginn der Gelbwesten-Bewegung, was ihn zum unmittelbaren Verantwortlichen für die umstrittenste Strategie zur Aufrechterhaltung der öffentlichen Ordnung seit Mai 1968 macht. Castaner bezeichnete die Demonstranten als «Aufrührer, die gekommen waren, um zu töten», und legitimierte damit eine unverhältnismäßige Sicherheitsreaktion. Unter seiner Führung stieg der Einsatz von Gummigeschossgewehren (LBD40) um mehr als 200% gegenüber dem Vorjahr. Die Menschenbilanz war beispiellos: 25 Menschen wurden geblendet, 5 Hände wurden abgerissen, 432 schwer verletzt. Die UNO, der Europarat und Amnesty International forderten das Verbot dieser Waffen. Castaner ignorierte systematisch Berichte über Polizeigewalt und weigerte sich, den Einsatz von LBDs auszusetzen. Als Philippes Minister trug seine Doktrin direkt zur Verantwortung des Premierministers bei. Die IGPN wurde mit 313 gerichtlichen Untersuchungen wegen mutmaßlicher Polizeigewalt befasst — ein Rekord. Castaner war zuvor Generaldelegierter der LREM, was die Verschmelzung zwischen dem macronistischen Apparat und dem Sicherheitsapparat unter der Regierung Philippe verdeutlicht.",
    "benoit-ribadeau-dumas": "Benoît Ribadeau-Dumas, Jahrgangsbester der ENA-Promotion Marc-Bloch (1997), war Kommilitone von Philippe. Kabinettsdirektor in Matignon (2017-2020) — entgegen Macrons Willen ausgewählt, der Nicolas Revel hatte durchsetzen wollen. Wegen seiner Unnachgiebigkeit «Le Vatican» genannt. Mitglied der FCF (Gründungskohorte 2013 mit Philippe und Macron). Vor Matignon: stellvertretender Kabinettschef von Sarkozy im Élysée (2011-2012), stellvertretender Generalsekretär unter Hollande — eine Laufbahn, die politische Wechsel überschreitet. Operativer Architekt aller Entscheidungen der Regierung Philippe: Arbeitsverordnungen, 80-km/h-Tempolimit, Gelbwesten, Rentenreform, Covid. Befürwortete die Beibehaltung des ersten Wahlgangs der Kommunalwahlen am 15. März 2020. Nach Matignon Einstieg bei Exor (Family Office Elkann/Agnelli), Vorstandsmitglied von Stellantis und Iveco. Innerer Kreis der Juppéie — der Knoten, der das ENA-Netzwerk, die FCF und die Exekutivmacht verbindet.",
    "france-china-foundation": "Die France China Foundation (FCF) ist eine 2012 gegründete Organisation, um die führenden Eliten Frankreichs und Chinas zusammenzubringen. Ihr Strategierat umfasst Jean-Pierre Raffarin, Laurent Fabius und Alain Mérieux (Architekt des P4-Labors in Wuhan). Ihr offizieller chinesischer Partner ist das CPIFA (Chinese People's Institute of Foreign Affairs), das dem chinesischen Außenministerium angegliedert ist. Die Gründungskohorte 2013 versammelte Philippe, Macron und Ribadeau-Dumas. 2015 empfing Philippe die FCF-Delegation in Le Havre für einen Hafenbesuch. Im Mai 2018 nahm er als Premierminister und ehemaliger Young Leader am Jahresgala in Versailles teil. Die Intransparenz der FCF ist vergleichbar mit der der FAF: keine Veröffentlichung von Tagesordnungen, keine öffentlichen Berichte. Die Gleichzeitigkeit der FAF (transatlantisch) und FCF (sino-französisch) Netzwerke um denselben Kern — Philippe, Ribadeau-Dumas, Lenain — schafft ein beispielloses bipolares Einflusssystem in Matignon. Villepin erscheint in keinem FCF-Raum — sein chinesisches Netzwerk ist persönlich und privat, nicht institutionell.",
    "emmanuel-lenain": "Emmanuel Lenain ist Berufsdiplomat, Mitbegründer der France China Foundation im Jahr 2012 und diplomatischer Berater von Édouard Philippe in Matignon von 2017 bis 2020. Diese doppelte Funktion — Architekt des sino-französischen Netzwerks und Berater des Premierministers — macht ihn zur menschlichen Brücke zwischen den transatlantischen (FAF) und asiatischen (FCF) Netzwerken im Herzen der Exekutivmacht. Vor Matignon bekleidete Lenain mehrere strategische Diplomatenstellen, insbesondere bei der ständigen Vertretung Frankreichs bei den Vereinten Nationen. Nach seinem Aufenthalt in Matignon wurde er zum Botschafter Frankreichs in Indien ernannt (2019-2022), ein Posten, der ihn im strategischen Dreieck Frankreich-China-Indien verankert. Seine Gründung der FCF im Jahr 2012, ein Jahr nach Philippes Auswahl als Young Leader der FAF, lässt eine bewusste Strategie zum Aufbau komplementärer bilateraler Einflußnetzwerke vermuten. Als diplomatischer Berater von Philippe hatte Lenain Zugang zu allen internationalen Verhandlungen der Regierung, einschließlich derer, die China und maritime Handelsrouten betrafen. Le Havre, Frankreichs wichtigster Hafen und Philippes Hochburg, ist direkt von den Fragen des sino-französischen Handels und der Belt-and-Road-Initiative (Neue Seidenstraßen) betroffen. Lenains Position an der Kreuzung von FCF, Matignon und asiatischer Diplomatie verdeutlicht, wie eine einzelne Person als Transmissionsriemen zwischen diplomatischen, wirtschaftlichen und politischen Interessen dienen kann. Seine Laufbahn nach Matignon — Botschaft in Indien, dann Posten im Quai d'Orsay — bestätigt seinen Weg innerhalb des auf Asien ausgerichteten französischen Diplomatieapparats. Lenain ist das fehlende Glied, das Philippes Young-Leaders-Netzwerk mit dem sino-französischen Netzwerk verbindet.",
    "port-du-havre": "Der Hafen von Le Havre ist Frankreichs führender Containerhafen und der fünftgrößte in Europa. Seit 2021 ist er in den HAROPA-Komplex (Le Havre, Rouen, Paris) integriert, dem größten Hafenverbund Frankreichs. Édouard Philippe ist seit 2010 Bürgermeister und übt damit direkten Einfluss auf die strategische Ausrichtung des Hafens und der Stadtgemeinschaft Le Havre Seine Métropole aus. CMA CGM, Frankreichs führende Reederei, wickelt dort einen großen Anteil des Containerverkehrs ab, mit Direktverbindungen nach Shanghai, Ningbo, Shenzhen und den großen asiatischen Häfen. Der französisch-chinesische Seehandel über Le Havre beträgt jährlich Milliarden Euro. Der Hafen ist auch von der chinesischen Belt and Road Initiative betroffen, die darauf abzielt, europäische Hafeninfrastrukturen mit dem chinesischen Logistiknetz zu verbinden. Laut Europol ist Le Havre Europas wichtigster Kokain-Einfuhrpunkt. Die Drogenmengen sind explodiert: 2023 beschlagnahmten die französischen Zollbehörden 18 Tonnen Kokain — ein Rekord. Die Hafensicherheit liegt in der gemeinsamen Verantwortung von Staat, Zoll und Hafenbehörden — ein Bereich, in dem sich die Interessen von CMA CGM (über Yann Le Goff, Sicherheit), des Rathauses (Philippe) und der Einflussnetzwerke (FAF, FCF) überschneiden. Die Erweiterung des Hafens und Investitionen in Containerterminals sind wichtige wirtschaftliche Anliegen der Region, wo Philippe seit fünfzehn Jahren eine unangefochtene politische Stellung genießt. Die Frage der Hafensteuerung — wer über Investitionen, Konzessionen und Kontrollen entscheidet — steht im Mittelpunkt des Nexus Philippe-CMA CGM-FCF.",
    "jean-pierre-raffarin": "Jean-Pierre Raffarin, Premierminister unter Chirac (2002-2005), ist das Drehkreuz zwischen Philippes und Villepins chinesischen Netzwerken. Er hält eine unvergleichliche Anzahl chinesischer Positionen: Mitglied des Beirats des Bo'ao-Forums (asiatisches Davos), des Belt & Road Forums, Vorstandsmitglied der CEIBS Shanghai, Ko-Präsident der Sino-International Entrepreneurs Federation, Moderator bei CGTN (chinesisches öffentliches Fernsehen), Sonderbeauftragter der französischen Regierung für China (seit 2018), Co-Schirmherr der FCF und Präsident des Comité France-Chine. Am 29. September 2019 überreichte Xi Jinping ihm die Medaille des Freundschaftsordens — die höchste chinesische Auszeichnung für Ausländer, die er mit Putin und Castro teilt. Die DGSI lud ihn im Sommer 2018 zu einem „Sensibilisierungsgespräch\" vor, aufgrund seiner Kontakte zu chinesischen Geschäftsleuten, die als Agenten der Partei gelten. Seine Fondation Prospective et Innovation (FPI) verfügt über ein Budget von 3,5 Millionen Euro, das von rund dreißig Unternehmen (Carrefour, Kering, L'Oréal, LVMH) finanziert wird, und erhielt 85.000 Euro vom ehemaligen chinesischen Botschafter Wu Jianmin. 2022 trat Raffarin Horizons bei — seine Doppelrolle (offizieller Vertreter für China UND Mitglied von Philippes Partei) ist ohne Gegenstück. Causeur stellt fest, dass Raffarin und Villepin in ihren chinesischen Neuausrichtungen nach Matignon „Spiegelwege\" beschritten.",
    "rodolphe-saade": "Rodolphe Saadé ist seit 2017 Vorstandsvorsitzender von CMA CGM, als Nachfolger seines Vaters Jacques Saadé, der die Gruppe 1978 gegründet hat. Unter seiner Führung ist CMA CGM zur drittgrößten Reederei der Welt geworden, mit einem Umsatz von über 70 Milliarden Euro im Jahr 2022. Saadé hat die Gruppe über den Seetransport hinaus diversifiziert: Erwerb von CEVA Logistics (Logistik), Kauf von La Tribune und La Provence (Medien), Technologieinvestitionen. Die Saadé-Gruppe ist libanesischen Ursprungs, in Marseille ansässig und unterhält bedeutende Geschäftsbeziehungen zu China — die Asien-Europa-Routen sind der Kern der Tätigkeit von CMA CGM. Der Hafen von Le Havre, die Hochburg Édouard Philippes, ist einer der wichtigsten europäischen Hubs von CMA CGM. Yann Le Goff, Sicherheitschef von CMA CGM und Young Leader 2011 zusammen mit Philippe, arbeitet direkt unter der Autorität der Saadé-Konzernleitung. Das Vermögen von Rodolphe Saadé wird auf über 40 Milliarden Euro geschätzt, was ihn zu einem der größten Vermögen Frankreichs macht. Seine Expansion in den Medien (La Tribune, La Provence, BFM Marseille) verleiht ihm neben seinem wirtschaftlichen Gewicht auch medialen Einfluss. CMA CGM ist ein zentraler Akteur der chinesischen Belt and Road Initiative mit Hafenpartnerschaften im Mittelmeer, in Afrika und in Südostasien. Die Überschneidung des Saadé-Imperiums, des Hafens von Le Havre unter Philippe und der FCF-Netzwerke von Ribadeau-Dumas bildet einen Nexus aus wirtschaftlichen und politischen Interessen von erheblicher Tragweite.",
    "belt-and-road": "Die Belt and Road Initiative (BRI), von Xi Jinping 2013 ins Leben gerufen, ist das größte Infrastrukturprogramm der Geschichte mit geschätzten Investitionen von über einer Billion Dollar in Asien, Afrika und Europa. Der maritime Zweig der BRI — die „Maritime Seidenstraße des 21. Jahrhunderts\" — zielt darauf ab, chinesische Häfen über Investitionen in Terminals, Logistik und Hafenkonzessionen mit europäischen Häfen zu verbinden. In Europa hat China in die Häfen von Piräus (Griechenland, via COSCO), Hamburg, Antwerpen und Valencia investiert. Der Hafen von Le Havre, Frankreichs führender Containerhafen und Hochburg Édouard Philippes, ist von dieser Strategie direkt betroffen. CMA CGM, dessen Asien-Europa-Routen den Kern des Geschäfts bilden, ist sowohl Konkurrent als auch potenzieller Partner der chinesischen Reedereien COSCO und OOCL. Die France China Foundation, deren Mitglied Ribadeau-Dumas als Kabinettschef von Philippe in Matignon tätig war, operiert in diesem Raum, in dem die chinesische Wirtschaftsdiplomatie versucht, Einflusspunkte bei europäischen Entscheidungsträgern zu etablieren. Die BRI wurde als Instrument der „Schuldendiplomatie\" und des chinesischen geopolitischen Einflusses kritisiert. Die Tatsache, dass der französische Premierminister in Matignon von Personen umgeben war, die in sino-französischen Netzwerken (FCF) eingebettet sind, während er gleichzeitig Bürgermeister des wichtigsten französischen Hafens an der chinesischen Seeroute ist, schafft eine beispiellose Interessenkonvergenz. Italien unterzeichnete 2019 ein BRI-Memorandum, bevor es 2023 zurücktrat — Frankreich unter Philippe hat nie unterzeichnet, aber eine mehrdeutige Position beibehalten. Die Frage der Hafensouveränität angesichts chinesischer Investitionen ist ein strategisches Thema, das Le Havre direkt betrifft.",
    "cosco-shipping": "COSCO Shipping ist Chinas größte Reederei und die viertgrößte der Welt. Sie gehört dem chinesischen Staat über die SASAC (Kommission zur Aufsicht und Verwaltung staatlicher Vermögen). COSCO betreibt über 1.300 Schiffe und bedient mehr als 300 Häfen weltweit. In Europa erwarb COSCO 2016 67 % des Piraeus-Hafens in Griechenland — ein Beispiel für die chinesische Strategie zur Übernahme strategischer Hafeninfrastrukturen. COSCO und CMA CGM sind innerhalb der Ocean Alliance gleichzeitig Konkurrenten und Partner. Diese deckt die Asien-Europa-Routen ab — dieselben Routen, die über Le Havre verlaufen. Diese Allianz bedeutet, dass CMA CGM- und COSCO-Container dieselben Schiffe und Terminals teilen, auch in Le Havre. COSCOs Präsenz in europäischen Häfen hat Bedenken hinsichtlich nationaler Sicherheit und Souveränität geweckt. Deutschland blockierte 2022 COSCOs Beteiligung am Hamburger Terminal oberhalb von 24,9 %. Für Le Havre stellt sich die Frage: Inwieweit beeinflussen chinesische Investitionen in Konkurrenzhäfen die Strategie des wichtigsten französischen Hafens? Die France China Foundation, deren Mitglieder Philippe in Matignon umgeben, operiert genau in diesem Raum der sino-europäischen Hafendiplomatie. Die Verflechtung zwischen Ocean Alliance (COSCO + CMA CGM), FCF-Netzwerken und Philippes Bürgermeisteramt in Le Havre bildet ein Interessengeflecht, das einer eingehenden Prüfung bedarf. COSCO ist ein Instrument der chinesischen Belt and Road Politik im maritimen Bereich.",
    "comite-france-chine": "Das Comité France-Chine, dem MEDEF International angegliedert, ist das wichtigste Lobbying-Gremium der französischen Wirtschaft gegenüber China. Unter dem Vorsitz von Jean-Pierre Raffarin arbeitet es in Synergie mit der France China Foundation: Das Komitee agiert auf Unternehmensebene, die FCF auf Individualebene. Raffarins Präsenz an der Spitze des Komitees und als Schirmherr der FCF schafft eine Brücke zwischen offizieller Wirtschaftsdiplomatie und informellen Einflussnetzwerken. Zu den Mitgliedern gehören im CAC 40 gelistete Konzerne, die in China aktiv sind: Airbus, Total, L'Oréal, Sanofi sowie Akteure aus dem Hafen- und Logistikbereich. Ribadeau-Dumas (Philippes Kabinettschef, FCF 2013) und Lenain (FCF-Mitgründer, diplomatischer Berater) haben beide in diesem Ökosystem gewirkt.",
    "alexis-kohler": "Alexis Kohler (geboren 1972 in Straßburg) ist Énarque, Kabinettschef im Wirtschaftsministerium unter Macron (2014), dann Generalsekretär des Élysée (2017-2025) — der rechte Hand von Emmanuel Macron acht Jahre lang. Im März 2022 wurde er wegen unzulässiger Interessennahme, Einflusshandel und passiver Korruption formell angeklagt, aufgrund seiner Interessenkonflikte mit MSC (Mediterranean Shipping Company), gegründet von der Familie Aponte — Cousins seiner Mutter. Von 2010 bis 2012 saß Kohler im Aufsichtsrat des Grand Port Maritime du Havre (GPMH) als Vertreter der Agence des participations de l'État, neben Édouard Philippe (Bürgermeister seit Oktober 2010). Laut Mediapart hat Kohler seine Familienverbindungen zu MSC nie deklariert und sich bei Abstimmungen zu MSC nicht zurückgehalten, während Philippe die Befangenheitsregeln peinlich genau einhielt. Kohler fungiert als Drehangelagent: Inspection des finances → APE/GPMH (neben Philippe) → Macron-Kabinett (Bercy) → MSC (Drehtür) → Élysée (SG) → Société Générale (2025). Dieser Kreislauf veranschaulicht den Mechanismus steigender Renditen des Adressbuchs. Der Hafen von Le Havre, wo Kohler und Philippe nebeneinander arbeiteten, ist ein geostrategischer Knotenpunkt: Hub von CMA CGM (3. größter Reeder der Welt), Kunde von MSC (2. größter, Kohlers Familie), verbunden mit COSCO Shipping (1. chinesischer Reeder, Städtepartnerschaft Dalian), unter der politischen Führung von Philippe. 2025 verließ Kohler den Élysée zur Société Générale und setzte den Drehtür-Kreislauf zwischen Staat und Finanzwelt fort.",
    "sibyle-veil": "Sibyle Veil ist seit April 2018 Präsidentin von Radio France, ernannt vom CSA (jetzt Arcom), dessen Mitglieder von der Exekutive beeinflusst werden. Sie stammt aus dem Jahrgang Leopold Sedar Senghor der ENA (2004), demselben Jahrgang wie Emmanuel Macron. Diese Kameradschaft unter Absolventen — eine der stärksten Bindungen im französischen höheren öffentlichen Dienst — verbindet die Präsidentschaft des führenden öffentlichen Radiosenders direkt mit dem Staatspräsidenten. Unter ihrer Führung ist France Inter das meistgehörte Radio Frankreichs geblieben, mit seiner politischen Morgensendung. Die Interviews Édouard Philippes bei France Inter zeichnen sich durch einen wohlwollenden Ton und das systematische Fehlen von Fragen zu sensiblen Themen aus: CMA CGM-Verbindungen, die France China Foundation, die Atos-Affäre. Veil wurde 2022 im Amt bestätigt, was das Vertrauen der Macron-Exekutive unterstreicht. Vor Radio France war sie Mitglied des Conseil d'État und hatte am Rechnungshof gearbeitet. Ihr Karriereweg — ENA → Conseil d'État → Leitung eines öffentlichen Mediums — ist ein Archetypus des französischen Systems, in dem dieselben Jahrgänge exekutive und mediale Macht kontrollieren. Die Kette Macron (Präsident) → Arcom (Ernennung) → Veil (Leitung) → France Inter (Redaktion) illustriert die indirekte Kontrolle des öffentlichen Rundfunks. Radio France erreicht täglich rund 15 Millionen Hörer.",
    "bernard-arnault": "Bernard Arnault ist Vorstandsvorsitzender von LVMH, der reichste Mensch der Welt mit einem geschätzten Vermögen von über 200 Milliarden Euro. Er ist Eigentümer der Gruppe Les Échos-Le Parisien, zu der das Wirtschaftsblatt Les Échos gehört, dessen Chefredakteur David Barroux Young Leader 2011 gemeinsam mit Édouard Philippe ist. Arnault gilt als Emmanuel Macrons engster oligarchischer Verbündeter, mit dem er dokumentierte persönliche Beziehungen pflegt. LVMH ist Frankreichs größter Werbetreibender, was ihm indirekten Einfluss auf alle französischen Medien verschafft. Die Berichterstattung von Les Échos ist systematisch zugunsten der von Philippe getragenen Wirtschaftsreformen (Arbeitsverordnungen, PACTE-Gesetz). Le Parisien, die meistgelesene Volkszeitung in der Île-de-France, ergänzt das Medienarsenal durch die Ansprache eines breiteren Publikums. Arnault hat mehrere Architektprojekte gemeinsam mit Macron und Philippe eingeweiht. Die Konvergenz zwischen dem reichsten Menschen der Welt, dem Präsidenten, der Philippe ernannte, und dem Young-Leader-Chefredakteur bildet ein Dreieck aus Macht, Geld und Medien. LVMH hat bedeutende Wirtschaftsinteressen in China, was Arnault über andere Kanäle als die FCF mit dem sino-französischen Netzwerk verbindet. Die Tatsache, dass der Eigentümer des wichtigsten Wirtschaftsmediums Frankreichs auch der wichtigste finanzielle Unterstützer des Präsidenten ist, der Philippe ernannte, schafft einen strukturellen medialen Interessenkonflikt.",
    "vincent-bollore": "Vincent Bolloré ist ein bretonischer Industrieller, der über Vivendi ein Medienimperium aufgebaut hat: Canal+, CNews, C8, Europe 1, Paris Match, Le Journal du Dimanche. Die schrittweise Übernahme dieser Medien ab 2015 war von einer redaktionellen Ausrichtung hin zur Rechten und extremen Rechten begleitet, mit Figuren wie Eric Zemmour, Pascal Praud und Laurence Ferrari. CNews wurde zum „französischen Fox News\". Im politischen Spiel ist Bolloré ein „Königsmacher\": Sein Sender ermöglichte Zemmours Aufstieg als Präsidentschaftskandidat 2022. Für Philippe spielt CNews eine paradoxe Rolle: Der Sender präsentierte ihn als die „vernünftige\" Alternative zum RN und bediente damit die macronistische Erzählung des republikanischen Schutzwalls. Europe 1, unter Bollorés Kontrolle über Lagardère, wurde hin zu einer Linie umpositioniert, die mit Philippes Mitte-Rechts-Kurs kompatibel ist. Bolloré hat auch massive Interessen in Afrika (Bolloré Africa Logistics, Häfen) und in Asien, was ihn mit maritimen Transportfragen und sino-afrikanischen Netzwerken verbindet. Sein afrikanisches Logistikimperium wurde 2022 an CMA CGM (MSC) verkauft, was eine direkte Verbindung zwischen Bolloré und dem Saadé-Konzern schafft. Die Medienkonzentration zwischen Arnault (Les Échos, Le Parisien), Bolloré (CNews, Europe 1) und Saadé/CMA CGM (BFM TV) bedeutet, dass Frankreichs drei führende Nachrichtenmedien im Besitz von Oligarchen sind, die der macronistischen Macht nahestehen.",
    "patrick-drahi": "Patrick Drahi ist ein französisch-israelischer Unternehmer, Gründer von Altice, der BFM TV, RMC und Libération besaß, bis er seine Medienaktiva 2024 an CMA CGM (Rodolphe Saadé) verkaufte. Diese Transaktion ist entscheidend in der Kette der Interessenkonflikte: BFM TV, Frankreichs führender Nachrichtenkanal, wechselte von einem von finanziellen Kontroversen umgebenen Eigentümer (massive Verschuldung von Altice) zu CMA CGM, der führenden Reederei, die im Hafen von Édouard Philippes Hochburg tätig ist. Drahi war bereits wegen seines Einflusses auf die redaktionelle Linie von BFM kritisiert worden. Der Übergang zu CMA CGM verschärft den Konflikt: Der Hafenbetreiber von Le Havre besitzt nun das Medium, das den Bürgermeisterkandidaten von Le Havre abdeckt. Drahi ist auch Eigentümer von HOT in Israel und Sotheby's. Sein Imperium basiert auf massiver Verschuldung (über 60 Milliarden Euro auf dem Höhepunkt), ein Finanzmodell, das in mehreren Ländern Steuerermittlungen ausgelöst hat. Der Verkauf an Saadé illustriert die fortschreitende Medienkonzentration in Frankreich: Nachrichtenmedien wechseln von den Händen eines verschuldeten Milliardärs zu denen eines milliardenschweren Reeders, der mit chinesischen Handelsrouten verbunden ist. Die Kette Drahi → BFM → CMA CGM → Le Havre → Philippe ist ein durch sukzessive Übernahmen aufgebauter Interessenkonflikt-Weg.",
    "pierre-moscovici": "Pierre Moscovici ist seit Juni 2020 Präsident des Rechnungshofs. Young Leader 1996 (gleicher Jahrgang wie Hollande). Ehemaliger Finanzminister und anschließend EU-Kommissar. Die Tatsache, dass der oberste Rechnungsprüfer Frankreichs und der ehemalige Premierminister aus demselben Young-Leaders-Netzwerk stammen, wirft Fragen zur Unabhängigkeit der Kontrolle auf.",
    "dominique-de-villepin": "Dominique de Villepin, Premierminister unter Chirac (2005-2007), betreibt ein privates, multipolares und undurchsichtiges Netzwerk. Keine direkt dokumentierte Beziehung verbindet ihn mit Philippe — ihre Netzwerke konvergieren über Juppé und chinesische Verbindungen. Villepin trat 1979 der „Groupe J\" (Juppé-Treue) bei und wurde 1993 von Juppé zum Kabinettsdirektor im Quai d'Orsay ernannt. Seit 2008: rund 50 bezahlte Konferenzen in China (94.000 Euro für zwei laut Radio France), Präsidentschaft der IMTA (chinesische Organisation), Gesellschaften in Hongkong (Konten seit 2015 nicht mehr eingereicht), Nähe zu Xi Jinping. Multipolares Netzwerk über China hinaus: befreundet mit der Familie Al-Thani (Katar), Position bei der Museen-Behörde Katars, gemeinsame Plattform mit Putin bei Valdaï (2014), 800.000 Euro/Jahr von der saudischen Gruppe Bugshan über eine panamaische Gesellschaft, die mit Djouhri verbunden ist (2008-2010), 17-jähriger Veolia-Vertrag über Proglio, Aktivitäten im Iran, Venezuela, Armenien, Aserbaidschan. Unterstützt chinesische Unternehmen in Afrika und Europa, manchmal in Konkurrenz zu französischen Firmen. Umfragen Mai 2025: Villepin 51 %, Philippe 50 %. Beliebt bei der Linken (65 % LFI), Philippe bei der Mitte-Rechts. Direkter Konkurrent für 2027.",
    "villepin-international": "Villepin International ist Dominique de Villepins Beratungsgesellschaft, die nach seinem Abgang aus Matignon gegründet wurde. Ihre Bilanzen werden seit 2015 nicht mehr eingereicht — im selben Jahr wurden zwei Gesellschaften in Hongkong gegründet, danach eine dritte (Villepin Group Limited), mit erheblichen Finanzströmen. Die Untersuchung der Investigativredaktion von Radio France (Dezember 2025) enthüllt das Ausmaß der über diese Strukturen laufenden chinesischen Aktivitäten. Ziel und Empfänger der Finanzströme bleiben bedeutende Graubereiche. Die finanzielle Undurchsichtigkeit steht im Kontrast zu Philippes institutionellem und relativ transparentem Netzwerk über die FCF.",
    "alexandre-djouhri": "Alexandre Djouhri ist ein Vermittler, der im September 2025 im Rahmen der Libyen-Finanzierungsaffäre zu sechs Jahren Gefängnis verurteilt wurde. Die Untersuchung von Radio France enthüllt, dass Villepin in seiner Begleitung Auslandsreisen unternommen hat. Beim Forum von St. Petersburg registrierten sich beide als „Vizepräsidenten\" von Veolia — eine Registrierung, die von der Konzernführung bestritten wurde. Keine vergleichbare Verbindung ist für Philippe dokumentiert. Djouhri ist ein Schattenknoten, der spezifisch für das Villepin-Netzwerk ist und den ehemaligen Premierminister mit den umstrittensten Geschäftskreisen (Russland, Golf, Libyen) verbindet.",
    "henri-proglio": "Henri Proglio ist der ehemalige CEO von Veolia Environnement (2003-2009) und anschließend von EDF (2009-2014). Laut Untersuchungen steht Villepin seit 17 Jahren über Proglio unter Vertrag mit Veolia. Diese Verbindung erklärt die Episode beim Forum von St. Petersburg, bei der sich Villepin und Djouhri als „Vizepräsidenten\" von Veolia registrierten. Proglio ist eine Persönlichkeit des französischen Kapitalismus, die zwischen öffentlichem und privatem Sektor navigiert ist. Seine Rolle als Kontaktstelle zwischen Villepin und der Geschäftswelt ist ein im Bericht identifizierter Ansatzpunkt für vertiefte Untersuchungen.",
    "imta": "Die International Mountain Tourism Alliance (IMTA) ist eine chinesische Organisation, deren Präsident Villepin ist. Diese Präsidentschaft ist Teil des Netzwerks offizieller und halboffizieller Funktionen, die Villepin seit 2008 in China angehäuft hat: Präsidentschaft von Vereinigungen nach chinesischem Recht, Einbindung in die Leitungsgremien von Investmentfonds. Die IMTA illustriert Villepins institutionelle Verankerung in China — eine Legitimität, die von oben, direkt von der Zentralmacht erlangt wird, im Gegensatz zu Philippes FCF-Weg, der über geregelte franco-chinesische Strukturen verläuft.",
    "alain-merieux": "Alain Mérieux ist der Lyoner Industrielle und Gründer von bioMérieux, einem Weltmarktführer in der In-vitro-Diagnostik. Er ist der Architekt des Hochsicherheits-P4-Labors in Wuhan, das 2018 eingeweiht wurde — ein unter der Präsidentschaft Chirac gestartetes franco-chinesisches Kooperationsprojekt. Mérieux sitzt im Strategierat der FCF neben Raffarin und Fabius. Seine Präsenz im Herzstück des FCF-Apparats stellt eine Verbindung zwischen der franco-chinesischen Gesundheitsdiplomatie (das P4-Labor in Wuhan) und den Einflussnetzwerken her, in denen Philippe eingebettet ist. Die Frage des P4-Labors ist seit 2020 und der Covid-19-Pandemie geopolitisch sensibel geworden.",
    "laurent-fabius": "Laurent Fabius, ehemaliger Premierminister (1984-1986) und Präsident des Verfassungsrats seit 2016, ist gemeinsam mit Raffarin Co-Schirmherr der France China Foundation. Als ehemaliger Außenminister unter Hollande (2012-2016) hat er zur Strukturierung der sino-französischen Diplomatie beigetragen. Seine Präsenz im FCF-Strategierat neben Raffarin und Mérieux überschreitet die Links-Rechts-Grenzen und illustriert den Konsens der französischen Eliten rund um die Annäherung an Peking. Fabius prüft die Verfassungsmäßigkeit von Gesetzen — einschließlich derer der Philippe-Regierung.",
    "hubert-vedrine": "Hubert Védrine, ehemaliger Generalsekretär des Élysée unter Mitterrand und anschließend Außenminister (1997-2002), ist Mitglied des FCF-Strategierate. Als Theoretiker der französischen Außenpolitik und Erfinder des Konzepts der amerikanischen „Hyperpuissance\" repräsentiert er die Kontinuität der französischen diplomatischen Tradition der Unabhängigkeit von den Vereinigten Staaten — dieselbe Tradition, die Chiracs Erben in Richtung China gelenkt hat.",
    "jacques-chirac": "Jacques Chirac (1932-2019), Präsident der Republik (1995-2007), ist die gemeinsame Quelle des gesamten Ökosystems. Seine Politik der Unabhängigkeit von den Vereinigten Staaten und sein privilegierter Dialog mit Peking haben eine Tradition sino-französischer Beziehungen hervorgebracht, deren Erben Philippe und Villepin über unterschiedliche Kanäle sind. Eine Umfrage von JDD/Ifop aus dem Jahr 2019 rangierte Juppé als Chiracs führenden Erben (62 %), Villepin an dritter Stelle, während gefragt wurde, ob „die letzte Bastion des Chiraquismus nicht in Matignon liegt, mit Édouard Philippe\". Villepin war einer von Chiracs „Lieblingssöhnen\" (La Libre). Chirac → Juppé → Philippe und Chirac → Villepin sind die zwei Äste dieses politischen Stammbaums.",
    "cpifa": "Das CPIFA (Chinese People's Institute of Foreign Affairs) ist der offizielle chinesische Partner der France China Foundation. Dem chinesischen Außenministerium verbunden, ist es der institutionelle Gesprächspartner des sino-französischen Netzwerks von Philippe und Raffarin. Das CPIFA ist die Schnittstelle zwischen französischer Soft Power (FCF) und dem chinesischen diplomatischen Apparat. Diese Verbindung unterscheidet das Netzwerk Philippe/Raffarin (institutionell, geregelt) vom Netzwerk Villepin (privat, direkter Zugang zur Zentralmacht über Xi Jinping).",
    "charles-hufnagel": "Charles Hufnagel ist der Kommunikationsberater von Juppé, dem er in den 2000er Jahren bei Areva begegnet ist. Er war Philippes Sprecher in Matignon. Politische Journalisten schätzen ihn als „weit zuverlässiger\" als seinen Kollegen im Élysée (Le Temps). Er verkörpert die kommunikative Kontinuität der Juppéie: dieselbe Doktrin der Diskretion und medialen Zurückhaltung, die Juppés Kampagnen und Philippes Zeit in Matignon geprägt hat. Erster Kreis der Juppéie.",
    "benoist-apparu": "Benoist Apparu, ehemaliger Staatssekretär für Wohnungsbau unter Sarkozy, war Co-Sprecher der Juppé-Kampagne 2016 neben Philippe. Nach Juppés Niederlage in den Vorwahlen trat er dem Kampagnenteam Fillon bei. Sein Werdegang illustriert die Zerstreuung der Juppéisten nach November 2016 — ein Teil schloss sich Macron an (Boyer, Philippe), ein anderer verblieb im LR-Umfeld. Erster Kreis der Juppéie.",
    "anne-clerc": "Anne Clerc ist Kabinettschefin in Matignon unter Philippe. Ehemaliges Mitglied von Raffarins Team in Matignon — was sie zur menschlichen Brücke zwischen den Kabinetten der beiden chiraquistischen Premierminister macht. Ihre Präsenz im Kabinett Philippe illustriert die Kontinuität der Juppéie innerhalb des Staatsapparats: Dieselben Netzwerke übertragen sich von einem Matignon zum nächsten.",
    "xavier-chinaud": "Xavier Chinaud ist unter Philippe Berater für die Beziehungen zu den Abgeordneten in Matignon. Ehemaliger Leiter der «politischen Studien» in Matignon unter Raffarin. Wie Anne Clerc ist er ein Bindeglied zwischen den Kabinetten Raffarin und Philippe und sorgt für die Weitergabe von Praktiken und Netzwerken zwischen den beiden chiraquianischen Matignons.",
    "christophe-bechu": "Christophe Béchu ist Generalsekretär der Partei Horizons, ehemaliger Minister für ökologischen Wandel (2022-2024) und Bürgermeister von Angers. Seine Rolle innerhalb von Horizons ist strukturgebend: Er sorgt für die territoriale Organisation der Partei und verbindet den philippistischen Apparat mit den lokalen Gewählten. Die Achse Philippe (Normandie) / Béchu (Loire) / Estrosi (PACA) gibt Horizons für 2027 eine multiregionale Basis. Dritter Kreis der Juppéie — institutioneller Verbündeter.",
    "nathalie-loiseau": "Nathalie Loiseau, Renaissance-Europaabgeordnete und ehemalige Ministerin für Europäische Angelegenheiten (2017-2019), steht den juppéistischen Kreisen nahe. Als ehemalige ENA-Direktorin repräsentiert sie die europäische Verbindung der Juppéie. Nach der Niederlage von Juppé bei der Vorwahl gehört sie zur Gruppe der «Marschierenden» — der Juppéisten, die sich Macron angeschlossen haben. Dritter Kreis der Juppéie.",
    "virginie-calmels": "Virginie Calmels, ehemalige erste Bürgermeisterin von Juppé im Rathaus von Bordeaux, repräsentiert den «neo-rechten» Flügel der Juppéie — jenen, der sich von Philippe distanziert hat, um über die DroiteLib-Bewegung zu Laurent Wauquiez zu wechseln. Ihr Werdegang veranschaulicht die Fragmentierung der Juppéie nach der Niederlage 2016: Während die Mehrheit der Juppéisten zu Macron wechselte, entschied sich eine Minderheit für die Rechtsverschiebung von LR. Als ehemalige Chefin von Endemol France verkörpert sie das von Juppé geschätzte Manager-Politiker-Profil.",
    "julien-miro": "Julien Miro ist einer der Organisatoren des «bébés Juppé»-Netzwerks — rund dreißig Dreißigjährige, Veteranen der Vorwahlkampagne 2016, die sich nach der Niederlage in einem informellen Netzwerk zusammengeschlossen haben. Mit Guillaume Pfister organisiert er zweimonatliche Abendessen mit befreundeten Persönlichkeiten (Boyer, Gaymard, Keller, Bournazel). Bezeichnend erklärte Miro: «Alain Juppé hat verloren, aber die Juppéisten haben gewonnen: Sie sind überall in den Ministerialkabinetten.» Berater in Matignon, am Quai d'Orsay, in den Ministerien für Wirtschaft, ökologischen Wandel und Kultur — die bébés Juppé standen an den Hebeln der macronistischen Reformen. Zweiter Kreis der Juppéie.",
    "guillaume-pfister": "Guillaume Pfister ist der Mit-Organisator, zusammen mit Julien Miro, des informellen «bébés Juppé»-Netzwerks. Ihr erklärtes Ziel: «die juppéistische Flamme am Leben zu erhalten» und «die Zeit nach Juppé vorzubereiten». Bei den Abendessen treffen sich Persönlichkeiten, die Juppé nahestehen (Boyer, Gaymard, Keller, Bournazel), sowie junge Berater, die in den Ministerialkabinetten verteilt sind. Dieses Netzwerk bildet die Kaderschmiede von Horizons. Zweiter Kreis der Juppéie.",
    "fpi-raffarin": "Die FPI ist Raffarins Stiftung, die umgestaltet wurde, um als Vehikel für die französisch-chinesischen Beziehungen zu dienen. Budget von 3,5 Mio. €, finanziert von rund dreißig Unternehmen (Carrefour, Kering, L'Oréal, LVMH) zu je 15.000 €/Jahr. Die Stiftung erhielt Spenden von chinesischen Persönlichkeiten, darunter 85.000 € vom ehemaligen Botschafter Wu Jianmin. Die FPI operiert an der Schnittstelle zwischen Think Tank und Einflussnetzwerk und bietet Raffarin eine institutionelle Infrastruktur für seine chinesischen Aktivitäten. Sie ist ein paralleler Kanal zur FCF — der eine (FPI) ist Raffarins persönliches Vehikel, der andere (FCF) ist die kollektive Struktur.",
    "groupe-bugshan": "Die Bugshan-Gruppe ist ein saudischer Mischkonzern, der zwischen 2008 und 2010 über eine mit Alexandre Djouhri verbundene panamaische Gesellschaft 800.000 €/Jahr an Villepin zahlte. Diese Geldflüsse, die durch eine Recherche von Radio France aufgedeckt wurden, veranschaulichen die Undurchsichtigkeit von Villepins Geschäftsnetzwerk. Das Geld floss durch eine Offshore-Struktur, was die Rückverfolgung der Begünstigten erschwert. Die Verbindung Bugshan-Djouhri-Villepin ist einer der undurchsichtigsten Knotenpunkte des Netzwerks.",
    "sebastien-lecornu": "Sébastien Lecornu, amtierender Premierminister, unterhält eine Wettbewerbs-Kooperations-Beziehung mit Philippe. Ehemaliger LeMaire-Anhänger, der nach der Vorwahl 2016 mit den Juppéisten zum Fillon-Team wechselte. Sein Werdegang berührt den der Juppéie, ohne sich damit zu vermischen. Wie Philippe ist er Normanne (Évreux) und stellt innerhalb der Mehrheit einen potenziellen Rivalen um den Einfluss auf die gemäßigte Rechte dar.",
    "plastic-omnium": "Plastic Omnium ist ein französischer Kfz-Zulieferer, dessen Aufsichtsrat Raffarin angehörte. Die Gruppe erzielt einen erheblichen Teil ihres Umsatzes in China, was sie zu einem direkten Nutznießer der von Raffarin geförderten französisch-chinesischen Netzwerke macht. Ihre Präsenz im Raffarin-Ökosystem veranschaulicht den Mechanismus der Adressbuch-Verwertung: Unternehmen mit chinesischen Interessen finanzieren die FPI (15.000 €/Jahr) und profitieren im Gegenzug von dem durch den «Herrn China» der französischen Politik erleichterten Zugang zum chinesischen Markt.",
    "laurent-marcangeli": "Laurent Marcangeli sitzt der Parlamentsfraktion «Horizons et indépendants» in der Nationalversammlung vor. Er ist Philippes legislatives Bindeglied: Er koordiniert die Positionen der Fraktion zu Gesetzestexten und sorgt für den Zusammenhalt der philippistischen Abgeordneten. Nach der Auflösung 2024 schrumpfte die Fraktion von dreißig auf sechs Abgeordnete — ein Einbruch, der die Fragilität der parlamentarischen Basis von Horizons verdeutlicht.",
    "jacques-attali": "Jacques Attali (geboren 1943) ist Polytechniker und Énarque (Promotion Robespierre, 1970). Ehemaliger Rechnungsprüfer beim Conseil d'État, zehnjähriger Sonderberater von François Mitterrand (1981-1991), Gründer und erster Präsident der BERD (1991-1993), Präsident der Kommission zur Befreiung des französischen Wachstums (2007-2010). Als Vermittlungsagent hat Attali das Duo Macron-Philippe entworfen: 2007 wählte er den jungen Macron als stellvertretenden Berichterstatter seiner Kommission. 2011 stellte er Macron Hollande vor. Im März 2017 schlug er Macron vor, Philippe als Premierminister zu wählen, und organisierte ihr Treffen. Diese Kette Attali → Macron → Philippe ist der Grundmechanismus der Regierung Philippe (2017-2020). Attali ist Mitgründer des Strategischen Rates der France China Foundation (2013), wo er neben Philippe, Raffarin, Fabius, Mérieux und de Castries sitzt — eine einzigartige Konvergenz von fünf Machtebenen. Er verließ die FCF im März 2020, zum Zeitpunkt des Ausbruchs der Pandemie. Im Multi-Agenten-System besitzt Attali kein eigenes Zentroid, sondern fungiert als Verbindungsknoten, der indirekten Einfluss durch die Verknüpfung von Zentroiden maximiert. Sein Wert liegt im Netzwerk, nicht in formaler Macht, was es ihm ermöglicht, Regierungswechsel unbeschadet zu überstehen — ein Präsident kann wechseln, ein Premierminister kann fallen, Attali bleibt.",
    "alain-minc": "Alain Minc (geboren 1954) ist Énarque (Promotion Léon Blum, 1975, Jahrgangserster), Generalinspektor der Finanzen. Ehemaliger Vorsitzender des Aufsichtsrats von Le Monde, Präsident von AM Conseil, Vorsitzender des Verwaltungsrats der Sanef, Schatzmeister der Fondation Saint-Simon, Mitglied von Le Siècle. Ein Drittel der großen CAC-40-Unternehmenslenker hat seine Dienste vergütet (Bolloré, Bouygues, Vinci, Club Med, Suez). Als Vermittlungsagent operiert Minc von der französischen Rechten aus (Balladur, Sarkozy, Juppé), während sein Gegenstück Attali von der Linken aus operiert (Mitterrand, Hollande) — eine Symmetrie, die es ihnen ermöglicht, das gesamte politische Spektrum abzudecken. Minc unterstützte Juppé bei der Vorwahl 2016, wechselte dann 2017 zu Macron über (identischer Transfer wie bei den Juppéisten selbst). Er unterhält einen indirekten Kanal zu Philippe über Gilles Boyer (Berater im Matignon), der vom JDD bezüglich der Quellensteuer (2018) dokumentiert wurde. Macron hatte beim Verlassen der ENA zwei Mentoren: Minc und Attali, was das Tandem-Facilitator-Modell bestätigt. Minc ist ehemaliger Young Leader der FAF und bildet so eine vier Jahrzehnte umspannende Kette: Minc (YL) → Juppé (YL 1982) → Philippe (YL 2011) → Macron (YL 2012). Wie Attali maximiert Minc seinen indirekten Einfluss, indem er in der Öffentlichkeit unsichtbar bleibt. Keine Wahlverantwortung, keine formale Macht, aber eine unübertroffene Vernetzungskapazität.",
    "commission-attali": "Von Sarkozy in Auftrag gegeben, von Attali geleitet, mit Macron als stellvertretendem Generalberichterstatter. Unter den 316 Maßnahmen: die Liberalisierung der VTCs, die zum Novelli-Gesetz (2009) und dann zum «Uber-Macron-Deal» (2014-2016) führte. Ausgangspunkt der Deregulierungskette: Commission → Uber → Macron → Philippe.",
    "msc-aponte": "Gegründet von der Familie Aponte, Cousins der Mutter von Alexis Kohler. Zweitgrößtes Schifffahrtsunternehmen der Welt, betreibt ein Containerumschlag-Terminal im Hafen von Le Havre. Kohler erklärte während seines Mandats beim GPMH nie seine familiären Verbindungen zu MSC. Im Mittelpunkt der Anklage gegen Kohler wegen unerlaubter Interessenkonflikte.",
    "rodolphe-saade-cma-cgm": "CEO von CMA CGM (drittgrößtes Schifffahrtsunternehmen der Welt), Eigentümer von BFM TV und RMC nach dem Kauf von Altice Media (2023). CMA CGM betreibt Terminals im Hafen von Le Havre, Philippes Heimathfen. Übernahm Bolloré Transport & Logistics (2024). Ein dreifacher Knotenpunkt: wirtschaftlich (Seetransport), medial (BFM/RMC) und politisch (Hafenpartner des Bürgermeisters von Le Havre).",
    "gpmh": "Frankreichs führender Hafen, ein Konvergenzknoten des Netzwerks. Kohler und Philippe saßen gemeinsam im Aufsichtsrat (2010-2012). Hub von CMA CGM und Kunde von MSC. Partnerstadt mit Dalian (China). Verbunden mit COSCO Shipping (erster chinesischer Reederei). Der geografische Punkt, an dem politische, finanzielle, mediale und geostrategische Macht zusammenlaufen.",
    "uber-files": "124.000 interne Uber-Dokumente, die an die ICIJ durchgesickert sind. Sie enthüllen 17 Kommunikationsvorgänge zwischen Uber und Macrons Kabinett, 4 Treffen zwischen Macron und Kalanick, einen versteckten Deal (Uber verzichtet auf UberPop, der Staat reduziert die VTC-Ausbildung von 250 auf 7 Stunden) sowie von Uber verfasste Gesetzesänderungsanträge, die an Abgeordnete weitergegeben wurden. Parlamentarische Untersuchungskommission (2023): kein Interessenkonflikt, aber bestätigte «privilegierte Beziehungen».",
    "henri-de-castries": "Ein einzigartiger Knoten im System: leitet den Bilderberg-Lenkungsausschuss seit 2012, sitzt im Conseil stratégique der FCF neben Attali, Raffarin und Philippe und war Klassenkamerad von Villepin an der ENA (Promotion Voltaire, 1980). Ehemaliger CEO von AXA (2000-2016), Präsident des Institut Montaigne, dreifacher Young Leader FAF (1994, 1995, 1998). Einzigartiger Brückenkopf zwischen dem transatlantischen Netzwerk (Bilderberg, FAF) und dem französisch-chinesischen Netzwerk (FCF).",
    "gabriel-attal": "Premierminister (Januar-September 2024), jüngster PM der Fünften Republik. Als Haushaltsminister zum Bilderberg nach Lissabon eingeladen (2023), sieben Monate später zum PM ernannt. Anwesend in Stockholm (2025) neben Philippe — das erste Mal, dass zwei ehemalige macronistische PMs gemeinsam teilnahmen. Wiederkehrendes Muster: Macron (Bilderberg 2014 → Minister 2 Monate später), Philippe (2016 → PM 11 Monate später), Attal (2023 → PM 7 Monate später).",
    "patricia-barbizet": "Mitglied des ständigen Bilderberg-Lenkungsausschusses — zweite ständige französische Vertreterin nach de Castries. Ehemalige Präsidentin des Siècle, ehemalige Generaldirektorin der Holding Artémis (Pinault). Anwesend beim Bilderberg 2023 in Lissabon. Verbindet Bilderberg mit dem Siècle, wo auch Attali und Minc Mitglieder sind.",
    "institut-montaigne": "Liberaler Think Tank unter dem Vorsitz von Henri de Castries, finanziert von AXA, Engie, BNP Paribas, LVMH und TotalEnergies. Intellektueller Bezugspunkt der Macron-Kampagne 2017: Sein Direktor Laurent Bigorgne hatte die Kampagnenadresse für LREM bereitgestellt. Ein Vehikel für die doktrinäre Produktion des Horizons-Programms 2027.",
    "blackrock": "Weltgrößter Vermögensverwalter, gegründet von Larry Fink. Hält Beteiligungen an mindestens 18 CAC-40-Unternehmen, darunter AXA (de Castries), BNP (Lemierre, Bilderberg 2025), TotalEnergies (Pouyanné, Bilderberg), Société Générale (Kohler 2025). Alliierter von MSC beim Erwerb von 43 Häfen weltweit für 22,8 Mrd. $ (2025). Philippe schlägt 2027 eine Rentenkapitalisierung von 15% vor — genau das Ziel von BlackRock in Frankreich.",
    "jean-francois-cirelli": "ENA-Absolvent (Promotion Léonard de Vinci, 1985), ehemaliger Berater Chiracs, stellvertretender Kabinettschef von Raffarin (2002-2004), Mitgestalter der Rentenreform Fillon 2003. CEO von Gaz de France, Nummer 2 bei Engie. Präsident von BlackRock Frankreich seit 2015. Von Philippe in den Comité Action Publique 2022 (2018) eingeladen. Am 31. Dezember 2019, mitten im historischen Rentenstreik, von Philippe zum Offizier der Légion d'honneur ernannt.",
    "marc-ferracci": "Ökonom, HEC-Absolvent, Doktor der Wirtschaftswissenschaften. Lernte Macron mit 22 Jahren an der Sciences Po kennen. Macrons Trauzeuge. Sein Vater Pierre Ferracci war Mitglied der Attali-Kommission (2007), bei der Macron als Berichterstatter tätig war. Abgeordneter der Renaissance, ehemaliger Industrieminister. Deklariertes Vermögen: 23 Mio. €. Unterzeichner des Manifests \"Pour la France, construisons l'union !\" (29. März 2026). Brückenagent zwischen dem Macron-Ökosystem und der Philippe-Koalition.",
    "philippe-tabarot": "Verkehrsminister seit Dezember 2024. Beaufsichtigt die französischen Seehäfen, darunter das GPMH (Knotenpunkt Philippe/Kohler/MSC/CMA CGM). Ehemaliger stellvertretender Regionspräsident der PACA an der Seite von Estrosi (Horizons). LR-Senator. Vom PNF wegen Unterschlagung öffentlicher Mittel und unzulässiger Interessennahme ermittelt. Der Posten des Verkehrsministers ist ein wiederkehrender Knotenpunkt: Djebbari (YL FCF 2020) wurde von der HATVP verboten, CMA CGM beizutreten.",
    "maud-bregeon": "Regierungssprecherin der Regierung Lecornu, delegierte Ministerin. Unterzeichnerin des Manifests \"Pour la France, construisons l'union !\" (29. März 2026). Erklärte auf LCI, dass Philippe \"eine ernstzunehmende Option ergriffen hat, da er potenziell am besten positioniert ist, diesen Kampf zu führen\". Stellt die explizite Verbindung zwischen der aktuellen Regierung und der Kandidatur von Philippe 2027 her.",
    "jean-paul-delevoye": "Hoher Kommissar für Renten in der Regierung Philippe, verantwortlich für das universelle Punktesystem. Traf BlackRock bereits im März 2018, drei Monate nach seiner Ernennung. Trat am 16. Dezember 2019 zurück wegen 13 Mandaten, die bei der HATVP nicht angemeldet waren. Die von ihm vorbereitete Reform steht im Verdacht, die Kapitalisierung zugunsten von BlackRock vorzubereiten. Der Rückgriff auf Artikel 49.3 im Februar 2020 und die Pandemie froren die Reform auf unbestimmte Zeit ein.",
    "elabe-bfmtv": "Elabe-Umfrage für BFMTV (Eigentum von CMA CGM/Saadé) vom 28. März 2026, die Philippe im ersten Wahlgang auf 20,5–25,5 % setzt. Die unabhängige bayesianische Aggregation von moipresident.online gibt ihm 17 %, d. h. 3,5 bis 8,5 Punkte weniger. Das Ergebnis von 51,5 % gegen Bardella im zweiten Wahlgang liegt innerhalb der Fehlerquote. Der Auftraggeber (BFMTV/CMA CGM) teilt ein Interesse mit dem Kandidaten (Hafen von Le Havre).",
    "patrick-pouyanné": "CEO von TotalEnergies, wiederkehrender Teilnehmer des Bilderberg (2023, 2025) an der Seite von Philippe. TotalEnergies ist Aktionär des Institut Montaigne (de Castries) und wird zu einem erheblichen Anteil von BlackRock gehalten. In Lissabon und Stockholm anwesend mit Philippe, Attal und de Castries. Knotenpunkt, der den Bilderberg-Kreis mit dem Unternehmens-/BlackRock-Kreis verbindet.",
    "jean-lemierre": "Präsident von BNP Paribas, beim Bilderberg 2025 in Stockholm an der Seite von Philippe und Attal. BNP wird teilweise von BlackRock gehalten und finanziert das Institut Montaigne. Kohler verließ den Élysée 2025, um zur Société Générale zu wechseln — dasselbe Bankensystem. Der Bilderberg-Kreis verbindet die französischen Systembanken direkt mit Präsidentschaftskandidaten.",
    "bernard-emie": "Generaldirektor für äußere Sicherheit (DGSE, 2017-2024), beim Bilderberg 2023 in Lissabon an der Seite von Philippe, Attal und de Castries. Die Anwesenheit des Chefs des französischen Auslandsnachrichtendienstes in einem privaten transatlantischen Forum ist eine bemerkenswerte Tatsache, die von Regards.fr aufgegriffen wurde. 2025 ersetzte ihn Nicolas Roche (SGDSN), zwei Monate zuvor ernannt, beim Bilderberg.",
    "laurent-nunez": "Laurent Nuñez-Belda (geboren 1964 in Bourges) ist Énarque (Promotion Cyrano de Bergerac, 1997-1999, interner Wettbewerb). Direktor der DGSI (Juni 2017 – Oktober 2018), Staatssekretär für Inneres in der Regierung Philippe II (Oktober 2018 – Juli 2020), nationaler Geheimdienstkoordinator im Élysée (Juli 2020 – Juli 2022), Polizeipräfekt von Paris (Juli 2022 – Oktober 2025), dann Innenminister in der Regierung Lecornu II (seit Oktober 2025). Er ist der operative Vollstrecker der Unterdrückung der Gilets jaunes an der Seite von Castaner, während Philippe die politische Verantwortung trägt. Nuñez verteidigte öffentlich die LBDs, beteiligte sich an der Absetzung von Präfekt Delpuech (März 2019) und übernahm eindeutig die härteste Sicherheitsdoktrin der Fünften Republik. In MAS-Begriffen ist er ein staatlicher Vollstreckungsagent: seine Loyalität gilt direkt Macron (der ihn persönlich für jeden Posten ernennt), nicht Philippe (seinem nominellen Vorgesetzten). Seine Anwesenheit in der Regierung Lecornu II, neben Horizons-Mitgliedern, schafft eine zusätzliche indirekte Verbindung zur philippistischen Sphäre. Das Dreieck Nuñez–Bompard–Caubel ist die strukturierende Entdeckung des Berichts: Kommilitone der ENA von Bompard (CEO Carrefour), dessen Ehefrau Charlotte Caubel Leiterin des Justizreferats im Kabinett Philippe (2017-2020) war und Mitglied von Horizons ist.",
    "alexandre-bompard": "Alexandre Joubert-Bompard (geboren 1972) ist CEO der Carrefour-Gruppe (Umsatz 2024: 86 Milliarden Euro), belegt den 4. Platz in der Promotion Cyrano de Bergerac der ENA (1997-1999). Er ist der Kommilitone von Laurent Nuñez in dieser Promotion (Erlass vom 19. April 1999, Légifrance, JORFTEXT000000211140). Seine Ehefrau Charlotte Caubel war Leiterin des Justizreferats im Kabinett von Édouard Philippe im Matignon (2017-2020). Bompard hat keine dokumentierte direkte Verbindung zu Philippe, aber sein Familiennetzwerk (über Caubel) und berufliches Netzwerk (über Nuñez) verbindet die Welt des Großhandels mit den Kreisen der Exekutivmacht. Carrefour hat bedeutende Interessen in China und war offizieller Partner der Olympischen Spiele Paris 2024.",
    "charlotte-caubel": "Charlotte Caubel (Magistratin, Sciences Po) wurde im Mai 2017 als Justizberaterin im Kabinett von Édouard Philippe im Matignon ernannt. Sie blieb dort drei Jahre (2017-2020) und wurde Leiterin des Justizreferats. Nach dem Matignon leitete sie die Protection judiciaire de la jeunesse (2020-2022), bevor sie als Staatssekretärin für Kindheit in der Regierung Borne (2022-2024) ernannt wurde. Sie ist Mitglied der Partei Horizons. Im August 2025 wurde sie zur stellvertretenden Staatsanwältin in Paris ernannt. Ihr Ehemann ist Alexandre Bompard (CEO Carrefour), Kommilitone der ENA von Laurent Nuñez. Dieses Dreieck Nuñez–Bompard–Caubel verbindet Nuñez' ENA-Jahrgang direkt mit dem Herzstück des Kabinetts Philippe und der Partei Horizons.",
  },
  es: {
    "emmanuel-macron": "Emmanuel Macron fue seleccionado como Young Leader en la promoción 2012, un año después de Édouard Philippe. Su mentor común, Alain Juppé, pertenecía a la promoción fundadora de 1982 — tres generaciones de Young Leaders ligadas por el mismo padrino político. Macron nombró a Philippe Primer Ministro el 15 de mayo de 2017, pese a las críticas anteriores de este último («antiguo banquero de Rothschild», «cinismo de un veterano»). Este acercamiento post-críticas ilustra la fuerza de los vínculos de red sobre las posiciones públicas. Macron procedía de la Inspección de Finanzas, luego del banco Rothschild, antes de ser nombrado secretario general adjunto del Élysée bajo Hollande (él mismo Young Leader 1996). La cadena Hollande (YL 1996) → Macron (YL 2012) → Philippe (YL 2011) en la cúspide del Estado es única en la historia de la FAF. Las tensiones entre ambos han ido creciendo desde 2020: Philippe reprochó a Macron la disolución de 2024 («una decisión funesta y absurda») y le pidió que dimitiera a finales de 2025. La promoción 2012 de Macron incluía también a Fleur Pellerin y Cédric Villani, ambos convertidos en figuras políticas. El hecho de que un presidente y su Primer Ministro procedan de promociones consecutivas del mismo programa transatlántico es inédito y plantea interrogantes sobre la influencia americana en la formación de las élites dirigentes francesas.",
    "alain-juppe": "Alain Juppé es el padrino de todo el ecosistema. Primer Ministro de Chirac (1995-1997), condenado en 2004 (empleos ficticios del RPR), Young Leader de la promoción fundadora de la FAF (1982), alcalde de Burdeos (2006-2019), miembro del Conseil constitutionnel desde marzo de 2019 (mandato hasta 2028) y presidente del Institut Georges-Pompidou desde febrero de 2025. Fue Juppé quien lanzó a Philippe en política (como director general de la UMP en 2002), y Villepin ya le conocía desde el «grupo J» (1979) antes de ser nombrado jefe de gabinete en el Quai d'Orsay por Juppé (1993). El triángulo Juppé (YL 1982) → Philippe (YL 2011) → Macron (YL 2012) es el caso más espectacular de transmisión del poder dentro de la FAF. Hoy neutralizado por las restricciones del Conseil constitutionnel (deber de reserva, prohibición de cualquier responsabilidad partidaria, incompatibilidad con todo mandato), no puede ni apoyar a Philippe, ni pronunciarse sobre temas políticos, ni ejercer papel alguno en Horizons. Pero su poder residual es triple: institucional (participa en las decisiones constitucionales, ocupa un escaño junto a Richard Ferrand YL 2005), simbólico (su legado impregna Horizons: pragmatismo, europeísmo, liberalismo moderado) y reticular (la «Juppéie» — su red informal de fieles — forma la columna vertebral de Horizons). Publicación de L'heure du choix (Tallandier, 2025) sobre la independencia europea. «Alain Juppé perdió, pero los juppéístas ganaron: están en todas partes en los gabinetes ministeriales» (Julien Miro).",
    "cma-cgm": "CMA CGM es el primer armador francés y el tercero a nivel mundial, fundado en Marsella por Jacques Saadé en 1978. El grupo posee más de 600 buques y sirve a 420 puertos en todo el mundo. Yann Le Goff, responsable de seguridad regional en CMA CGM, fue seleccionado en la promoción 2011 de Young Leaders junto a Édouard Philippe. El puerto de El Havre, feudo político de Philippe desde 2010, es uno de los principales hubs europeos de CMA CGM — los buques del grupo representan una parte significativa del tráfico de contenedores allí. El Havre es el principal punto de entrada de cocaína en Europa según Europol, con 18 toneladas incautadas en 2023. La cuestión de la seguridad portuaria — ámbito donde convergen CMA CGM (a través de Le Goff), la responsabilidad del alcalde (Philippe) y las redes transatlánticas (FAF) — es un nudo crítico. CMA CGM está dirigida por Rodolphe Saadé desde 2017, y el grupo ha diversificado sus actividades en medios de comunicación (adquisición de La Tribune, La Provence) y logística. La France China Foundation, de la que Ribadeau-Dumas (jefe de gabinete de Philippe) es miembro, se inscribe en los mismos circuitos de influencia sino-marítimos. Las rutas comerciales de CMA CGM hacia Asia transitan masivamente por El Havre, convirtiendo el puerto en un punto de convergencia entre intereses comerciales, diplomáticos y políticos.",
    "yann-le-goff": "Yann Le Goff es responsable de seguridad regional en CMA CGM, el principal armador francés, en el momento de su selección como Young Leader en 2011 junto a Édouard Philippe. Su función en CMA CGM le sitúa en el núcleo de las cuestiones de seguridad del transporte marítimo — un ámbito que incluye la lucha contra el narcotráfico en los puertos. El puerto de El Havre, feudo político de Philippe, es el principal punto de entrada de cocaína en Europa según Europol. Los buques de CMA CGM representan una gran parte del tráfico de contenedores en El Havre, lo que significa que la seguridad de CMA CGM y la seguridad portuaria de El Havre están íntimamente ligadas. Le Goff y Philippe se relacionaron durante dos seminarios de cinco días en 2011-2012, forjando vínculos personales en un marco informal y confidencial. La presencia en la misma promoción Young Leaders de un futuro alcalde/Primer Ministro y de un responsable de seguridad de la principal naviera que opera en su puerto crea un canal de influencia directo. Esta conexión es tanto más significativa cuanto que la cuestión del narcotráfico portuario se ha convertido en un tema político mayor en Francia, con incautaciones récord en El Havre (18 toneladas de cocaína en 2023). Le Goff representa el nodo de CMA CGM en la red Young Leaders de Philippe. La convergencia entre su puesto (seguridad marítima), el territorio de Philippe (El Havre) y el problema estructural (narcotráfico) merece un examen exhaustivo.",
    "atos": "Atos es un grupo informático francés especializado en transformación digital, ciberseguridad y computación en la nube. Édouard Philippe fue nombrado administrador independiente en 2020, inmediatamente después de su salida de Matignon, con un mandato remunerado de aproximadamente 70.000 euros anuales. Atos está a la vanguardia del tratamiento informatizado de los datos de infracciones de tráfico, especialmente los radares automáticos — un mercado que se benefició directamente de la medida de los 80 km/h impuesta por Philippe en 2018. Boulevard Voltaire y Blast señalaron este potencial conflicto de intereses: el Primer Ministro que impone una medida vial masivamente impopular pasa a integrar el consejo de administración de la empresa que trata los datos generados por esa misma medida. Los vínculos entre Philippe y Atos se remontan a 2006, mucho antes de su nombramiento en Matignon. La empresa experimentó graves dificultades financieras a partir de 2022, con un espectacular desplome bursátil y reestructuraciones masivas. Atos también gestiona actividades estratégicas para el Estado francés (superordenadores, defensa, JJ.OO. 2024), lo que la convierte en un actor sensible cuyo consejero es también candidato a la presidencia. La cronología — 80 km/h en 2018, salida de Matignon en 2020, nombramiento en Atos en 2020 — plantea interrogantes sobre la porosidad entre decisiones públicas e intereses privados. Philippe jamás ha comentado públicamente este potencial conflicto de intereses.",
    "areva": "Areva (rebautizada Orano en 2018) es la multinacional francesa de la industria nuclear, que cubre todo el ciclo del combustible. Édouard Philippe ocupó el puesto de director de asuntos públicos de octubre de 2007 a octubre de 2010, una función de lobbying y relaciones con los cargos electos que le mantuvo en el núcleo de la esfera decisional. Este período coincidió con su selección como Young Leader en 2011, cuando fue presentado como «alcalde de El Havre y director de asuntos públicos de Areva». El lobbying nuclear es uno de los más poderosos en Francia, donde la industria representa aproximadamente el 70% de la producción eléctrica. Como director de asuntos públicos, Philippe tenía encomendada la defensa de los intereses de Areva ante los parlamentarios y el gobierno — las mismas instituciones que dirigiría más tarde como Primer Ministro. Su trayectoria Conseil d'État → Debevoise & Plimpton (abogado de negocios) → Areva (lobbying) → alcaldía de El Havre → Matignon ilustra un clásico recorrido de puertas giratorias entre lo público y lo privado. Areva vivió un escándalo mayúsculo con la desastrosa adquisición de UraMin en 2007 (3.600 millones de euros de pérdidas), un asunto que estalló durante el período en que Philippe trabajaba allí. El grupo tuvo que ser reestructurado y recapitalizado por el Estado por importe de 5.000 millones de euros en 2017 — bajo el gobierno Philippe. El Primer Ministro que rescata a la empresa que le empleó como lobbyista es un caso paradigmático de potencial conflicto de intereses.",
    "debevoise-plimpton": "Debevoise & Plimpton LLP es un bufete de abogados americano fundado en 1931 en Nueva York, especializado en derecho mercantil internacional, fusiones y adquisiciones, capital riesgo y arbitraje internacional. El bufete cuenta con aproximadamente 800 abogados y oficinas en Nueva York, Washington, Londres, París, Fráncfort, Hong Kong y Shanghái. Édouard Philippe ejerció como abogado allí de 2004 a 2007, en la filial parisina, tras dejar sus funciones de director general de la UMP y solicitar una excedencia del Conseil d'État. Esta etapa en un bufete anglosajón de primera fila ilustra la clásica trayectoria de puertas giratorias: alta función pública (ENA, Conseil d'État), dirección de partido político (UMP), luego sector privado internacional, antes de volver a la política. Debevoise representa a empresas del Fortune 500 y fondos de inversión, lo que permitió a Philippe tejer una red en los círculos empresariales internacionales. El bufete está presente en Hong Kong y Shanghái, centros neurálgicos del comercio asiático — un detalle que cobra sentido a la vista de las posteriores conexiones sino-francesas del entorno de Philippe. Tras Debevoise, Philippe se incorporó a Areva como director de asuntos públicos (lobbying), confirmando su arraigo en los círculos de influencia económica. La secuencia Conseil d'État → UMP → Debevoise → Areva → alcaldía → Matignon traza un recorrido en el que cada etapa enriquece la agenda de la siguiente. El paso por Debevoise es el paréntesis anglosajón de este recorrido esencialmente francés. Los honorarios y mandatos que gestionó en Debevoise nunca han sido hechos públicos.",
    "antoine-rufenacht": "Antoine Rufenacht fue alcalde de El Havre de 1995 a 2010, antiguo graduado de la ENA y figura de la derecha normanda. Fue él quien identificó a Édouard Philippe como posible sucesor y le introdujo en política en 2001, integrándole en su lista municipal como teniente de alcalde encargado de asuntos jurídicos. Rufenacht recomendó después a Philippe a Alain Juppé para la dirección de la UMP en 2002, lanzando así su carrera nacional. Cuando Rufenacht dimitió de la alcaldía en 2010, el consejo municipal eligió a Philippe para sucederle — una transmisión del poder local perfectamente orquestada. Christine Poyer-Rufenacht, abogada que lleva el mismo apellido que el exalcalde, fue seleccionada en la promoción 2011 de Young Leaders de la FAF junto a Philippe — una coincidencia que nunca ha sido explicada públicamente. Rufenacht dirigió El Havre durante quince años, configurando la red política y económica local que Philippe heredó. Bajo Rufenacht, El Havre emprendió una transformación urbana en torno al puerto y la arquitectura Perret declarada Patrimonio de la UNESCO. La relación Rufenacht-Philippe es un caso de libro de texto de sucesión política local: el mentor identifica, forma e instala a su protegido al frente de la ciudad. El arraigo de Philippe en El Havre — ayuntamiento, puerto, comunidad urbana — es herencia directa de la red Rufenacht. El hecho de que el mentor local y la red transatlántica (FAF) converjan en torno al mismo apellido interroga sobre los mecanismos de cooptación en las élites francesas.",
    "french-american-foundation": "La French-American Foundation (FAF) es una organización fundada en 1976 bajo los auspicios de los presidentes Gerald Ford y Valéry Giscard d'Estaing. Su programa Young Leaders, creado en 1981, selecciona cada año a diez franceses y diez americanos de entre 30 y 40 años, procedentes de la alta función pública, la empresa, los medios de comunicación, el ejército y la investigación. Los participantes asisten a dos seminarios de cinco días durante dos años consecutivos, alternando entre Francia y Estados Unidos. El contenido de los seminarios no se publica — la FAF no divulga los órdenes del día de las ediciones pasadas. Al concluir el programa, los participantes se integran en una red de más de 600 exalumnos. El programa es descrito regularmente como un instrumento del poder blando americano, aunque la FAF se presenta como «ni un think tank, ni un lobby, ni una asociación parlamentaria de amistad». La presencia de Young Leaders en el gobierno francés es notable y trasciende las alternaciones políticas. Édouard Philippe pertenece a la promoción 2011, Emmanuel Macron a la de 2012, Alain Juppé a la fundadora de 1982 y François Hollande a la de 1996. Richard Ferrand, ministro del gobierno Philippe, fue Young Leader en 2005. Más de 400 dirigentes se han beneficiado del programa desde 1981, y el hecho de que un presidente y su Primer Ministro procedan de promociones consecutivas es inédito en la historia de la FAF. Los patrocinadores del programa incluyen a Airbus, J.P. Morgan y Sodexo.",
    "david-barroux": "David Barroux es periodista y redactor jefe del diario económico Les Échos, uno de los principales periódicos de negocios de Francia. Formó parte de la promoción 2011 de Young Leaders de la French-American Foundation junto a Édouard Philippe. Su posición al frente de un medio económico de referencia le confiere una influencia significativa sobre la cobertura de la política económica francesa. Les Échos pertenece al grupo LVMH de Bernard Arnault, lo que inscribe a Barroux en un ecosistema mediático ligado a las grandes fortunas francesas. Como Young Leader, compartió con Philippe dos seminarios de cinco días entre 2011 y 2012, forjando vínculos personales y profesionales duraderos. La convergencia entre un futuro Primer Ministro y el redactor jefe de un gran diario en la misma red transatlántica merece ser señalada. Les Échos dispensó en general una cobertura favorable a las reformas del gobierno Philippe, especialmente sobre el Código del Trabajo y la ley PACTE. Esta proximidad ilustra el entrelazamiento de las élites políticas y mediáticas francesas dentro de las mismas redes de influencia. Barroux representa el pilar mediático de la promoción 2011. La FAF no publica los intercambios que tuvieron lugar entre estos futuros dirigentes durante los seminarios.",
    "yohann-benard": "Yohann Bénard es director de asuntos públicos de Amazon Francia en el momento de su selección como Young Leader en 2011. Comparte la promoción de la FAF con Édouard Philippe, entonces alcalde de El Havre y director de asuntos públicos de Areva. Ambos hombres ocupan funciones similares — el lobbying y las relaciones institucionales — uno para el gigante nuclear, el otro para el gigante americano del comercio electrónico. Amazon es una de las empresas más controvertidas en Francia por sus prácticas sociales y fiscales y su impacto en el comercio de proximidad. Bénard tiene encomendada la defensa de los intereses de Amazon ante los cargos electos y las administraciones francesas. Al compartir una red élite transatlántica con un futuro Primer Ministro, dispone de un acceso privilegiado a los círculos decisionales. El gobierno Philippe no endureció especialmente la fiscalidad de los GAFA durante sus tres años en Matignon, a pesar de las promesas al respecto. La presencia simultánea en la promoción 2011 de un lobbyista de Amazon y de un lobbyista de Areva que se convertiría en Primer Ministro ilustra la porosidad entre intereses corporativos y poder político. Los seminarios de la FAF ofrecieron un marco informal para tejer estos vínculos. Bénard representa el pilar corporativo americano de la promoción.",
    "stephane-israel": "Stéphane Israël fue seleccionado como Young Leader 2011, el mismo año que Édouard Philippe. Se convertiría en presidente ejecutivo de Arianespace, líder mundial de los servicios de lanzamiento espacial, filial de ArianeGroup (empresa conjunta Airbus/Safran). Antes de Arianespace, Israël fue jefe de gabinete de la ministra de Enseñanza Superior e Investigación, Geneviève Fioraso (2012-2014), bajo la presidencia Hollande. Encarna el perfil típico de las puertas giratorias entre la alta función pública y la industria estratégica. Su trayectoria — gabinete ministerial y luego dirección de una empresa pública — es comparable a la de Philippe (Conseil d'État, Areva, política). Arianespace es un actor clave de la soberanía espacial europea, y su presidente mantiene necesariamente relaciones estrechas con el poder ejecutivo francés. La presencia de Israël en la misma promoción Young Leaders que Philippe crea un vínculo transversal entre las industrias nuclear y espacial y el poder político. Airbus, empresa matriz de ArianeGroup, es además uno de los patrocinadores del programa Young Leaders de la FAF. Estas interconexiones entre patrocinadores del programa y miembros seleccionados plantean interrogantes sobre la independencia del proceso de selección. Israël representa el pilar industrial estratégico de la promoción 2011.",
    "christine-poyer-rufenacht": "Christine Poyer-Rufenacht es abogada asociada, seleccionada en la promoción 2011 de Young Leaders de la FAF junto a Édouard Philippe. Su apellido evoca inevitablemente al de Antoine Rufenacht, el alcalde de El Havre que lanzó a Philippe en política en 2001 — una homonimia perturbadora que las biografías oficiales no comentan. Antoine Rufenacht fue el mentor local de Philippe, ofreciéndole su primer puesto en una lista municipal y recomendándole luego para la dirección de la UMP ante Alain Juppé. La presencia en la misma promoción Young Leaders de un protegido de Rufenacht y de una persona con el mismo apellido interroga sobre los mecanismos de cooptación dentro de estas redes. La FAF no publica criterios de selección detallados, y el proceso de candidatura se apoya en parte en el patrocinio. Si Christine Poyer-Rufenacht es pariente de Antoine Rufenacht, esto constituiría un caso de red familiar y política que se reproduce dentro de una institución transatlántica. Como mínimo, la coincidencia patronímica ilustra la estrechez de los círculos en los que se mueven las élites francesas seleccionadas por la FAF. El Havre aparece como un nodo recurrente en estas redes: Philippe, Rufenacht, CMA CGM. Esta conexión merece una investigación exhaustiva. La opacidad de la FAF sobre sus procesos dificulta la verificación.",
    "estelle-youssouffa": "Estelle Youssouffa es actualmente diputada de la primera circunscripción de Mayotte, elegida en 2022. Fue seleccionada como Young Leader 2011 en la misma promoción que Édouard Philippe. Antes de entrar en política, Youssouffa era periodista, en particular para France 24 y Al Jazeera, lo que la inscribe en el pilar mediático del programa. Su trayectoria — del periodismo internacional a la representación parlamentaria — ilustra el camino clásico de los Young Leaders hacia los puestos de poder. Como diputada, ocupa un escaño en la Asamblea Nacional donde el grupo Horizons de Édouard Philippe también tiene representantes, creando posibilidades de alianza parlamentaria entre antiguos miembros de la misma promoción. Mayotte es un territorio enfrentado a grandes desafíos (inmigración, seguridad, desarrollo) que son objeto regular de debates nacionales. La presencia de Youssouffa y Philippe en la misma promoción FAF establece un vínculo entre los retos ultramarinos y la red philippista. El programa Young Leaders ha producido históricamente conexiones duraderas entre sus miembros, que se encuentran luego en puestos de influencia en distintas esferas. Esta dinámica de cohorte es uno de los mecanismos más eficaces de la red. Youssouffa representa el pilar ultramarino y mediático de la promoción 2011.",
    "richard-ferrand": "Richard Ferrand es un político francés, expresidente de la Asamblea Nacional (2018-2022) y exministro de Cohesión de los Territorios en el primer gobierno de Édouard Philippe (mayo-junio 2017). Es Young Leader de la promoción 2005, seis años antes que Philippe. Ferrand fue uno de los primeros apoyos de Emmanuel Macron y cofundador de En Marche en 2016. Como ministro de Philippe y luego presidente de la Asamblea, fue un engranaje esencial del sistema macronista en el que Philippe operaba. Su promoción Young Leader 2005 le inscribe en la misma red transatlántica que Philippe (2011), Macron (2012) y Juppé (1982). El hecho de que el ministro de Cohesión de los Territorios y el Primer Ministro fueran ambos antiguos Young Leaders ilustra la densidad de esta red dentro del gobierno. Ferrand fue imputado en 2019 por conflicto de intereses ilegal en un asunto inmobiliario — las Mutuelles de Bretagne. Se benefició de un sobreseimiento en 2023. Su trayectoria judicial muestra que la pertenencia a la red Young Leaders no protege necesariamente de los procedimientos judiciales. No obstante, la convergencia de Young Leaders en la cúspide del ejecutivo y del legislativo merece un examen crítico.",
    "francois-hollande": "François Hollande, presidente de la República de 2012 a 2017, es Young Leader de la promoción 1996 de la FAF, junto a Pierre Moscovici. Su paso por el programa quince años antes que Philippe ilustra la continuidad de la red a través de las generaciones políticas y las alternaciones. Hollande nombró a Manuel Valls y luego a Bernard Cazeneuve como Primeros Ministros, pero fue su sucesor Macron (Young Leader 2012) quien nombraría a Philippe (Young Leader 2011). La cadena de sucesión presidencial Hollande-Macron es pues una cadena interna a la red Young Leaders. Hollande fue Primer Secretario del PS durante once años (1997-2008) antes de acceder a la presidencia, lo que le permitió estructurar una densa red política. Su promoción 1996 incluía a Pierre Moscovici, futuro comisario europeo y luego presidente del Tribunal de Cuentas, lo que ilustra la diversidad de puestos ocupados por los antiguos Young Leaders. El programa FAF ha producido así dos presidentes de la República (Hollande y Macron), al menos cuatro Primeros Ministros (Juppé, Philippe e indirectamente otros) y numerosos ministros. Esta concentración de poder procedente de un mismo programa de selección plantea interrogantes democráticos sobre la formación de las élites dirigentes francesas. Hollande ha criticado a Philippe en varias ocasiones desde 2017, pero comparten la misma red estructural.",
    "laurent-wauquiez": "Laurent Wauquiez, presidente de la región Auvergne-Rhône-Alpes y expresidente de Les Républicains (2017-2019), es Young Leader de la promoción 2006. Representa el ala derecha de la misma red transatlántica que Édouard Philippe. Ambos hombres se enfrentaron dentro de LR antes de que Philippe se uniera a Macron en 2017. Wauquiez criticó duramente el nombramiento de Philippe en Matignon, calificándolo de traición a la derecha. A pesar de su rivalidad política, comparten el mismo itinerario de formación de élite — ENA para ambos, Young Leaders para ambos. Wauquiez es considerado un posible candidato a la presidencia en 2027, lo que le convertiría en un rival directo de Philippe procedente de la misma red. El hecho de que dos posibles candidatos a la presidencia sean ex Young Leaders ilustra la capacidad del programa para producir a los futuros dirigentes del país, independientemente del bando político. La promoción 2006 de Wauquiez le sitúa entre las generaciones Ferrand (2005) y Philippe (2011) en la cronología de la red. Su trayectoria política — de secretario de Estado con Sarkozy a presidente de región — muestra un recorrido paralelo al de Philippe pero en un registro más derechista. Los seminarios de la FAF permitieron potencialmente a Wauquiez y Philippe cruzarse a través de la red de exalumnos incluso antes de su confrontación política pública.",
    "fleur-pellerin": "Fleur Pellerin fue seleccionada en la promoción 2012 de Young Leaders, el mismo año que Emmanuel Macron. Era entonces ministra delegada de PYME, Innovación y Economía Digital bajo Hollande, antes de convertirse en ministra de Cultura (2014-2016). Su promoción 2012 es inmediatamente posterior a la de Philippe (2011), lo que significa que los seminarios de ambas cohortes se solapaban potencialmente — el segundo seminario de Philippe en 2012 pudo coincidir con el primero de Pellerin y Macron. Pellerin es graduada de la ENA (promoción Senghor, 2000), una escuela que aparece constantemente en los perfiles de Young Leaders. Tras su etapa ministerial, fundó una sociedad de capital riesgo, Korelya Capital, especializada en inversiones en Asia — creando un puente entre las redes transatlánticas (FAF) y asiáticas que recuerda a la France China Foundation. Pellerin nació en Corea del Sur y fue adoptada en Francia, lo que le confiere un perfil bicultural valorado por la FAF. Su trayectoria postministerial hacia el capital riesgo asiático ilustra cómo las conexiones tejidas en las redes de élite se transforman en oportunidades económicas. La promoción 2012, que incluye también a Macron y Cédric Villani, es una de las más políticamente influyentes de la historia del programa.",
    "laphonza-butler": "Laphonza Butler es una política americana nombrada senadora de California en octubre de 2023 por el gobernador Gavin Newsom para sustituir a la senadora Dianne Feinstein. Forma parte de la promoción 2011 de Young Leaders, en el lado americano, junto a Édouard Philippe en el lado francés. Antes del Senado, Butler era presidenta de la SEIU Local 2015, el mayor sindicato de trabajadores sanitarios de California (400.000 miembros). Luego dirigió EMILYs List, la organización demócrata de apoyo a candidatas feministas. Su nombramiento en el Senado ilustra la trayectoria de los Young Leaders americanos hacia las más altas funciones. El hecho de que una senadora americana y un ex Primer Ministro francés hayan sido formados juntos en el mismo programa transatlántico crea un canal de influencia directo entre el Senado americano y la política francesa. Butler compartió con Philippe dos seminarios de cinco días en 2011-2012, forjando vínculos personales duraderos. El programa Young Leaders está concebido precisamente para crear estos puentes entre futuros dirigentes de ambos países. Butler representa el pilar político progresista americano de la promoción 2011. Su presencia ilustra la capacidad de la FAF para identificar futuros líderes mucho antes de que accedan a las funciones más elevadas.",
    "horizons": "Horizons es el partido político fundado por Édouard Philippe el 9 de octubre de 2021 en un mitin público en El Havre, su feudo. El partido se posiciona en el centro-derecha, encarnando el ala derecha de la mayoría presidencial macronista. Sus cuatro temas centrales son la demografía, el medio ambiente, la geopolítica y la tecnología, bajo el lema «Ver lejos para actuar bien». Emmanuel Macron no acogió bien la creación de Horizons por este ex Primer Ministro «leal pero libre». En enero de 2022, el partido se integró en la coalición Ensemble Citoyens. Christian Estrosi, alcalde de Niza, se convirtió en su número dos, aportando un anclaje mediterráneo al partido enraizado en Normandía. Para las legislativas de 2022, Horizons obtuvo 58 investiduras dentro de la coalición y constituyó un grupo parlamentario «Horizons et indépendants» de una treintena de diputados, presidido por Laurent Marcangeli. Tras la disolución de 2024, el partido solo conservó 6 escaños. En marzo de 2026, Horizons reivindicaba 465 alcaldes inscritos en todo el territorio — un tejido local que constituye la columna vertebral de la campaña presidencial 2027 de Philippe. El partido funciona como un vehículo electoral personal: su único objetivo estratégico es llevar a Philippe al Élysée. Los cuadros del partido proceden en gran medida de las redes de Philippe en El Havre y el entorno juppéísta.",
    "christian-estrosi": "Christian Estrosi es alcalde de Niza desde 2008 (con una interrupción entre 2014 y 2017, cuando fue presidente de la región PACA) y el número dos del partido Horizons de Édouard Philippe. Exministro de Industria con Sarkozy (2009-2010) y figura de la derecha provenzal, Estrosi aporta a Horizons un anclaje sureño que complementa el arraigo normando de Philippe. Su adhesión a Horizons en 2021 fue un golpe político mayor: dejó LR para unirse a un partido centrista, arrastrando a una parte de la derecha nicense y azurenense. Niza es la quinta ciudad de Francia y un centro turístico y económico de primer orden, lo que confiere a Estrosi un peso político considerable dentro del partido. Estrosi fue marcado por el atentado de Niza del 14 de julio de 2016 (86 muertos), que gestionó como presidente de la metrópolis — un acontecimiento que forjó su imagen de gestor de crisis. Está casado con Laura Tenoudji, periodista, lo que le garantiza una visibilidad mediática suplementaria. Dentro de Horizons, Estrosi ejerce el papel de reclutador entre los cargos electos de LR tentados por el centro-derecha. Su trayectoria ilustra la estrategia de Philippe: absorber a los cuadros de derechas decepcionados por la evolución de LR hacia la derecha dura. El dúo Philippe (Normandía) / Estrosi (PACA) da a Horizons una base bi-regional que estructurará la campaña presidencial 2027. Estrosi es también vicepresidente de Intercommunalités de France, lo que le proporciona una red territorial complementaria a la de Philippe.",
    "gilles-boyer": "Gilles Boyer es el asesor más cercano de Édouard Philippe desde hace más de veinte años, forjado en la órbita de Juppé. Director de gabinete de Juppé en el ayuntamiento de Burdeos (2002-2004, 2006-2010), luego director de campaña de Juppé en las primarias de 2016 (Philippe era coportavoz). Coautor con Philippe de dos novelas políticas (L'heure de vérité 2007, Dans l'ombre 2011) y de Impressions et lignes claires (2021). Consejero especial de Philippe en Matignon (2017-2019). Hoy eurodiputado de Renaissance. Un sarkozísta les apodó «Plic y Ploc» (Boyer y Philippe), tan inseparable era su tándem. Boyer hace de enlace entre el legado de Juppé y la maquinaria Horizons: es el guardián de la doctrina philippista y el arquetipo del asesor en la sombra que influye en cada orientación política. Círculo interior de la Juppéie.",
    "christophe-castaner": "Christophe Castaner fue nombrado ministro del Interior por Édouard Philippe en octubre de 2018, tras el período de interinidad más largo de la Quinta República en la Place Beauvau después de la dimisión de Gérard Collomb. Su nombramiento se produjo un mes antes del inicio del movimiento de los Chalecos Amarillos, lo que le convirtió en el responsable directo de la doctrina de mantenimiento del orden más contestada desde Mayo del 68. Castaner calificó a los manifestantes de «facciosos que habían venido a matar», legitimando una respuesta de seguridad desproporcionada. Bajo su dirección, el uso de lanzadores de pelotas de defensa (LBD40) se disparó más de un 200% respecto al año anterior. El balance humano fue sin precedentes: 25 personas con un ojo perdido, 5 manos arrancadas, 432 heridos graves. La ONU, el Consejo de Europa y Amnistía Internacional solicitaron la prohibición de estas armas. Castaner ignoró sistemáticamente las denuncias de violencia policial y se negó a suspender el uso de los LBD. Como ministro de Philippe, su doctrina comprometía directamente la responsabilidad del Primer Ministro. La IGPN fue objeto de 313 investigaciones judiciales por sospechas de violencia policial — un récord. Castaner había sido anteriormente delegado general de LREM, lo que ilustra la fusión entre el aparato macronista y el aparato de seguridad bajo el gobierno Philippe.",
    "benoit-ribadeau-dumas": "Benoît Ribadeau-Dumas, primero de la promoción Marc-Bloch de la ENA (1997), condiscípulo de Philippe. Director de gabinete en Matignon (2017-2020) — elegido contra la voluntad de Macron, quien quería imponer a Nicolas Revel. Apodado «El Vaticano» por su rigidez. Miembro de la FCF (promoción inaugural de 2013 con Philippe y Macron). Antes de Matignon: subjefe de gabinete de Sarkozy en el Élysée (2011-2012), secretario general adjunto bajo Hollande — una trayectoria que trasciende las alternaciones políticas. Arquitecto operativo de todas las decisiones del gobierno Philippe: ordenanzas laborales, límite de 80 km/h, Chalecos Amarillos, reforma de las pensiones, Covid. Abogó por el mantenimiento de la primera vuelta de las municipales el 15 de marzo de 2020. Tras Matignon, se incorporó a Exor (family office Elkann/Agnelli), consejero de Stellantis e Iveco. Círculo interior de la Juppéie — el nodo que une la red de la ENA, la FCF y el poder ejecutivo.",
    "france-china-foundation": "La France China Foundation (FCF) es una organización fundada en 2012 para acercar a las élites dirigentes francesas y chinas. Su consejo estratégico incluye a Jean-Pierre Raffarin, Laurent Fabius y Alain Mérieux (arquitecto del laboratorio P4 de Wuhan). Su socio chino oficial es el CPIFA (Chinese People's Institute of Foreign Affairs), vinculado al Ministerio chino de Asuntos Exteriores. La promoción inaugural de 2013 reunió a Philippe, Macron y Ribadeau-Dumas. En 2015, Philippe acogió a la delegación de la FCF en El Havre para una visita al puerto. En mayo de 2018, asistió al gala anual en Versalles como Primer Ministro y ex Young Leader. La opacidad de la FCF es comparable a la de la FAF: sin publicación de órdenes del día, sin informes públicos. La simultaneidad de las redes FAF (transatlántica) y FCF (sino-francesa) alrededor del mismo núcleo — Philippe, Ribadeau-Dumas, Lenain — crea un sistema de influencia bipolar sin precedentes en Matignon. Villepin no figura en ningún espacio de la FCF — su red china es personal y privada, no institucional.",
    "emmanuel-lenain": "Emmanuel Lenain es diplomático de carrera, cofundador de la France China Foundation en 2012 y consejero diplomático de Édouard Philippe en Matignon de 2017 a 2020. Este doble papel — arquitecto de la red sino-francesa y asesor del Primer Ministro — le convierte en el puente humano entre las redes transatlánticas (FAF) y asiáticas (FCF) en el corazón del poder ejecutivo. Antes de Matignon, Lenain ocupó varios puestos diplomáticos estratégicos, en particular en la representación permanente de Francia ante las Naciones Unidas. Tras su paso por Matignon, fue nombrado embajador de Francia en la India (2019-2022), un puesto que le inscribe en el triángulo estratégico Francia-China-India. Su creación de la FCF en 2012, un año después de la selección de Philippe como Young Leader en la FAF, sugiere una estrategia deliberada de construcción de redes de influencia bilateral complementarias. Como consejero diplomático de Philippe, Lenain tenía acceso a todas las negociaciones internacionales del gobierno, incluidas las que involucraban a China y las rutas comerciales marítimas. El Havre, principal puerto francés y feudo de Philippe, está directamente concernido por los retos del comercio sino-francés y la iniciativa Franja y Ruta (Nuevas Rutas de la Seda). La posición de Lenain en la encrucijada de la FCF, Matignon y la diplomacia asiática ilustra cómo un solo individuo puede servir de correa de transmisión entre intereses diplomáticos, económicos y políticos. Su trayectoria tras Matignon — embajada en la India, luego puestos en el Quai d'Orsay — confirma su recorrido dentro del aparato diplomático francés orientado hacia Asia. Lenain es el eslabón perdido que une la red Young Leaders de Philippe con la red sino-francesa.",
    "port-du-havre": "El puerto de El Havre es el principal puerto de contenedores de Francia y el quinto de Europa. Desde 2021 está integrado en el complejo HAROPA (El Havre, Ruan, París), el mayor grupo portuario de Francia. Édouard Philippe es su alcalde desde 2010, lo que le otorga influencia directa sobre la orientación estratégica del puerto y de la comunidad urbana Le Havre Seine Métropole. CMA CGM, la principal naviera francesa, concentra allí una gran parte del tráfico de contenedores, con líneas directas a Shanghái, Ningbo, Shenzhen y los principales puertos asiáticos. El comercio marítimo franco-chino que transita por El Havre representa miles de millones de euros anuales. El puerto también se ve afectado por la iniciativa china Belt and Road, que pretende conectar las infraestructuras portuarias europeas con la red logística china. Según Europol, El Havre es el principal punto de entrada de cocaína en Europa. Las incautaciones de droga se han disparado: 18 toneladas de cocaína confiscadas por las aduanas francesas en 2023, un récord. La seguridad portuaria es responsabilidad compartida del Estado, las aduanas y las autoridades portuarias — un ámbito donde convergen los intereses de CMA CGM (a través de Yann Le Goff, seguridad), el ayuntamiento (Philippe) y las redes de influencia (FAF, FCF). La ampliación del puerto y las inversiones en terminales de contenedores son cuestiones económicas fundamentales para la región, donde Philippe goza de un arraigo político sin igual desde hace quince años. La cuestión de la gobernanza portuaria — quién decide sobre las inversiones, las concesiones, los controles — está en el corazón del nexo Philippe-CMA CGM-FCF.",
    "jean-pierre-raffarin": "Jean-Pierre Raffarin, primer ministro bajo Chirac (2002-2005), es el eje entre las redes chinas de Philippe y Villepin. Acumula un número sin parangón de posiciones chinas: miembro del «consejo de asesores» del Foro de Bo'ao (el Davos asiático), del Belt & Road Forum, consejero de administración de la CEIBS de Shanghái, copresidente de la Sino-International Entrepreneurs Federation, presentador en CGTN (televisión pública china), representante especial del gobierno francés para China (desde 2018), copadrino de la FCF y presidente del Comité France-Chine. El 29 de septiembre de 2019, Xi Jinping le entregó la medalla de la Orden de la Amistad — la distinción china más alta para un extranjero, compartida con Putin y Castro. La DGSI lo convocó a una «entrevista de sensibilización» en el verano de 2018 por su relación con empresarios chinos considerados agentes del Partido. Su Fondation Prospective et Innovation (FPI) tiene un presupuesto de 3,5 millones de euros financiado por una treintena de empresas (Carrefour, Kering, L'Oréal, LVMH) y recibió 85.000 euros del exembajador chino Wu Jianmin. En 2022, Raffarin se unió a Horizons — su doble papel (representante oficial para China Y miembro del partido de Philippe) es sin precedentes. Causeur señala que Raffarin y Villepin siguieron «caminos espejo» en sus reconversiones chinas tras dejar Matignon.",
    "rodolphe-saade": "Rodolphe Saadé es el presidente-director general de CMA CGM desde 2017, sucediendo a su padre Jacques Saadé, fundador del grupo en 1978. Bajo su dirección, CMA CGM se ha convertido en la tercera naviera mundial con una facturación que superó los 70.000 millones de euros en 2022. Saadé ha diversificado el grupo más allá del transporte marítimo: adquisición de CEVA Logistics (logística), compra de La Tribune y La Provence (medios), inversiones tecnológicas. El grupo Saadé es de origen libanés, con sede en Marsella, y mantiene importantes vínculos comerciales con China — las rutas Asia-Europa son el núcleo de la actividad de CMA CGM. El puerto de El Havre, feudo de Édouard Philippe, es uno de los principales centros europeos de CMA CGM. Yann Le Goff, responsable de seguridad de CMA CGM y Young Leader 2011 con Philippe, opera directamente bajo la autoridad de la dirección Saadé. La fortuna de Rodolphe Saadé se estima en más de 40.000 millones de euros, lo que le convierte en una de las mayores fortunas de Francia. Su expansión en los medios (La Tribune, La Provence, BFM Marseille) le otorga influencia mediática además de su peso económico. CMA CGM es un actor central de la iniciativa china Belt and Road, con asociaciones portuarias en el Mediterráneo, África y el sudeste asiático. La convergencia entre el imperio Saadé, el puerto de El Havre de Philippe y las redes FCF de Ribadeau-Dumas constituye un nexo de intereses económicos y políticos de considerable magnitud.",
    "belt-and-road": "La iniciativa Belt and Road (BRI), lanzada por Xi Jinping en 2013, es el mayor programa de infraestructuras de la historia, con inversiones estimadas en más de un billón de dólares a través de Asia, África y Europa. El componente marítimo de la BRI — la «Ruta de la Seda Marítima del siglo XXI» — pretende conectar los puertos chinos con los europeos mediante inversiones en terminales, logística y concesiones portuarias. En Europa, China ha invertido en los puertos del Pireo (Grecia, a través de COSCO), Hamburgo, Amberes y Valencia. El puerto de El Havre, el principal puerto de contenedores de Francia y feudo de Édouard Philippe, está directamente afectado por esta estrategia. CMA CGM, cuyas rutas Asia-Europa son el núcleo de su actividad, es a la vez competidora y socia potencial de las navieras chinas COSCO y OOCL. La France China Foundation, cuyo miembro Ribadeau-Dumas actuó como jefe de gabinete de Philippe en Matignon, opera en este espacio donde la diplomacia económica china busca establecer puntos de influencia entre los decisores europeos. La BRI ha sido criticada como instrumento de «diplomacia de la deuda» e influencia geopolítica china. El hecho de que el primer ministro francés estuviera rodeado en Matignon de personas insertadas en las redes sino-francesas (FCF) mientras era alcalde del principal puerto francés en la ruta marítima china crea una convergencia de intereses sin precedentes. Italia firmó un memorando BRI en 2019 antes de retirarse en 2023 — Francia, bajo Philippe, nunca lo firmó pero mantuvo una posición ambigua. La cuestión de la soberanía portuaria frente a las inversiones chinas es un problema estratégico que afecta directamente a El Havre.",
    "cosco-shipping": "COSCO Shipping es la principal naviera china y la cuarta del mundo, perteneciente al Estado chino a través de la SASAC (Comisión de Supervisión y Administración de Activos Estatales). COSCO opera más de 1.300 buques y da servicio a más de 300 puertos en todo el mundo. En Europa, COSCO adquirió el 67 % del puerto del Pireo en Grecia (2016), ilustrando la estrategia china de toma de control de infraestructuras portuarias estratégicas. COSCO y CMA CGM son a la vez competidores y socios dentro de la alianza marítima Ocean Alliance, que cubre las rutas Asia-Europa — las mismas rutas que transitan por El Havre. Esta alianza significa que los contenedores de CMA CGM y COSCO comparten los mismos buques y terminales, incluidos los de El Havre. La presencia de COSCO en los puertos europeos ha suscitado preocupaciones en materia de seguridad nacional y soberanía. Alemania bloqueó en 2022 la participación de COSCO en el terminal de Hamburgo por encima del 24,9 %. La pregunta se plantea para El Havre: ¿en qué medida afectan las inversiones chinas en los puertos competidores a la estrategia del principal puerto francés? La France China Foundation, cuyos miembros rodean a Philippe en Matignon, opera precisamente en este espacio de diplomacia portuaria sino-europea. La interconexión entre Ocean Alliance (COSCO + CMA CGM), las redes FCF y la alcaldía de Philippe en El Havre constituye un entramado de intereses que merece un examen riguroso. COSCO es un instrumento de la política china Belt and Road en el ámbito marítimo.",
    "comite-france-chine": "El Comité France-Chine, adscrito al MEDEF Internacional, es el principal órgano de presión del empresariado francés ante China. Presidido por Jean-Pierre Raffarin, funciona en sinergia con la France China Foundation: el Comité opera a nivel empresarial, la FCF a nivel individual. La presencia de Raffarin al frente del Comité y como padrino de la FCF crea un puente entre la diplomacia económica oficial y las redes de influencia informales. Entre sus miembros figuran grupos del CAC 40 activos en China: Airbus, Total, L'Oréal, Sanofi, y actores portuarios y logísticos. Ribadeau-Dumas (jefe de gabinete de Philippe, FCF 2013) y Lenain (cofundador de la FCF, consejero diplomático) han evolucionado ambos en este ecosistema.",
    "alexis-kohler": "Alexis Kohler (nacido en 1972 en Estrasburgo) es énarque, director de gabinete en el Ministerio de Economía bajo Macron (2014) y posteriormente secretario general del Élysée (2017-2025) — el brazo derecho de Emmanuel Macron durante ocho años. En marzo de 2022, fue imputado por toma ilegal de intereses, tráfico de influencias y corrupción pasiva, por sus conflictos de intereses con MSC (Mediterranean Shipping Company), fundada por la familia Aponte — primos de su madre. De 2010 a 2012, Kohler integró el consejo de supervisión del Grand Port Maritime du Havre (GPMH) como representante de la Agence des participations de l'État, junto a Édouard Philippe (alcalde desde octubre de 2010). Según Mediapart, Kohler jamás declaró sus vínculos familiares con MSC y no se abstuvo en las votaciones relativas a MSC, mientras que Philippe respetaba escrupulosamente las normas de abstención. Kohler funciona como agente pivote: Inspección de Finanzas → APE/GPMH (junto a Philippe) → gabinete Macron (Bercy) → MSC (puerta giratoria) → Élysée (SG) → Société Générale (2025). Este circuito ilustra el mecanismo de rendimientos crecientes de la agenda de contactos. El puerto de Le Havre, donde Kohler y Philippe trabajaron juntos, es un nodo geoestratégico: hub de CMA CGM (3.er armador mundial), cliente de MSC (2.o armador, familia de Kohler), vinculado a COSCO Shipping (1.er armador chino, hermanamiento Dalian), bajo la gobernanza política de Philippe. En 2025, Kohler dejó el Élysée para incorporarse a Société Générale, continuando el circuito de puerta giratoria entre el Estado y las finanzas.",
    "sibyle-veil": "Sibyle Veil es presidenta de Radio France desde abril de 2018, nombrada por el CSA (ahora Arcom), cuyos miembros están influenciados por el ejecutivo. Procede de la promoción Leopold Sedar Senghor de la ENA (2004), la misma que Emmanuel Macron. Esta camaradería de promoción — uno de los vínculos más sólidos en la alta función pública francesa — conecta directamente la presidencia de la principal radio pública con el presidente de la República. Bajo su dirección, France Inter ha seguido siendo la radio más escuchada de Francia con su matinal política. Las entrevistas de Édouard Philippe en France Inter se caracterizan por un tono favorable y la ausencia sistemática de preguntas sobre expedientes sensibles: lazos con CMA CGM, la France China Foundation, el asunto Atos. Veil fue renovada en 2022, confirmando la confianza del ejecutivo macronista. Antes de Radio France, fue consejera en el Conseil d'État y había trabajado en la Cour des comptes. Su trayectoria — ENA → Conseil d'État → dirección de un medio público — es un arquetipo del sistema francés en el que las mismas promociones controlan el poder ejecutivo y el mediático. La cadena Macron (presidente) → Arcom (nombramiento) → Veil (dirección) → France Inter (línea editorial) ilustra el control indirecto de la audiovisual pública. Radio France llega a unos 15 millones de oyentes diarios.",
    "bernard-arnault": "Bernard Arnault es el presidente-director general de LVMH, la primera fortuna mundial con un patrimonio estimado en más de 200.000 millones de euros. Es propietario del grupo Les Échos-Le Parisien, que incluye el diario económico Les Échos, cuyo director David Barroux es Young Leader 2011 junto con Édouard Philippe. Arnault está considerado el aliado oligárquico más cercano de Emmanuel Macron, con quien mantiene relaciones personales documentadas. LVMH es el primer anunciante publicitario de Francia, lo que le confiere una influencia indirecta sobre todos los medios franceses. La cobertura de Les Échos es sistemáticamente favorable a las reformas económicas promovidas por Philippe (ordenanzas laborales, ley PACTE). Le Parisien, el diario popular más leído en Île-de-France, completa el dispositivo mediático llegando a un público más amplio. Arnault ha inaugurado varios proyectos arquitectónicos junto con Macron y Philippe. La convergencia entre la primera fortuna mundial, el presidente que nombró a Philippe y el director Young Leader forman un triángulo de poder-dinero-media. LVMH tiene importantes intereses comerciales en China, lo que conecta a Arnault con la red sino-francesa a través de canales distintos a los de la FCF. El hecho de que el propietario del principal medio económico de Francia sea también el principal apoyo financiero del presidente que nombró a Philippe crea un conflicto de intereses mediático estructural.",
    "vincent-bollore": "Vincent Bolloré es un industrial bretón que construyó un imperio mediático a través de Vivendi: Canal+, CNews, C8, Europe 1, Paris Match, Le Journal du Dimanche. Su adquisición progresiva de estos medios a partir de 2015 fue acompañada de una reorientación editorial hacia la derecha y la extrema derecha, con figuras como Eric Zemmour, Pascal Praud y Laurence Ferrari. CNews se convirtió en la «Fox News francesa». En el juego político, Bolloré es un «hacedor de reyes»: su cadena permitió el ascenso mediático de Zemmour como candidato presidencial en 2022. Para Philippe, CNews juega un papel paradójico: la cadena lo presentó como la alternativa «razonable» frente al RN, sirviendo al relato macronista del dique republicano. Europe 1, bajo el control de Bolloré a través de Lagardère, fue reorientada hacia una línea compatible con el centro-derecha de Philippe. Bolloré también tiene intereses masivos en África (Bolloré Africa Logistics, puertos) y Asia, lo que lo conecta con las cuestiones del transporte marítimo y las redes sino-africanas. Su imperio logístico africano fue vendido a CMA CGM (MSC) en 2022, creando un vínculo directo entre Bolloré y el grupo Saadé. La concentración mediática entre Arnault (Les Échos, Le Parisien), Bolloré (CNews, Europe 1) y Saadé/CMA CGM (BFM TV) significa que los tres principales medios informativos de Francia están en manos de oligarcas próximos al poder macronista.",
    "patrick-drahi": "Patrick Drahi es un empresario franco-israelí, fundador de Altice, que poseyó BFM TV, RMC y Libération hasta la venta de sus activos mediáticos a CMA CGM (Rodolphe Saadé) en 2024. Esta operación es crucial en la cadena de conflictos de intereses: BFM TV, el principal medio informativo en continuo de Francia, pasó de manos de un propietario rodeado de controversias financieras (el endeudamiento masivo de Altice) a CMA CGM, la principal naviera que opera en el puerto del feudo de Édouard Philippe. Drahi ya había sido criticado por su influencia en la línea editorial de BFM. El traspaso a CMA CGM agrava el conflicto: el operador portuario de El Havre posee ahora el medio que cubre al alcalde-candidato de El Havre. Drahi también es propietario de HOT en Israel y de Sotheby's. Su imperio se construyó sobre un endeudamiento masivo (más de 60.000 millones de euros en su pico), un modelo financiero que ha suscitado investigaciones fiscales en varios países. La venta a Saadé ilustra la concentración mediática en curso en Francia: los medios informativos pasan de las manos de un multimillonario endeudado a las de un armador multimillonario vinculado a las rutas comerciales chinas. La cadena Drahi → BFM → CMA CGM → El Havre → Philippe es un recorrido de conflicto de intereses construido mediante adquisiciones sucesivas.",
    "pierre-moscovici": "Pierre Moscovici es presidente del Tribunal de Cuentas desde junio de 2020. Young Leader 1996 (misma promoción que Hollande). Antiguo ministro de Economía y luego comisario europeo. El hecho de que el máximo contralor de las cuentas públicas y el exprimero ministro provengan de la misma red de Young Leaders plantea interrogantes sobre la independencia del control.",
    "dominique-de-villepin": "Dominique de Villepin, primer ministro bajo Chirac (2005-2007), opera una red privada, multipolar y opaca. Ninguna relación directa documentada lo vincula a Philippe — sus redes convergen a través de Juppé y las conexiones chinas. Villepin se incorporó al «groupe J» (fieles de Juppé) en 1979, luego fue nombrado director de gabinete en el Quai d'Orsay por Juppé en 1993. Desde 2008: unas 50 conferencias remuneradas en China (94.000 euros por dos según Radio France), presidencia de la IMTA (organismo chino), sociedades en Hong Kong (cuentas no presentadas desde 2015), proximidad a Xi Jinping. Red multipolar más allá de China: amigo de la familia Al-Thani (Qatar), cargo en la Autoridad de Museos de Qatar, tribuna compartida con Putin en Valdaï (2014), 800.000 euros/año del grupo saudí Bugshan a través de una sociedad panameña ligada a Djouhri (2008-2010), contrato Veolia de 17 años a través de Proglio, actividades en Irán, Venezuela, Armenia, Azerbaiyán. Ayuda a empresas chinas en África y Europa, a veces en competencia con empresas francesas. Sondeos de mayo de 2025: Villepin 51 %, Philippe 50 %. Seduce a la izquierda (65 % LFI), Philippe al centro-derecha. Rival directo para 2027.",
    "villepin-international": "Villepin International es la sociedad de consultoría de Dominique de Villepin, creada tras su salida de Matignon. Sus cuentas no se han presentado desde 2015 — ese mismo año se crearon dos sociedades en Hong Kong, y luego una tercera (Villepin Group Limited), con importantes flujos financieros. La investigación de la unidad de periodismo de investigación de Radio France (diciembre de 2025) revela el alcance de las actividades chinas que transitan por estas estructuras. El destino y los beneficiarios de los flujos financieros siguen siendo grandes zonas de sombra. La opacidad financiera contrasta con la red institucional y relativamente transparente de Philippe a través de la FCF.",
    "alexandre-djouhri": "Alexandre Djouhri es un intermediario condenado en septiembre de 2025 a seis años de prisión en el caso de las financiaciones libias. La investigación de Radio France revela que Villepin realizó desplazamientos al extranjero en su compañía. En el foro de San Petersburgo, los dos hombres se registraron como «vicepresidentes» de Veolia — un registro desmentido por la dirección del grupo. Ningún vínculo comparable está documentado en el caso de Philippe. Djouhri es un nodo oscuro específico de la red Villepin, que conecta al exprimero ministro con los círculos empresariales más controvertidos (Rusia, Golfo, Libia).",
    "henri-proglio": "Henri Proglio es el expresidente de Veolia Environnement (2003-2009) y luego de EDF (2009-2014). Según las investigaciones, Villepin está bajo contrato con Veolia desde hace 17 años a través de Proglio. Este vínculo explica el episodio del foro de San Petersburgo en el que Villepin y Djouhri se registraron como «vicepresidentes» de Veolia. Proglio es una figura del capitalismo francés que ha navegado entre los sectores público y privado. Su papel como punto de contacto entre Villepin y el mundo empresarial constituye una pista de profundización identificada en el informe.",
    "imta": "La International Mountain Tourism Alliance (IMTA) es un organismo chino del que Villepin es el presidente. Esta presidencia se inscribe en la red de funciones oficiales y semiofficiales que Villepin ha acumulado en China desde 2008: presidencia de asociaciones de derecho chino, integración en comités ejecutivos de fondos de inversión. La IMTA ilustra el arraigo institucional chino de Villepin — una legitimidad obtenida desde arriba, directamente ante el poder central, a diferencia del camino FCF de Philippe, que pasa por estructuras franco-chinas encuadradas.",
    "alain-merieux": "Alain Mérieux es el industrial lionés fundador de bioMérieux, líder mundial en diagnóstico in vitro. Es el arquitecto del laboratorio de alta seguridad P4 de Wuhan, inaugurado en 2018 — un proyecto de cooperación franco-china lanzado bajo la presidencia Chirac. Mérieux es miembro del Consejo estratégico de la FCF junto a Raffarin y Fabius. Su presencia en el corazón del dispositivo FCF establece un vínculo entre la diplomacia sanitaria franco-china (el P4 de Wuhan) y las redes de influencia en las que se inscribe Philippe. La cuestión del laboratorio P4 se ha vuelto geopolíticamente sensible desde 2020 y la pandemia de Covid-19.",
    "laurent-fabius": "Laurent Fabius, exprimero ministro (1984-1986) y presidente del Consejo Constitucional desde 2016, es copadrino de la France China Foundation con Raffarin. Antiguo ministro de Asuntos Exteriores con Hollande (2012-2016), contribuyó a estructurar la diplomacia sino-francesa. Su presencia en el Consejo estratégico de la FCF junto a Raffarin y Mérieux trasciende las divisiones izquierda-derecha e ilustra el consenso de las élites francesas en torno al acercamiento a Pekín. Fabius valida la constitucionalidad de las leyes — incluidas las del gobierno Philippe.",
    "hubert-vedrine": "Hubert Védrine, ex secretario general del Élysée con Mitterrand y luego ministro de Asuntos Exteriores (1997-2002), es miembro del Consejo estratégico de la FCF. Teórico de la política exterior francesa e inventor del concepto de «hiperpotencia» americana, representa la continuidad de la tradición diplomática francesa de independencia respecto a los Estados Unidos — la misma tradición que empujó a los herederos de Chirac hacia China.",
    "jacques-chirac": "Jacques Chirac (1932-2019), presidente de la República (1995-2007), es la fuente común de todo el ecosistema. Su política de independencia frente a los Estados Unidos y su diálogo privilegiado con Pekín produjeron una tradición de relaciones sino-francesas de la que Philippe y Villepin son herederos por canales distintos. Una encuesta JDD/Ifop de 2019 clasificaba a Juppé como el primer heredero de Chirac (62 %), Villepin en tercero, preguntándose si «el último bastión del chiraquismo no está en Matignon, con Édouard Philippe». Villepin era uno de los «hijos preferidos» de Chirac (La Libre). Chirac → Juppé → Philippe y Chirac → Villepin son las dos ramas de este árbol político.",
    "cpifa": "El CPIFA (Chinese People's Institute of Foreign Affairs) es el socio chino oficial de la France China Foundation. Vinculado al Ministerio de Asuntos Exteriores chino, constituye el interlocutor institucional de la red sino-francesa de Philippe y Raffarin. El CPIFA es la interfaz entre el poder blando francés (FCF) y el aparato diplomático chino. Esta conexión distingue la red Philippe/Raffarin (institucional, encuadrada) de la red Villepin (privada, acceso directo al poder central vía Xi Jinping).",
    "charles-hufnagel": "Charles Hufnagel es el asesor de comunicación de Juppé, con quien se cruzó en Areva en los años 2000. Fue portavoz de Philippe en Matignon. Los periodistas políticos lo consideran «mucho más fiable» que su homólogo del Élysée (Le Temps). Encarna la continuidad comunicacional de la Juppéie: la misma doctrina de discreción y sobriedad mediática que marcó las campañas de Juppé y el paso de Philippe por Matignon. Primer círculo de la Juppéie.",
    "benoist-apparu": "Benoist Apparu, ex secretario de Estado de Vivienda con Sarkozy, fue coportavoz de la campaña Juppé 2016 junto a Philippe. Tras la derrota de Juppé en las primarias, se integró en el equipo de campaña de Fillon. Su trayectoria ilustra la dispersión de los juppéístas tras noviembre de 2016 — una parte se unió a Macron (Boyer, Philippe), otra permaneció en la órbita LR. Primer círculo de la Juppéie.",
    "anne-clerc": "Anne Clerc es directora de gabinete en Matignon bajo Philippe. Antigua miembro del equipo de Raffarin en Matignon — lo que la convierte en el puente humano entre los dos gabinetes de primeros ministros chiraquianos. Su presencia en el gabinete Philippe ilustra la continuidad de la Juppéie dentro del aparato del Estado: las mismas redes se transmiten de un Matignon a otro.",
    "xavier-chinaud": "Xavier Chinaud es consejero de relaciones con los electos en Matignon bajo Philippe. Antiguo responsable de «estudios políticos» en Matignon bajo Raffarin. Al igual que Anne Clerc, es un eslabón entre los gabinetes Raffarin y Philippe, asegurando la transmisión de prácticas y redes entre los dos Matignons chiraquianos.",
    "christophe-bechu": "Christophe Béchu es secretario general del partido Horizons, exministro de la Transición Ecológica (2022-2024) y alcalde de Angers. Su papel dentro de Horizons es estructurante: asegura la organización territorial del partido y sirve de enlace entre el aparato philippista y los electos locales. El eje Philippe (Normandía) / Béchu (Loire) / Estrosi (PACA) otorga a Horizons una base multirregional de cara a 2027. Tercer círculo de la Juppéie — aliado institucional.",
    "nathalie-loiseau": "Nathalie Loiseau, eurodiputada de Renaissance y exministra de Asuntos Europeos (2017-2019), está próxima a los círculos juppéistas. Exdirectora de la ENA, representa el vínculo europeo de la Juppéie. Tras la derrota de Juppé en las primarias, forma parte del grupo de los «marchadores» — los juppéistas que se sumaron a Macron. Tercer círculo de la Juppéie.",
    "virginie-calmels": "Virginie Calmels, exteniente de alcalde de Juppé en el ayuntamiento de Burdeos, representa la rama «neoderechista» de la Juppéie — la que se alejó de Philippe para unirse a Laurent Wauquiez a través del movimiento DroiteLib. Su trayectoria ilustra la fragmentación de la Juppéie tras la derrota de 2016: si bien la mayoría de los juppéistas se unió a Macron, una minoría optó por la deriva derechista de LR. Exdirectora de Endemol France, encarna el perfil de político-directivo valorado por Juppé.",
    "julien-miro": "Julien Miro es uno de los organizadores de la red de los «bébés Juppé» — una treintena de treintañeros, veteranos de la campaña de las primarias de 2016, estructurados en una red informal tras la derrota. Con Guillaume Pfister, organiza cenas bimestrales con personalidades afines (Boyer, Gaymard, Keller, Bournazel). De forma reveladora, Miro declaró: «Alain Juppé perdió, pero los juppéistas ganaron: están en todas partes en los gabinetes ministeriales». Asesores en Matignon, en el Quai d'Orsay, en los ministerios de Economía, Transición Ecológica y Cultura — los bébés Juppé estaban al frente de las reformas macronistas. Segundo círculo de la Juppéie.",
    "guillaume-pfister": "Guillaume Pfister es el coorganizador, junto con Julien Miro, de la red informal de los «bébés Juppé». Su objetivo declarado: «mantener viva la llama juppéista» y «preparar el post-Juppé». Las cenas reúnen a personalidades próximas a Juppé (Boyer, Gaymard, Keller, Bournazel) y a jóvenes asesores diseminados en los gabinetes ministeriales. Esta red constituye el vivero de cuadros de Horizons. Segundo círculo de la Juppéie.",
    "fpi-raffarin": "La FPI es la fundación de Raffarin, reconfigurada para servir de vehículo para las relaciones franco-chinas. Presupuesto de 3,5 M€ financiado por unas treinta empresas (Carrefour, Kering, L'Oréal, LVMH) a 15.000 €/año cada una. La fundación recibió donaciones de personalidades chinas, incluidos 85.000 € del exembajador Wu Jianmin. La FPI opera en la intersección entre el think tank y la red de influencia, proporcionando a Raffarin una infraestructura institucional para sus actividades chinas. Es un canal paralelo a la FCF — uno (FPI) es el vehículo personal de Raffarin, el otro (FCF) es la estructura colectiva.",
    "groupe-bugshan": "El grupo Bugshan es un conglomerado saudí que pagó 800.000 €/año a Villepin entre 2008 y 2010, a través de una sociedad panameña vinculada a Alexandre Djouhri. Estos flujos financieros, revelados por una investigación de Radio France, ilustran la opacidad de la red de negocios de Villepin. El dinero transitó por una estructura offshore, lo que dificulta rastrear a los beneficiarios. El vínculo Bugshan-Djouhri-Villepin es uno de los nodos más opacos de la red.",
    "sebastien-lecornu": "Sébastien Lecornu, primer ministro en ejercicio, mantiene una relación de competencia-cooperación con Philippe. Antiguo seguidor de LeMaire que se unió al equipo Fillon con los juppéistas tras las primarias de 2016. Su trayectoria se cruza con la de la Juppéie sin fusionarse con ella. Normando como Philippe (Évreux), representa un rival potencial dentro de la mayoría por la influencia sobre la derecha moderada.",
    "plastic-omnium": "Plastic Omnium es un proveedor automovilístico francés cuyo consejo de administración ha contado con Raffarin. El grupo genera una parte significativa de su facturación en China, lo que lo convierte en un beneficiario directo de las redes francosinesas facilitadas por Raffarin. Su presencia en el ecosistema Raffarin ilustra el mecanismo de valorización de la agenda de contactos: las empresas con intereses en China financian la FPI (15.000 €/año) y se benefician a cambio del acceso al mercado chino facilitado por el «señor China» de la política francesa.",
    "laurent-marcangeli": "Laurent Marcangeli preside el grupo parlamentario «Horizons et indépendants» en la Asamblea Nacional. Es el relevo legislativo de Philippe: coordina las posiciones del grupo sobre los textos legislativos y garantiza la cohesión de los diputados philippistas. Tras la disolución de 2024, el grupo pasó de treinta diputados a seis — un derrumbe que ilustra la fragilidad de la base parlamentaria de Horizons.",
    "jacques-attali": "Jacques Attali (nacido en 1943) es politécnico y énarque (promoción Robespierre, 1970). Exauditor en el Conseil d'État, consejero especial de François Mitterrand durante diez años (1981-1991), fundador y primer presidente del BERD (1991-1993), presidente de la Comisión para la liberación del crecimiento francés (2007-2010). Como agente facilitador, Attali diseñó el dúo Macron-Philippe: en 2007, eligió al joven Macron como ponente adjunto de su Comisión. En 2011, presentó a Macron ante Hollande. En marzo de 2017, sugirió a Macron que eligiera a Philippe como Primer Ministro y organizó su encuentro. Esta cadena Attali → Macron → Philippe es el mecanismo fundacional del gobierno Philippe (2017-2020). Attali es cofundador del Consejo Estratégico de la France China Foundation (2013), donde ocupa un asiento junto a Philippe, Raffarin, Fabius, Mérieux y de Castries — una convergencia única de cinco niveles de poder. Abandonó la FCF en marzo de 2020, en la fecha de llegada de la pandemia. En un sistema multiagente, Attali no posee un centroide propio, sino que funciona como nodo de conexión que maximiza la influencia indirecta enlazando centroides entre sí. Su valor reside en la red, no en el poder formal, lo que le permite atravesar los cambios de gobierno sin daño — un presidente puede cambiar, un Primer Ministro puede caer, Attali permanece.",
    "alain-minc": "Alain Minc (nacido en 1954) es énarque (promoción Léon Blum, 1975, primero de su promoción), inspector general de finanzas. Expresidente del consejo de supervisión de Le Monde, presidente de AM Conseil, presidente del consejo de administración de la Sanef, tesorero de la Fondation Saint-Simon, miembro del Siècle. Un tercio de los grandes presidentes ejecutivos del CAC 40 han remunerado sus servicios (Bolloré, Bouygues, Vinci, Club Med, Suez). Como agente facilitador, Minc opera desde la derecha francesa (Balladur, Sarkozy, Juppé) mientras que su complementario Attali opera desde la izquierda (Mitterrand, Hollande) — una simetría que les permite cubrir todo el espectro político. Minc apoyó a Juppé en la primaria de 2016 y luego se pasó a Macron en 2017 (transferencia idéntica a la de los propios juppéistas). Mantiene un canal indirecto con Philippe a través de Gilles Boyer (asesor en Matignon), documentado por el JDD en relación con la retención en la fuente (2018). Macron disponía de dos mentores al salir de la ENA: Minc y Attali, lo que confirma el modelo de facilitador en tándem. Minc fue antiguo Young Leader de la FAF, formando así una cadena de cuatro décadas: Minc (YL) → Juppé (YL 1982) → Philippe (YL 2011) → Macron (YL 2012). Como Attali, Minc maximiza su influencia indirecta permaneciendo invisible a los ojos del público. Sin responsabilidad electoral, sin poder formal, pero con una capacidad de conexión incomparable.",
    "commission-attali": "Encargada por Sarkozy, presidida por Attali, con Macron como ponente general adjunto. Entre las 316 medidas: la liberalización de los VTC, que conduce a la ley Novelli (2009) y luego al «acuerdo Uber-Macron» (2014-2016). Punto de origen de la cadena de desregulación: Comisión → Uber → Macron → Philippe.",
    "msc-aponte": "Fundada por la familia Aponte, primos de la madre de Alexis Kohler. Segunda naviera mundial, explota una terminal de contenedores en el puerto de El Havre. Kohler nunca declaró sus vínculos familiares con MSC durante su mandato en el GPMH. En el centro de la imputación de Kohler por toma ilegal de intereses.",
    "rodolphe-saade-cma-cgm": "CEO de CMA CGM (3.ª naviera mundial), propietario de BFM TV y RMC desde la compra de Altice Media (2023). CMA CGM explota terminales en el puerto de El Havre, feudo de Philippe. Adquirió Bolloré Transport & Logistics (2024). Un nodo triple: económico (transporte marítimo), mediático (BFM/RMC) y político (socio portuario del alcalde de El Havre).",
    "gpmh": "Principal puerto de Francia, nodo de convergencia de la red. Kohler y Philippe formaron parte juntos del consejo de supervisión (2010-2012). Hub de CMA CGM y cliente de MSC. Hermanado con Dalian (China). Vinculado a COSCO Shipping (1.ª naviera china). Punto geográfico donde convergen el poder político, financiero, mediático y geoestratégico.",
    "uber-files": "124.000 documentos internos de Uber filtrados a la ICIJ. Revelan 17 intercambios entre Uber y el gabinete Macron, 4 reuniones entre Macron y Kalanick, un acuerdo oculto (Uber abandona UberPop, el Estado reduce la formación VTC de 250h a 7h) y enmiendas redactadas por Uber transmitidas a diputados. Comisión de investigación parlamentaria (2023): sin conflicto de intereses pero «relaciones privilegiadas» confirmadas.",
    "henri-de-castries": "Un nodo único del sistema: preside el comité directivo de Bilderberg desde 2012, forma parte del Conseil stratégique de la FCF junto a Attali, Raffarin y Philippe, y fue condiscípulo de Villepin en la ENA (promoción Voltaire, 1980). Expresidente y CEO de AXA (2000-2016), presidente del Institut Montaigne, triple Young Leader FAF (1994, 1995, 1998). Puente único entre la red transatlántica (Bilderberg, FAF) y la red francosinesa (FCF).",
    "gabriel-attal": "Primer ministro (enero-septiembre 2024), el PM más joven de la Quinta República. Invitado al Bilderberg de Lisboa (2023) siendo ministro de Cuentas Públicas, nombrado PM siete meses después. Presente en Estocolmo (2025) junto a Philippe — primera vez que dos exprimer ministros macronistas participan juntos. Patrón recurrente: Macron (Bilderberg 2014 → ministro 2 meses después), Philippe (2016 → PM 11 meses después), Attal (2023 → PM 7 meses después).",
    "patricia-barbizet": "Miembro del comité directivo permanente del Bilderberg — segunda representante francesa permanente tras de Castries. Expresidenta del Siècle, ex directora general de la holding Artémis (Pinault). Presente en el Bilderberg 2023 en Lisboa. Conecta el Bilderberg con el Siècle, donde también son miembros Attali y Minc.",
    "institut-montaigne": "Think tank liberal presidido por Henri de Castries, financiado por AXA, Engie, BNP Paribas, LVMH y TotalEnergies. Referencia intelectual de la campaña Macron 2017: su director Laurent Bigorgne había facilitado la dirección de campaña de LREM. Vehículo de producción doctrinal para el programa Horizons 2027.",
    "blackrock": "Primer gestor de activos mundial, fundado por Larry Fink. Posee participaciones en al menos 18 empresas del CAC 40, incluidas AXA (de Castries), BNP (Lemierre, Bilderberg 2025), TotalEnergies (Pouyanné, Bilderberg), Société Générale (Kohler 2025). Aliado de MSC en la adquisición de 43 puertos mundiales por 22.800 millones de dólares (2025). Philippe propone un 15% de capitalización de las pensiones en 2027 — precisamente el objetivo de BlackRock en Francia.",
    "jean-francois-cirelli": "ENA (promoción Léonard de Vinci, 1985), exconsejero de Chirac, director adjunto del gabinete de Raffarin (2002-2004), artífice de la reforma de las pensiones Fillon 2003. CEO de Gaz de France, número 2 de Engie. Presidente de BlackRock Francia desde 2015. Invitado por Philippe al Comité Action Publique 2022 (2018). Nombrado oficial de la Légion d'honneur por Philippe el 31 de diciembre de 2019, en plena huelga histórica de las pensiones.",
    "marc-ferracci": "Economista, licenciado en HEC, doctor en ciencias económicas. Conoció a Macron a los 22 años en Sciences Po. Testigo de boda de Macron. Su padre Pierre Ferracci formó parte de la Comisión Attali (2007), donde Macron era ponente. Diputado de Renaissance, exministro de Industria. Patrimonio declarado: 23 millones de euros. Firmante del manifiesto \"Pour la France, construisons l'union !\" (29 de marzo de 2026). Agente puente entre el ecosistema Macron y la coalición Philippe.",
    "philippe-tabarot": "Ministro de Transportes desde diciembre de 2024. Supervisa los puertos marítimos franceses, incluido el GPMH (nodo Philippe/Kohler/MSC/CMA CGM). Exvicepresidente regional de PACA junto a Estrosi (Horizons). Senador de LR. Investigado por el PNF por malversación de fondos públicos y toma ilegal de intereses. El puesto de ministro de Transportes es un nodo recurrente: a Djebbari (YL FCF 2020) la HATVP le prohibió incorporarse a CMA CGM.",
    "maud-bregeon": "Portavoz del gobierno Lecornu, ministra delegada. Firmante del manifiesto \"Pour la France, construisons l'union !\" (29 de marzo de 2026). Declaró en LCI que Philippe \"ha tomado una seria opción, siendo potencialmente el mejor posicionado para librar esta batalla\". Establece el vínculo explícito entre el gobierno actual y la candidatura de Philippe en 2027.",
    "jean-paul-delevoye": "Alto Comisionado para las Pensiones en el gobierno Philippe, responsable del sistema universal de puntos. Se reunió con BlackRock en marzo de 2018, tres meses después de su nombramiento. Dimitió el 16 de diciembre de 2019 por 13 mandatos no declarados a la HATVP. La reforma que preparaba se sospecha que allana el camino a la capitalización en beneficio de BlackRock. El recurso al 49.3 en febrero de 2020 y la pandemia congelaron la reforma indefinidamente.",
    "elabe-bfmtv": "Sondeo de Elabe para BFMTV (propiedad de CMA CGM/Saadé) del 28 de marzo de 2026, que sitúa a Philippe entre el 20,5 % y el 25,5 % en primera vuelta. La agregación bayesiana independiente de moipresident.online le da un 17 %, es decir, entre 3,5 y 8,5 puntos menos. El resultado del 51,5 % frente a Bardella en segunda vuelta está dentro del margen de error. El cliente (BFMTV/CMA CGM) comparte un interés con el candidato (puerto de Le Havre).",
    "patrick-pouyanné": "CEO de TotalEnergies, participante habitual del Bilderberg (2023, 2025) junto a Philippe. TotalEnergies es accionista del Institut Montaigne (de Castries) y está participada de forma significativa por BlackRock. Presente en Lisboa y Estocolmo junto a Philippe, Attal y de Castries. Nodo que conecta el círculo Bilderberg con el círculo de empresas/BlackRock.",
    "jean-lemierre": "Presidente de BNP Paribas, presente en el Bilderberg 2025 de Estocolmo junto a Philippe y Attal. BNP está participada parcialmente por BlackRock y financia el Institut Montaigne. Kohler dejó el Élysée en 2025 para incorporarse a Société Générale, el mismo ecosistema bancario. El círculo Bilderberg conecta directamente los bancos sistémicos franceses con los candidatos presidenciales.",
    "bernard-emie": "Director general de la Seguridad Exterior (DGSE, 2017-2024), presente en el Bilderberg 2023 en Lisboa junto a Philippe, Attal y de Castries. La presencia del jefe de la inteligencia exterior francesa en un foro privado transatlántico es un hecho notable, señalado por Regards.fr. En 2025, Nicolas Roche (SGDSN), nombrado dos meses antes, lo sustituyó en el Bilderberg.",
    "laurent-nunez": "Laurent Nuñez-Belda (nacido en 1964 en Bourges) es énarque (promoción Cyrano de Bergerac, 1997-1999, concurso interno). Director de la DGSI (junio de 2017 – octubre de 2018), secretario de Estado de Interior en el gobierno Philippe II (octubre de 2018 – julio de 2020), coordinador nacional de inteligencia en el Élysée (julio de 2020 – julio de 2022), prefecto de policía de París (julio de 2022 – octubre de 2025) y posteriormente ministro de Interior en el gobierno Lecornu II (desde octubre de 2025). Es el ejecutor operacional de la represión de los Gilets jaunes junto a Castaner, mientras que Philippe asume la responsabilidad política. Nuñez defiende públicamente los LBD, participa en el cese del prefecto Delpuech (marzo de 2019) y asume sin ambigüedad la doctrina de orden público más dura de la V República. En términos MAS, es un agente de ejecución estatal: su lealtad va directamente a Macron (quien le nombra personalmente para cada cargo), no a Philippe (su superior nominal). Su presencia en el gobierno Lecornu II, junto a miembros de Horizons, crea un vínculo indirecto adicional con la esfera philippista. El triángulo Nuñez–Bompard–Caubel es el hallazgo estructural del informe: condiscípulo de la ENA de Bompard (CEO Carrefour), cuya esposa Charlotte Caubel fue jefa del área de justicia en el gabinete Philippe (2017-2020) y es miembro de Horizons.",
    "alexandre-bompard": "Alexandre Joubert-Bompard (nacido en 1972) es CEO del grupo Carrefour (facturación 2024: 86 000 millones de euros), cuarto clasificado en la promoción Cyrano de Bergerac de la ENA (1997-1999). Es el condiscípulo de Laurent Nuñez en esa misma promoción (resolución de 19 de abril de 1999, Légifrance, JORFTEXT000000211140). Su esposa Charlotte Caubel fue jefa del área de justicia en el gabinete de Édouard Philippe en Matignon (2017-2020). Bompard no tiene ningún vínculo documentado directo con Philippe, pero su red familiar (a través de Caubel) y profesional (a través de Nuñez) conecta el mundo de la gran distribución con los círculos del poder ejecutivo. Carrefour tiene importantes intereses en China y fue socio oficial de los Juegos Olímpicos de París 2024.",
    "charlotte-caubel": "Charlotte Caubel (magistrada, Sciences Po) fue nombrada asesora de justicia en el gabinete de Édouard Philippe en Matignon en mayo de 2017. Permaneció allí tres años (2017-2020), convirtiéndose en jefa del área de justicia. Tras Matignon, dirigió la Protection judiciaire de la jeunesse (2020-2022) y fue nombrada secretaria de Estado de Infancia en el gobierno Borne (2022-2024). Es miembro del partido Horizons. En agosto de 2025 fue nombrada fiscal adjunta en París. Su marido es Alexandre Bompard (CEO Carrefour), condiscípulo de la ENA de Laurent Nuñez. Este triángulo Nuñez–Bompard–Caubel conecta directamente la promoción ENA de Nuñez con el núcleo del gabinete Philippe y el partido Horizons.",
  },
  it: {
    "emmanuel-macron": "Emmanuel Macron è stato selezionato come Young Leader nella promozione 2012, un anno dopo Édouard Philippe. Il loro mentore comune, Alain Juppé, apparteneva alla promozione fondatrice del 1982 — tre generazioni di Young Leaders legati dallo stesso padrino politico. Macron ha nominato Philippe Primo Ministro il 15 maggio 2017, nonostante le precedenti critiche di quest'ultimo («ex banchiere di Rothschild», «cinismo di un vecchio lupo di mare»). Questo avvicinamento post-critica illustra la forza dei legami di rete rispetto alle posizioni pubbliche. Macron proveniva dall'Inspection des finances, poi dalla banca Rothschild, prima di essere nominato segretario generale aggiunto dell'Élysée sotto Hollande (a sua volta Young Leader 1996). La catena Hollande (YL 1996) → Macron (YL 2012) → Philippe (YL 2011) al vertice dello Stato è unica nella storia della FAF. Le tensioni tra i due uomini sono cresciute dal 2020: Philippe ha rimproverato a Macron lo scioglimento del 2024 («una decisione funesta e assurda») e lo ha invitato a dimettersi alla fine del 2025. La promozione 2012 di Macron includeva anche Fleur Pellerin e Cédric Villani, entrambi divenuti figure politiche. Il fatto che un presidente e il suo Primo Ministro provengano da promozioni consecutive dello stesso programma transatlantico è senza precedenti e solleva interrogativi sull'influenza americana nella formazione delle élite dirigenti francesi.",
    "alain-juppe": "Alain Juppé è il padrino dell'intero ecosistema. Primo Ministro di Chirac (1995-1997), condannato nel 2004 (impieghi fittizi del RPR), Young Leader della promozione fondatrice della FAF (1982), sindaco di Bordeaux (2006-2019), membro del Conseil constitutionnel dal marzo 2019 (mandato fino al 2028) e presidente dell'Institut Georges-Pompidou dal febbraio 2025. Fu Juppé a lanciare Philippe in politica (come direttore generale dell'UMP nel 2002), e Villepin lo aveva conosciuto fin dal «groupe J» (1979) prima di essere nominato da Juppé capo di gabinetto al Quai d'Orsay (1993). Il triangolo Juppé (YL 1982) → Philippe (YL 2011) → Macron (YL 2012) è il caso più spettacolare di trasmissione del potere all'interno della FAF. Oggi neutralizzato dai vincoli del Conseil constitutionnel (dovere di riservatezza, divieto di qualsiasi responsabilità partitica, incompatibilità con qualsiasi mandato), non può né sostenere Philippe, né pronunciarsi su argomenti politici, né esercitare alcun ruolo in Horizons. Ma il suo potere residuale è triplice: istituzionale (partecipa alle decisioni costituzionali, siede accanto a Richard Ferrand YL 2005), simbolico (la sua eredità permea Horizons: pragmatismo, europeismo, liberalismo temperato) e reticolare (la «Juppéie» — la sua rete informale di fedeli — forma la spina dorsale di Horizons). Pubblicazione di L'heure du choix (Tallandier, 2025) sull'indipendenza europea. «Alain Juppé ha perso ma i juppéisti hanno vinto: sono ovunque nei gabinetti ministeriali» (Julien Miro).",
    "cma-cgm": "CMA CGM è il primo armatore francese e il terzo a livello mondiale, fondato a Marsiglia da Jacques Saadé nel 1978. Il gruppo possiede più di 600 navi e serve 420 porti nel mondo. Yann Le Goff, responsabile della sicurezza regionale di CMA CGM, è stato selezionato nella promozione 2011 dei Young Leaders insieme a Édouard Philippe. Il porto de Le Havre, feudo politico di Philippe dal 2010, è uno dei principali hub europei di CMA CGM — le navi del gruppo rappresentano una quota significativa del traffico di contenitori. Le Havre è il principale punto di ingresso della cocaina in Europa secondo Europol, con 18 tonnellate sequestrate nel 2023. La questione della sicurezza portuale — un dominio in cui convergono CMA CGM (tramite Le Goff), la responsabilità del sindaco (Philippe) e le reti transatlantiche (FAF) — è un nodo critico. CMA CGM è guidata da Rodolphe Saadé dal 2017, e il gruppo si è diversificato nei media (acquisizione di La Tribune, La Provence) e nella logistica. La France China Foundation, di cui Ribadeau-Dumas (capo di gabinetto di Philippe) è membro, si inscrive negli stessi circuiti di influenza sino-marittimi. Le rotte commerciali di CMA CGM verso l'Asia transitano massivamente per Le Havre, facendo del porto un punto di convergenza tra interessi commerciali, diplomatici e politici.",
    "yann-le-goff": "Yann Le Goff è responsabile della sicurezza regionale di CMA CGM, il principale armatore francese, al momento della sua selezione come Young Leader nel 2011 insieme a Édouard Philippe. La sua funzione in CMA CGM lo colloca al cuore delle problematiche di sicurezza del trasporto marittimo — un dominio che include la lotta al narcotraffico nei porti. Il porto de Le Havre, feudo politico di Philippe, è il principale punto di ingresso della cocaina in Europa secondo Europol. Le navi di CMA CGM rappresentano una quota maggioritaria del traffico di contenitori a Le Havre, il che significa che la sicurezza di CMA CGM e la sicurezza portuale di Le Havre sono intimamente legate. Le Goff e Philippe si sono frequentati durante due seminari di cinque giorni nel 2011-2012, stringendo legami personali in un contesto informale e riservato. La presenza nella stessa promozione Young Leaders di un futuro sindaco/Primo Ministro e di un responsabile della sicurezza del principale armatore operante nel suo porto crea un canale di influenza diretto. Questa connessione è tanto più significativa in quanto la questione del narcotraffico portuale è diventata un tema politico rilevante in Francia, con sequestri record a Le Havre (18 tonnellate di cocaina nel 2023). Le Goff rappresenta il nodo CMA CGM nella rete Young Leaders di Philippe. La convergenza tra la sua posizione (sicurezza marittima), il territorio di Philippe (Le Havre) e il problema strutturale (narcotraffico) merita un esame approfondito.",
    "atos": "Atos è un gruppo informatico francese specializzato in trasformazione digitale, cybersicurezza e cloud computing. Édouard Philippe vi è stato nominato amministratore indipendente nel 2020, immediatamente dopo la sua uscita da Matignon, per un mandato retribuito di circa 70.000 euro annui. Atos è all'avanguardia nel trattamento informatizzato dei dati delle infrazioni stradali, in particolare gli autovelox — un mercato che ha beneficiato direttamente della misura degli 80 km/h imposta da Philippe nel 2018. Boulevard Voltaire e Blast hanno evidenziato questo potenziale conflitto d'interessi: il Primo Ministro che impone una misura stradale massicciamente impopolare entra poi nel consiglio di amministrazione dell'azienda che tratta i dati generati da quella stessa misura. I legami tra Philippe e Atos risalgono al 2006, ben prima della sua nomina a Matignon. L'azienda ha attraversato gravi difficoltà finanziarie a partire dal 2022, con un crollo spettacolare del titolo in borsa e massicce ristrutturazioni. Atos gestisce anche attività strategiche per lo Stato francese (supercomputer, difesa, Giochi Olimpici 2024), il che ne fa un attore sensibile il cui consigliere è anche candidato alla presidenza. La cronologia — 80 km/h nel 2018, uscita da Matignon nel 2020, nomina in Atos nel 2020 — solleva interrogativi sulla porosità tra decisioni pubbliche e interessi privati. Philippe non ha mai commentato pubblicamente questo potenziale conflitto d'interessi.",
    "areva": "Areva (rinominata Orano nel 2018) è la multinazionale francese dell'industria nucleare, che copre l'intero ciclo del combustibile. Édouard Philippe ha occupato il posto di direttore degli affari pubblici dall'ottobre 2007 all'ottobre 2010, una funzione di lobbying e relazioni con i funzionari eletti che lo ha mantenuto al cuore della sfera decisionale. Questo periodo ha coinciso con la sua selezione come Young Leader nel 2011, quando fu presentato come «sindaco di Le Havre e direttore degli affari pubblici di Areva». Il lobbying nucleare è uno dei più potenti in Francia, dove l'industria rappresenta circa il 70% della produzione elettrica. Come direttore degli affari pubblici, Philippe era incaricato di difendere gli interessi di Areva di fronte ai parlamentari e al governo — le stesse istituzioni che avrebbe poi guidato come Primo Ministro. La sua traiettoria Conseil d'État → Debevoise & Plimpton (avvocato d'affari) → Areva (lobbying) → municipio di Le Havre → Matignon illustra un classico percorso di porte girevoli tra settore pubblico e privato. Areva ha vissuto uno scandalo maggiore con la disastrosa acquisizione di UraMin nel 2007 (3,6 miliardi di euro di perdite), una vicenda scoppiata nel periodo in cui Philippe vi lavorava. Il gruppo ha dovuto essere ristrutturato e ricapitalizzato dallo Stato per 5 miliardi di euro nel 2017 — sotto il governo Philippe. Il Primo Ministro che salva l'azienda che lo aveva assunto come lobbista è un caso emblematico di potenziale conflitto d'interessi.",
    "debevoise-plimpton": "Debevoise & Plimpton LLP è uno studio legale americano fondato nel 1931 a New York, specializzato in diritto commerciale internazionale, fusioni e acquisizioni, private equity e arbitrato internazionale. Lo studio conta circa 800 avvocati e uffici a New York, Washington, Londra, Parigi, Francoforte, Hong Kong e Shanghai. Édouard Philippe vi ha esercitato come avvocato dal 2004 al 2007, nella filiale parigina, dopo aver lasciato le sue funzioni di direttore generale dell'UMP e essersi messo in disponibilità dal Conseil d'État. Questo passaggio in uno studio anglosassone di primo piano illustra la classica traiettoria delle porte girevoli: alta funzione pubblica (ENA, Conseil d'État), direzione di partito politico (UMP), poi settore privato internazionale, prima di tornare in politica. Debevoise rappresenta aziende del Fortune 500 e fondi d'investimento, il che ha permesso a Philippe di tessere una rete nei circoli d'affari internazionali. Lo studio è presente a Hong Kong e Shanghai, centri nevralgici del commercio asiatico — un dettaglio che acquista significato alla luce delle successive connessioni sino-francesi dell'entourage di Philippe. Dopo Debevoise, Philippe è entrato in Areva come direttore degli affari pubblici (lobbying), confermando il suo radicamento nei circoli d'influenza economica. La sequenza Conseil d'État → UMP → Debevoise → Areva → municipio → Matignon traccia un percorso in cui ogni tappa arricchisce la rubrica per la successiva. Il passaggio da Debevoise è la parentesi anglosassone di questo percorso essenzialmente francese. I compensi e i mandati che ha gestito in Debevoise non sono mai stati resi pubblici.",
    "antoine-rufenacht": "Antoine Rufenacht è stato sindaco di Le Havre dal 1995 al 2010, ex énarque e figura della destra normanda. Fu lui a identificare Édouard Philippe come potenziale successore e a introdurlo in politica nel 2001, integrandolo nella sua lista municipale come assessore agli affari giuridici. Rufenacht ha poi raccomandato Philippe ad Alain Juppé per la direzione dell'UMP nel 2002, lanciando così la sua carriera nazionale. Quando Rufenacht si è dimesso dal municipio nel 2010, il consiglio comunale ha eletto Philippe per succedergli — un passaggio del potere locale perfettamente orchestrato. Christine Poyer-Rufenacht, avvocata con lo stesso cognome dell'ex sindaco, è stata selezionata nella promozione 2011 dei Young Leaders della FAF insieme a Philippe — una coincidenza che non è mai stata spiegata pubblicamente. Rufenacht ha guidato Le Havre per quindici anni, plasmando la rete politica ed economica locale che Philippe ha ereditato. Sotto Rufenacht, Le Havre ha avviato una trasformazione urbana intorno al porto e all'architettura Perret classificata dall'UNESCO. La relazione Rufenacht-Philippe è un caso emblematico di successione politica locale: il mentore identifica, forma e insedia il suo protetto alla testa della città. Il radicamento di Philippe a Le Havre — municipio, porto, comunità urbana — è direttamente ereditato dalla rete Rufenacht. Il fatto che il mentore locale e la rete transatlantica (FAF) convergano intorno allo stesso cognome pone interrogativi sui meccanismi di cooptazione nelle élite francesi.",
    "french-american-foundation": "La French-American Foundation (FAF) è un'organizzazione fondata nel 1976 sotto gli auspici dei presidenti Gerald Ford e Valéry Giscard d'Estaing. Il suo programma Young Leaders, creato nel 1981, seleziona ogni anno dieci francesi e dieci americani di età compresa tra 30 e 40 anni, provenienti dall'alta funzione pubblica, dall'impresa, dai media, dall'esercito e dalla ricerca. I partecipanti seguono due seminari di cinque giorni nell'arco di due anni consecutivi, alternando tra Francia e Stati Uniti. Il contenuto dei seminari non viene pubblicato — la FAF non divulga i programmi delle edizioni passate. Al termine del programma, i partecipanti si integrano in una rete di alumni di oltre 600 membri. Il programma è regolarmente descritto come uno strumento del soft power americano, sebbene la FAF si presenti come «né un think tank, né una lobby, né un'associazione parlamentare di amicizia». La presenza dei Young Leaders nel governo francese è notevole e trascende le alternanze politiche. Édouard Philippe appartiene alla promozione 2011, Emmanuel Macron a quella del 2012, Alain Juppé alla fondatrice del 1982 e François Hollande a quella del 1996. Richard Ferrand, ministro del governo Philippe, era Young Leader 2005. Più di 400 dirigenti hanno beneficiato del programma dal 1981, e il fatto che un presidente e il suo Primo Ministro provengano da promozioni consecutive è senza precedenti nella storia della FAF. I promotori del programma includono Airbus, J.P. Morgan e Sodexo.",
    "david-barroux": "David Barroux è giornalista e caporedattore del quotidiano economico Les Échos, uno dei principali giornali d'affari francesi. Ha fatto parte della promozione 2011 dei Young Leaders della French-American Foundation, insieme a Édouard Philippe. La sua posizione alla guida di un media economico di riferimento gli conferisce un'influenza significativa sulla copertura della politica economica francese. Les Échos appartiene al gruppo LVMH di Bernard Arnault, il che inscrive Barroux in un ecosistema mediatico legato alle grandi fortune francesi. Come Young Leader, ha condiviso con Philippe due seminari di cinque giorni tra il 2011 e il 2012, stringendo legami personali e professionali duraturi. La convergenza tra un futuro Primo Ministro e un caporedattore di un grande quotidiano nella stessa rete transatlantica merita di essere notata. Les Échos ha generalmente dato una copertura favorevole alle riforme del governo Philippe, in particolare sul Codice del lavoro e la legge PACTE. Questa prossimità illustra l'intreccio delle élite politiche e mediatiche francesi all'interno delle stesse reti d'influenza. Barroux rappresenta il pilastro mediatico della promozione 2011. La FAF non pubblica gli scambi avvenuti tra questi futuri dirigenti durante i seminari.",
    "yohann-benard": "Yohann Bénard è direttore degli affari pubblici di Amazon Francia al momento della sua selezione come Young Leader nel 2011. Condivide la promozione FAF con Édouard Philippe, allora sindaco di Le Havre e direttore degli affari pubblici di Areva. I due uomini svolgono dunque funzioni simili — il lobbying e le relazioni istituzionali — uno per il gigante del nucleare, l'altro per il gigante americano dell'e-commerce. Amazon è una delle aziende più controverse in Francia per le sue pratiche sociali e fiscali e il suo impatto sul commercio di prossimità. Bénard è incaricato di difendere gli interessi di Amazon di fronte agli eletti e alle amministrazioni francesi. Condividendo una rete d'élite transatlantica con un futuro Primo Ministro, dispone di un accesso privilegiato ai circoli decisionali. Il governo Philippe non ha particolarmente inasprito la fiscalità dei GAFA durante i suoi tre anni a Matignon, nonostante le promesse in materia. La presenza simultanea nella promozione 2011 di un lobbista di Amazon e di un lobbista di Areva che sarebbe diventato Primo Ministro illustra la porosità tra interessi aziendali e potere politico. I seminari della FAF hanno offerto un contesto informale per tessere questi legami. Bénard rappresenta il pilastro aziendale americano della promozione.",
    "stephane-israel": "Stéphane Israël è stato selezionato come Young Leader 2011, lo stesso anno di Édouard Philippe. Sarebbe diventato presidente esecutivo di Arianespace, leader mondiale dei servizi di lancio spaziale, filiale di ArianeGroup (joint venture Airbus/Safran). Prima di Arianespace, Israël è stato capo di gabinetto della ministra dell'Istruzione Superiore e della Ricerca Geneviève Fioraso (2012-2014) sotto la presidenza Hollande. Incarna il profilo tipico delle porte girevoli tra alta funzione pubblica e industria strategica. La sua traiettoria — gabinetto ministeriale poi direzione di un'azienda pubblica — è paragonabile a quella di Philippe (Conseil d'État, Areva, politica). Arianespace è un attore chiave della sovranità spaziale europea, e il suo presidente intrattiene necessariamente relazioni strette con il potere esecutivo francese. La presenza di Israël nella stessa promozione Young Leaders di Philippe crea un legame trasversale tra le industrie nucleare, spaziale e il potere politico. Airbus, casa madre di ArianeGroup, è peraltro uno dei promotori del programma Young Leaders della FAF. Queste interconnessioni tra sponsor del programma e membri selezionati sollevano interrogativi sull'indipendenza del processo di selezione. Israël rappresenta il pilastro industriale strategico della promozione 2011.",
    "christine-poyer-rufenacht": "Christine Poyer-Rufenacht è avvocata associata, selezionata nella promozione 2011 dei Young Leaders della FAF insieme a Édouard Philippe. Il suo cognome evoca inevitabilmente Antoine Rufenacht, il sindaco di Le Havre che aveva lanciato Philippe in politica nel 2001 — una omonimia inquietante che le biografie ufficiali non commentano. Antoine Rufenacht è stato il mentore locale di Philippe, offrendogli il suo primo posto in una lista municipale e raccomandandolo poi per la direzione dell'UMP ad Alain Juppé. La presenza nella stessa promozione Young Leaders di un protetto di Rufenacht e di una persona con lo stesso cognome pone interrogativi sui meccanismi di cooptazione all'interno di queste reti. La FAF non pubblica i criteri di selezione dettagliati, e il processo di candidatura si basa in parte sul patronage. Se Christine Poyer-Rufenacht è parente di Antoine Rufenacht, ciò costituirebbe un caso di rete familiare e politica che si riproduce all'interno di un'istituzione transatlantica. Come minimo, la coincidenza patronimica illustra la ristrettezza dei circoli in cui si muovono le élite francesi selezionate dalla FAF. Le Havre appare come un nodo ricorrente in queste reti: Philippe, Rufenacht, CMA CGM. Questa connessione merita un'indagine approfondita. L'opacità della FAF sui suoi processi rende la verifica difficile.",
    "estelle-youssouffa": "Estelle Youssouffa è oggi deputata della prima circoscrizione di Mayotte, eletta nel 2022. È stata selezionata come Young Leader 2011 nella stessa promozione di Édouard Philippe. Prima del suo ingresso in politica, Youssouffa era giornalista, in particolare per France 24 e Al Jazeera, il che la colloca nel pilastro mediatico del programma. Il suo percorso — dal giornalismo internazionale alla rappresentanza parlamentare — illustra la classica traiettoria dei Young Leaders verso le posizioni di potere. Come deputata, siede all'Assemblea Nazionale dove il gruppo Horizons di Édouard Philippe ha anch'esso rappresentanti, creando possibilità di alleanze parlamentari tra ex membri della stessa promozione. Mayotte è un territorio che affronta grandi sfide (immigrazione, sicurezza, sviluppo) che sono regolarmente oggetto di dibattiti nazionali. La presenza di Youssouffa e Philippe nella stessa promozione FAF stabilisce un legame tra le problematiche d'oltremare e la rete philippista. Il programma Young Leaders ha storicamente prodotto connessioni durature tra i suoi membri, che si ritrovano poi in posizioni d'influenza in diverse sfere. Questa dinamica di coorte è uno dei meccanismi più efficaci della rete. Youssouffa rappresenta il pilastro ultramarino e mediatico della promozione 2011.",
    "richard-ferrand": "Richard Ferrand è un politico francese, ex presidente dell'Assemblea Nazionale (2018-2022) ed ex ministro della Coesione dei Territori nel primo governo di Édouard Philippe (maggio-giugno 2017). È Young Leader della promozione 2005, sei anni prima di Philippe. Ferrand è stato uno dei primi sostenitori di Emmanuel Macron e cofondatore di En Marche nel 2016. Come ministro di Philippe e poi presidente dell'Assemblea, è stato un ingranaggio essenziale del sistema macronista in cui Philippe operava. La sua promozione Young Leader 2005 lo inscrive nella stessa rete transatlantica di Philippe (2011), Macron (2012) e Juppé (1982). Il fatto che il ministro della Coesione dei Territori e il Primo Ministro fossero entrambi ex Young Leaders illustra la densità di questa rete all'interno del governo. Ferrand è stato messo sotto inchiesta nel 2019 per conflitto d'interessi illecito in una vicenda immobiliare — le Mutuelles de Bretagne. Ha beneficiato di un non luogo a procedere nel 2023. Il suo percorso giudiziario mostra che l'appartenenza alla rete Young Leaders non protegge necessariamente dai procedimenti penali. Tuttavia, la convergenza di Young Leaders al vertice dell'esecutivo e del legislativo merita un esame critico.",
    "francois-hollande": "François Hollande, Presidente della Repubblica dal 2012 al 2017, è Young Leader della promozione 1996 della FAF, insieme a Pierre Moscovici. Il suo passaggio nel programma quindici anni prima di Philippe illustra la continuità della rete attraverso le generazioni politiche e le alternanze. Hollande ha nominato Manuel Valls e poi Bernard Cazeneuve come Primi Ministri, ma è stato il suo successore Macron (Young Leader 2012) a nominare Philippe (Young Leader 2011). La catena di successione presidenziale Hollande-Macron è dunque una catena interna alla rete Young Leaders. Hollande è stato Primo Segretario del PS per undici anni (1997-2008) prima di accedere alla presidenza, il che gli ha permesso di strutturare una densa rete politica. La sua promozione 1996 includeva Pierre Moscovici, futuro commissario europeo poi presidente della Cour des comptes, illustrando la diversità dei posti occupati dagli ex Young Leaders. Il programma FAF ha così prodotto due Presidenti della Repubblica (Hollande e Macron), almeno quattro Primi Ministri (Juppé, Philippe e indirettamente altri) e numerosi ministri. Questa concentrazione di potere proveniente da un unico programma di selezione solleva interrogativi democratici sulla formazione delle élite dirigenti francesi. Hollande ha criticato Philippe in più occasioni dopo il 2017, ma condividono la stessa rete strutturale.",
    "laurent-wauquiez": "Laurent Wauquiez, presidente della regione Auvergne-Rhône-Alpes ed ex presidente dei Républicains (2017-2019), è Young Leader della promozione 2006. Rappresenta l'ala destra della stessa rete transatlantica di Édouard Philippe. I due uomini si sono scontrati all'interno di LR prima che Philippe si unisse a Macron nel 2017. Wauquiez ha criticato duramente la nomina di Philippe a Matignon, definendola un tradimento verso la destra. Nonostante la loro rivalità politica, condividono lo stesso percorso di formazione d'élite — ENA per entrambi, Young Leaders per entrambi. Wauquiez è considerato un potenziale candidato alle presidenziali del 2027, il che ne farebbe un rivale diretto di Philippe proveniente dalla stessa rete. Il fatto che due potenziali candidati alla presidenza siano ex Young Leaders illustra la capacità del programma di produrre i futuri dirigenti del paese, indipendentemente dallo schieramento politico. La promozione 2006 di Wauquiez lo colloca tra le generazioni Ferrand (2005) e Philippe (2011) nella cronologia della rete. La sua traiettoria politica — da segretario di Stato sotto Sarkozy a presidente di regione — mostra un percorso parallelo a quello di Philippe ma in un registro più a destra. I seminari FAF hanno potenzialmente permesso a Wauquiez e Philippe di incrociarsi tramite la rete alumni anche prima del loro scontro politico pubblico.",
    "fleur-pellerin": "Fleur Pellerin è stata selezionata nella promozione 2012 dei Young Leaders, lo stesso anno di Emmanuel Macron. Era allora ministra delegata alle PMI, all'Innovazione e all'Economia digitale sotto Hollande, prima di diventare ministra della Cultura (2014-2016). La sua promozione 2012 segue immediatamente quella di Philippe (2011), il che significa che i seminari delle due coorti si sovrapponevano potenzialmente — il secondo seminario di Philippe nel 2012 poteva coincidere con il primo di Pellerin e Macron. Pellerin è laureata all'ENA (promozione Senghor, 2000), una scuola che ricorre costantemente nei profili dei Young Leaders. Dopo il suo mandato ministeriale, ha fondato una società di venture capital, Korelya Capital, specializzata negli investimenti in Asia — creando un ponte tra le reti transatlantiche (FAF) e asiatiche che richiama la France China Foundation. Pellerin è nata in Corea del Sud ed è stata adottata in Francia, il che le conferisce un profilo biculturale apprezzato dalla FAF. La sua traiettoria post-ministeriale verso il venture capital asiatico illustra come le connessioni tessute nelle reti d'élite si trasformino in opportunità economiche. La promozione 2012, che include anche Macron e Cédric Villani, è una delle più politicamente influenti nella storia del programma.",
    "laphonza-butler": "Laphonza Butler è una politica americana nominata senatrice della California nell'ottobre 2023 dal governatore Gavin Newsom per sostituire la senatrice Dianne Feinstein. Fa parte della promozione 2011 dei Young Leaders, sul lato americano, insieme a Édouard Philippe sul lato francese. Prima del Senato, Butler era presidente della SEIU Local 2015, il più grande sindacato dei lavoratori della sanità in California (400.000 membri). Ha poi guidato EMILYs List, l'organizzazione democratica di sostegno alle candidate femministe. La sua nomina al Senato illustra la traiettoria dei Young Leaders americani verso le più alte funzioni. Il fatto che una senatrice americana e un ex Primo Ministro francese siano stati formati insieme nello stesso programma transatlantico crea un canale di influenza diretto tra il Senato americano e la politica francese. Butler ha trascorso del tempo con Philippe durante due seminari di cinque giorni nel 2011-2012, stringendo legami personali duraturi. Il programma Young Leaders è concepito precisamente per creare questi ponti tra futuri dirigenti dei due paesi. Butler rappresenta il pilastro politico progressista americano della promozione 2011. La sua presenza illustra la capacità della FAF di identificare futuri leader molto prima del loro accesso alle funzioni più elevate.",
    "horizons": "Horizons è il partito politico fondato da Édouard Philippe il 9 ottobre 2021 in una riunione pubblica a Le Havre, sua città-feudo. Il partito si posiziona al centro-destra, incarnando l'ala destra della maggioranza presidenziale macronista. I suoi quattro temi centrali sono la demografia, l'ambiente, la geopolitica e la tecnologia, sotto il motto «Vedere lontano per agire bene». Emmanuel Macron gradì poco la creazione di Horizons da parte di questo ex Primo Ministro «leale ma libero». Nel gennaio 2022, il partito si è integrato nella coalizione Ensemble Citoyens. Christian Estrosi, sindaco di Nizza, ne è diventato il numero due, portando un radicamento mediterraneo al partito ancorato in Normandia. Per le legislative del 2022, Horizons ha ottenuto 58 investiture all'interno della coalizione e ha costituito un gruppo parlamentare «Horizons et indépendants» di una trentina di deputati, presieduto da Laurent Marcangeli. Dopo lo scioglimento del 2024, il partito ha conservato solo 6 seggi. Nel marzo 2026, Horizons rivendicava 465 sindaci iscritti sull'intero territorio — un tessuto locale che costituisce la spina dorsale della campagna presidenziale 2027 di Philippe. Il partito funziona come un veicolo elettorale personale: il suo unico obiettivo strategico è portare Philippe all'Élysée. I quadri del partito provengono in gran parte dalle reti di Philippe a Le Havre e dell'entourage juppéista.",
    "christian-estrosi": "Christian Estrosi è sindaco di Nizza dal 2008 (con un'interruzione nel 2014-2017 quando era presidente della regione PACA) e il numero due del partito Horizons di Édouard Philippe. Ex ministro dell'Industria sotto Sarkozy (2009-2010) e figura della destra provenzale, Estrosi porta a Horizons un radicamento meridionale che completa quello normanno di Philippe. Il suo ralliamento a Horizons nel 2021 è stato un grande colpo politico: ha lasciato LR per unirsi a un partito centrista, trascinando parte della destra nizzarda e della Costa Azzurra. Nizza è la quinta città di Francia e un importante hub turistico ed economico, il che conferisce a Estrosi un peso politico considerevole all'interno del partito. Estrosi è stato segnato dall'attentato di Nizza del 14 luglio 2016 (86 morti), che ha gestito come presidente della metropoli — un evento che ha forgiato la sua immagine di gestore di crisi. È sposato con Laura Tenoudji, giornalista, il che gli assicura una visibilità mediatica supplementare. All'interno di Horizons, Estrosi svolge il ruolo di reclutatore tra gli eletti di LR tentati dal centro-destra. La sua traiettoria illustra la strategia di Philippe: assorbire i quadri di destra delusi dall'evoluzione di LR verso la destra dura. Il duo Philippe (Normandia) / Estrosi (PACA) dà a Horizons una base bi-regionale che strutturerà la campagna presidenziale 2027. Estrosi è anche vicepresidente di Intercommunalités de France, il che gli conferisce una rete territoriale complementare a quella di Philippe.",
    "gilles-boyer": "Gilles Boyer è il consigliere più vicino a Édouard Philippe da più di vent'anni, forgiato nell'orbita di Juppé. Direttore di gabinetto di Juppé al municipio di Bordeaux (2002-2004, 2006-2010), poi direttore di campagna di Juppé alle primarie del 2016 (Philippe era co-portavoce). Coautore con Philippe di due romanzi politici (L'heure de vérité 2007, Dans l'ombre 2011) e di Impressions et lignes claires (2021). Consigliere speciale di Philippe a Matignon (2017-2019). Oggi eurodeputato Renaissance. Un sarkozista li soprannominava «Plic e Ploc» (Boyer e Philippe), tanto era inscindibile il loro tandem. Boyer fa da ponte tra l'eredità di Juppé e la macchina Horizons: è il custode della dottrina philippista e l'archetipo del consigliere nell'ombra che influenza ogni orientamento politico. Cerchio interno della Juppéie.",
    "christophe-castaner": "Christophe Castaner è stato nominato ministro dell'Interno da Édouard Philippe nell'ottobre 2018, dopo il periodo di interim più lungo della Quinta Repubblica a Place Beauvau a seguito delle dimissioni di Gérard Collomb. La sua nomina è avvenuta un mese prima dell'inizio del movimento dei Gilets Jaunes, il che lo ha reso direttamente responsabile della dottrina di mantenimento dell'ordine più contestata dal Maggio '68. Castaner ha definito i manifestanti «faziosi venuti per uccidere», legittimando una risposta di sicurezza sproporzionata. Sotto la sua direzione, l'uso dei lanciatori di palline di difesa (LBD40) è aumentato di oltre il 200% rispetto all'anno precedente. Il bilancio umano è stato senza precedenti: 25 persone con un occhio perduto, 5 mani amputate, 432 feriti gravi. L'ONU, il Consiglio d'Europa e Amnesty International hanno chiesto il divieto di queste armi. Castaner ha sistematicamente ignorato le segnalazioni di violenze poliziesche e si è rifiutato di sospendere l'uso degli LBD. Come ministro di Philippe, la sua dottrina impegnava direttamente la responsabilità del Primo Ministro. L'IGPN è stata investita di 313 indagini giudiziarie per sospetti di violenze poliziesche — un record. Castaner era in precedenza delegato generale di LREM, il che illustra la fusione tra l'apparato macronista e l'apparato di sicurezza sotto il governo Philippe.",
    "benoit-ribadeau-dumas": "Benoît Ribadeau-Dumas, primo della promozione Marc-Bloch dell'ENA (1997), condiscepolo di Philippe. Direttore di gabinetto a Matignon (2017-2020) — scelto contro la volontà di Macron che voleva imporre Nicolas Revel. Soprannominato «Il Vaticano» per la sua rigidità. Membro della FCF (promozione inaugurale 2013 con Philippe e Macron). Prima di Matignon: vice capo di gabinetto di Sarkozy all'Élysée (2011-2012), segretario generale aggiunto sotto Hollande — un percorso che trascende le alternanze politiche. Architetto operativo di tutte le decisioni del governo Philippe: ordinanze sul lavoro, limite di 80 km/h, Gilets Jaunes, riforma delle pensioni, Covid. Ha sostenuto il mantenimento del primo turno delle municipali il 15 marzo 2020. Dopo Matignon, è entrato in Exor (family office Elkann/Agnelli), amministratore di Stellantis e Iveco. Cerchio interno della Juppéie — il nodo che collega la rete ENA, FCF e il potere esecutivo.",
    "france-china-foundation": "La France China Foundation (FCF) è un'organizzazione fondata nel 2012 per avvicinare le élite dirigenti francesi e cinesi. Il suo consiglio strategico include Jean-Pierre Raffarin, Laurent Fabius e Alain Mérieux (architetto del laboratorio P4 di Wuhan). Il suo partner cinese ufficiale è il CPIFA (Chinese People's Institute of Foreign Affairs), legato al ministero cinese degli Affari Esteri. La promozione inaugurale del 2013 ha riunito Philippe, Macron e Ribadeau-Dumas. Nel 2015, Philippe ha accolto la delegazione della FCF a Le Havre per una visita al porto. Nel maggio 2018, ha partecipato al gala annuale a Versailles in qualità di Primo Ministro ed ex Young Leader. L'opacità della FCF è paragonabile a quella della FAF: nessuna pubblicazione degli ordini del giorno, nessun rapporto pubblico. La simultaneità delle reti FAF (transatlantica) e FCF (sino-francese) attorno allo stesso nucleo — Philippe, Ribadeau-Dumas, Lenain — crea un sistema di influenza bipolare senza precedenti a Matignon. Villepin non compare in nessuno spazio FCF — la sua rete cinese è personale e privata, non istituzionale.",
    "emmanuel-lenain": "Emmanuel Lenain è un diplomatico di carriera, cofondatore della France China Foundation nel 2012 e consigliere diplomatico di Édouard Philippe a Matignon dal 2017 al 2020. Questo doppio ruolo — architetto della rete sino-francese e consigliere del Primo Ministro — lo rende il ponte umano tra le reti transatlantiche (FAF) e asiatiche (FCF) al cuore del potere esecutivo. Prima di Matignon, Lenain ha occupato diversi posti diplomatici strategici, in particolare alla rappresentanza permanente della Francia presso le Nazioni Unite. Dopo il suo passaggio a Matignon, è stato nominato ambasciatore di Francia in India (2019-2022), un posto che lo inscrive nel triangolo strategico Francia-Cina-India. La sua creazione della FCF nel 2012, un anno dopo la selezione di Philippe come Young Leader alla FAF, suggerisce una strategia deliberata di costruzione di reti di influenza bilaterale complementari. Come consigliere diplomatico di Philippe, Lenain aveva accesso a tutte le negoziazioni internazionali del governo, incluse quelle che coinvolgevano la Cina e le rotte commerciali marittime. Le Havre, il principale porto francese e feudo di Philippe, è direttamente interessato dalle problematiche del commercio sino-francese e dell'iniziativa Belt and Road (Nuove Vie della Seta). La posizione di Lenain all'incrocio della FCF, di Matignon e della diplomazia asiatica illustra come un singolo individuo possa fungere da cinghia di trasmissione tra interessi diplomatici, economici e politici. Il suo percorso dopo Matignon — ambasciata in India, poi posti al Quai d'Orsay — conferma la sua traiettoria all'interno dell'apparato diplomatico francese orientato verso l'Asia. Lenain è l'anello mancante che collega la rete Young Leaders di Philippe alla rete sino-francese.",
    "port-du-havre": "Il porto di Le Havre è il principale porto container della Francia e il quinto d'Europa. Dal 2021 è integrato nel complesso HAROPA (Le Havre, Rouen, Parigi), il più grande gruppo portuale francese. Édouard Philippe ne è sindaco dal 2010, il che gli conferisce un'influenza diretta sugli orientamenti strategici del porto e della comunità urbana Le Havre Seine Métropole. CMA CGM, il principale armatore francese, vi gestisce una quota considerevole del traffico containerizzato, con linee dirette verso Shanghai, Ningbo, Shenzhen e i principali porti asiatici. Il commercio marittimo franco-cinese che transita da Le Havre rappresenta miliardi di euro annui. Il porto è anche coinvolto dall'iniziativa cinese Belt and Road, che mira a connettere le infrastrutture portuali europee alla rete logistica cinese. Secondo Europol, Le Havre è il principale punto d'ingresso della cocaina in Europa. I sequestri di droga sono esplosi: 18 tonnellate di cocaina sequestrate dalla dogana francese nel 2023, un record. La sicurezza portuale è sotto la responsabilità condivisa dello Stato, delle dogane e delle autorità portuali — un ambito dove gli interessi di CMA CGM (tramite Yann Le Goff, sicurezza), del municipio (Philippe) e delle reti di influenza (FAF, FCF) si intersecano. L'estensione del porto e gli investimenti nei terminal container sono temi economici di primaria importanza per la regione, dove Philippe gode di un radicamento politico senza rivali da quindici anni. La questione della governance portuale — chi decide su investimenti, concessioni, controlli — è al cuore del nexus Philippe-CMA CGM-FCF.",
    "jean-pierre-raffarin": "Jean-Pierre Raffarin, Primo ministro sotto Chirac (2002-2005), è il perno tra le reti cinesi di Philippe e Villepin. Cumula un numero senza pari di posizioni cinesi: membro del «consiglio di consulenti» del Forum di Bo'ao (il Davos asiatico), del Belt & Road Forum, consigliere di amministrazione della CEIBS di Shanghai, copresidente della Sino-International Entrepreneurs Federation, presentatore su CGTN (TV pubblica cinese), rappresentante speciale del governo francese per la Cina (dal 2018), co-padrino FCF e presidente del Comité France-Chine. Il 29 settembre 2019, Xi Jinping gli ha consegnato la medaglia dell'Ordine dell'Amicizia — la più alta distinzione cinese per uno straniero, condivisa con Putin e Castro. La DGSI lo ha convocato per un «colloquio di sensibilizzazione» nell'estate del 2018 per i suoi rapporti con uomini d'affari cinesi considerati agenti del Partito. La sua Fondation Prospective et Innovation (FPI) dispone di un budget di 3,5 milioni di euro finanziato da una trentina di aziende (Carrefour, Kering, L'Oréal, LVMH) e ha ricevuto 85.000 euro dall'ex ambasciatore cinese Wu Jianmin. Nel 2022, Raffarin aderisce a Horizons — il suo doppio ruolo (rappresentante ufficiale per la Cina E membro del partito di Philippe) è senza eguali. Causeur rileva che Raffarin e Villepin hanno seguito «percorsi speculari» nelle loro riconversioni cinesi post-Matignon.",
    "rodolphe-saade": "Rodolphe Saadé è il presidente-direttore generale di CMA CGM dal 2017, succedendo al padre Jacques Saadé, fondatore del gruppo nel 1978. Sotto la sua guida, CMA CGM è diventato il terzo armatore mondiale con un fatturato superiore a 70 miliardi di euro nel 2022. Saadé ha diversificato il gruppo oltre il trasporto marittimo: acquisizione di CEVA Logistics (logistica), acquisto di La Tribune e La Provence (media), investimenti nella tecnologia. Il gruppo Saadé è di origine libanese, con sede a Marsiglia, e intrattiene importanti legami commerciali con la Cina — le rotte Asia-Europa sono il cuore dell'attività di CMA CGM. Il porto di Le Havre, feudo di Édouard Philippe, è uno dei principali hub europei di CMA CGM. Yann Le Goff, responsabile della sicurezza di CMA CGM e Young Leader 2011 con Philippe, opera direttamente sotto l'autorità della direzione Saadé. La fortuna di Rodolphe Saadé è stimata in oltre 40 miliardi di euro, rendendolo una delle più grandi fortune di Francia. La sua espansione nei media (La Tribune, La Provence, BFM Marseille) gli conferisce un'influenza mediatica oltre al suo peso economico. CMA CGM è un attore centrale dell'iniziativa cinese Belt and Road, con partnership portuali nel Mediterraneo, in Africa e nel Sud-Est asiatico. La convergenza tra l'impero Saadé, il porto di Le Havre di Philippe e le reti FCF di Ribadeau-Dumas costituisce un nexus di interessi economici e politici di considerevole portata.",
    "belt-and-road": "L'iniziativa Belt and Road (BRI), lanciata da Xi Jinping nel 2013, è il più grande programma infrastrutturale della storia, con investimenti stimati in oltre 1.000 miliardi di dollari in Asia, Africa ed Europa. Il segmento marittimo della BRI — la «Via della Seta Marittima del XXI secolo» — mira a collegare i porti cinesi a quelli europei mediante investimenti nei terminal, nella logistica e nelle concessioni portuali. In Europa, la Cina ha investito nei porti del Pireo (Grecia, tramite COSCO), di Amburgo, di Anversa e di Valencia. Il porto di Le Havre, principale porto container della Francia e feudo di Édouard Philippe, è direttamente coinvolto da questa strategia. CMA CGM, le cui rotte Asia-Europa sono il cuore dell'attività, è al contempo concorrente e potenziale partner degli armatori cinesi COSCO e OOCL. La France China Foundation, il cui membro Ribadeau-Dumas era capo di gabinetto di Philippe a Matignon, opera in questo spazio dove la diplomazia economica cinese cerca di stabilire punti di influenza presso i decisori europei. La BRI è stata criticata come strumento di «diplomazia del debito» e di influenza geopolitica cinese. Il fatto che il Primo ministro francese fosse circondato a Matignon da persone inserite nelle reti sino-francesi (FCF) pur essendo sindaco del principale porto francese sulla rotta marittima cinese crea una convergenza di interessi senza precedenti. L'Italia ha firmato un memorandum BRI nel 2019 prima di ritirarsene nel 2023 — la Francia, con Philippe, non ha mai firmato ma ha mantenuto una posizione ambigua. La questione della sovranità portuale di fronte agli investimenti cinesi è un nodo strategico che tocca direttamente Le Havre.",
    "cosco-shipping": "COSCO Shipping è il primo armatore cinese e il quarto mondiale, di proprietà dello Stato cinese tramite la SASAC (commissione di supervisione delle imprese statali). COSCO gestisce oltre 1.300 navi e serve più di 300 porti nel mondo. In Europa, COSCO ha acquisito il 67 % del porto del Pireo in Grecia (2016), illustrando la strategia cinese di controllo delle infrastrutture portuali strategiche. COSCO e CMA CGM sono al contempo concorrenti e partner all'interno dell'alleanza marittima Ocean Alliance, che copre le rotte Asia-Europa — le stesse rotte che transitano per Le Havre. Quest'alleanza significa che i container di CMA CGM e COSCO condividono le stesse navi e gli stessi terminal, incluso Le Havre. La presenza di COSCO nei porti europei ha suscitato preoccupazioni in materia di sicurezza nazionale e sovranità. La Germania ha bloccato nel 2022 la partecipazione di COSCO nel terminal di Amburgo oltre il 24,9 %. La questione si pone per Le Havre: in che misura gli investimenti cinesi nei porti concorrenti influenzano la strategia del principale porto francese? La France China Foundation, i cui membri circondano Philippe a Matignon, opera proprio in questo spazio di diplomazia portuale sino-europea. L'intreccio tra Ocean Alliance (COSCO + CMA CGM), le reti FCF e la sindacatura di Philippe a Le Havre costituisce un intreccio di interessi che merita un esame approfondito. COSCO è uno strumento della politica cinese Belt and Road nel campo marittimo.",
    "comite-france-chine": "Il Comité France-Chine, collegato al MEDEF International, è il principale organo di lobbying del patronato francese nei confronti della Cina. Presieduto da Jean-Pierre Raffarin, funziona in sinergia con la France China Foundation: il Comitato opera a livello aziendale, la FCF a livello individuale. La presenza di Raffarin alla guida del Comitato e come padrino della FCF crea un ponte tra la diplomazia economica ufficiale e le reti di influenza informali. I membri includono gruppi del CAC 40 attivi in Cina: Airbus, Total, L'Oréal, Sanofi, e attori portuali e logistici. Ribadeau-Dumas (capo di gabinetto di Philippe, FCF 2013) e Lenain (co-creatore FCF, consigliere diplomatico) hanno entrambi operato in questo ecosistema.",
    "alexis-kohler": "Alexis Kohler (nato nel 1972 a Strasburgo) è énarque, capo di gabinetto al Ministero dell'Economia sotto Macron (2014), poi segretario generale dell'Élysée (2017-2025) — il braccio destro di Emmanuel Macron per otto anni. Nel marzo 2022 è stato messo sotto inchiesta per presa illegale di interessi, traffico di influenze e corruzione passiva, per i suoi conflitti di interesse con MSC (Mediterranean Shipping Company), fondata dalla famiglia Aponte — cugini di sua madre. Dal 2010 al 2012, Kohler ha fatto parte del consiglio di sorveglianza del Grand Port Maritime du Havre (GPMH) come rappresentante dell'Agence des participations de l'État, accanto a Édouard Philippe (sindaco dall'ottobre 2010). Secondo Mediapart, Kohler non ha mai dichiarato i suoi legami familiari con MSC e non si è astenuto durante le votazioni riguardanti MSC, mentre Philippe rispettava scrupolosamente le norme di astensione. Kohler funziona come agente pivot: Inspection des finances → APE/GPMH (accanto a Philippe) → gabinetto Macron (Bercy) → MSC (porta girevole) → Élysée (SG) → Société Générale (2025). Questo circuito illustra il meccanismo dei rendimenti crescenti della rubrica dei contatti. Il porto di Le Havre, dove Kohler e Philippe hanno lavorato fianco a fianco, è un nodo geostrategico: hub di CMA CGM (3° armatore mondiale), cliente di MSC (2° armatore, famiglia di Kohler), collegato a COSCO Shipping (1° armatore cinese, gemellaggio Dalian), sotto la governance politica di Philippe. Nel 2025, Kohler ha lasciato l'Élysée per la Société Générale, proseguendo il circuito della porta girevole tra Stato e finanza.",
    "sibyle-veil": "Sibyle Veil è presidente di Radio France dall'aprile 2018, nominata dal CSA (oggi Arcom), i cui membri sono influenzati dall'esecutivo. Proviene dalla promozione Leopold Sedar Senghor dell'ENA (2004), la stessa di Emmanuel Macron. Questa solidarietà di promozione — uno dei legami più forti nell'alta funzione pubblica francese — connette direttamente la presidenza della principale radio pubblica al presidente della Repubblica. Sotto la sua guida, France Inter è rimasta la radio più ascoltata di Francia con la sua mattinale politica. Le interviste di Édouard Philippe su France Inter si contraddistinguono per un tono favorevole e l'assenza sistematica di domande sui fascicoli sensibili: legami con CMA CGM, la France China Foundation, l'affaire Atos. Veil è stata rinnovata nel 2022, confermando la fiducia dell'esecutivo macronista. Prima di Radio France era consigliera al Conseil d'État e aveva lavorato alla Cour des comptes. Il suo percorso — ENA → Conseil d'État → direzione di un media pubblico — è un archetipo del sistema francese in cui le stesse promozioni controllano il potere esecutivo e quello mediatico. La catena Macron (presidente) → Arcom (nomina) → Veil (direzione) → France Inter (linea editoriale) illustra il controllo indiretto dell'audiovisivo pubblico. Radio France raggiunge circa 15 milioni di ascoltatori quotidiani.",
    "bernard-arnault": "Bernard Arnault è il presidente-direttore generale di LVMH, prima fortuna mondiale con un patrimonio stimato in oltre 200 miliardi di euro. È proprietario del gruppo Les Échos-Le Parisien, che comprende il quotidiano economico Les Échos, il cui direttore David Barroux è Young Leader 2011 insieme a Édouard Philippe. Arnault è considerato il più stretto alleato oligarchico di Emmanuel Macron, con cui intrattiene relazioni personali documentate. LVMH è il principale inserzionista pubblicitario di Francia, conferendogli un'influenza indiretta sull'insieme dei media francesi. La copertura de Les Échos è sistematicamente favorevole alle riforme economiche portate avanti da Philippe (ordinanze sul lavoro, legge PACTE). Le Parisien, il quotidiano popolare più letto in Île-de-France, completa il dispositivo mediatico raggiungendo un pubblico più ampio. Arnault ha inaugurato diversi progetti architettonici con Macron e Philippe. La convergenza tra la prima fortuna mondiale, il presidente che ha nominato Philippe e il direttore Young Leader forma un triangolo potere-denaro-media. LVMH ha importanti interessi commerciali in Cina, il che collega Arnault alla rete sino-francese attraverso canali diversi dalla FCF. Il fatto che il proprietario del principale media economico di Francia sia anche il principale sostenitore finanziario del presidente che ha nominato Philippe crea un conflitto d'interessi mediatico strutturale.",
    "vincent-bollore": "Vincent Bolloré è un industriale bretone che ha costruito un impero mediatico tramite Vivendi: Canal+, CNews, C8, Europe 1, Paris Match, Le Journal du Dimanche. La sua progressiva acquisizione di questi media a partire dal 2015 è stata accompagnata da una riorientazione editoriale verso la destra e l'estrema destra, con figure come Eric Zemmour, Pascal Praud e Laurence Ferrari. CNews è diventata la «Fox News francese». Nel gioco politico, Bolloré è un «kingmaker»: il suo canale ha permesso l'emersione mediatica di Zemmour come candidato presidenziale nel 2022. Per Philippe, CNews gioca un ruolo paradossale: il canale lo ha presentato come l'alternativa «ragionevole» rispetto all'RN, alimentando la narrazione macronista dello sbarramento repubblicano. Europe 1, sotto il controllo Bolloré tramite Lagardère, è stata riorientata verso una linea compatibile con il centro-destra di Philippe. Bolloré ha anche massicci interessi in Africa (Bolloré Africa Logistics, porti) e in Asia, collegandolo ai temi del trasporto marittimo e alle reti sino-africane. Il suo impero logistico africano è stato ceduto a CMA CGM (MSC) nel 2022, creando un legame diretto tra Bolloré e il gruppo Saadé. La concentrazione mediatica tra Arnault (Les Échos, Le Parisien), Bolloré (CNews, Europe 1) e Saadé/CMA CGM (BFM TV) significa che i tre principali media informativi di Francia sono di proprietà di oligarchi vicini al potere macronista.",
    "patrick-drahi": "Patrick Drahi è un uomo d'affari franco-israeliano, fondatore di Altice, che ha detenuto BFM TV, RMC e Libération fino alla vendita dei suoi asset mediatici a CMA CGM (Rodolphe Saadé) nel 2024. Questa operazione è cruciale nella catena dei conflitti d'interessi: BFM TV, il principale media d'informazione in continuo, è passata da un proprietario circondato da controversie finanziarie (l'indebitamento massiccio di Altice) a CMA CGM, il principale armatore che opera nel porto del feudo di Édouard Philippe. Drahi era già stato criticato per la sua influenza sulla linea editoriale di BFM. Il passaggio a CMA CGM aggrava il conflitto: l'operatore portuale di Le Havre possiede ora il media che copre il candidato-sindaco di Le Havre. Drahi è anche proprietario di HOT in Israele e di Sotheby's. Il suo impero è fondato su un indebitamento massiccio (oltre 60 miliardi di euro al picco), un modello finanziario che ha suscitato indagini fiscali in diversi paesi. La cessione a Saadé illustra la concentrazione mediatica in corso in Francia: i media informativi passano dalle mani di un miliardario indebitato a quelle di un armatore miliardario legato alle rotte commerciali cinesi. La catena Drahi → BFM → CMA CGM → Le Havre → Philippe è un percorso di conflitto d'interessi costruito per acquisizioni successive.",
    "pierre-moscovici": "Pierre Moscovici è presidente della Cour des comptes dal giugno 2020. Young Leader 1996 (stessa promozione di Hollande). Ex ministro dell'Economia e poi commissario europeo. Il fatto che il massimo controllore dei conti pubblici e l'ex Primo ministro provengano dalla stessa rete Young Leaders solleva interrogativi sull'indipendenza del controllo.",
    "dominique-de-villepin": "Dominique de Villepin, Primo ministro sotto Chirac (2005-2007), gestisce una rete privata, multipolare e opaca. Nessuna relazione diretta documentata lo lega a Philippe — le loro reti convergono tramite Juppé e le connessioni cinesi. Villepin ha aderito al «groupe J» (fedeli di Juppé) nel 1979, poi è stato nominato direttore di gabinetto al Quai d'Orsay da Juppé nel 1993. Dal 2008: circa 50 conferenze remunerate in Cina (94.000 euro per due secondo Radio France), presidenza dell'IMTA (organismo cinese), società a Hong Kong (conti non depositati dal 2015), vicinanza a Xi Jinping. Rete multipolare oltre la Cina: amico della famiglia Al-Thani (Qatar), incarico all'Autorità dei musei del Qatar, tribuna condivisa con Putin a Valdaï (2014), 800.000 euro/anno dal gruppo saudita Bugshan tramite una società panamense legata a Djouhri (2008-2010), contratto Veolia di 17 anni tramite Proglio, attività in Iran, Venezuela, Armenia, Azerbaigian. Assiste le imprese cinesi in Africa e in Europa, a volte in concorrenza con aziende francesi. Sondaggi di maggio 2025: Villepin 51 %, Philippe 50 %. Seduce la sinistra (65 % LFI), Philippe il centro-destra. Concorrente diretto per il 2027.",
    "villepin-international": "Villepin International è la società di consulenza di Dominique de Villepin, creata dopo la sua uscita da Matignon. I suoi conti non vengono depositati dal 2015 — lo stesso anno vengono create due società a Hong Kong, poi una terza (Villepin Group Limited), con flussi finanziari considerevoli. L'inchiesta della cellula investigativa di Radio France (dicembre 2025) rivela l'ampiezza delle attività cinesi che transitano attraverso queste strutture. La destinazione e i beneficiari dei flussi finanziari restano zone d'ombra maggiori. L'opacità finanziaria contrasta con la rete istituzionale e relativamente trasparente di Philippe tramite la FCF.",
    "alexandre-djouhri": "Alexandre Djouhri è un intermediario condannato nel settembre 2025 a sei anni di carcere nell'affaire dei finanziamenti libici. L'inchiesta di Radio France rivela che Villepin ha effettuato spostamenti all'estero in sua compagnia. Al forum di San Pietroburgo, i due uomini si sono registrati come «vicepresidenti» di Veolia — una registrazione smentita dalla direzione del gruppo. Nessun legame comparabile è documentato per Philippe. Djouhri è un nodo oscuro specifico alla rete Villepin, che collega l'ex Primo ministro agli ambienti d'affari più controversi (Russia, Golfo, Libia).",
    "henri-proglio": "Henri Proglio è l'ex CEO di Veolia Environnement (2003-2009) e poi di EDF (2009-2014). Secondo le inchieste, Villepin è sotto contratto con Veolia da 17 anni tramite Proglio. Questo legame spiega l'episodio del forum di San Pietroburgo in cui Villepin e Djouhri si sono registrati come «vicepresidenti» di Veolia. Proglio è una figura del capitalismo francese che ha navigato tra settore pubblico e privato. Il suo ruolo di punto di contatto tra Villepin e il mondo degli affari costituisce una pista di approfondimento identificata dalla relazione.",
    "imta": "La International Mountain Tourism Alliance (IMTA) è un organismo cinese di cui Villepin è il presidente. Questa presidenza si inscrive nella rete di funzioni ufficiali e semi-ufficiali che Villepin ha accumulato in Cina dal 2008: presidenza di associazioni di diritto cinese, integrazione in comitati esecutivi di fondi d'investimento. L'IMTA illustra il radicamento istituzionale cinese di Villepin — una legittimità ottenuta dall'alto, direttamente presso il potere centrale, al contrario del percorso FCF di Philippe che passa per strutture franco-cinesi inquadrate.",
    "alain-merieux": "Alain Mérieux è l'industriale lionese fondatore di bioMérieux, leader mondiale della diagnostica in vitro. È l'architetto del laboratorio di sicurezza P4 di Wuhan, inaugurato nel 2018 — un progetto di cooperazione franco-cinese lanciato sotto la presidenza Chirac. Mérieux siede nel Consiglio strategico della FCF accanto a Raffarin e Fabius. La sua presenza al cuore del dispositivo FCF stabilisce un legame tra la diplomazia sanitaria franco-cinese (il P4 di Wuhan) e le reti di influenza in cui si inscrive Philippe. La questione del laboratorio P4 è diventata geopoliticamente sensibile dal 2020 e la pandemia di Covid-19.",
    "laurent-fabius": "Laurent Fabius, ex Primo ministro (1984-1986) e presidente del Consiglio costituzionale dal 2016, è co-padrino della France China Foundation con Raffarin. Ex ministro degli Affari esteri sotto Hollande (2012-2016), ha contribuito a strutturare la diplomazia sino-francese. La sua presenza nel Consiglio strategico della FCF accanto a Raffarin e Mérieux trascende le divisioni destra-sinistra e illustra il consenso delle élite francesi intorno al riavvicinamento con Pechino. Fabius valida la costituzionalità delle leggi — comprese quelle del governo Philippe.",
    "hubert-vedrine": "Hubert Védrine, ex segretario generale dell'Élysée sotto Mitterrand e poi ministro degli Affari esteri (1997-2002), è membro del Consiglio strategico della FCF. Teorico della politica estera francese e inventore del concetto di «iperpotenza» americana, rappresenta la continuità della tradizione diplomatica francese di indipendenza dagli Stati Uniti — la stessa tradizione che ha spinto gli eredi di Chirac verso la Cina.",
    "jacques-chirac": "Jacques Chirac (1932-2019), presidente della Repubblica (1995-2007), è la fonte comune dell'intero ecosistema. La sua politica di indipendenza dagli Stati Uniti e il suo dialogo privilegiato con Pechino hanno prodotto una tradizione di relazioni sino-francesi di cui Philippe e Villepin sono gli eredi per canali distinti. Un sondaggio JDD/Ifop del 2019 classificava Juppé come il primo erede di Chirac (62 %), Villepin al terzo posto, chiedendosi se «l'ultimo bastione del chiraquismo non sia a Matignon, con Édouard Philippe». Villepin era uno dei «figli preferiti» di Chirac (La Libre). Chirac → Juppé → Philippe e Chirac → Villepin sono i due rami di questo albero politico.",
    "cpifa": "Il CPIFA (Chinese People's Institute of Foreign Affairs) è il partner cinese ufficiale della France China Foundation. Collegato al Ministero degli Affari Esteri cinese, costituisce l'interlocutore istituzionale della rete sino-francese di Philippe e Raffarin. Il CPIFA è l'interfaccia tra il soft power francese (FCF) e l'apparato diplomatico cinese. Questa connessione distingue la rete Philippe/Raffarin (istituzionale, inquadrata) dalla rete Villepin (privata, accesso diretto al potere centrale tramite Xi Jinping).",
    "charles-hufnagel": "Charles Hufnagel è il consigliere della comunicazione di Juppé, incontrato ad Areva negli anni 2000. Portavoce di Philippe a Matignon. I giornalisti politici lo considerano «molto più affidabile» del suo omologo all'Élysée (Le Temps). Incarna la continuità comunicativa della Juppéie: la stessa dottrina di discrezione e sobrietà mediatica che ha caratterizzato le campagne di Juppé e il passaggio di Philippe a Matignon. Primo cerchio della Juppéie.",
    "benoist-apparu": "Benoist Apparu, ex sottosegretario di Stato all'Edilizia sotto Sarkozy, è co-portavoce della campagna Juppé 2016 con Philippe. Dopo la sconfitta di Juppé alle primarie, entra nel team di campagna di Fillon. Il suo percorso illustra la dispersione dei juppéisti dopo il novembre 2016 — una parte aderisce a Macron (Boyer, Philippe), un'altra rimane nell'orbita LR. Primo cerchio della Juppéie.",
    "anne-clerc": "Anne Clerc è direttrice di gabinetto a Matignon sotto Philippe. Ex membro del team di Raffarin a Matignon — il che la rende il ponte umano tra i due gabinetti di Primi ministri chiraquiani. La sua presenza nel gabinetto Philippe illustra la continuità della Juppéie all'interno dell'apparato statale: le stesse reti si trasmettono da un Matignon all'altro.",
    "xavier-chinaud": "Xavier Chinaud è consigliere per i rapporti con gli eletti a Matignon sotto Philippe. Ex responsabile degli «studi politici» a Matignon sotto Raffarin. Come Anne Clerc, è il trait d'union tra i gabinetti Raffarin e Philippe, garantendo la trasmissione di pratiche e reti tra i due Matignon chiraquiani.",
    "christophe-bechu": "Christophe Béchu è segretario generale del partito Horizons, ex ministro della Transizione ecologica (2022-2024) e sindaco di Angers. Il suo ruolo all'interno di Horizons è strutturante: assicura l'organizzazione territoriale del partito e fa da raccordo tra l'apparato philippista e gli eletti locali. L'asse Philippe (Normandia) / Béchu (Loire) / Estrosi (PACA) conferisce a Horizons una base multiregionale in vista del 2027. Terzo cerchio della Juppéie — alleato istituzionale.",
    "nathalie-loiseau": "Nathalie Loiseau, europarlamentare di Renaissance ed ex ministra per gli Affari europei (2017-2019), è vicina ai circoli juppéisti. Ex direttrice dell'ENA, rappresenta il legame europeo della Juppéie. Dopo la sconfitta di Juppé alle primarie, entra a far parte del gruppo dei «marciatori» — i juppéisti che si sono uniti a Macron. Terzo cerchio della Juppéie.",
    "virginie-calmels": "Virginie Calmels, ex prima vicesindaco di Juppé al municipio di Bordeaux, rappresenta la corrente «neo-destra» della Juppéie — quella che si è allontanata da Philippe per unirsi a Laurent Wauquiez tramite il movimento DroiteLib. La sua traiettoria illustra la frammentazione della Juppéie dopo la sconfitta del 2016: se la maggioranza dei juppéisti si è unita a Macron, una minoranza ha optato per la deriva a destra di LR. Ex responsabile di Endemol France, incarna il profilo manager-politico valorizzato da Juppé.",
    "julien-miro": "Julien Miro è uno degli organizzatori della rete dei «bébés Juppé» — una trentina di trentenni, veterani della campagna per le primarie del 2016, strutturatisi in una rete informale dopo la sconfitta. Con Guillaume Pfister organizza cene bimestrali con personalità amiche (Boyer, Gaymard, Keller, Bournazel). Significativa la dichiarazione di Miro: «Alain Juppé ha perso ma i juppéisti hanno vinto: sono ovunque negli staff ministeriali». Consiglieri a Matignon, al Quai d'Orsay, ai ministeri dell'Economia, della Transizione ecologica, della Cultura — i bébés Juppé erano al timone delle riforme macroniste. Secondo cerchio della Juppéie.",
    "guillaume-pfister": "Guillaume Pfister è il co-organizzatore, insieme a Julien Miro, della rete informale dei «bébés Juppé». Il loro obiettivo dichiarato: «mantenere viva la fiamma juppéista» e «preparare il dopo-Juppé». Le cene riuniscono personalità vicine a Juppé (Boyer, Gaymard, Keller, Bournazel) e giovani consiglieri sparsi nei gabinetti ministeriali. Questa rete costituisce il vivaio dei quadri di Horizons. Secondo cerchio della Juppéie.",
    "fpi-raffarin": "La FPI è la fondazione di Raffarin, riconfigurata per fungere da veicolo per le relazioni franco-cinesi. Budget di 3,5 M€ finanziato da una trentina di imprese (Carrefour, Kering, L'Oréal, LVMH) a 15.000 €/anno ciascuna. La fondazione ha ricevuto donazioni da personalità cinesi, tra cui 85.000 € dall'ex ambasciatore Wu Jianmin. La FPI opera all'intersezione tra think tank e rete d'influenza, fornendo a Raffarin un'infrastruttura istituzionale per le sue attività cinesi. È un canale parallelo alla FCF — l'uno (FPI) è il veicolo personale di Raffarin, l'altro (FCF) è la struttura collettiva.",
    "groupe-bugshan": "Il gruppo Bugshan è un conglomerato saudita che ha versato 800.000 €/anno a Villepin tra il 2008 e il 2010, tramite una società panamense legata ad Alexandre Djouhri. Questi flussi finanziari, rivelati da un'inchiesta di Radio France, illustrano l'opacità della rete d'affari di Villepin. Il denaro transitava attraverso una struttura offshore, rendendo difficile risalire ai beneficiari. Il legame Bugshan-Djouhri-Villepin è uno dei nodi più opachi della rete.",
    "sebastien-lecornu": "Sébastien Lecornu, Primo ministro in carica, intrattiene una relazione di competizione-cooperazione con Philippe. Ex sostenitore di LeMaire passato nella squadra Fillon con i juppéisti dopo le primarie del 2016. La sua traiettoria si incrocia con quella della Juppéie senza fondersi con essa. Normanno come Philippe (Évreux), rappresenta un potenziale rivale all'interno della maggioranza per l'influenza sulla destra moderata.",
    "plastic-omnium": "Plastic Omnium è un fornitore automobilistico francese il cui consiglio d'amministrazione ha incluso Raffarin. Il gruppo realizza una quota significativa del proprio fatturato in Cina, il che lo rende un beneficiario diretto delle reti franco-cinesi facilitate da Raffarin. La sua presenza nell'ecosistema Raffarin illustra il meccanismo di valorizzazione della rubrica: le imprese con interessi cinesi finanziano la FPI (15.000 €/anno) e beneficiano in cambio dell'accesso al mercato cinese facilitato dal «Signor Cina» della politica francese.",
    "laurent-marcangeli": "Laurent Marcangeli presiede il gruppo parlamentare «Horizons et indépendants» all'Assemblea nazionale. È il relé legislativo di Philippe: coordina le posizioni del gruppo sui testi di legge e garantisce la coesione dei deputati philippisti. Dopo lo scioglimento del 2024, il gruppo è passato da trenta deputati a sei — un crollo che illustra la fragilità della base parlamentare di Horizons.",
    "jacques-attali": "Jacques Attali (nato nel 1943) è politecnico ed énarque (promozione Robespierre, 1970). Ex revisore al Conseil d'État, consigliere speciale di François Mitterrand per dieci anni (1981-1991), fondatore e primo presidente della BERS (1991-1993), presidente della Commissione per la liberazione della crescita francese (2007-2010). Come agente facilitatore, Attali ha progettato il duo Macron-Philippe: nel 2007 ha scelto il giovane Macron come relatore aggiunto della sua Commissione. Nel 2011 ha presentato Macron a Hollande. Nel marzo 2017 ha suggerito a Macron di scegliere Philippe come Primo Ministro e ha organizzato il loro incontro. Questa catena Attali → Macron → Philippe è il meccanismo fondante del governo Philippe (2017-2020). Attali è cofondatore del Consiglio Strategico della France China Foundation (2013), dove siede accanto a Philippe, Raffarin, Fabius, Mérieux e de Castries — una convergenza unica di cinque livelli di potere. Ha lasciato la FCF nel marzo 2020, in corrispondenza dell'arrivo della pandemia. In un sistema multi-agente, Attali non possiede un centroide proprio ma funziona come nodo di connessione che massimizza l'influenza indiretta collegando i centroidi tra loro. Il suo valore risiede nella rete, non nel potere formale, il che gli permette di attraversare i cambi di governo indenne — un presidente può cambiare, un Primo Ministro può cadere, Attali rimane.",
    "alain-minc": "Alain Minc (nato nel 1954) è énarque (promozione Léon Blum, 1975, primo della classe), ispettore generale delle finanze. Ex presidente del consiglio di sorveglianza di Le Monde, presidente di AM Conseil, presidente del consiglio di amministrazione della Sanef, tesoriere della Fondation Saint-Simon, membro del Siècle. Un terzo dei grandi CEO del CAC 40 ha remunerato i suoi servizi (Bolloré, Bouygues, Vinci, Club Med, Suez). Come agente facilitatore, Minc opera dalla destra francese (Balladur, Sarkozy, Juppé) mentre il suo complementare Attali opera dalla sinistra (Mitterrand, Hollande) — una simmetria che permette loro di coprire l'intero spettro politico. Minc ha sostenuto Juppé alla primaria del 2016, per poi passare a Macron nel 2017 (trasferimento identico a quello degli stessi juppéisti). Mantiene un canale indiretto con Philippe tramite Gilles Boyer (consigliere a Matignon), documentato dal JDD riguardo al prelievo alla fonte (2018). Macron disponeva di due mentori all'uscita dall'ENA: Minc e Attali, confermando il modello del facilitatore in tandem. Minc è ex Young Leader della FAF, formando così una catena di quattro decenni: Minc (YL) → Juppé (YL 1982) → Philippe (YL 2011) → Macron (YL 2012). Come Attali, Minc massimizza la sua influenza indiretta restando invisibile agli occhi del pubblico. Nessuna responsabilità elettorale, nessun potere formale, ma una capacità di connessione ineguagliabile.",
    "commission-attali": "Commissionata da Sarkozy, presieduta da Attali, con Macron come vicesegretario generale relatore. Tra le 316 misure: la liberalizzazione delle VTC, che porta alla legge Novelli (2009) e poi all'«accordo Uber-Macron» (2014-2016). Punto di origine della catena di deregolamentazione: Commission → Uber → Macron → Philippe.",
    "msc-aponte": "Fondata dalla famiglia Aponte, cugini della madre di Alexis Kohler. Seconda compagnia di navigazione mondiale, gestisce un terminal per container nel porto di Le Havre. Kohler non ha mai dichiarato i suoi legami familiari con MSC durante il suo mandato al GPMH. Al centro dell'indagine su Kohler per conflitto illecito di interessi.",
    "rodolphe-saade-cma-cgm": "CEO di CMA CGM (3ª compagnia di navigazione mondiale), proprietario di BFM TV e RMC dall'acquisizione di Altice Media (2023). CMA CGM gestisce terminal nel porto di Le Havre, feudo di Philippe. Ha acquisito Bolloré Transport & Logistics (2024). Un nodo triplo: economico (trasporto marittimo), mediatico (BFM/RMC) e politico (partner portuale del sindaco di Le Havre).",
    "gpmh": "Primo porto di Francia, nodo di convergenza della rete. Kohler e Philippe hanno fatto parte insieme del consiglio di sorveglianza (2010-2012). Hub di CMA CGM e cliente di MSC. Gemellato con Dalian (Cina). Collegato a COSCO Shipping (1ª compagnia di navigazione cinese). Il punto geografico in cui convergono il potere politico, finanziario, mediatico e geostrategico.",
    "uber-files": "124.000 documenti interni di Uber trapelati all'ICIJ. Rivelano 17 scambi tra Uber e il gabinetto Macron, 4 incontri tra Macron e Kalanick, un accordo segreto (Uber rinuncia a UberPop, lo Stato riduce la formazione VTC da 250h a 7h) e emendamenti redatti da Uber trasmessi ai deputati. Commissione d'inchiesta parlamentare (2023): nessun conflitto di interessi ma «relazioni privilegiate» confermate.",
    "henri-de-castries": "Un nodo unico del sistema: presiede il comitato direttivo del Bilderberg dal 2012, siede nel Conseil stratégique della FCF accanto ad Attali, Raffarin e Philippe, ed è condiscepolo di Villepin all'ENA (promozione Voltaire, 1980). Ex CEO di AXA (2000-2016), presidente dell'Institut Montaigne, triple Young Leader FAF (1994, 1995, 1998). Ponte unico tra la rete transatlantica (Bilderberg, FAF) e la rete franco-cinese (FCF).",
    "gabriel-attal": "Primo ministro (gennaio-settembre 2024), il PM più giovane della Quinta Repubblica. Invitato al Bilderberg a Lisbona (2023) come ministro dei Conti pubblici, nominato PM sette mesi dopo. Presente a Stoccolma (2025) accanto a Philippe — la prima volta che due ex PM macronisti partecipano insieme. Tendenza ricorrente: Macron (Bilderberg 2014 → ministro 2 mesi dopo), Philippe (2016 → PM 11 mesi dopo), Attal (2023 → PM 7 mesi dopo).",
    "patricia-barbizet": "Membro del comitato direttivo permanente del Bilderberg — seconda rappresentante francese permanente dopo de Castries. Ex presidente del Siècle, ex direttrice generale della holding Artémis (Pinault). Presente al Bilderberg 2023 a Lisbona. Connette il Bilderberg al Siècle, dove siedono anche Attali e Minc.",
    "institut-montaigne": "Think tank liberale presieduto da Henri de Castries, finanziato da AXA, Engie, BNP Paribas, LVMH e TotalEnergies. Riferimento intellettuale della campagna Macron 2017: il suo direttore Laurent Bigorgne aveva fornito l'indirizzo della campagna di LREM. Veicolo di produzione dottrinale per il programma Horizons 2027.",
    "blackrock": "Primo gestore patrimoniale mondiale, fondato da Larry Fink. Detiene partecipazioni in almeno 18 imprese del CAC 40, tra cui AXA (de Castries), BNP (Lemierre, Bilderberg 2025), TotalEnergies (Pouyanné, Bilderberg), Société Générale (Kohler 2025). Alleato di MSC nell'acquisizione di 43 porti mondiali per 22,8 Mrd $ (2025). Philippe propone una capitalizzazione pensionistica del 15% nel 2027 — precisamente l'obiettivo di BlackRock in Francia.",
    "jean-francois-cirelli": "ENA (promozione Léonard de Vinci, 1985), ex consigliere di Chirac, direttore aggiunto del gabinetto di Raffarin (2002-2004), artefice della riforma pensionistica Fillon 2003. CEO di Gaz de France, numero 2 di Engie. Presidente di BlackRock Francia dal 2015. Invitato da Philippe al Comité Action Publique 2022 (2018). Promosso ufficiale della Légion d'honneur da Philippe il 31 dicembre 2019, in pieno sciopero storico delle pensioni.",
    "marc-ferracci": "Economista, laureato all'HEC, dottore in scienze economiche. Ha incontrato Macron a 22 anni a Sciences Po. Testimone di nozze di Macron. Suo padre Pierre Ferracci ha fatto parte della Commissione Attali (2007), dove Macron era relatore. Deputato di Renaissance, ex ministro dell'Industria. Patrimonio dichiarato: 23 milioni di euro. Firmatario del manifesto \"Pour la France, construisons l'union !\" (29 marzo 2026). Agente ponte tra l'ecosistema Macron e la coalizione Philippe.",
    "philippe-tabarot": "Ministro dei Trasporti dal dicembre 2024. Supervisiona i porti marittimi francesi, tra cui il GPMH (nodo Philippe/Kohler/MSC/CMA CGM). Ex vicepresidente regionale della PACA al fianco di Estrosi (Horizons). Senatore LR. Indagato dal PNF per peculato e presa illegale di interessi. Il ruolo di ministro dei Trasporti è un nodo ricorrente: Djebbari (YL FCF 2020) è stato vietato dall'HATVP dall'entrare in CMA CGM.",
    "maud-bregeon": "Portavoce del governo Lecornu, ministra delegata. Firmataria del manifesto \"Pour la France, construisons l'union !\" (29 marzo 2026). Ha dichiarato su LCI che Philippe \"ha preso un'opzione seria, essendo potenzialmente il meglio posizionato per condurre questa battaglia\". Stabilisce il collegamento esplicito tra il governo attuale e la candidatura di Philippe nel 2027.",
    "jean-paul-delevoye": "Alto Commissario per le Pensioni nel governo Philippe, incaricato del sistema universale a punti. Ha incontrato BlackRock già nel marzo 2018, tre mesi dopo la sua nomina. Si dimette il 16 dicembre 2019 per 13 mandati non dichiarati all'HATVP. La riforma che stava preparando è sospettata di aprire la strada alla capitalizzazione a favore di BlackRock. Il ricorso all'articolo 49.3 nel febbraio 2020, poi la pandemia, hanno congelato la riforma a tempo indeterminato.",
    "elabe-bfmtv": "Sondaggio Elabe per BFMTV (di proprietà di CMA CGM/Saadé) del 28 marzo 2026, che colloca Philippe tra il 20,5 % e il 25,5 % al primo turno. L'aggregazione bayesiana indipendente di moipresident.online lo dà al 17 %, ovvero da 3,5 a 8,5 punti in meno. Il risultato del 51,5 % contro Bardella al secondo turno è nel margine di errore. Il committente (BFMTV/CMA CGM) condivide un interesse con il candidato (porto di Le Havre).",
    "patrick-pouyanné": "CEO di TotalEnergies, partecipante ricorrente al Bilderberg (2023, 2025) al fianco di Philippe. TotalEnergies è azionista dell'Institut Montaigne (de Castries) ed è detenuta in misura significativa da BlackRock. Presente a Lisbona e Stoccolma con Philippe, Attal e de Castries. Nodo che collega il circolo Bilderberg al circolo imprese/BlackRock.",
    "jean-lemierre": "Presidente di BNP Paribas, presente al Bilderberg 2025 di Stoccolma al fianco di Philippe e Attal. BNP è parzialmente detenuta da BlackRock e finanzia l'Institut Montaigne. Kohler ha lasciato l'Élysée nel 2025 per entrare in Société Générale — stesso ecosistema bancario. Il circolo Bilderberg collega direttamente le banche sistemiche francesi ai candidati presidenziali.",
    "bernard-emie": "Direttore generale della Sicurezza Esterna (DGSE, 2017-2024), presente al Bilderberg 2023 a Lisbona al fianco di Philippe, Attal e de Castries. La presenza del capo dell'intelligence estera francese in un forum privato transatlantico è un fatto notevole, sollevato da Regards.fr. Nel 2025, Nicolas Roche (SGDSN), nominato due mesi prima, lo ha sostituito al Bilderberg.",
    "laurent-nunez": "Laurent Nuñez-Belda (nato nel 1964 a Bourges) è énarque (promozione Cyrano de Bergerac, 1997-1999, concorso interno). Direttore della DGSI (giugno 2017 – ottobre 2018), Segretario di Stato all'Interno nel governo Philippe II (ottobre 2018 – luglio 2020), coordinatore nazionale dell'intelligence all'Élysée (luglio 2020 – luglio 2022), prefetto di polizia di Parigi (luglio 2022 – ottobre 2025), poi ministro dell'Interno nel governo Lecornu II (dall'ottobre 2025). È l'esecutore operativo della repressione dei Gilets jaunes al fianco di Castaner, mentre Philippe ne assume la responsabilità politica. Nuñez difende pubblicamente i LBD, partecipa al licenziamento del prefetto Delpuech (marzo 2019) e assume senza ambiguità la dottrina di ordine pubblico più dura della V Repubblica. In termini MAS, è un agente di esecuzione statale: la sua lealtà va direttamente a Macron (che lo nomina personalmente per ogni incarico), non a Philippe (il suo superiore nominale). La sua presenza nel governo Lecornu II, accanto a membri di Horizons, crea un ulteriore collegamento indiretto con la sfera philippista. Il triangolo Nuñez–Bompard–Caubel è la scoperta strutturante del rapporto: condiscepolo ENA di Bompard (CEO Carrefour), la cui moglie Charlotte Caubel era responsabile del polo giustizia nel gabinetto Philippe (2017-2020) ed è membro di Horizons.",
    "alexandre-bompard": "Alexandre Joubert-Bompard (nato nel 1972) è CEO del gruppo Carrefour (fatturato 2024: 86 miliardi di euro), classificatosi 4° nella promozione Cyrano de Bergerac dell'ENA (1997-1999). È il condiscepolo di Laurent Nuñez in quella stessa promozione (decreto del 19 aprile 1999, Légifrance, JORFTEXT000000211140). Sua moglie Charlotte Caubel è stata responsabile del polo giustizia nel gabinetto di Édouard Philippe a Matignon (2017-2020). Bompard non ha alcun collegamento documentato diretto con Philippe, ma la sua rete familiare (tramite Caubel) e professionale (tramite Nuñez) collega il mondo della grande distribuzione ai circoli del potere esecutivo. Carrefour ha importanti interessi in Cina ed è stato partner ufficiale dei Giochi Olimpici di Parigi 2024.",
    "charlotte-caubel": "Charlotte Caubel (magistrata, Sciences Po) è stata nominata consigliera per la giustizia nel gabinetto di Édouard Philippe a Matignon nel maggio 2017. Vi è rimasta tre anni (2017-2020), diventando responsabile del polo giustizia. Dopo Matignon ha diretto la Protection judiciaire de la jeunesse (2020-2022), poi è stata nominata Segretaria di Stato all'Infanzia nel governo Borne (2022-2024). È membro del partito Horizons. Nell'agosto 2025 è stata nominata procuratrice aggiunta a Parigi. Suo marito è Alexandre Bompard (CEO Carrefour), condiscepolo ENA di Laurent Nuñez. Questo triangolo Nuñez–Bompard–Caubel collega direttamente la promozione ENA di Nuñez al cuore del gabinetto Philippe e al partito Horizons.",
  },
  ru: {
    "emmanuel-macron": "Эмманюэль Макрон был отобран как «Молодой лидер» в когорте 2012 года, на год позже Эдуара Филиппа. Их общий наставник, Ален Жюппе, принадлежал к основавшей когорте 1982 года — три поколения «Молодых лидеров», связанных одним политическим крёстным отцом. Макрон назначил Филиппа премьер-министром 15 мая 2017 года, несмотря на прежние критические высказывания последнего («бывший банкир Rothschild», «цинизм старого политического лиса»). Это сближение после публичной критики наглядно демонстрирует силу сетевых связей над публичными позициями. Макрон прошёл путь через Инспекцию финансов, затем банк Rothschild, прежде чем быть назначен заместителем генерального секретаря Елисейского дворца при Олланде (сам — «Молодой лидер» 1996 года). Цепочка Олланд (YL 1996) → Макрон (YL 2012) → Филипп (YL 2011) на вершине государства уникальна в истории FAF. Напряжённость между двумя мужчинами нарастает с 2020 года: Филипп упрекнул Макрона за роспуск парламента 2024 года («пагубное и абсурдное решение») и призвал его уйти в отставку в конце 2025 года. В когорту 2012 года Макрона также входили Флёр Пеллерен и Седрик Виллани, оба ставшие политическими фигурами. То, что президент и его премьер-министр вышли из последовательных когорт одной и той же трансатлантической программы, не имеет прецедента и поднимает вопросы об американском влиянии на формирование правящей элиты Франции.",
    "alain-juppe": "Ален Жюппе — крёстный отец всей этой экосистемы. Премьер-министр при Шираке (1995–1997), осуждён в 2004 году (фиктивные должности RPR), «Молодой лидер» основавшей когорты FAF (1982), мэр Бордо (2006–2019), член Конституционного совета с марта 2019 года (мандат до 2028 года) и президент Института Жоржа Помпиду с февраля 2025 года. Именно Жюппе вывел Филиппа в политику (в качестве генерального директора UMP в 2002 году), а Вильпен был знаком с ним ещё с «groupe J» (1979) до того, как был назначен Жюппе руководителем кабинета в Кэ д'Орсе (1993). Треугольник Жюппе (YL 1982) → Филипп (YL 2011) → Макрон (YL 2012) — наиболее показательный случай передачи власти внутри FAF. Сегодня нейтрализованный ограничениями Конституционного совета (обязанность соблюдать нейтралитет, запрет на любые партийные обязанности, несовместимость с любым мандатом), он не может ни поддерживать Филиппа, ни высказываться о политических вопросах, ни выполнять какую-либо роль в Horizons. Но его остаточная власть трояка: институциональная (он участвует в конституционных решениях, заседает рядом с Ришаром Ферраном YL 2005), символическая (его наследие пронизывает Horizons: прагматизм, проевропейство, умеренный либерализм) и сетевая («Жюппе» — его неформальная сеть преданных сторонников — составляет хребет Horizons). Публикация L'heure du choix (Tallandier, 2025) о европейской независимости. «Ален Жюппе проиграл, но жюппеисты выиграли: они повсюду в министерских кабинетах» (Жюльен Миро).",
    "cma-cgm": "CMA CGM — крупнейшая французская судоходная компания и третья в мире, основанная в Марселе Жаком Саадом в 1978 году. Группа владеет более чем 600 судами и обслуживает 420 портов по всему миру. Янн Ле Гофф, региональный директор по безопасности CMA CGM, был отобран в когорту «Молодых лидеров» 2011 года вместе с Эдуаром Филиппом. Порт Гавра — политическая вотчина Филиппа с 2010 года — является одним из главных европейских хабов CMA CGM: суда группы обеспечивают значительную долю контейнерного трафика. По данным Europol, Гавр является главным пунктом ввоза кокаина в Европу: в 2023 году здесь было изъято 18 тонн. Вопрос безопасности порта — сфера, где пересекаются интересы CMA CGM (через Ле Гоффа), ответственность мэра (Филиппа) и трансатлантические сети (FAF) — является критическим узлом. CMA CGM руководит Родольф Саадэ с 2017 года, и группа диверсифицировалась в медиа (приобретение La Tribune, La Provence) и логистику. Фонд France China Foundation, членом которого является Рибадо-Дюма (руководитель аппарата Филиппа), вписывается в те же китайско-морские круги влияния. Торговые маршруты CMA CGM в Азию проходят в основном через Гавр, делая порт точкой схождения коммерческих, дипломатических и политических интересов.",
    "yann-le-goff": "Янн Ле Гофф — региональный директор по безопасности CMA CGM, крупнейшего французского судоходного предприятия, на момент его отбора в «Молодые лидеры» 2011 года вместе с Эдуаром Филиппом. Его должность в CMA CGM ставит его в центр вопросов безопасности морского транспорта — сферы, включающей борьбу с наркоторговлей в портах. Порт Гавра, политическая вотчина Филиппа, является главным пунктом ввоза кокаина в Европу по данным Europol. Суда CMA CGM обеспечивают значительную часть контейнерного трафика в Гавре, а значит, безопасность CMA CGM и безопасность гаврского порта неразрывно связаны. Ле Гофф и Филипп общались во время двух пятидневных семинаров 2011–2012 годов, установив личные контакты в неформальной и конфиденциальной обстановке. Присутствие в одной когорте «Молодых лидеров» будущего мэра/премьер-министра и директора по безопасности главного судоходного предприятия, работающего в его порту, создаёт прямой канал влияния. Эта связь тем более значима, что вопрос портовой наркоторговли стал крупной политической проблемой во Франции: рекордные изъятия в Гавре (18 тонн кокаина в 2023 году). Ле Гофф представляет узел CMA CGM в сети «Молодых лидеров» Филиппа. Конвергенция между его должностью (морская безопасность), территорией Филиппа (Гавр) и структурной проблемой (наркоторговля) заслуживает тщательного изучения.",
    "atos": "Atos — французская IT-группа, специализирующаяся на цифровой трансформации, кибербезопасности и облачных вычислениях. Эдуар Филипп был назначен независимым членом совета директоров в 2020 году, сразу после ухода из Матиньона, за вознаграждение около 70 000 евро в год. Atos является лидером в обработке компьютеризированных данных о дорожных нарушениях, в частности данных систем автоматической фиксации скорости — рынка, который напрямую выиграл от ограничения скорости до 80 км/ч, введённого Филиппом в 2018 году. Boulevard Voltaire и Blast указали на этот потенциальный конфликт интересов: премьер-министр, введший массово непопулярную дорожную меру, входит в совет директоров компании, обрабатывающей данные, порождённые этой же мерой. Связи между Филиппом и Atos восходят к 2006 году, задолго до его назначения в Матиньон. С 2022 года компания испытывает серьёзные финансовые трудности: резкое падение курса акций и масштабная реструктуризация. Atos также управляет стратегическими активами для французского государства (суперкомпьютеры, оборона, Олимпийские игры 2024), что делает её чувствительным игроком, член совета директоров которого является ещё и кандидатом в президенты. Хронология — 80 км/ч в 2018 году, уход из Матиньона в 2020-м, назначение в Atos в 2020-м — поднимает вопросы о проницаемости границы между публичными решениями и частными интересами. Филипп никогда публично не комментировал этот потенциальный конфликт интересов.",
    "areva": "Areva (переименована в Orano в 2018 году) — французская многонациональная компания ядерной промышленности, охватывающая весь топливный цикл. Эдуар Филипп занимал должность директора по публичным делам с октября 2007 по октябрь 2010 года — функцию лоббирования и выстраивания отношений с выборными чиновниками, которая удерживала его в центре принятия решений. Этот период совпал с его отбором в «Молодые лидеры» в 2011 году, когда он был представлен как «мэр Гавра и директор по публичным делам Areva». Ядерное лоббирование — одно из наиболее влиятельных во Франции, где отрасль обеспечивает около 70% производства электроэнергии. Как директор по публичным делам, Филипп был обязан защищать интересы Areva перед парламентариями и правительством — теми самыми институтами, которые он впоследствии возглавит в должности премьер-министра. Его карьерная траектория: Государственный совет → Debevoise & Plimpton (корпоративный юрист) → Areva (лоббирование) → мэрия Гавра → Матиньон — иллюстрирует классический путь через «вращающиеся двери» между государственным и частным сектором. Areva пережила крупный скандал, связанный с катастрофическим приобретением UraMin в 2007 году (убытки 3,6 млрд евро) — дело, вспыхнувшее в период, когда Филипп там работал. Группа была реструктурирована и рекапитализирована государством на сумму 5 млрд евро в 2017 году — при правительстве Филиппа. Премьер-министр, спасающий компанию, в которой он работал лоббистом, — хрестоматийный случай потенциального конфликта интересов.",
    "debevoise-plimpton": "Debevoise & Plimpton LLP — американская юридическая фирма, основанная в 1931 году в Нью-Йорке, специализирующаяся на международном коммерческом праве, слияниях и поглощениях, прямых инвестициях и международном арбитраже. В фирме работают около 800 юристов, с офисами в Нью-Йорке, Вашингтоне, Лондоне, Париже, Франкфурте, Гонконге и Шанхае. Эдуар Филипп работал там юристом с 2004 по 2007 год в парижском офисе — после ухода с должности генерального директора UMP и перевода в распоряжение Государственного совета. Этот эпизод в одной из ведущих англосаксонских фирм иллюстрирует классическую карьеру «вращающихся дверей»: высший государственный аппарат (ENA, Государственный совет), руководство политической партией (UMP), затем международный частный сектор — и возвращение в политику. Debevoise представляет компании из списка Fortune 500 и инвестиционные фонды, что позволило Филиппу выстроить сеть в международных деловых кругах. Фирма присутствует в Гонконге и Шанхае — нервных центрах азиатской торговли, — что становится значимым в свете последующих китайско-французских связей окружения Филиппа. После Debevoise Филипп перешёл в Areva директором по публичным делам (лоббирование), подтвердив свою укоренённость в экономических кругах влияния. Цепочка: Государственный совет → UMP → Debevoise → Areva → мэрия → Матиньон — прослеживает путь, где каждый этап обогащает контактную книгу для следующего. Эпизод в Debevoise — англосаксонская скобка в этой по существу французской карьере. Гонорары и дела, которыми он занимался в Debevoise, так и не были преданы огласке.",
    "antoine-rufenacht": "Антуан Рюфено — мэр Гавра с 1995 по 2010 год, бывший выпускник ENA и фигура нормандских правых. Именно он идентифицировал Эдуара Филиппа как потенциального преемника и ввёл его в политику в 2001 году, включив в свой муниципальный список на должность заместителя по правовым вопросам. Затем Рюфено рекомендовал Филиппа Алену Жюппе на должность генерального директора UMP в 2002 году, тем самым запустив его национальную карьеру. Когда Рюфено ушёл в отставку с поста мэра в 2010 году, муниципальный совет избрал Филиппа его преемником — идеально срежиссированная передача местной власти. Кристин Пуайе-Рюфено, адвокат с той же фамилией, что и бывший мэр, была отобрана в когорту 2011 года «Молодых лидеров» FAF вместе с Филиппом — совпадение, которое так и не получило публичного объяснения. Рюфено руководил Гавром на протяжении пятнадцати лет, формируя местную политическую и экономическую сеть, доставшуюся Филиппу в наследство. При Рюфено Гавр провёл городскую трансформацию вокруг порта и архитектуры Перре, внесённой в список Всемирного наследия ЮНЕСКО. Отношения Рюфено–Филипп — хрестоматийный случай местной политической преемственности: наставник выявляет, воспитывает и устанавливает своего протеже во главе города. Укоренённость Филиппа в Гавре — мэрия, порт, городское сообщество — напрямую унаследована от сети Рюфено. Тот факт, что местный наставник и трансатлантическая сеть (FAF) сходятся вокруг одной и той же фамилии, поднимает вопросы о механизмах кооптации во французской элите.",
    "french-american-foundation": "French-American Foundation (FAF) — организация, основанная в 1976 году под эгидой президентов Джеральда Форда и Валери Жискар д'Эстена. Её программа Young Leaders, созданная в 1981 году, ежегодно отбирает десять французов и десять американцев в возрасте от 30 до 40 лет из высшего государственного аппарата, бизнеса, СМИ, армии и научных кругов. Участники посещают два пятидневных семинара в течение двух последовательных лет, чередуя Францию и США. Содержание семинаров не публикуется — FAF не раскрывает повестки прошедших мероприятий. По завершении программы участники вступают в сеть выпускников численностью более 600 человек. Программу регулярно описывают как инструмент американской «мягкой силы», хотя FAF позиционирует себя как «не мозговой центр, не лоббистская организация и не парламентская группа дружбы». Присутствие «Молодых лидеров» во французском правительстве примечательно и выходит за рамки политических чередований. Эдуар Филипп принадлежит к когорте 2011 года, Эмманюэль Макрон — к 2012-й, Ален Жюппе — к основавшей когорте 1982-го, Франсуа Олланд — к когорте 1996-го. Ришар Ферран, министр правительства Филиппа, был «Молодым лидером» 2005 года. Более 400 руководителей воспользовались программой с 1981 года, и тот факт, что президент и его премьер-министр вышли из последовательных когорт, не имеет прецедента в истории FAF. Спонсоры программы — Airbus, J.P. Morgan и Sodexo.",
    "david-barroux": "Давид Барру — журналист и главный редактор экономической газеты Les Échos, одного из ведущих деловых изданий Франции. Он входил в когорту «Молодых лидеров» 2011 года French-American Foundation вместе с Эдуаром Филиппом. Его позиция во главе авторитетного экономического СМИ даёт ему значительное влияние на освещение французской экономической политики. Les Échos принадлежит группе LVMH Бернара Арно, что вписывает Барру в медийную экосистему, связанную с крупными французскими состояниями. Как «Молодой лидер», он участвовал вместе с Филиппом в двух пятидневных семинарах 2011–2012 годов, установив прочные личные и профессиональные связи. Конвергенция будущего премьер-министра и главного редактора крупной ежедневной газеты в одной трансатлантической сети заслуживает внимания. Les Échos в целом освещала реформы правительства Филиппа благосклонно, особенно в части Трудового кодекса и закона PACTE. Эта близость иллюстрирует переплетение политических и медийных элит Франции в одних и тех же сетях влияния. Барру представляет медийный столп когорты 2011 года. FAF не публикует переписку, имевшую место между этими будущими руководителями на семинарах.",
    "yohann-benard": "Йоанн Бенар — директор по публичным делам Amazon France на момент его отбора в «Молодые лидеры» 2011 года. Он разделяет когорту FAF с Эдуаром Филиппом, тогда мэром Гавра и директором по публичным делам Areva. Оба занимают схожие должности — лоббирование и институциональные отношения: один в ядерном гиганте, другой — в американском гиганте электронной торговли. Amazon — одна из наиболее спорных компаний во Франции из-за своей социальной и налоговой практики и влияния на местную торговлю. Бенар отвечает за защиту интересов Amazon перед французскими выборными должностными лицами и органами власти. Участвуя в элитной трансатлантической сети с будущим премьер-министром, он получает привилегированный доступ к кругам принятия решений. Правительство Филиппа не стало особо ужесточать налогообложение GAFA за три года в Матиньоне, несмотря на соответствующие обещания. Одновременное присутствие в когорте 2011 года лоббиста Amazon и лоббиста Areva, ставшего впоследствии премьер-министром, наглядно демонстрирует проницаемость границы между корпоративными интересами и политической властью. Семинары FAF предоставили неформальную площадку для выстраивания этих связей. Бенар представляет американский корпоративный столп когорты.",
    "stephane-israel": "Стефан Израэль был отобран как «Молодой лидер» 2011 года, в том же году, что и Эдуар Филипп. В дальнейшем он стал исполнительным президентом Arianespace — мирового лидера в сфере коммерческих космических запусков, дочерней компании ArianeGroup (совместного предприятия Airbus/Safran). До Arianespace Израэль был руководителем кабинета министра высшего образования и исследований Женевьев Фьорасо (2012–2014) при президенте Олланде. Он воплощает типичный профиль «вращающихся дверей» между высшим государственным аппаратом и стратегической промышленностью. Его траектория — министерский аппарат, затем руководство государственным предприятием — сопоставима с траекторией Филиппа (Государственный совет, Areva, политика). Arianespace — ключевой игрок европейского космического суверенитета, и её президент по необходимости поддерживает тесные отношения с французской исполнительной властью. Присутствие Израэля в той же когорте «Молодых лидеров», что и Филипп, создаёт поперечный канал между ядерной и космической промышленностями и политической властью. Airbus, материнская компания ArianeGroup, является одним из спонсоров программы Young Leaders FAF. Эти взаимосвязи между спонсорами программы и отобранными участниками поднимают вопросы о независимости отборочного процесса. Израэль представляет стратегический промышленный столп когорты 2011 года.",
    "christine-poyer-rufenacht": "Кристин Пуайе-Рюфено — партнёр-адвокат, отобранная в когорту 2011 года «Молодых лидеров» FAF вместе с Эдуаром Филиппом. Её фамилия неизбежно вызывает ассоциации с Антуаном Рюфено — мэром Гавра, вывевшим Филиппа в политику в 2001 году, — тревожащая омонимия, которую официальные биографии не комментируют. Антуан Рюфено был местным наставником Филиппа: он дал ему первое место в муниципальном списке, а затем рекомендовал Алену Жюппе на должность генерального директора UMP. Присутствие в одной когорте «Молодых лидеров» протеже Рюфено и человека с той же фамилией вызывает вопросы о механизмах кооптации внутри этих сетей. FAF не публикует детальных критериев отбора, а процедура подачи заявок отчасти опирается на поручительство. Если Кристин Пуайе-Рюфено является родственницей Антуана Рюфено, это составило бы случай семейной и политической сети, воспроизводящей себя внутри трансатлантического института. Как минимум, совпадение фамилий иллюстрирует узость кругов, в которых вращается французская элита, отбираемая FAF. Гавр предстаёт повторяющимся узлом в этих сетях: Филипп, Рюфено, CMA CGM. Эта связь заслуживает тщательного расследования. Непрозрачность FAF в отношении своих процессов делает проверку затруднительной.",
    "estelle-youssouffa": "Эстель Юссуффа сегодня является депутатом Национального собрания от первого округа Майотта, избранным в 2022 году. Она была отобрана в когорту «Молодых лидеров» 2011 года вместе с Эдуаром Филиппом. До прихода в политику Юссуффа работала журналистом, в частности на France 24 и Al Jazeera, что относит её к медийному столпу программы. Её траектория — от международной журналистики к парламентскому представительству — иллюстрирует классический путь «Молодых лидеров» к должностям власти. Как депутат, она заседает в Национальном собрании, где группа Horizons Эдуара Филиппа также имеет представителей, создавая возможности для парламентских альянсов между бывшими членами одной когорты. Майотта — территория, сталкивающаяся с серьёзными вызовами (миграция, безопасность, развитие), которые регулярно становятся предметом общенациональных дискуссий. Присутствие Юссуффа и Филиппа в одной когорте FAF устанавливает связь между заморскими проблемами и сетью Филиппа. Программа Young Leaders исторически формировала прочные связи между своими участниками, которые впоследствии оказываются на влиятельных позициях в различных сферах. Эта динамика когорты — один из наиболее действенных механизмов сети. Юссуффа представляет заморский и медийный столп когорты 2011 года.",
    "richard-ferrand": "Ришар Ферран — французский политик, бывший президент Национального собрания (2018–2022) и бывший министр территориальной сплочённости в первом правительстве Эдуара Филиппа (май–июнь 2017 года). Он является «Молодым лидером» когорты 2005 года, на шесть лет раньше Филиппа. Ферран был одним из первых сторонников Эмманюэля Макрона и сооснователем движения «Вперёд» (En Marche) в 2016 году. Будучи министром Филиппа, а затем президентом Собрания, он стал важнейшим звеном в макронистской системе, в которой действовал Филипп. Его когорта Young Leaders 2005 года вписывает его в ту же трансатлантическую сеть, что и Филипп (2011), Макрон (2012) и Жюппе (1982). Тот факт, что министр территориальной сплочённости и премьер-министр оба являлись бывшими «Молодыми лидерами», иллюстрирует плотность этой сети внутри правительства. В 2019 году Ферран был привлечён к уголовной ответственности за незаконный конфликт интересов в недвижимостном деле — Mutuelles de Bretagne. В 2023 году дело было прекращено. Его судебная история показывает, что членство в сети Young Leaders не обязательно защищает от уголовного преследования. Тем не менее конвергенция «Молодых лидеров» на вершинах исполнительной и законодательной власти заслуживает критического осмысления.",
    "francois-hollande": "Франсуа Олланд, президент Республики с 2012 по 2017 год, является «Молодым лидером» когорты FAF 1996 года вместе с Пьером Московичи. Его участие в программе за пятнадцать лет до Филиппа иллюстрирует непрерывность сети через политические поколения и чередования власти. Олланд назначил Мануэля Вальса, затем Бернара Казнёва премьер-министрами, но именно его преемник Макрон (YL 2012) назначил Филиппа (YL 2011). Цепочка президентской преемственности Олланд–Макрон, таким образом, является внутренней цепочкой сети Young Leaders. Олланд был первым секретарём PS в течение одиннадцати лет (1997–2008) до прихода к власти, что позволило ему сформировать разветвлённую политическую сеть. В его когорту 1996 года входил Пьер Московичи, будущий еврокомиссар, а затем председатель Счётной палаты, — что иллюстрирует разнообразие должностей, занимаемых бывшими «Молодыми лидерами». Программа FAF произвела двух президентов Республики (Олланда и Макрона), как минимум четырёх премьер-министров (Жюппе, Филиппа и косвенно других) и многочисленных министров. Эта концентрация власти, исходящей из одной отборочной программы, поднимает демократические вопросы о формировании правящей элиты Франции. Олланд неоднократно критиковал Филиппа после 2017 года, однако они разделяют одну и ту же структурную сеть.",
    "laurent-wauquiez": "Лоран Вокьез, президент региона Овернь–Рона–Альпы и бывший председатель Les Républicains (2017–2019), является «Молодым лидером» когорты 2006 года. Он представляет правое крыло той же трансатлантической сети, что и Эдуар Филипп. Оба столкнулись внутри LR, прежде чем Филипп примкнул к Макрону в 2017 году. Вокьез резко критиковал назначение Филиппа в Матиньон, называя его предательством правых. Несмотря на политическое соперничество, они разделяют один и тот же элитный образовательный путь — ENA для обоих, Young Leaders для обоих. Вокьез считается потенциальным кандидатом на президентские выборы 2027 года, что сделало бы его прямым соперником Филиппа из той же сети. То, что два потенциальных кандидата в президенты являются бывшими «Молодыми лидерами», иллюстрирует способность программы производить будущих руководителей страны вне зависимости от политической принадлежности. Когорта 2006 года Вокьеза помещает его между поколениями Феррана (2005) и Филиппа (2011) в хронологии сети. Его политическая траектория — от государственного секретаря при Саркози до президента региона — демонстрирует путь, параллельный пути Филиппа, но в более правом регистре. Семинары FAF, вероятно, позволили Вокьезу и Филиппу пересечься через сеть выпускников ещё до их публичного политического противостояния.",
    "fleur-pellerin": "Флёр Пеллерен была отобрана в когорту «Молодых лидеров» 2012 года — в том же году, что и Эмманюэль Макрон. В то время она являлась министром-делегатом по делам МСП, инновациям и цифровой экономике при Олланде, прежде чем стать министром культуры (2014–2016). Её когорта 2012 года непосредственно следует за когортой Филиппа (2011), а значит, семинары двух когорт потенциально пересекались: второй семинар Филиппа в 2012 году мог совпасть с первым семинаром Пеллерен и Макрона. Пеллерен — выпускница ENA (когорта Сенгора, 2000), школы, неизменно присутствующей в профилях «Молодых лидеров». После министерства она основала венчурный фонд Korelya Capital, специализирующийся на инвестициях в Азии, — создав мост между трансатлантическими (FAF) и азиатскими сетями, что перекликается с France China Foundation. Пеллерен родилась в Южной Корее и была усыновлена во Франции, что придаёт ей двукультурный профиль, ценимый FAF. Её послеминистерская траектория в сторону азиатского венчурного капитала иллюстрирует, как связи, сформированные в элитных сетях, трансформируются в экономические возможности. Когорта 2012 года, включающая также Макрона и Седрика Виллани, является одной из наиболее политически влиятельных в истории программы.",
    "laphonza-butler": "Лафонза Батлер — американский политик, назначенная сенатором от Калифорнии в октябре 2023 года губернатором Гэвином Ньюсомом на место сенатора Дайэнн Файнстайн. Она входила в когорту «Молодых лидеров» 2011 года — на американской стороне, рядом с Эдуаром Филиппом на французской. До Сената Батлер была президентом SEIU Local 2015 — крупнейшего профсоюза работников здравоохранения в Калифорнии (400 000 членов). Затем она возглавила EMILYs List — демократическую организацию поддержки феминистских кандидатов. Её назначение в Сенат иллюстрирует траекторию американских «Молодых лидеров» к высшим должностям. Тот факт, что американский сенатор и бывший французский премьер-министр прошли подготовку вместе в одной трансатлантической программе, создаёт прямой канал влияния между Сенатом США и французской политикой. Батлер провела время с Филиппом в ходе двух пятидневных семинаров 2011–2012 годов, установив прочные личные связи. Программа Young Leaders создана именно для того, чтобы строить такие мосты между будущими руководителями двух стран. Батлер представляет американский прогрессивный политический столп когорты 2011 года. Её присутствие иллюстрирует способность FAF идентифицировать будущих лидеров задолго до их прихода к высшим должностям.",
    "horizons": "Horizons — политическая партия, основанная Эдуаром Филиппом 9 октября 2021 года на публичном митинге в Гавре, его политической вотчине. Партия позиционирует себя в правоцентристском спектре, воплощая правое крыло макронистского президентского большинства. Четыре центральные темы: демография, экология, геополитика и технологии, под девизом «Видеть далеко, чтобы действовать верно». Эмманюэль Макрон был недоволен созданием Horizons бывшим премьер-министром, называющим себя «лояльным, но свободным». В январе 2022 года партия вошла в коалицию Ensemble Citoyens. Кристиан Эстрози, мэр Ниццы, стал её вторым номером, придав партии, укоренённой в Нормандии, средиземноморскую опору. На законодательных выборах 2022 года Horizons получила 58 выдвижений в рамках коалиции и сформировала парламентскую группу «Horizons et indépendants» примерно из тридцати депутатов под руководством Лорана Маркантьели. После роспуска парламента в 2024 году партия сохранила лишь 6 мест. В марте 2026 года Horizons заявила о 465 зарегистрированных мэрах по всей стране — местная сеть, составляющая хребет президентской кампании Филиппа 2027 года. Партия функционирует как личный избирательный механизм: её единственная стратегическая цель — провести Филиппа в Елисейский дворец. Руководящие кадры партии в основном вышли из гаврской и жюппеистской сетей Филиппа.",
    "christian-estrosi": "Кристиан Эстрози является мэром Ниццы с 2008 года (с перерывом в 2014–2017 годах, когда он был президентом региона ПАКА) и вторым номером партии Horizons Эдуара Филиппа. Бывший министр промышленности при Саркози (2009–2010) и фигура провансальских правых, Эстрози привносит в Horizons южную опору, дополняющую нормандский базис Филиппа. Его присоединение к Horizons в 2021 году стало крупным политическим успехом: он покинул LR ради центристской партии, увлекая за собой часть ниццского и лазурного правого электората. Ницца — пятый по величине город Франции и крупный туристический и экономический центр, что придаёт Эстрози значительный политический вес внутри партии. Эстрози был отмечен терактом в Ницце 14 июля 2016 года (86 погибших), который он урегулировал в качестве президента метрополии, — событием, сформировавшим его образ антикризисного управленца. Он женат на Лоре Тенуджи, журналисте, что обеспечивает ему дополнительную медийную заметность. Внутри Horizons Эстрози выполняет роль вербовщика среди депутатов LR, привлечённых центром-правым. Его траектория иллюстрирует стратегию Филиппа: поглощение правых кадров, разочарованных дрейфом LR в сторону жёстких правых. Дуэт Филипп (Нормандия) / Эстрози (ПАКА) придаёт Horizons двухрегиональную базу, которая будет определять президентскую кампанию 2027 года. Эстрози является также вице-президентом объединения «Intercommunalités de France», что обеспечивает ему территориальную сеть, дополняющую сеть Филиппа.",
    "gilles-boyer": "Жиль Буайе — ближайший советник Эдуара Филиппа на протяжении более двадцати лет, сформировавшийся в орбите Жюппе. Директор кабинета Жюппе в мэрии Бордо (2002–2004, 2006–2010), затем директор кампании Жюппе на праймериз 2016 года (Филипп был со-спикером). Соавтор с Филиппом двух политических романов (L'heure de vérité, 2007; Dans l'ombre, 2011) и книги Impressions et lignes claires (2021). Специальный советник Филиппа в Матиньоне (2017–2019). Ныне депутат Европарламента от Renaissance. Один из сторонников Саркози прозвал их «Плик и Плок» (Буайе и Филипп) — настолько неразрывен был их тандем. Буайе соединяет наследие Жюппе с механизмом Horizons: он — хранитель филиппистской доктрины и архетип советника в тени, влияющего на каждую политическую ориентацию. Внутренний круг «Жюппе».",
    "christophe-castaner": "Кристоф Кастанер был назначен министром внутренних дел Эдуаром Филиппом в октябре 2018 года — после самого длительного периода временного исполнения обязанностей на площади Бово в Пятой республике, последовавшего за отставкой Жерара Коллома. Его назначение произошло за месяц до начала движения «жёлтых жилетов», что сделало его непосредственно ответственным за наиболее оспариваемую доктрину поддержания порядка со времён Мая 1968 года. Кастанер назвал демонстрантов «мятежниками, пришедшими убивать», легитимизируя несоразмерный силовой ответ. Под его руководством использование резиновых пуль (LBD40) выросло более чем на 200% по сравнению с предыдущим годом. Человеческие жертвы оказались беспрецедентными: 25 человек лишились глаз, 5 лишились кисти руки, 432 получили тяжёлые ранения. ООН, Совет Европы и Amnesty International потребовали запрета этих видов оружия. Кастанер систематически игнорировал сообщения о полицейском насилии и отказывался приостановить применение LBD. Как министр Филиппа, его доктрина напрямую вовлекала ответственность премьер-министра. В IGPN поступило 313 судебных запросов по подозрению в полицейском насилии — рекордный показатель. Ранее Кастанер являлся генеральным делегатом LREM, что иллюстрирует слияние макронистского аппарата с силовым под руководством правительства Филиппа.",
    "benoit-ribadeau-dumas": "Бенуа Рибадо-Дюма, лучший в выпуске когорты ENA Марка Блока (1997), однокурсник Филиппа. Директор кабинета в Матиньоне (2017–2020) — выбран вопреки воле Макрона, желавшего провести Николя Ревеля. Прозван «Ватиканом» за жёсткость. Член FCF (учредительная когорта 2013 года вместе с Филиппом и Макроном). До Матиньона: заместитель руководителя кабинета Саркози в Елисейском дворце (2011–2012), заместитель генерального секретаря при Олланде — карьера, преодолевающая политические чередования. Операционный архитектор всех решений правительства Филиппа: трудовые ордонансы, ограничение скорости до 80 км/ч, «жёлтые жилеты», пенсионная реформа, Ковид. Выступал за сохранение первого тура муниципальных выборов 15 марта 2020 года. После Матиньона перешёл в Exor (семейный офис Элькана/Аньелли), вошёл в советы директоров Stellantis и Iveco. Внутренний круг «Жюппе» — узел, связывающий сеть ENA, FCF и исполнительную власть.",
    "france-china-foundation": "France China Foundation (FCF) — организация, основанная в 2012 году для сближения французских и китайских правящих элит. В её стратегический совет входят Жан-Пьер Раффарен, Лоран Фабюс и Ален Мерьё (архитектор лаборатории P4 в Ухане). Её официальный китайский партнёр — CPIFA (Chinese People's Institute of Foreign Affairs), связанный с МИД КНР. Учредительная когорта 2013 года объединила Филиппа, Макрона и Рибадо-Дюма. В 2015 году Филипп принял делегацию FCF в Гавре для посещения порта. В мае 2018 года он присутствовал на ежегодном приёме в Версале в качестве премьер-министра и бывшего «Молодого лидера». Непрозрачность FCF сопоставима с непрозрачностью FAF: повестки заседаний не публикуются, публичных отчётов нет. Одновременное существование сетей FAF (трансатлантической) и FCF (китайско-французской) вокруг одного ядра — Филипп, Рибадо-Дюма, Ленен — создаёт беспрецедентную двухполюсную систему влияния в Матиньоне. Вильпен не фигурирует ни в одном пространстве FCF — его китайская сеть личная и частная, не институциональная.",
    "emmanuel-lenain": "Эмманюэль Ленен — профессиональный дипломат, сооснователь France China Foundation в 2012 году и дипломатический советник Эдуара Филиппа в Матиньоне с 2017 по 2020 год. Эта двойная роль — архитектор китайско-французской сети и советник премьер-министра — делает его живым мостом между трансатлантическими (FAF) и азиатскими (FCF) сетями в центре исполнительной власти. До Матиньона Ленен занимал ряд стратегических дипломатических постов, в частности при постоянном представительстве Франции в ООН. После работы в Матиньоне он был назначен послом Франции в Индии (2019–2022) — пост, вписывающий его в стратегический треугольник Франция–Китай–Индия. Его создание FCF в 2012 году, через год после отбора Филиппа в «Молодые лидеры» FAF, предполагает намеренную стратегию выстраивания дополняющих друг друга двусторонних сетей влияния. Как дипломатический советник Филиппа, Ленен имел доступ ко всем международным переговорам правительства, включая касающиеся Китая и морских торговых путей. Гавр, главный порт Франции и политическая вотчина Филиппа, непосредственно затрагивается вопросами китайско-французской торговли и инициативы «Пояс и путь» (Новые Шёлковые пути). Позиция Ленена на пересечении FCF, Матиньона и азиатской дипломатии иллюстрирует, как один человек может служить приводным ремнём между дипломатическими, экономическими и политическими интересами. Его последующая карьера — посольство в Индии, затем должности в Кэ д'Орсе — подтверждает его траекторию в рамках французского дипломатического аппарата, ориентированного на Азию. Ленен — недостающее звено, связывающее сеть «Молодых лидеров» Филиппа с китайско-французской сетью.",
    "port-du-havre": "Порт Гавра — крупнейший контейнерный порт Франции и пятый в Европе. С 2021 года он входит в состав комплекса HAROPA (Гавр, Руан, Париж) — крупнейшей портовой группы Франции. Édouard Philippe является его мэром с 2010 года, что даёт ему прямое влияние на стратегическое развитие порта и городского сообщества Le Havre Seine Métropole. CMA CGM, ведущая французская судоходная компания, обрабатывает там значительную долю контейнерного трафика, с прямыми линиями в Шанхай, Нинбо, Шэньчжэнь и крупнейшие азиатские порты. Французско-китайская морская торговля через Гавр составляет миллиарды евро ежегодно. Порт также затрагивает китайская инициатива «Один пояс, один путь», цель которой — связать европейскую портовую инфраструктуру с китайской логистической сетью. По данным Европола, Гавр является главным пунктом ввоза кокаина в Европу. Изъятия наркотиков там резко возросли: в 2023 году французская таможня конфисковала 18 тонн кокаина — рекордный показатель. Ответственность за портовую безопасность разделена между государством, таможенными органами и портовыми властями — сфера, в которой пересекаются интересы CMA CGM (через Яна Ле Гоффа, безопасность), мэрии (Philippe) и сетей влияния (FAF, FCF). Расширение порта и инвестиции в контейнерные терминалы — важнейшие экономические вопросы для региона, где Philippe на протяжении пятнадцати лет пользуется безраздельной политической поддержкой. Вопрос портового управления — кто принимает решения об инвестициях, концессиях, проверках — находится в центре связки Philippe–CMA CGM–FCF.",
    "jean-pierre-raffarin": "Жан-Пьер Раффарен, премьер-министр при Шираке (2002–2005), является связующим звеном между китайскими сетями Philippe и Villepin. Он занимает несравнимое по числу количество китайских должностей: член «совета советников» Боаоского форума (азиатский Давос), форума «Один пояс, один путь», член совета директоров CEIBS Shanghai, сопредседатель Sino-International Entrepreneurs Federation, ведущий программ на CGTN (китайское государственное телевидение), специальный представитель правительства Франции по Китаю (с 2018 года), со-покровитель FCF и президент Comité France-Chine. 29 сентября 2019 года Си Цзиньпин вручил ему медаль ордена Дружбы — высшее китайское отличие для иностранца, разделяемое с Путиным и Кастро. DGSI вызвала его на «ознакомительную беседу» летом 2018 года из-за его контактов с китайскими бизнесменами, считающимися агентами Партии. Его Fondation Prospective et Innovation (FPI) располагает бюджетом в 3,5 миллиона евро, финансируемым примерно тридцатью компаниями (Carrefour, Kering, L'Oréal, LVMH), и получила 85 000 евро от бывшего китайского посла У Цзяньминя. В 2022 году Раффарен вступил в Horizons — его двойная роль (официальный представитель по Китаю И член партии Philippe) не имеет аналогов. Causeur отмечает, что Раффарен и Villepin прошли «зеркальными путями» в своей китайской переориентации после Матиньона.",
    "rodolphe-saade": "Родольф Саадé является президентом-директором CMA CGM с 2017 года, сменив своего отца Жака Саадé, основавшего группу в 1978 году. Под его руководством CMA CGM стала третьей по величине судоходной компанией в мире с оборотом, превысившим 70 миллиардов евро в 2022 году. Саадé диверсифицировал группу за пределы морского транспорта: приобретение CEVA Logistics (логистика), покупка La Tribune и La Provence (СМИ), инвестиции в технологии. Группа Саадe имеет ливанское происхождение, базируется в Марселе и поддерживает крупные коммерческие связи с Китаем — маршруты Азия-Европа составляют ядро деятельности CMA CGM. Порт Гавра, вотчина Édouard Philippe, является одним из главных европейских хабов CMA CGM. Ян Ле Гофф, руководитель службы безопасности CMA CGM и Young Leader 2011 вместе с Philippe, действует непосредственно под руководством дирекции Саадe. Состояние Родольфа Саадe оценивается в более чем 40 миллиардов евро, что делает его одним из крупнейших состояний Франции. Его экспансия в СМИ (La Tribune, La Provence, BFM Marseille) придаёт ему медийное влияние в дополнение к экономическому весу. CMA CGM является центральным игроком в китайской инициативе «Один пояс, один путь», с портовыми партнёрствами в Средиземноморье, Африке и Юго-Восточной Азии. Совпадение империи Саадe, порта Гавра под управлением Philippe и сетей FCF Рибадо-Дюма представляет собой узел экономических и политических интересов значительного масштаба.",
    "belt-and-road": "Инициатива «Один пояс, один путь» (BRI), запущенная Си Цзиньпином в 2013 году, является крупнейшей инфраструктурной программой в истории, с расчётными инвестициями свыше 1 триллиона долларов в Азии, Африке и Европе. Морской сегмент BRI — «Морской Шёлковый путь XXI века» — нацелен на соединение китайских портов с европейскими посредством инвестиций в терминалы, логистику и портовые концессии. В Европе Китай инвестировал в порты Пирей (Греция, через COSCO), Гамбург, Антверпен и Валенсию. Порт Гавра, крупнейший контейнерный порт Франции и вотчина Édouard Philippe, непосредственно затронут этой стратегией. CMA CGM, чьи маршруты Азия-Европа составляют ядро деятельности, является одновременно конкурентом и потенциальным партнёром китайских судоходных компаний COSCO и OOCL. France China Foundation, чей член Рибадо-Дюма служил начальником кабинета Philippe в Матиньоне, действует в этом пространстве, где китайская экономическая дипломатия стремится установить точки влияния на европейских лиц, принимающих решения. BRI критиковалась как инструмент «долговой дипломатии» и китайского геополитического влияния. То обстоятельство, что французский премьер-министр был окружён в Матиньоне людьми, вписанными в китайско-французские сети (FCF), будучи при этом мэром важнейшего французского порта на китайском морском пути, создаёт беспрецедентное совпадение интересов. Италия подписала меморандум BRI в 2019 году, прежде чем отказаться от него в 2023 году — Франция при Philippe никогда не подписывала, но придерживалась неоднозначной позиции. Вопрос портового суверенитета перед лицом китайских инвестиций — стратегическая проблема, непосредственно касающаяся Гавра.",
    "cosco-shipping": "COSCO Shipping — ведущая китайская судоходная компания и четвёртая в мире, принадлежащая китайскому государству через SASAC (Комитет по надзору и управлению государственными активами). COSCO эксплуатирует более 1 300 судов и обслуживает более 300 портов по всему миру. В Европе COSCO приобрела 67 % порта Пирей в Греции (2016), демонстрируя китайскую стратегию захвата стратегических портовых инфраструктур. COSCO и CMA CGM являются одновременно конкурентами и партнёрами в рамках морского альянса Ocean Alliance, охватывающего маршруты Азия-Европа — те же маршруты, которые проходят через Гавр. Этот альянс означает, что контейнеры CMA CGM и COSCO используют одни и те же суда и терминалы, в том числе в Гавре. Присутствие COSCO в европейских портах вызвало опасения в области национальной безопасности и суверенитета. В 2022 году Германия заблокировала долю COSCO в гамбургском терминале выше 24,9 %. Для Гавра встаёт вопрос: в какой мере китайские инвестиции в конкурирующих портах влияют на стратегию важнейшего французского порта? France China Foundation, чьи члены окружают Philippe в Матиньоне, действует именно в этом пространстве китайско-европейской портовой дипломатии. Переплетение Ocean Alliance (COSCO + CMA CGM), сетей FCF и мэрства Philippe в Гавре образует совокупность интересов, заслуживающих тщательного изучения. COSCO является инструментом китайской политики «Один пояс, один путь» в морской сфере.",
    "comite-france-chine": "Comité France-Chine, приписанный к MEDEF International, является главным лоббистским органом французского предпринимательства в отношении Китая. Под председательством Жан-Пьера Раффарена он действует в синергии с France China Foundation: Комитет работает на уровне предприятий, FCF — на уровне отдельных лиц. Присутствие Раффарена во главе Комитета и в качестве покровителя FCF создаёт мост между официальной экономической дипломатией и неформальными сетями влияния. В число членов входят группы CAC 40, активные в Китае: Airbus, Total, L'Oréal, Sanofi, а также портовые и логистические игроки. Рибадо-Дюма (начальник кабинета Philippe, FCF 2013) и Ленен (сооснователь FCF, дипломатический советник) оба функционировали в этой экосистеме.",
    "alexis-kohler": "Алексис Колер (р. 1972 в Страсбурге) — выпускник ЭНА, директор кабинета в Министерстве экономики при Макроне (2014), затем генеральный секретарь Елисейского дворца (2017-2025) — правая рука Эмманюэля Макрона в течение восьми лет. В марте 2022 года ему было предъявлено официальное обвинение в незаконном получении выгоды, торговле влиянием и пассивной коррупции за его конфликты интересов с MSC (Mediterranean Shipping Company), основанной семьёй Апонте — двоюродными братьями его матери. С 2010 по 2012 год Колер входил в наблюдательный совет Grand Port Maritime du Havre (GPMH) в качестве представителя Agence des participations de l'État, рядом с Эдуаром Филиппом (мэром с октября 2010 года). По данным Mediapart, Колер никогда не декларировал свои семейные связи с MSC и не воздерживался при голосованиях по вопросам, касающимся MSC, тогда как Филипп скрупулёзно соблюдал правила отвода. Колер функционирует как агент-ось: Инспекция финансов → APE/GPMH (рядом с Филиппом) → кабинет Макрона (Bercy) → MSC (вращающаяся дверь) → Елисейский дворец (SG) → Société Générale (2025). Этот круговорот иллюстрирует механизм возрастающей отдачи от записной книжки. Порт Гавра, где Колер и Филипп работали бок о бок, является геостратегическим узлом: хаб CMA CGM (3-й крупнейший судоходный концерн мира), клиент MSC (2-й по величине, семья Колера), связанный с COSCO Shipping (1-й китайский судоходный концерн, побратимство с Далянем), под политическим управлением Филиппа. В 2025 году Колер покинул Елисейский дворец ради Société Générale, продолжая круговорот вращающейся двери между государством и финансами.",
    "sibyle-veil": "Сибиль Вейль является президентом Radio France с апреля 2018 года, назначенная CSA (ныне Arcom), члены которой испытывают влияние исполнительной власти. Она происходит из выпуска Леопольда Седара Сенгора ЭНА (2004) — того же выпуска, что и Эммануэль Макрон. Эта корпоративная солидарность — одна из наиболее прочных связей в системе высшей французской государственной службы — напрямую соединяет президентство ведущего общественного радио с президентом Республики. Под её руководством France Inter оставалась самой прослушиваемой радиостанцией Франции с её политическим утренним выпуском. Интервью Édouard Philippe на France Inter характеризуются благожелательным тоном и систематическим отсутствием вопросов по чувствительным делам: связи с CMA CGM, France China Foundation, дело Atos. Вейль была обновлена в 2022 году, подтвердив доверие правительства Макрона. До Radio France она была советником в Conseil d'État и работала в Cour des comptes. Её карьерный путь — ЭНА → Conseil d'État → руководство государственным СМИ — является архетипом французской системы, в которой одни и те же выпуски контролируют исполнительную и медийную власть. Цепочка Macron (президент) → Arcom (назначение) → Veil (руководство) → France Inter (редакционная политика) иллюстрирует косвенный контроль над общественным вещанием. Radio France ежедневно охватывает около 15 миллионов слушателей.",
    "bernard-arnault": "Бернар Арно является президентом-директором LVMH, богатейшим человеком мира с расчётным состоянием свыше 200 миллиардов евро. Он является владельцем группы Les Échos–Le Parisien, включающей деловую газету Les Échos, главным редактором которой Давид Барру является Young Leader 2011 вместе с Édouard Philippe. Арно считается ближайшим олигархическим союзником Эммануэля Макрона, с которым он поддерживает задокументированные личные отношения. LVMH является ведущим рекламодателем Франции, что обеспечивает ему косвенное влияние на все французские СМИ. Освещение Les Échos систематически благоприятно по отношению к экономическим реформам Philippe (трудовые ордонансы, закон PACTE). Le Parisien, самая читаемая народная газета Île-de-France, дополняет медийный арсенал, охватывая более широкую аудиторию. Арно открывал несколько архитектурных проектов совместно с Макроном и Philippe. Совпадение богатейшего человека мира, президента, назначившего Philippe, и главного редактора — Young Leader образует треугольник власть-деньги-медиа. LVMH имеет крупные коммерческие интересы в Китае, что связывает Арно с китайско-французской сетью через каналы, отличные от FCF. Тот факт, что владелец ведущего делового СМИ Франции является также главным финансовым спонсором президента, назначившего Philippe, создаёт структурный медийный конфликт интересов.",
    "vincent-bollore": "Венсан Болоре — бретонский промышленник, создавший медиаимперию через Vivendi: Canal+, CNews, C8, Europe 1, Paris Match, Le Journal du Dimanche. Его постепенное поглощение этих СМИ начиная с 2015 года сопровождалось редакционной переориентацией вправо и к крайне правым, с такими фигурами, как Эрик Земмур, Паскаль Про и Лоранс Феррари. CNews стала «французским Fox News». В политической игре Болоре является «делателем королей»: его канал обеспечил медийный взлёт Земмура как кандидата в президенты в 2022 году. Для Philippe CNews играет парадоксальную роль: канал представлял его как «разумную» альтернативу RN, обслуживая макронистский нарратив республиканского барьера. Europe 1, под контролем Болоре через Lagardère, была переориентирована к линии, совместимой с центристско-правым курсом Philippe. Болоре также имеет огромные интересы в Африке (Bolloré Africa Logistics, порты) и Азии, что связывает его с проблемами морского транспорта и китайско-африканскими сетями. Его африканская логистическая империя была продана CMA CGM (MSC) в 2022 году, создав прямую связь между Болоре и группой Саадe. Медийная концентрация между Арно (Les Échos, Le Parisien), Болоре (CNews, Europe 1) и Саадe/CMA CGM (BFM TV) означает, что три ведущих информационных СМИ Франции принадлежат олигархам, близким к макронистской власти.",
    "patrick-drahi": "Патрик Драи — французско-израильский бизнесмен, основатель Altice, который владел BFM TV, RMC и Libération вплоть до продажи своих медийных активов CMA CGM (Родольфу Саадe) в 2024 году. Эта сделка является ключевой в цепочке конфликтов интересов: BFM TV, ведущий французский новостной канал непрерывного вещания, перешёл от владельца, окружённого финансовыми скандалами (колоссальная задолженность Altice), к CMA CGM, ведущей судоходной компании, работающей в порту вотчины Édouard Philippe. Драи уже подвергался критике за влияние на редакционную линию BFM. Переход к CMA CGM усугубляет конфликт: портовый оператор Гавра теперь владеет СМИ, освещающим кандидата-мэра Гавра. Драи также является владельцем HOT в Израиле и Sotheby's. Его империя построена на колоссальной задолженности (более 60 миллиардов евро на пике), финансовая модель, повлёкшая налоговые расследования в нескольких странах. Продажа Саадe иллюстрирует продолжающуюся медийную концентрацию во Франции: информационные СМИ переходят из рук задолжавшего миллиардера к миллиардеру-судовладельцу, связанному с китайскими торговыми маршрутами. Цепочка Drahi → BFM → CMA CGM → Le Havre → Philippe — это путь конфликта интересов, выстроенный через последовательные приобретения.",
    "pierre-moscovici": "Пьер Московичи является президентом Счётной палаты с июня 2020 года. Young Leader 1996 (тот же выпуск, что и Олланд). Бывший министр экономики, затем еврокомиссар. То обстоятельство, что верховный контролёр государственных счётов и бывший премьер-министр происходят из одной сети Young Leaders, ставит вопросы о независимости контроля.",
    "dominique-de-villepin": "Доминик де Вильпен, премьер-министр при Шираке (2005–2007), управляет частной, многополярной и непрозрачной сетью. Никакая прямо документально подтверждённая связь не объединяет его с Philippe — их сети сходятся через Жюппе и китайские связи. Вильпен вступил в «groupe J» (верные Жюппе) в 1979 году, затем был назначен Жюппе директором кабинета в Кэ д'Орсэ в 1993 году. С 2008 года: около 50 оплачиваемых конференций в Китае (94 000 евро за две по данным Radio France), председательство в IMTA (китайская организация), компании в Гонконге (счета не сдаются с 2015 года), близость к Си Цзиньпину. Многополярная сеть за пределами Китая: дружба с семьёй Аль-Тани (Катар), должность в Управлении музеев Катара, совместная трибуна с Путиным на Валдае (2014), 800 000 евро/год от саудовской группы Bugshan через панамскую компанию, связанную с Джухри (2008–2010), 17-летний контракт с Veolia через Прольо, деятельность в Иране, Венесуэле, Армении, Азербайджане. Помогает китайским компаниям в Африке и Европе, порой конкурируя с французскими фирмами. Опросы мая 2025 года: Вильпен 51 %, Philippe 50 %. Привлекает левых (65 % LFI), Philippe — центристов-правых. Прямой конкурент на 2027 год.",
    "villepin-international": "Villepin International — консалтинговая компания Доминика де Вильпена, созданная после его ухода из Матиньона. Её счета не сдаются с 2015 года — в тот же год были созданы две компании в Гонконге, а затем третья (Villepin Group Limited) со значительными финансовыми потоками. Расследование следственного отдела Radio France (декабрь 2025 года) раскрывает масштаб китайской деятельности, проходящей через эти структуры. Назначение и получатели финансовых потоков остаются крупными тёмными зонами. Финансовая непрозрачность контрастирует с институциональной и относительно прозрачной сетью Philippe через FCF.",
    "alexandre-djouhri": "Александр Джухри — посредник, приговорённый в сентябре 2025 года к шести годам заключения по делу о ливийском финансировании. Расследование Radio France показывает, что Вильпен совершал поездки за рубеж в его компании. На Санкт-Петербургском форуме оба зарегистрировались как «вице-президенты» Veolia — регистрация, опровергнутая руководством группы. Никакой сопоставимой связи для Philippe не задокументировано. Джухри является теневым узлом, специфичным для сети Вильпена, связывающим бывшего премьер-министра с наиболее скандальными деловыми кругами (Россия, Персидский залив, Ливия).",
    "henri-proglio": "Анри Прольо — бывший генеральный директор Veolia Environnement (2003–2009), затем EDF (2009–2014). По данным расследований, Вильпен находится под контрактом с Veolia в течение 17 лет через Прольо. Эта связь объясняет эпизод на Санкт-Петербургском форуме, где Вильпен и Джухри зарегистрировались как «вице-президенты» Veolia. Прольо — фигура французского капитализма, лавировавшая между государственным и частным секторами. Его роль как точки контакта между Вильпеном и деловым миром является направлением для углублённого изучения, выявленным в отчёте.",
    "imta": "International Mountain Tourism Alliance (IMTA) — китайская организация, председателем которой является Вильпен. Это председательство входит в сеть официальных и полуофициальных функций, которые Вильпен накопил в Китае с 2008 года: председательство в ассоциациях по китайскому праву, включение в исполнительные комитеты инвестиционных фондов. IMTA иллюстрирует институциональный китайский якорь Вильпена — легитимность, полученную сверху, непосредственно от центральной власти, в отличие от пути Philippe через FCF, который проходит через регулируемые французско-китайские структуры.",
    "alain-merieux": "Ален Мерьё — лионский промышленник, основатель bioMérieux, мирового лидера in vitro-диагностики. Он является архитектором высокозащитной лаборатории P4 в Ухане, открытой в 2018 году — франко-китайского проекта сотрудничества, запущенного при президентстве Ширака. Мерьё заседает в Стратегическом совете FCF рядом с Раффареном и Фабюсом. Его присутствие в сердце аппарата FCF устанавливает связь между франко-китайской санитарной дипломатией (лаборатория P4 в Ухане) и сетями влияния, в которых участвует Philippe. Вопрос лаборатории P4 приобрёл геополитическую чувствительность с 2020 года и пандемии Covid-19.",
    "laurent-fabius": "Лоран Фабюс, бывший премьер-министр (1984–1986) и президент Конституционного совета с 2016 года, является со-покровителем France China Foundation вместе с Раффареном. Бывший министр иностранных дел при Олланде (2012–2016), он способствовал структурированию франко-китайской дипломатии. Его присутствие в Стратегическом совете FCF рядом с Раффареном и Мерьё выходит за рамки разделения левых и правых и иллюстрирует консенсус французских элит вокруг сближения с Пекином. Фабюс подтверждает конституционность законов — в том числе правительства Philippe.",
    "hubert-vedrine": "Юбер Ведрин, бывший генеральный секретарь Елисейского дворца при Миттеране и затем министр иностранных дел (1997–2002), является членом Стратегического совета FCF. Теоретик французской внешней политики и изобретатель концепции американской «гиперпуissance», он представляет непрерывность французской дипломатической традиции независимости от Соединённых Штатов — той же традиции, которая направила наследников Ширака к Китаю.",
    "jacques-chirac": "Жак Ширак (1932–2019), президент Республики (1995–2007), является общим источником всей экосистемы. Его политика независимости от Соединённых Штатов и привилегированный диалог с Пекином породили традицию франко-китайских отношений, наследниками которой по различным каналам являются Philippe и Вильпен. Опрос JDD/Ifop 2019 года ставил Жюппе первым наследником Ширака (62 %), Вильпена — третьим, задавая вопрос, не является ли «последним бастионом ширакизма Матиньон, с Édouard Philippe». Вильпен был одним из «любимых сыновей» Ширака (La Libre). Chirac → Juppé → Philippe и Chirac → Villepin — две ветви этого политического дерева.",
    "cpifa": "CPIFA (Chinese People's Institute of Foreign Affairs) — официальный китайский партнёр France China Foundation. Связанный с Министерством иностранных дел Китая, он является институциональным собеседником китайско-французской сети Philippe и Раффарена. CPIFA является интерфейсом между французской мягкой силой (FCF) и китайским дипломатическим аппаратом. Это соединение отличает сеть Philippe/Raffarin (институциональную, регулируемую) от сети Вильпена (частной, с прямым доступом к центральной власти через Си Цзиньпина).",
    "charles-hufnagel": "Шарль Гуфнагель — советник по коммуникациям Жюппе, встреченный им в Areva в 2000-е годы. Пресс-секретарь Philippe в Матиньоне. Политические журналисты считают его «куда более надёжным», чем его коллегу в Елисейском дворце (Le Temps). Он воплощает коммуникативную преемственность Juppéie: ту же доктрину дискретности и медийной сдержанности, которая отличала кампании Жюппе и пребывание Philippe в Матиньоне. Первый круг Juppéie.",
    "benoist-apparu": "Бенуа Аппару, бывший государственный секретарь по жилищному строительству при Саркози, был со-пресс-секретарём кампании Жюппе 2016 года вместе с Philippe. После поражения Жюппе на праймериз он вошёл в команду кампании Фийона. Его путь иллюстрирует рассеивание жюппеистов после ноября 2016 года — часть примкнула к Макрону (Буайе, Philippe), другая осталась в орбите LR. Первый круг Juppéie.",
    "anne-clerc": "Анн Клер является руководителем аппарата Матиньона при Philippe. Бывший член команды Раффарена в Матиньоне — что делает её человеческим мостом между двумя кабинетами ширакистских премьер-министров. Её присутствие в кабинете Philippe иллюстрирует преемственность Juppéie внутри государственного аппарата: те же сети передаются из одного Матиньона в другой.",
    "xavier-chinaud": "Ксавье Шино является советником по связям с избранными должностными лицами в Матиньон при Филиппе. Бывший руководитель отдела «политических исследований» в Матиньон при Раффарене. Как и Анн Клерк, он служит связующим звеном между кабинетами Раффарена и Филиппа, обеспечивая преемственность практик и сетей между двумя ширакианскими Матиньонами.",
    "christophe-bechu": "Кристоф Беши является генеральным секретарём партии Horizons, бывшим министром экологического перехода (2022-2024) и мэром Анже. Его роль внутри Horizons носит структурирующий характер: он обеспечивает территориальную организацию партии и является связующим звеном между филиппистским аппаратом и местными избранными. Ось Филипп (Нормандия) / Беши (Луара) / Эстрози (ПАКА) придаёт Horizons многорегиональную основу для выборов 2027 года. Третий круг Жюппеи — институциональный союзник.",
    "nathalie-loiseau": "Натали Луазо, депутат Европарламента от Renaissance и бывший министр по европейским делам (2017-2019), близка к жюппеистским кругам. Бывший директор ENA, она представляет европейское звено Жюппеи. После поражения Жюппе на праймериз она вошла в группу «маршировавших» — жюппеистов, примкнувших к Макрону. Третий круг Жюппеи.",
    "virginie-calmels": "Виржини Кальмель, бывший первый заместитель мэра Жюппе в мэрии Бордо, представляет «неоправый» крыло Жюппеи — то, которое дистанцировалось от Филиппа, чтобы примкнуть к Лорану Вокье через движение DroiteLib. Её путь иллюстрирует фрагментацию Жюппеи после поражения 2016 года: если большинство жюппеистов присоединилось к Макрону, то меньшинство выбрало поворот вправо внутри LR. Бывший руководитель Endemol France, она воплощает профиль менеджера-политика, ценимый Жюппе.",
    "julien-miro": "Жюльен Миро является одним из организаторов сети «bébés Juppé» — около тридцати тридцатилетних, ветеранов праймериз-кампании 2016 года, объединившихся в неформальную сеть после поражения. Вместе с Гийомом Пфистером он организует двухмесячные ужины с дружественными деятелями (Boyer, Gaymard, Keller, Bournazel). Показательно, что Миро заявлял: «Ален Жюппе проиграл, но жюппеисты победили: они повсюду в министерских кабинетах». Советники в Матиньоне, на Кe д'Орсе, в министерствах экономики, экологического перехода, культуры — bébés Juppé стояли у руля реформ макронизма. Второй круг Жюппеи.",
    "guillaume-pfister": "Гийом Пфистер является со-организатором, вместе с Жюльеном Миро, неформальной сети «bébés Juppé». Их заявленная цель: «поддерживать жюппеистский огонь» и «подготовить постжюппеистскую эпоху». На ужинах встречаются деятели, близкие к Жюппе (Boyer, Gaymard, Keller, Bournazel), и молодые советники, рассредоточенные по министерским кабинетам. Эта сеть составляет питомник кадров Horizons. Второй круг Жюппеи.",
    "fpi-raffarin": "FPI — это фонд Раффарена, перенастроенный для использования в качестве инструмента франко-китайских отношений. Бюджет в 3,5 млн €, финансируемый примерно тридцатью предприятиями (Carrefour, Kering, L'Oréal, LVMH) по 15 000 €/год каждое. Фонд получил пожертвования от китайских деятелей, в том числе 85 000 € от бывшего посла У Цзяньминя. FPI действует на пересечении аналитического центра и сети влияния, предоставляя Раффарену институциональную инфраструктуру для его китайской деятельности. Это параллельный канал к FCF — один (FPI) является личным инструментом Раффарена, другой (FCF) — коллективной структурой.",
    "groupe-bugshan": "Группа Bugshan — саудовский конгломерат, который выплачивал Вильпену 800 000 €/год в период с 2008 по 2010 год через панамскую компанию, связанную с Александром Джухри. Эти финансовые потоки, раскрытые расследованием Radio France, иллюстрируют непрозрачность деловой сети Вильпена. Деньги проходили через офшорную структуру, что затрудняет отслеживание бенефициаров. Связь Bugshan-Djouhri-Villepin является одним из наиболее непрозрачных узлов сети.",
    "sebastien-lecornu": "Себастьен Лекорню, действующий премьер-министр, поддерживает с Филиппом отношения конкуренции-сотрудничества. Бывший сторонник Лемера, перешедший в команду Фийона вместе с жюппеистами после праймериз 2016 года. Его путь пересекается с путём Жюппеи, не сливаясь с ней. Нормандец, как и Филипп (Эврё), он представляет потенциального соперника внутри большинства за влияние на умеренных правых.",
    "plastic-omnium": "Plastic Omnium — французский автомобильный поставщик, в совет директоров которого входил Раффарен. Группа получает значительную долю выручки в Китае, что делает её прямым бенефициаром синофранцузских сетей, содействием которым занимается Раффарен. Её присутствие в экосистеме Раффарена иллюстрирует механизм монетизации связей: компании с китайскими интересами финансируют FPI (15 000 €/год) и в ответ получают доступ к китайскому рынку, облегчённый «господином Китаем» французской политики.",
    "laurent-marcangeli": "Лоран Маркандже возглавляет парламентскую группу «Horizons et indépendants» в Национальном собрании. Он является законодательным представителем Филиппа: координирует позиции группы по законодательным текстам и обеспечивает сплочённость депутатов-филиппистов. После роспуска 2024 года группа сократилась с тридцати депутатов до шести — обвал, иллюстрирующий хрупкость парламентской базы Horizons.",
    "jacques-attali": "Жак Аттали (р. 1943) — выпускник Политехнической школы и ЭНА (набор Робеспьера, 1970). Бывший аудитор Государственного совета, специальный советник Франсуа Миттерана в течение десяти лет (1981-1991), основатель и первый президент ЕБРР (1991-1993), председатель Комиссии по освобождению роста французской экономики (2007-2010). Как агент-посредник, Аттали спроектировал дуэт Макрон-Филипп: в 2007 году он выбрал молодого Макрона заместителем докладчика своей Комиссии. В 2011 году он представил Макрона Олланду. В марте 2017 года он предложил Макрону избрать Филиппа премьер-министром и организовал их встречу. Эта цепочка Аттали → Макрон → Филипп является основополагающим механизмом правительства Филиппа (2017-2020). Аттали является сооснователем Стратегического совета France China Foundation (2013), где он заседает рядом с Филиппом, Раффареном, Фабиусом, Мерьё и де Кастри — уникальное схождение пяти уровней власти. Он покинул FCF в марте 2020 года, в момент начала пандемии. В мультиагентной системе Аттали не имеет собственного центроида, но функционирует как узел связи, максимизирующий косвенное влияние через соединение центроидов между собой. Его ценность заключается в сети, а не в формальной власти, что позволяет ему пережить смены власти без ущерба — президент может смениться, премьер-министр может пасть, Аттали остаётся.",
    "alain-minc": "Ален Минк (р. 1954) — выпускник ЭНА (набор Леона Блюма, 1975, первый в выпуске), генеральный инспектор финансов. Бывший председатель наблюдательного совета газеты Le Monde, президент AM Conseil, председатель совета директоров Sanef, казначей Fondation Saint-Simon, член Le Siècle. Треть крупных руководителей CAC 40 оплачивали его услуги (Bolloré, Bouygues, Vinci, Club Med, Suez). Как агент-посредник, Минк действует со стороны французских правых (Балладюр, Саркози, Жюппе), тогда как его дополнение Аттали действует со стороны левых (Миттеран, Олланд) — симметрия, позволяющая им охватить весь политический спектр. Минк поддержал Жюппе на праймериз 2016 года, затем перешёл к Макрону в 2017 году (аналогичный переход, как у самих жюппеистов). Он поддерживает косвенный канал с Филиппом через Жиля Буайе (советника в Матиньоне), задокументированный JDD в связи с налогом у источника (2018). У Макрона было два наставника после окончания ЭНА: Минк и Аттали, что подтверждает модель посредника в тандеме. Минк — бывший Young Leader FAF, образуя тем самым цепочку четырёх десятилетий: Минк (YL) → Жюппе (YL 1982) → Филипп (YL 2011) → Макрон (YL 2012). Как и Аттали, Минк максимизирует своё косвенное влияние, оставаясь невидимым для публики. Никакой избирательной ответственности, никакой формальной власти, но непревзойдённая способность к установлению связей.",
    "commission-attali": "Заказана Саркози, возглавлена Аттали, с Макроном в качестве заместителя главного докладчика. Среди 316 мер: либерализация частного найма транспортных средств (VTC), которая привела к закону Новелли (2009), а затем к «сделке Uber-Macron» (2014-2016). Отправная точка цепочки дерегулирования: Commission → Uber → Macron → Philippe.",
    "msc-aponte": "Основана семьёй Апонте, двоюродными родственниками матери Алексиса Колера. Вторая по величине судоходная компания в мире, эксплуатирует контейнерный терминал в порту Гавра. Колер ни разу не задекларировал свои семейные связи с MSC в период своего мандата в GPMH. В центре официального следствия против Колера по делу о незаконном конфликте интересов.",
    "rodolphe-saade-cma-cgm": "Генеральный директор CMA CGM (3-я судоходная компания в мире), владелец BFM TV и RMC после покупки Altice Media (2023). CMA CGM эксплуатирует терминалы в порту Гавра, вотчине Филиппа. Приобрела Bolloré Transport & Logistics (2024). Тройной узел: экономический (морской транспорт), медийный (BFM/RMC) и политический (портовый партнёр мэра Гавра).",
    "gpmh": "Главный порт Франции, узел конвергенции сети. Колер и Филипп совместно входили в наблюдательный совет (2010-2012). Хаб CMA CGM и клиент MSC. Побратим Далянь (Китай). Связан с COSCO Shipping (1-я китайская судоходная компания). Географическая точка, где сходятся политическая, финансовая, медийная и геостратегическая власть.",
    "uber-files": "124 000 внутренних документов Uber, утечка которых произошла в ICIJ. Раскрывают 17 контактов между Uber и кабинетом Макрона, 4 встречи Макрон-Каланик, скрытую сделку (Uber отказывается от UberPop, государство сокращает профподготовку водителей VTC с 250 до 7 часов), поправки, составленные Uber и переданные депутатам. Парламентская следственная комиссия (2023): конфликта интересов не выявлено, однако «привилегированные отношения» подтверждены.",
    "henri-de-castries": "Уникальный узел системы: возглавляет руководящий комитет Bilderberg с 2012 года, входит в Conseil stratégique FCF вместе с Аттали, Раффареном и Филиппом, и является однокурсником Вильпена по ENA (группа Voltaire, 1980). Бывший генеральный директор AXA (2000-2016), президент Institut Montaigne, трёхкратный Young Leader FAF (1994, 1995, 1998). Уникальный мост между трансатлантической сетью (Bilderberg, FAF) и синофранцузской сетью (FCF).",
    "gabriel-attal": "Премьер-министр (январь-сентябрь 2024 года), самый молодой ПМ Пятой республики. Приглашён на Bilderberg в Лисабоне (2023) в качестве министра по государственным счетам, назначен ПМ семь месяцев спустя. Присутствовал в Стокгольме (2025) вместе с Филиппом — впервые двое бывших макронистских ПМ участвовали совместно. Повторяющаяся закономерность: Макрон (Bilderberg 2014 → министр 2 месяца спустя), Филипп (2016 → ПМ 11 месяцев спустя), Аттал (2023 → ПМ 7 месяцев спустя).",
    "patricia-barbizet": "Член постоянного руководящего комитета Bilderberg — второй постоянный французский представитель после де Кастри. Бывший президент Siècle, бывший генеральный директор холдинга Artémis (Pinault). Присутствовала на Bilderberg 2023 в Лисабоне. Соединяет Bilderberg с Siècle, членами которого также являются Аттали и Минк.",
    "institut-montaigne": "Либеральный аналитический центр под председательством Анри де Кастри, финансируемый AXA, Engie, BNP Paribas, LVMH и TotalEnergies. Интеллектуальный ориентир кампании Макрона 2017 года: его директор Лоран Бигорн предоставил адрес для избирательной кампании LREM. Инструмент доктринального производства для программы Horizons 2027.",
    "blackrock": "Крупнейший в мире управляющий активами, основанный Ларри Финком. Владеет долями как минимум в 18 компаниях CAC 40, в том числе AXA (де Кастри), BNP (Лемьер, Bilderberg 2025), TotalEnergies (Пуйанне, Bilderberg), Société Générale (Колер 2025). Союзник MSC в приобретении 43 портов по всему миру за 22,8 млрд $ (2025). Филипп предлагает 15% капитализации пенсий в 2027 году — именно это является целью BlackRock во Франции.",
    "jean-francois-cirelli": "Выпускник ENA (группа Léonard de Vinci, 1985), бывший советник Ширака, заместитель начальника аппарата Раффарена (2002-2004), архитектор пенсионной реформы Фийона 2003 года. Генеральный директор Gaz de France, второй человек в Engie. Президент BlackRock Франция с 2015 года. Приглашён Филиппом в Comité Action Publique 2022 (2018). Произведён Филиппом в офицеры Légion d'honneur 31 декабря 2019 года, в разгар исторической пенсионной забастовки.",
    "marc-ferracci": "Экономист, выпускник HEC, доктор экономических наук. Познакомился с Макроном в возрасте 22 лет в Sciences Po. Свидетель на свадьбе Макрона. Его отец Пьер Феррачи входил в Комиссию Attali (2007), где Макрон был докладчиком. Депутат Renaissance, бывший министр промышленности. Задекларированное имущество: 23 млн евро. Подписант трибуны \"Pour la France, construisons l'union !\" (29 марта 2026 г.). Агент-мост между экосистемой Макрона и коалицией Филиппа.",
    "philippe-tabarot": "Министр транспорта с декабря 2024 года. Курирует французские морские порты, в том числе GPMH (узел Philippe/Kohler/MSC/CMA CGM). Бывший региональный вице-президент PACA рядом с Эстроси (Horizons). Сенатор от LR. Расследуется PNF по делу о хищении государственных средств и незаконном получении выгоды. Пост министра транспорта — повторяющийся узел: Джеббари (YL FCF 2020) был запрещён HATVP переходить в CMA CGM.",
    "maud-bregeon": "Официальный представитель правительства Лекорню, делегированный министр. Подписант трибуны \"Pour la France, construisons l'union !\" (29 марта 2026 г.). Заявила на LCI, что Филипп \"сделал серьёзную заявку, будучи потенциально лучше всего расположен для ведения этой борьбы\". Устанавливает явную связь между нынешним правительством и кандидатурой Филиппа в 2027 году.",
    "jean-paul-delevoye": "Верховный комиссар по пенсиям в правительстве Филиппа, ответственный за универсальную балльную систему. Встретился с BlackRock уже в марте 2018 года, через три месяца после своего назначения. Подал в отставку 16 декабря 2019 года из-за 13 мандатов, не задекларированных в HATVP. Реформа, которую он готовил, подозревается в открытии пути к накопительной системе в пользу BlackRock. Применение статьи 49.3 в феврале 2020 года, а затем пандемия заморозили реформу на неопределённый срок.",
    "elabe-bfmtv": "Опрос Elabe для BFMTV (собственность CMA CGM/Saadé) от 28 марта 2026 года, дающий Филиппу 20,5–25,5 % в первом туре. Независимая байесовская агрегация moipresident.online даёт ему 17 %, то есть на 3,5–8,5 пункта меньше. Результат 51,5 % против Барделлы во втором туре находится в пределах погрешности. Заказчик опроса (BFMTV/CMA CGM) имеет общий интерес с кандидатом (порт Гавра).",
    "patrick-pouyanné": "Генеральный директор TotalEnergies, постоянный участник Bilderberg (2023, 2025) рядом с Филиппом. TotalEnergies является акционером Institut Montaigne (де Кастри) и в значительной мере принадлежит BlackRock. Присутствовал в Лиссабоне и Стокгольме вместе с Филиппом, Атталем и де Кастри. Узел, соединяющий круг Bilderberg с кругом бизнеса/BlackRock.",
    "jean-lemierre": "Председатель BNP Paribas, присутствовавший на Bilderberg 2025 в Стокгольме рядом с Филиппом и Атталем. BNP частично принадлежит BlackRock и финансирует Institut Montaigne. Колер покинул Елисейский дворец в 2025 году, чтобы перейти в Société Générale — та же банковская экосистема. Круг Bilderberg напрямую связывает системообразующие французские банки с кандидатами в президенты.",
    "bernard-emie": "Генеральный директор внешней безопасности (DGSE, 2017-2024), присутствовавший на Bilderberg 2023 в Лиссабоне рядом с Филиппом, Атталем и де Кастри. Присутствие главы французской внешней разведки на частном трансатлантическом форуме — примечательный факт, отмеченный Regards.fr. В 2025 году Николя Рош (SGDSN), назначенный двумя месяцами ранее, заменил его на Bilderberg.",
    "laurent-nunez": "Лоран Нуньес-Бельда (р. 1964 в Бурже) — выпускник ЭНА (набор Сирано де Бержерак, 1997-1999, внутренний конкурс). Директор DGSI (июнь 2017 – октябрь 2018), государственный секретарь по внутренним делам в правительстве Филиппа II (октябрь 2018 – июль 2020), национальный координатор разведки при Елисейском дворце (июль 2020 – июль 2022), префект полиции Парижа (июль 2022 – октябрь 2025), затем министр внутренних дел в правительстве Лекорню II (с октября 2025 года). Он является оперативным исполнителем репрессий против \"жёлтых жилетов\" рядом с Кастанером, тогда как Филипп несёт политическую ответственность. Нуньес публично защищает LBD, участвует в отстранении префекта Дельпюша (март 2019), и без двусмысленности принимает самую жёсткую доктрину поддержания порядка Пятой республики. В терминах MAS он является государственным агентом-исполнителем: его лояльность направлена непосредственно к Макрону (который лично назначает его на каждую должность), а не к Филиппу (его номинальному руководителю). Его присутствие в правительстве Лекорню II рядом с членами Horizons создаёт дополнительную косвенную связь с philippe-сферой. Треугольник Nuñez–Bompard–Caubel — структурообразующее открытие доклада: однокурсник по ЭНА Бомпара (генеральный директор Carrefour), чья жена Шарлотта Кобель была руководителем отдела юстиции в кабинете Филиппа (2017-2020) и является членом Horizons.",
    "alexandre-bompard": "Александр Жубер-Бомпар (р. 1972) — генеральный директор группы Carrefour (выручка за 2024 год: 86 млрд евро), занявший 4-е место в наборе Сирано де Бержерак ЭНА (1997-1999). Он является однокурсником Лорана Нуньеса по этому набору (указ от 19 апреля 1999 года, Légifrance, JORFTEXT000000211140). Его жена Шарлотта Кобель была руководителем отдела юстиции в кабинете Эдуара Филиппа в Матиньоне (2017-2020). У Бомпара нет задокументированных прямых связей с Филиппом, однако его семейная сеть (через Кобель) и профессиональная сеть (через Нуньеса) связывает мир крупной розничной торговли с кругами исполнительной власти. Carrefour имеет значительные интересы в Китае и был официальным партнёром Олимпийских игр в Париже 2024 года.",
    "charlotte-caubel": "Шарлотта Кобель (магистрат, Sciences Po) была назначена советником по правосудию в кабинете Эдуара Филиппа в Матиньоне в мае 2017 года. Она проработала там три года (2017-2020), став руководителем отдела юстиции. После Матиньона она руководила Protection judiciaire de la jeunesse (2020-2022), затем была назначена государственным секретарём по вопросам детства в правительстве Борн (2022-2024). Она является членом партии Horizons. В августе 2025 года была назначена заместителем прокурора в Париже. Её муж — Александр Бомпар (генеральный директор Carrefour), однокурсник Лорана Нуньеса по ЭНА. Этот треугольник Nuñez–Bompard–Caubel напрямую связывает набор ЭНА Нуньеса с сердцем кабинета Филиппа и партией Horizons.",
  },
  ja: {
    "emmanuel-macron": "エマニュエル・マクロンは、エドゥアール・フィリップの1年後、2012年のヤング・リーダーズ・コホートに選ばれた。共通のメンター、アラン・ジュペは1982年の創設コホートに属しており、同じ政治的後見人によって結ばれたFAFの3世代にわたるヤング・リーダーたちをつないでいる。マクロンは2017年5月15日、フィリップの以前の批判（「ロスチャイルドの元銀行家」「古参政治家のシニシズム」）にもかかわらず、フィリップを首相に任命した。批判後のこの歩み寄りは、公的立場よりもネットワークの絆の強さを示している。マクロンは財務監察院、次いでロスチャイルド銀行を経て、オランド（自身も1996年のヤング・リーダー）の下でエリゼ宮の事務次長補に任命された。国家の頂点における「オランド（YL 1996）→マクロン（YL 2012）→フィリップ（YL 2011）」という連鎖はFAF史上唯一無二のものだ。2020年以降、両者の緊張は高まっており、フィリップは2024年の議会解散を「致命的で不合理な決断」と批判し、2025年末には辞任を求めた。2012年コホートにはフルール・ペルランとセドリック・ヴィラニも含まれており、両者とも政治的人物となった。大統領とその首相が同じ大西洋横断プログラムの連続するコホート出身というのは前例がなく、フランスの支配的エリート形成におけるアメリカの影響力について疑問を提起している。",
    "alain-juppe": "アラン・ジュペはエコシステム全体の名付け親だ。シラク政権の首相（1995〜1997年）、2004年有罪判決（RPRの幽霊職員）、FAFの創設コホート（1982年）のヤング・リーダー、ボルドー市長（2006〜2019年）、2019年3月以来の憲法院評議員（任期は2028年まで）、2025年2月以来のジョルジュ・ポンピドゥー研究所長。ジュペはフィリップを政界に送り込み（2002年にUMP事務局長として）、ヴィルパンは「groupe J」（1979年）以来の知己で、ジュペからケ・ドルセーの官房長に任命された（1993年）。「ジュペ（YL 1982）→フィリップ（YL 2011）→マクロン（YL 2012）」の三角形は、FAF内での権力移譲の最も顕著な事例だ。今日、憲法院の制約（留保義務、あらゆる党派的責任の禁止、あらゆる職務との非両立性）によって無力化され、フィリップを支持することも、政治問題について発言することも、Horizonsで役割を果たすこともできない。しかし、その残存する影響力は三重だ：制度的（憲法的決定に参加し、リシャール・フェラン YL 2005とともに着席）、象徴的（その遺産がHorizonsを浸透している：実用主義、欧州主義、温和な自由主義）、そしてネットワーク的（「ジュペ派」—彼の非公式な支持者ネットワーク—がHorizonsの脊骨を形成）。『L'heure du choix』（Tallandier、2025年）でヨーロッパの独立について出版。「アラン・ジュペは敗れたが、ジュペ主義者たちが勝利した：彼らは省庁のキャビネットいたるところにいる」（ジュリアン・ミロ）。",
    "cma-cgm": "CMA CGMはフランス最大の海運会社で世界第3位、1978年にジャック・サアデがマルセイユで設立した。グループは600隻以上の船舶を保有し、世界420港に就航している。CMA CGMの地域安全保障担当責任者ヤン・ル・ゴフは、エドゥアール・フィリップとともに2011年のヤング・リーダーズ・コホートに選ばれた。フィリップが2010年以来の政治的本拠地としているル・アーヴル港は、CMA CGMの主要な欧州ハブの一つで、同グループの船舶はコンテナ輸送の相当部分を担っている。ル・アーヴルはユーロポール（欧州刑事警察機構）によればヨーロッパへのコカイン最大の流入拠点で、2023年には18トンが押収された。港湾安全保障の問題は、CMA CGM（ル・ゴフを通じて）、市長の責任（フィリップ）、大西洋横断ネットワーク（FAF）が交差するクリティカルな結節点だ。CMA CGMは2017年以来ロドルフ・サアデが率いており、グループはメディア（La Tribune、La Provenceの買収）と物流に多角化してきた。フランス・チャイナ・ファウンデーション（FCF）—フィリップの官房長リバドー=デュマが会員—は同じ中国・海洋影響圏に組み込まれている。CMA CGMのアジア向け商業ルートはル・アーヴルを大量に経由しており、同港を商業・外交・政治的利益の収束点にしている。",
    "yann-le-goff": "ヤン・ル・ゴフは、エドゥアール・フィリップとともに2011年のヤング・リーダーに選出された時点で、フランス最大の海運会社CMA CGMの地域安全保障担当責任者だった。CMA CGMでの職務は、海上輸送の安全問題—港における麻薬対策を含む分野—の中心に彼を置く。フィリップの政治的本拠地ル・アーヴル港は、ユーロポールによればヨーロッパへのコカイン最大の流入拠点だ。CMA CGMの船舶はル・アーヴルのコンテナ輸送の大部分を占めており、CMA CGMの安全保障とル・アーヴル港の安全保障が密接に連動していることを意味する。ル・ゴフとフィリップは2011〜2012年の2回の5日間セミナーで交流し、非公式かつ秘密裏の場で個人的な絆を結んだ。将来の市長・首相と、その港で活動する主要海運会社の安全保障責任者が同じヤング・リーダーズ・コホートに存在することは、直接的な影響チャンネルを生む。ル・アーヴルでの記録的な押収（2023年に18トンのコカイン）を背景に、港湾麻薬取引の問題がフランスで重大な政治問題になっていることを考えれば、この関係はなおさら重要だ。ル・ゴフはフィリップのヤング・リーダーズネットワークにおけるCMA CGMのノードを代表する。彼のポスト（海事安全保障）、フィリップの領域（ル・アーヴル）、構造的問題（麻薬取引）の収束は、徹底した検討に値する。",
    "atos": "Atosはデジタルトランスフォーメーション、サイバーセキュリティ、クラウドコンピューティングを専門とするフランスのITグループだ。エドゥアール・フィリップは2020年、マティニョン退任直後に独立取締役として任命され、年約7万ユーロの報酬を受けるマンデートを得た。Atosは道路違反—特にオービス（自動速度取締機）—のコンピュータ処理の最前線にあり、フィリップが2018年に導入した時速80km制限から直接恩恵を受けた市場だ。ボルバール・ヴォルテールとブラストはこの潜在的利益相反を指摘した：不人気な道路措置を導入した首相が、その措置によって生成されたデータを処理する会社の取締役会に参加するという構図だ。フィリップとAtosの関係は、マティニョン就任のずっと前、2006年に遡る。同社は2022年以降に深刻な財務難を経験し、株価が急落し大規模リストラが行われた。Atosはまたフランス国家の戦略的活動（スーパーコンピュータ、防衛、2024年パリ五輪）を管理しており、その取締役が大統領候補でもある微妙なアクターとなっている。「2018年に時速80km制限→2020年マティニョン退任→2020年Atos就任」というタイムラインは、公的決定と私的利益の境界の曖昧さについて疑問を提起する。フィリップはこの潜在的利益相反について公式にコメントしたことがない。",
    "areva": "Areva（2018年にOranoに改名）はフランスの核燃料サイクル全体をカバーする多国籍原子力産業企業だ。エドゥアール・フィリップは2007年10月から2010年10月まで公共問題担当ディレクター—ロビー活動と政治家との関係構築の職—を務め、意思決定の中枢にとどまった。この期間は2011年のヤング・リーダー選出と重なり、当時「ル・アーヴル市長兼Areva公共問題ディレクター」として紹介されていた。原子力ロビーはフランスで最も影響力の強いものの一つで、同産業は電力生産の約70%を占める。公共問題ディレクターとして、フィリップはArevaの利益を国会議員や政府—後に首相として率いることになる同じ機関—に対して守る任務を担っていた。「コンセイユ・デタ→Debevoise & Plimpton（企業弁護士）→Areva（ロビー活動）→ル・アーヴル市長→マティニョン」というキャリアの軌跡は、官民間のいわゆる「回転ドア」の典型を示している。Arevaは2007年にUraMinを惨憺たる条件で買収し（損失36億ユーロ）、フィリップ在職中に発覚した大スキャンダルを経験した。グループは2017年に政府から50億ユーロの支援を受けて再建・資本増強を余儀なくされた—フィリップ政権下で。自分がロビイストとして働いた会社を救済する首相は、潜在的利益相反の典型事例だ。",
    "debevoise-plimpton": "Debevoise & Plimpton LLPは1931年ニューヨークで設立されたアメリカの法律事務所で、国際商事法、合併・買収、プライベートエクイティ、国際仲裁を専門とする。約800人の弁護士を擁し、ニューヨーク、ワシントン、ロンドン、パリ、フランクフルト、香港、上海にオフィスを持つ。エドゥアール・フィリップは、UMP事務局長を辞任してコンセイユ・デタへの出向を申請した後、2004年から2007年までパリ事務所で弁護士として勤務した。一流の英米系法律事務所でのこの経験は、高級官僚（ENA、コンセイユ・デタ）→政党指導（UMP）→国際民間部門→政治への復帰という「回転ドア」キャリアの典型を示す。Debevoiseはフォーチュン500企業と投資ファンドを代理しており、フィリップは国際ビジネス界にネットワークを築く機会を得た。同事務所は香港と上海—アジア貿易の中枢—にも拠点を持ち、その後のフィリップの周辺における中仏関係の展開を踏まえると重要な詳細だ。Debevoise後、フィリップはArevaに公共問題ディレクター（ロビー活動）として入り、経済的影響圏への埋め込みを確認した。「コンセイユ・デタ→UMP→Debevoise→Areva→市長→マティニョン」という連鎖は、各段階が次の段階の人脈帳を豊かにする軌跡を描く。Debevoiseでの経験は、このほぼフランス的な軌跡における英米的な挿話だ。Debevoiseで担当した報酬や案件は公開されたことがない。",
    "antoine-rufenacht": "アントワーヌ・リュフナクトは1995年から2010年までル・アーヴル市長を務めた、元エナルク（ENA卒業生）でノルマンディー右派の重鎮だ。エドゥアール・フィリップを潜在的な後継者として見出し、2001年に市議会選挙の候補者名簿に法律問題担当の副市長として加えることで政界に引き入れたのも彼だ。リュフナクトはその後、2002年にアラン・ジュペにフィリップをUMP事務局長として推薦し、国政の舞台への道を開いた。2010年にリュフナクトが市長を辞任した際、市議会はフィリップを後継者に選出した—完璧に演出された地方権力の移譲だ。前市長と同じ姓を名乗る弁護士クリスティーヌ・ポワイエ=リュフナクトは、フィリップとともに2011年のFAFヤング・リーダーズ・コホートに選ばれた—公的に説明されたことのない一致だ。リュフナクトは15年間ル・アーヴルを率い、フィリップが受け継ぐ地方の政治・経済ネットワークを形成した。リュフナクト時代、ル・アーヴルはユネスコ世界遺産に登録されたペレ建築と港を中心とした都市変革を進めた。リュフナクト=フィリップの関係は地方政治継承の教科書的事例だ：メンターが後継者を見出し、育て、都市のトップに据える。フィリップのル・アーヴルへの根付き—市庁舎、港、都市共同体—はリュフナクトのネットワークから直接受け継いだものだ。地元のメンターと大西洋横断ネットワーク（FAF）が同じ姓の周りに収束するという事実は、フランスエリートにおける共選メカニズムについての疑問を提起する。",
    "french-american-foundation": "French-American Foundation（FAF）は1976年にジェラルド・フォード大統領とヴァレリー・ジスカール・デスタン大統領の後援の下に設立された組織だ。1981年に創設されたヤング・リーダーズ・プログラムは毎年、高級官僚、企業、メディア、軍、研究機関から30〜40歳のフランス人10名とアメリカ人10名を選抜する。参加者は2年連続で、フランスとアメリカを交互に会場として2回の5日間セミナーに参加する。セミナーの内容は公開されない—FAFは過去の回の議題を開示しない。プログラム修了後、参加者は600名以上の卒業生ネットワークに加入する。プログラムはアメリカのソフトパワーの手段として繰り返し描写されるが、FAF自身は「シンクタンクでも、ロビー団体でも、議員友好グループでもない」と自己紹介する。フランス政府におけるヤング・リーダーズの存在感は顕著で、政治の交代を超えている。エドゥアール・フィリップは2011年コホート、エマニュエル・マクロンは2012年、アラン・ジュペは創設コホートの1982年、フランソワ・オランドは1996年に属する。フィリップ内閣大臣のリシャール・フェランは2005年のヤング・リーダーだった。1981年以来400名以上の指導者がプログラムの恩恵を受けており、大統領とその首相が連続コホート出身というのはFAF史上前例がない。プログラムのスポンサーにはエアバス、J.P.モルガン、ソデクソが含まれる。",
    "david-barroux": "ダヴィッド・バルーはフランスの主要経済紙「レゼコー」の記者兼編集長だ。彼はエドゥアール・フィリップとともにFrench-American Foundationの2011年ヤング・リーダーズ・コホートに属していた。参照的な経済メディアを率いる立場は、フランスの経済政策報道に対して大きな影響力を与える。レゼコーはベルナール・アルノーのLVMHグループに属しており、バルーをフランスの大富豪と結びついたメディア・エコシステムに位置づける。ヤング・リーダーとして、2011〜2012年に行われた2回の5日間セミナーをフィリップと共有し、永続する個人的・職業的な絆を築いた。将来の首相と大手日刊紙の編集長が同じ大西洋横断ネットワーク内に収束することは、注目に値する。レゼコーは一般に、フィリップ政権の改革—特に労働法典とPACTE法—に好意的な報道をした。この近さは、同じ影響力ネットワークにおけるフランスの政治エリートとメディアエリートの絡み合いを示している。バルーは2011年コホートのメディア的柱を代表する。FAFはセミナーでこれらの未来の指導者たちの間で交わされたやりとりを公開していない。",
    "yohann-benard": "ヨハン・ベナールは2011年にヤング・リーダーに選出された時点でAmazonフランスの公共問題ディレクターだった。彼はFAFのコホートをエドゥアール・フィリップ—当時ル・アーヴル市長兼Arevaの公共問題ディレクター—と共にする。両者は似た職務—ロビー活動と機関関係—を担っており、一方は原子力大手のために、もう一方はアメリカのeコマース大手のために働く。Amazonはその社会的・税務的慣行と地域商業への影響でフランスで最も物議を醸す企業の一つだ。ベナールはAmazonの利益をフランスの選出公務員と行政機関に対して守る任務を担う。将来の首相と共にエリート大西洋横断ネットワークを共有することで、意思決定の場への特権的アクセスを得る。フィリップ政権はマティニョンでの3年間に、約束にもかかわらずGAFAへの課税を特に強化しなかった。2011年コホートにAmazonのロビイストとArevaのロビイスト（後に首相となる）が同時に存在することは、企業利益と政治権力の間の透過性を示す。FAFのセミナーはこれらの絆を結ぶための非公式な場を提供した。ベナールはコホートのアメリカ的企業の柱を代表する。",
    "stephane-israel": "ステファン・イスラエルはエドゥアール・フィリップと同じ2011年にヤング・リーダーに選ばれた。後にArianeGroup（エアバス/サフランの合弁企業）の子会社で宇宙打ち上げサービスの世界的リーダーであるArianespaceの最高経営責任者となる。Arianespace以前、イスラエルはオランド政権下で高等教育・研究大臣ジュヌヴィエーヴ・フィオラゾの官房長（2012〜2014年）を務めた。高級官僚と戦略的産業の間の典型的な「回転ドア」プロフィールを体現する。大臣府、次に公企業のトップというその軌跡はフィリップ（コンセイユ・デタ、Areva、政治）のものと比較できる。Arianespaceはヨーロッパの宇宙主権の重要なプレーヤーであり、その社長はフランスの行政府と必然的に緊密な関係を維持する。フィリップと同じヤング・リーダーズ・コホートにイスラエルが存在することで、原子力産業と宇宙産業と政治権力の間の横断的なリンクが生まれる。ArianeGroupの親会社エアバスはFAFのヤング・リーダーズ・プログラムのスポンサーの一つでもある。プログラムのスポンサーと選ばれたメンバーの間のこれらの相互接続は、選考プロセスの独立性について疑問を投げかける。イスラエルは2011年コホートの戦略的産業の柱を代表する。",
    "christine-poyer-rufenacht": "クリスティーヌ・ポワイエ=リュフナクトはパートナー弁護士で、エドゥアール・フィリップとともにFAF 2011年ヤング・リーダーズ・コホートに選ばれた。彼女の姓は、2001年にフィリップを政界に引き入れたル・アーヴル市長アントワーヌ・リュフナクトを必然的に連想させる—公式の経歴書が触れない不安な同名性だ。アントワーヌ・リュフナクトはフィリップの地元メンターであり、市議会候補者名簿に初めて加えてアラン・ジュペにUMP事務局長として推薦した。リュフナクトの被保護者と同じ姓の人物が同じヤング・リーダーズ・コホートに存在することは、これらのネットワーク内の共選メカニズムについて疑問を提起する。FAFは詳細な選考基準を公表しておらず、応募プロセスは部分的にスポンサーシップに依拠している。クリスティーヌ・ポワイエ=リュフナクトがアントワーヌ・リュフナクトの親族であれば、大西洋横断機関の中で家族・政治ネットワークが自己再生産する事例となる。少なくとも、姓の一致はFAFによって選ばれたフランスエリートが動く圏の狭さを示している。ル・アーヴルはこれらのネットワークにおいて繰り返し現れるノードとして浮かび上がる：フィリップ、リュフナクト、CMA CGM。この関係は徹底した調査に値する。FAFがそのプロセスについて不透明であることが検証を困難にしている。",
    "estelle-youssouffa": "エステル・ユスフは現在、2022年に選出されたマヨット第一選挙区の国民議会議員だ。エドゥアール・フィリップと同じ2011年のヤング・リーダーズ・コホートに選出された。政界入りの前、ユスフはFrance 24やアルジャジーラで記者として活動しており、プログラムのメディア的柱に位置づけられる。国際ジャーナリズムから議会代表へという軌跡は、ヤング・リーダーズが権力の地位に向かう典型的なパスを示している。議員として国民議会に着席しており、エドゥアール・フィリップのHorizonsグループも代表を置いているため、同じコホートの元メンバー間の議会連合の可能性が生まれる。マヨットは移民、安全保障、発展などの重大な課題に直面しており、これらは定期的に国民的議論の対象となる。ユスフとフィリップが同じFAFコホートに属することは、海外領土の問題とフィリップのネットワークの間のリンクを確立する。ヤング・リーダーズ・プログラムは歴史的に、後に異なる分野で影響力ある地位に就くメンバー間の永続的な関係を生み出してきた。このコホートのダイナミクスはネットワークの最も効果的なメカニズムの一つだ。ユスフは2011年コホートの海外・メディア的柱を代表する。",
    "richard-ferrand": "リシャール・フェランはフランスの政治家で、国民議会議長（2018〜2022年）、エドゥアール・フィリップの第一次政権での領土結束大臣（2017年5〜6月）を歴任した。フィリップより6年早い2005年のヤング・リーダーズ・コホートのメンバーだ。フェランはエマニュエル・マクロンの最初期の支持者の一人で、2016年の「前進！」（En Marche）の共同創設者だ。フィリップの大臣、次に議会議長として、フィリップが活動したマクロン主義システムの不可欠な歯車だった。2005年のヤング・リーダーズ・コホートはフィリップ（2011）、マクロン（2012）、ジュペ（1982）と同じ大西洋横断ネットワークに彼を位置づける。領土結束大臣と首相がともに元ヤング・リーダーであるという事実は、政府内のこのネットワークの密度を示している。フェランは2019年に不動産案件—ブルターニュ共済組合—での不正利益相反の疑いで正式捜査対象となった。2023年に不起訴処分となった。その司法的経緯は、ヤング・リーダーズ・ネットワークのメンバーであることが必ずしも訴追から守るわけではないことを示している。それでも、行政府と立法府の頂点におけるヤング・リーダーズの収束は批判的な検討に値する。",
    "francois-hollande": "フランソワ・オランドは2012年から2017年まで共和国大統領を務め、ピエール・モスコヴィシとともにFAFの1996年コホートのヤング・リーダーだ。フィリップより15年前のプログラム参加は、政治世代と政権交代を超えたネットワークの連続性を示している。オランドはマニュエル・ヴァルス、次いでベルナール・カズヌーヴを首相に任命したが、後継者マクロン（YL 2012）がフィリップ（YL 2011）を任命した。オランド→マクロンという大統領継承の連鎖は、ヤング・リーダーズ・ネットワーク内部の連鎖だ。オランドは大統領就任前に11年間PS（社会党）の第一書記を務め（1997〜2008年）、密なる政治的ネットワークを構築した。1996年コホートには将来の欧州委員、次いで会計院院長になるピエール・モスコヴィシも含まれており、元ヤング・リーダーが占める職の多様性を示している。FAFプログラムは共和国大統領2名（オランドとマクロン）、少なくとも首相4名（ジュペ、フィリップおよび間接的に他者）、多数の大臣を輩出した。一つの選考プログラムからのこの権力集中は、フランスの支配的エリートの形成に関する民主的な疑問を提起する。オランドは2017年以降フィリップを数度批判しているが、同じ構造的ネットワークを共有している。",
    "laurent-wauquiez": "ロラン・ヴォキエはオーヴェルニュ=ローヌ=アルプ地域圏議長で共和党（LR）元党首（2017〜2019年）、2006年コホートのヤング・リーダーだ。エドゥアール・フィリップと同じ大西洋横断ネットワークの右翼を代表する。フィリップが2017年にマクロン陣営に加わる前、二人はLR内で対立していた。ヴォキエはフィリップのマティニョン任命を「右派への裏切り」と強く批判した。政治的対立にもかかわらず、両者は同じエリート教育の軌跡—両者ともENA出身、両者ともヤング・リーダーズ—を共有する。ヴォキエは2027年大統領選の有力候補と見なされており、同じネットワーク出身のフィリップの直接的なライバルとなる可能性がある。大統領候補の可能性を持つ二人がともに元ヤング・リーダーだという事実は、政治的立場にかかわらず国の未来の指導者を生み出すプログラムの能力を示している。2006年コホートはヴォキエをネットワークの年表上でフェラン（2005）とフィリップ（2011）の世代間に位置づける。サルコジ下の国務長官から地域圏議長へという政治的軌跡は、フィリップと平行だがより右派的なレジスターを示す。FAFのセミナーは、公的な政治対立が始まる前から、卒業生ネットワークを通じてヴォキエとフィリップが交差する可能性を提供した。",
    "fleur-pellerin": "フルール・ペルランはエマニュエル・マクロンと同じ2012年のヤング・リーダーズ・コホートに選ばれた。当時はオランド政権下でSME・イノベーション・デジタル経済担当副大臣を務め、後に文化大臣（2014〜2016年）となる。2012年コホートはフィリップの2011年コホートの直後に続くものであり、つまり二つのコホートのセミナーが重複していた可能性がある—フィリップの2012年の第2セミナーはペルランとマクロンの第1セミナーと重なりえた。ペルランはENA（サンゴール・プロモーション、2000年）の卒業生であり、ヤング・リーダーズのプロフィールには常にこの学校が登場する。大臣職後、アジアへの投資に特化したベンチャーキャピタル会社Korelya Capitalを設立し、大西洋横断（FAF）とアジア的ネットワーク（フランス・チャイナ・ファウンデーション）の間の橋を作った。ペルランは韓国生まれでフランスに養子として迎えられており、FAFが重視するバイカルチャー・プロフィールを持つ。大臣職後のアジア向けベンチャーキャピタルへの軌跡は、エリート・ネットワークで結ばれた関係が経済的機会に変換される様子を示している。マクロンとセドリック・ヴィラニも含む2012年コホートは、プログラムの歴史上最も政治的に影響力のあるものの一つだ。",
    "laphonza-butler": "ラフォンザ・バトラーはアメリカの政治家で、2023年10月に知事ギャビン・ニューサムによってダイアン・ファインスタイン上院議員の後任としてカリフォルニア州上院議員に任命された。彼女はフランス側のエドゥアール・フィリップとともに、アメリカ側として2011年のヤング・リーダーズ・コホートに属している。上院議員就任前、バトラーはカリフォルニア最大の医療従事者組合SEIU Local 2015（40万人会員）の会長だった。その後EMILYs List—フェミニスト候補を支援する民主党組織—を率いた。上院議員への任命はアメリカのヤング・リーダーが最高職位に至る軌跡を示している。アメリカの上院議員と元フランス首相が同じ大西洋横断プログラムで共に訓練されたという事実は、米上院とフランス政治の間の直接的な影響チャンネルを生む。バトラーは2011〜2012年に行われた2回の5日間セミナーでフィリップと交流し、永続する個人的な絆を結んだ。ヤング・リーダーズ・プログラムはまさに両国の未来の指導者の間にこのような橋を作るために設計されている。バトラーは2011年コホートのアメリカのプログレッシブな政治的柱を代表する。彼女の存在は、FAFが最高の職に就く以前から未来のリーダーを識別する能力を示している。",
    "horizons": "Horizonsはエドゥアール・フィリップが2021年10月9日、本拠地ル・アーヴルでの公開集会で設立した政党だ。党は中道右派に位置し、マクロン主義的大統領多数派の右翼を体現する。四つの中心的テーマは人口統計、環境、地政学、技術で、スローガンは「遠くを見て正しく行動する」。エマニュエル・マクロンは「誠実だが自由」と自称するこの元首相によるHorizonsの設立をよく思っていなかった。2022年1月、党はEnsemble Citoyens連合に参加した。ニース市長クリスティアン・エストロジがナンバー2となり、ノルマンディーに根付いた党に地中海的な拠点をもたらした。2022年総選挙でHorizonsは連合内で58の公認を得て、ロラン・マルカンジェリが議長を務める約30名の議会グループ「Horizons et indépendants」を結成した。2024年の解散後、党は6議席しか維持できなかった。2026年3月、Horizonsは全国465人の登録市長を主張し、フィリップの2027年大統領選挙キャンペーンの背骨を形成するローカルネットワークだ。党は個人的な選挙の乗り物として機能する：その唯一の戦略的目標はフィリップをエリゼ宮に送り込むことだ。党の幹部はフィリップのル・アーヴルおよびジュペ派ネットワーク出身者が大部分を占める。",
    "christian-estrosi": "クリスティアン・エストロジは2008年以来ニース市長（2014〜2017年はプロヴァンス=アルプ=コート・ダジュール地域圏議長として中断）でエドゥアール・フィリップのHorizons党ナンバー2だ。サルコジ下の産業大臣（2009〜2010年）を歴任したプロヴァンス右派の重鎮で、フィリップのノルマンディー的拠点を補完する南フランスへの根付きをHorizonsにもたらす。2021年のHorizonsへの結集は大きな政治的クーデターだった：LRを離れて中道右派政党に参加し、ニースとコート・ダジュールの右派の一部を引き連れた。ニースはフランス第5の都市で一流の観光・経済ハブであり、エストロジは党内で相当の政治的重みを持つ。エストロジは2016年7月14日のニス同時テロ（死者86名）に深く刻まれており、首都圏議長として対応した—危機管理者としてのイメージを形成した出来事だ。ジャーナリストのローラ・テヌジと結婚しており、追加の露出度を確保している。Horizons内でエストロジは中道右派に引き付けられたLR議員のリクルーターの役割を果たす。その軌跡はフィリップの戦略を示す：LRが強硬右派へと変容したことに失望した右派幹部を吸収する。「フィリップ（ノルマンディー）/エストロジ（PACA）」というデュオはHorizonsに2027年大統領選挙を構造化する二地域的基盤を与える。エストロジはまた「フランスの自治体間協力組合（Intercommunalités de France）」副議長でもあり、フィリップのものを補完する地域的ネットワークを持つ。",
    "gilles-boyer": "ジル・ボワイエは20年以上にわたりエドゥアール・フィリップの最も近い顧問で、ジュペの軌道圏で鍛えられた。ボルドー市庁舎でジュペの官房長（2002〜2004年、2006〜2010年）、次いで2016年予備選でジュペの選挙対策本部長（フィリップは共同スポークスマン）。フィリップとの共著で2冊の政治小説（『L'heure de vérité』2007年、『Dans l'ombre』2011年）と『Impressions et lignes claires』（2021年）を刊行。マティニョンでのフィリップの特別顧問（2017〜2019年）。現在はルネサンスの欧州議会議員。あるサルコジ主義者は彼らを「プリックとプロック」（ボワイエとフィリップ）と呼んだほどタンデムは不可分だった。ボワイエはジュペの遺産とHorizonsのマシンをつなぐ：彼はフィリピスト的教義の守護者であり、あらゆる政策方向性に影響を与える影の顧問の原型だ。「ジュペ派」の内側の輪。",
    "christophe-castaner": "クリストフ・カスタネールは、ジェラール・コロンの辞任後に起きた第五共和国で最長のボヴォ広場における暫定期間を経て、2018年10月にエドゥアール・フィリップによって内務大臣に任命された。任命は黄色いベスト運動開始の1か月前であり、彼を1968年5月以来最も争われた治安維持の教義の直接的責任者にした。カスタネールはデモ参加者を「殺しに来た分裂主義者」と表現し、不均衡な安全保障の対応を正当化した。彼の指揮下、護身用ゴム弾発射器（LBD40）の使用は前年比200%以上急増した。人的被害は前例のないものだった：25人が失明、5人が手首を失い、432人が重傷を負った。国連、欧州評議会、アムネスティ・インターナショナルがこれらの武器の禁止を求めた。カスタネールは警察による暴力の報告を組織的に無視し、LBDの使用停止を拒否した。フィリップの大臣として、その教義は首相の責任を直接巻き込んだ。IGPN（警察一般監察局）は警察による暴力の疑いで313件の司法調査を受理した—記録だ。カスタネールはそれ以前にLREMの総代理人だったことがあり、フィリップ政権下でマクロン主義的装置と安全保障装置の融合を示している。",
    "benoit-ribadeau-dumas": "ブノワ・リバドー=デュマ、ENA（マルク・ブロック・プロモーション、1997年）の首席、フィリップの同期生。マティニョンの官房長（2017〜2020年）—マクロンがニコラ・ルヴェルを押し込もうとした意志に反して選ばれた。その硬直性から「バチカン」と呼ばれた。FCFのメンバー（フィリップとマクロンとともに2013年の創設コホート）。マティニョン以前：エリゼ宮でのサルコジの副官房長（2011〜2012年）、オランド下の事務次長—政権交代を超えるキャリア。フィリップ政権のすべての決定の運営的設計者：労働法令、時速80km制限、黄色いベスト、年金改革、コロナ。2020年3月15日の地方選挙第一回投票の維持を主張した。マティニョン後、Exor（エルカン/アニエッリ・ファミリーオフィス）に加入、StellantisとIvecoの取締役。「ジュペ派」の内側の輪—ENAネットワーク、FCF、行政権力を結ぶノード。",
    "france-china-foundation": "France China Foundation（FCF）は2012年にフランスと中国の支配的エリートを引き合わせるために設立された組織だ。戦略委員会にはジャン＝ピエール・ラファラン、ロラン・ファビウス、アラン・メリュー（武漢のP4実験室の設計者）が含まれる。公式の中国パートナーはCPIFA（中国人民外交学会）で中国外交部に結びついている。2013年の創設コホートはフィリップ、マクロン、リバドー=デュマを結集させた。2015年、フィリップはFCFの代表団をル・アーヴルに迎え港を訪問した。2018年5月、首相兼元ヤング・リーダーとしてヴェルサイユでの年次ガラに出席した。FCFの不透明性はFAFのものと同等だ：議題は公開されず、公的報告書もない。FAF（大西洋横断）とFCF（中仏）のネットワークが同じ核—フィリップ、リバドー=デュマ、ルネン—の周りに同時に存在することは、マティニョンにおける前例のない二極的影響力システムを作る。ヴィルパンはどのFCFの空間にも現れない—その中国的ネットワークは個人的かつ私的で、制度的ではない。",
    "emmanuel-lenain": "エマニュエル・ルネンはキャリア外交官で、2012年にFrance China Foundationを共同設立し、2017年から2020年までエドゥアール・フィリップのマティニョンでの外交顧問を務めた。この二重の役割—中仏ネットワークの設計者かつ首相顧問—は、行政権力の中枢で大西洋横断（FAF）とアジア的（FCF）ネットワークの間の人的橋梁として彼を位置づける。マティニョン以前、ルネンは国連常駐フランス代表部での職を含む複数の戦略的外交ポストを歴任した。マティニョン後、インド駐仏大使に任命された（2019〜2022年）—フランス・中国・インドの戦略的三角形に彼を位置づけるポストだ。FAFでのフィリップのヤング・リーダー選出の1年後となる2012年のFCF設立は、補完的な二国間影響ネットワークを意図的に構築する戦略を示唆する。フィリップの外交顧問として、ルネンは中国と海上通商路を含む政府のすべての国際交渉にアクセスできた。フランス最大の港でフィリップの本拠地ル・アーヴルは、中仏貿易と一帯一路構想（新シルクロード）の問題に直接関係している。FCF、マティニョン、アジア外交の交差点にあるルネンの立場は、一個人が外交・経済・政治的利益の間の伝達ベルトとしていかに機能しうるかを示している。マティニョン後の軌跡—インド大使館、次いでケ・ドルセーでのポスト—はアジアに向けられたフランス外交機構内での彼の軌跡を確認する。ルネンはフィリップのヤング・リーダーズ・ネットワークと中仏ネットワークをつなぐ欠けたリンクだ。",
    "port-du-havre": "ル・アーヴル港はフランス最大のコンテナ港であり、ヨーロッパで5番目に大きい。2021年以降、フランス最大の港湾複合体HAROPA（ル・アーヴル、ルーアン、パリ）に統合されている。Édouard Philippeは2010年以来同市の市長を務め、港の戦略的方向性とル・アーヴル・セーヌ・メトロポール都市共同体への直接的な影響力を持つ。フランス最大の船会社CMA CGMはここで大規模なコンテナ輸送を行い、上海、寧波、深圳および主要アジア港への直行便を持つ。ル・アーヴルを経由する仏中間の海上貿易は年間数十億ユーロに上る。同港は欧州の港湾インフラを中国の物流ネットワークに接続することを目的とする中国の「一帯一路」構想にも関与している。ユーロポールによれば、ル・アーヴルはヨーロッパ最大のコカイン流入拠点である。薬物押収量は急増しており、2023年にフランス税関が押収したコカインは18トンと記録を更新した。港湾セキュリティは国家、税関当局、港湾当局の共同責任だが、これはCMA CGM（Yann Le Goffを通じたセキュリティ部門）、市役所（Philippe）、影響力ネットワーク（FAF、FCF）の利益が交差する領域である。港の拡張とコンテナターミナルへの投資は地域の主要な経済課題であり、Philippeは15年間にわたりここで比類のない政治的地盤を持つ。港湾ガバナンス—誰が投資・コンセッション・検査について決定するか—はPhilippe-CMA CGM-FCFネクサスの核心にある。",
    "jean-pierre-raffarin": "ジャック・シラク政権下の首相（2002-2005年）であったジャン=ピエール・ラファランは、PhilippeとVillepinの中国ネットワークを結ぶ要である。彼は他に類を見ない数の中国関連ポストを兼任している：博鰲アジアフォーラム（アジアのダボス）の顧問委員会メンバー、一帯一路フォーラム、上海CEIBS理事、Sino-International Entrepreneurs Federation共同会長、CGTN（中国公共テレビ）番組プレゼンター、フランス政府の対中特別代表（2018年以降）、FCFの共同後援者、そしてComité France-Chine会長。2019年9月29日、習近平は彼に友誼勲章を授与した—プーチンやカストロと共有する外国人への最高の中国栄誉。DGSIは2018年夏、中国共産党の工作員と見なされる中国人ビジネスマンとの付き合いを理由に「意識向上面接」のために彼を召喚した。彼のFondation Prospective et Innovation（FPI）は約30社（Carrefour、Kering、L'Oréal、LVMH）から資金を得た350万ユーロの予算を有し、元中国大使の呉建民から85,000ユーロを受け取っていた。2022年、RaffarinはHorizonsに参加した—中国の公式代表かつPhilippeの党員という二重の役割は前例がない。Causeurは、RaffarinとVillepinがマティニョン退任後の中国転身において「鏡のような軌跡」をたどったと指摘する。",
    "rodolphe-saade": "ロドルフ・サアデは2017年からCMA CGMの会長兼最高経営責任者を務め、1978年に同グループを設立した父ジャック・サアデの後継者である。彼のもとでCMA CGMは2022年に700億ユーロを超える売上を上げ、世界第3位の船会社となった。サアデはグループを海上輸送以外に多角化した：CEVA Logistics（物流）の買収、La TribuneとLa Provence（メディア）の購入、テクノロジーへの投資。サアデグループはレバノン系でマルセイユに本拠を置き、中国との主要な商業的つながりを持つ—アジア-ヨーロッパ航路はCMA CGMの事業の中核をなす。Édouard Philippeの牙城であるル・アーヴル港はCMA CGMの主要な欧州ハブの一つだ。CMA CGMのセキュリティ責任者でPhilippeと共にYoung Leader 2011であるYann Le Goffは、サアデ経営陣の直接の権限のもとで活動している。ロドルフ・サアデの資産は400億ユーロを超えると推定され、フランス有数の富豪の一人である。メディアへの拡張（La Tribune、La Provence、BFM Marseille）により、経済的影響力に加えてメディア影響力も備えることになった。CMA CGMは地中海、アフリカ、東南アジアにおける港湾パートナーシップを持ち、中国の「一帯一路」構想の中心的プレーヤーである。サアデ帝国、PhilippeのHAROPA港、Ribadeau-DumasのFCFネットワークの収斂は、相当な規模の経済的・政治的利害のネクサスを構成する。",
    "belt-and-road": "2013年に習近平が開始した「一帯一路」構想（BRI）は、アジア・アフリカ・欧州にわたる推定1兆ドル超の投資を伴う、史上最大のインフラ計画である。BRIの海上部門—「21世紀の海上シルクロード」—は、ターミナル・物流・港湾コンセッションへの投資を通じて中国の港を欧州の港に接続することを目的としている。欧州では中国がピレウス港（ギリシャ、COSCO経由）、ハンブルク、アントワープ、バレンシアに投資してきた。フランス最大のコンテナ港でありÉdouard Philippeの牙城であるル・アーヴル港は、この戦略に直接関わっている。アジア-ヨーロッパ航路を事業の核とするCMA CGMは、中国の船会社COSCOおよびOOCLの競合かつ潜在的パートナーである。Philippeのマティニョンで官房長を務めたFrance China Foundation（FCF）のメンバーであるRibadeau-Dumasは、中国の経済外交が欧州の意思決定者への影響拠点を構築しようとしているこの空間で活動している。BRIは「債務外交」および中国の地政学的影響力の道具として批判されてきた。フランスの首相が、中国海上航路上のフランス最大の港の市長でありながら、FCFに参加する人々に取り囲まれてマティニョンにいたという事実は、前例のない利益収斂を生み出している。イタリアは2019年にBRI覚書に署名したが2023年に撤退した—Philippe下のフランスは署名しなかったが曖昧な立場を維持した。中国投資に対する港湾主権の問題は、ル・アーヴルに直接関わる戦略的課題である。",
    "cosco-shipping": "COSCO Shippingは中国最大かつ世界第4位の船会社で、SASAC（国有資産監督管理委員会）を通じて中国国家が所有する。COSCOは1,300隻以上の船舶を運航し、世界300以上の港にサービスを提供している。欧州では2016年にギリシャのピレウス港の67%を取得し、中国の戦略的港湾インフラ掌握戦略を示した。COSCOとCMA CGMはOcean Alliance（アジア-ヨーロッパ航路を担うアライアンス）の中で競合かつパートナーである—この航路はル・アーヴルを経由する。このアライアンスにより、CMA CGMとCOSCOのコンテナはル・アーヴルも含め同じ船舶と同じターミナルを共有する。欧州港湾でのCOSCOの存在は、国家安全保障と主権に関する懸念を生じさせた。ドイツは2022年にCOSCOによるハンブルク港ターミナルへの出資が24.9%を超えることをブロックした。ル・アーヴルについても同様の問題がある：中国が競合港に投資することは、フランス最大の港の戦略にどの程度影響するのか？Philippeをマティニョンで囲むメンバーを持つFrance China Foundationは、まさにこの中欧間の港湾外交の空間で活動している。Ocean Alliance（COSCO + CMA CGM）、FCFネットワーク、そしてPhilippeのル・アーヴル市長職が絡み合う利害の連鎖は、詳細な検証に値する。COSCOは海洋分野における中国の「一帯一路」政策の道具である。",
    "comite-france-chine": "MEDEF Internationalに紐づくComité France-Chineは、中国に対するフランス財界の主要なロビー機関である。ジャン=ピエール・ラファランが会長を務め、France China Foundationと連携して機能する：Comitéは企業レベルで、FCFは個人レベルで活動する。ラファランがComitéの長でありFCFの後援者でもあることは、公式の経済外交と非公式の影響力ネットワークの間に橋を架ける。会員にはCAC 40のうち中国で活動するグループが含まれる：Airbus、Total、L'Oréal、Sanofi、港湾・物流関係者も名を連ねる。Ribadeau-Dumas（Philippeの官房長、FCF 2013）とLenain（FCF共同創設者、外交顧問）はともにこのエコシステムで活動してきた。",
    "alexis-kohler": "Alexis Kohler（1972年ストラスブール生）はénarque、マクロン政権下の経済省官房長（2014年）、その後エリゼ宮事務総長（2017-2025）——8年間エマニュエル・マクロンの右腕を務めた。2022年3月、彼は母方の従兄弟にあたるAponte一家が創設したMSC（Mediterranean Shipping Company）との利益相反について、不正利益取得、影響力行使および受動的汚職の容疑で正式に起訴された。2010年から2012年にかけて、KohlerはAgence des participations de l'Étatの代表としてGrand Port Maritime du Havre（GPMH）監督委員会に座り、その隣にはÉdouard Philippe（2010年10月から市長）がいた。Mediapartによると、KohlerはMSCとの家族的繋がりを一切申告せず、MSCに関わる投票でも回避しなかった一方、フィリップは回避ルールを厳格に守った。Kohlerはピボット型エージェントとして機能する：財政視察院 → APE/GPMH（フィリップと隣接）→ マクロン内閣（Bercy）→ MSC（天下り）→ エリゼ宮（SG）→ Société Générale（2025年）。この回路は手帳の逓増収益メカニズムを示している。KohlerとPhilippeが共にいたル・アーヴル港は地政学的なノードである：CMA CGM（世界第3位の海運会社）のハブ、MSC（第2位、Kohlerの家族）の顧客、COSCO Shipping（第1位の中国系海運会社、大連との姉妹都市関係）と連携し、Philippeの政治的管理下にある。2025年、KohlerはエリゼをSociété Généraleに移り、国家と金融の間の天下り回路を継続した。",
    "sibyle-veil": "シビル・ヴェイルは2018年4月以来、CSA（現Arcom）によってRadio France総裁に任命されている。Arcomのメンバーは行政府から影響を受けている。彼女はENA（国立行政学院）のLeopold Sedar Senghor組（2004年）の出身で、エマニュエル・マクロンと同期である。この同期の絆—フランスの高級官僚制において最も強い結びつきの一つ—は、主要な公共ラジオ局の長を共和国大統領と直接結びつける。彼女のもとでFrance Interは政治モーニングショーとともにフランス最も聴かれるラジオ局であり続けた。France InterにおけるÉdouard Philippeのインタビューは好意的なトーンが特徴で、敏感な案件—CMA CGMとの関係、France China Foundation、Atos事件—についての質問が系統的に欠けている。ヴェイルは2022年に更新され、マクロン政権の信任を確認した。Radio France以前は、Conseil d'Étatの顧問でありCour des comptesで働いた経験を持つ。ENA → Conseil d'État → 公共メディアの長というキャリアパスは、同じ同期が行政権とメディア権力を支配するフランスのシステムの典型例である。Macron（大統領）→ Arcom（任命）→ Veil（運営）→ France Inter（編集方針）という連鎖は、公共放送への間接的なコントロールを示す。Radio Franceは1日約1,500万人のリスナーに届く。",
    "bernard-arnault": "ベルナール・アルノーはLVMHの会長兼最高経営責任者で、資産総額が2,000億ユーロを超える世界一の富豪である。彼はLes Échos–Le Parisienグループのオーナーであり、このグループにはÉdouard Philippeと同じYoung Leader 2011であるDavid Barrouxが編集長を務める経済紙Les Échoも含まれる。アルノーはエマニュエル・マクロンの最も近い寡占的同盟者と見なされており、個人的な関係は文書化されている。LVMHはフランス最大の広告主であり、フランスのすべてのメディアに対する間接的な影響力を持つ。Les Échoの報道はPhilippeが推進する経済改革（労働オルドナンス、PACTE法）に系統的に好意的だ。イル・ド・フランスで最も読まれる大衆紙Le Parisienshは、より幅広い読者層にリーチするメディア装置を完成させる。アルノーはマクロンとPhilippeと共にいくつかの建築プロジェクトを落成した。世界一の富豪、Philippeを任命した大統領、Young Leaderの編集長が形成する三角形は、権力-金-メディアの三角形だ。LVMHは中国に大きな商業的利害を持ち、FCFとは異なるルートでアルノーを中仏ネットワークと結びつけている。フランス最大の経済メディアのオーナーがPhilippeを任命した大統領の主要な財政的支持者でもあるという事実は、構造的なメディアの利益相反を生む。",
    "vincent-bollore": "ヴァンサン・ボロレはVivendiを通じてメディア帝国を築いたブルターニュの実業家だ：Canal+、CNews、C8、Europe 1、Paris Match、Le Journal du Dimanche。2015年以降これらのメディアを徐々に買収する過程で、Eric Zemmour、Pascal Praud、Laurence Ferrariらの人物を通じた右翼・極右への編集路線転換が行われた。CNewsは「フランスのFox News」となった。政治的には、ボロレは「キングメーカー」だ：彼のチャンネルは2022年にZemmourを大統領候補として台頭させた。PhilippeにとってCNewsは逆説的な役割を果たす：チャンネルは彼をRNに対する「穏健な」代替案として提示し、共和主義の防壁というマクロン派の語りに奉仕した。Lagardèreを介したボロレ支配下のEurope 1は、Philippeのセンター右派路線と相容れる方向に再編された。ボロレはアフリカ（Bolloré Africa Logistics、港湾）とアジアにも巨大な利権を持ち、海上輸送問題と中国-アフリカネットワークと結びついている。彼のアフリカ物流帝国は2022年にCMA CGM（MSC）に売却され、ボロレとサアデグループの間に直接的なつながりが生まれた。アルノー（Les Échos、Le Parisien）、ボロレ（CNews、Europe 1）、サアデ/CMA CGM（BFM TV）間のメディア集中は、フランス3大ニュースメディアがマクロン権力に近い寡占者によって所有されていることを意味する。",
    "patrick-drahi": "パトリック・ドラヒはフランス系イスラエル人実業家でAlticeの創業者。2024年にメディア資産をCMA CGM（ロドルフ・サアデ）に売却するまでBFM TV、RMC、Libérationを所有していた。この取引は利益相反の連鎖において決定的だ：フランス最大の24時間ニュースチャンネルBFM TVが、財務的スキャンダルに囲まれたオーナー（Alticeの莫大な債務）から、Édouard Philippeの牙城の港で活動するCMA CGMへと移った。ドラヒはすでにBFMの編集方針への影響力を批判されていた。CMA CGMへの移行は対立をさらに深める：ル・アーヴルの港湾運営者が今やル・アーヴルの市長候補を報道するメディアを所有するからだ。ドラヒはイスラエルのHOTとSotheby'sも所有している。彼の帝国は莫大な債務（ピーク時で600億ユーロ超）の上に築かれており、このビジネスモデルは複数の国で税務調査を招いた。サアデへの売却はフランスで進行中のメディア集中を示している：ニュースメディアが多額の債務を抱えた億万長者の手から、中国の貿易ルートに結びついた億万長者の船会社オーナーの手へと渡るのだ。Drahi → BFM → CMA CGM → Le Havre → Philippeという連鎖は、逐次的な買収によって構築される利益相反の軌跡である。",
    "pierre-moscovici": "ピエール・モスコヴィシは2020年6月からCour des comptes（会計検査院）の院長を務める。Young Leader 1996（オランドと同期）。元財務大臣、その後EU委員。国の最高公的会計監査役と元首相が同じYoung Leaders networkの出身であるという事実は、監査の独立性に関する疑問を提起する。",
    "dominique-de-villepin": "ジャック・シラク政権の首相（2005-2007）であったドミニク・ド・ヴィルパンは、私的・多極的・不透明なネットワークを運営している。彼をPhilippeと直接結ぶ文書化された関係は存在しない—両者のネットワークはJuppéと中国との接点を通じて収斂する。Villepinは1979年に「groupe J」（Juppé派）に加わり、1993年にJuppéにより外務省の官房長に任命された。2008年以降：中国での約50回の有償講演（Radio Franceによれば2回で94,000ユーロ）、IMTA（中国機関）の会長職、香港での会社設立（2015年以降決算未提出）、習近平との親密さ。中国を超えた多極的ネットワーク：アル・サーニー家（カタール）との友情、カタール博物館局での地位、Valdaïでのプーチンとの共同登壇（2014年）、Djouhriと連携するパナマ企業を通じたサウジグループBugshan経由の年間80万ユーロ（2008-2010年）、Proglioを通じた17年のVeoliaとの契約、イラン・ベネズエラ・アルメニア・アゼルバイジャンでの活動。時にはフランス企業と競合しながらアフリカ・欧州での中国企業を支援。2025年5月世論調査：Villepin 51%、Philippe 50%。左翼（LFI 65%）を惹きつけるVillepin、中道右派のPhilippe。2027年の直接のライバル。",
    "villepin-international": "Villepin Internationalはドミニク・ド・ヴィルパンのマティニョン退任後に設立されたコンサルティング会社だ。その決算は2015年以来提出されていない—同年、香港で2社が設立され、次いで第3社（Villepin Group Limited）が設立され、多額の資金フローが存在する。Radio Franceの調査部門（2025年12月）による調査は、これらの構造を通じる中国活動の範囲を明らかにしている。資金フローの宛先と受益者は依然として大きな不明瞭な部分である。財務的不透明さは、FCFを通じたPhilippeの制度的で比較的透明なネットワークと対照をなす。",
    "alexandre-djouhri": "アレクサンドル・ジュリは、リビア資金供与事件で2025年9月に6年の禁固刑を宣告された仲介者だ。Radio Franceの調査は、Villepinが彼の同伴で海外渡航していたことを明らかにしている。サンクトペテルブルク・フォーラムでは、両者はVeoliaの「副社長」として登録した—これはグループ経営陣によって否定された。Philippeについて同様の結びつきは記録されていない。ジュリはVillepinネットワーク固有の影の結節点であり、元首相を最も物議を醸すビジネス界（ロシア、湾岸、リビア）と結びつける。",
    "henri-proglio": "アンリ・プローリョはVeolia Environnementの元CEO（2003-2009年）、次いでEDFの元CEO（2009-2014年）である。調査によれば、VillepinはProglioを通じて17年間Veoliaと契約関係にある。この繋がりは、VillepinとDjouhriがサンクトペテルブルク・フォーラムでVeoliaの「副社長」として登録したエピソードを説明する。Proglioはフランスの資本主義において公共・民間セクター間を行き来してきた人物だ。Villepinとビジネス界の間の接点としての彼の役割は、報告書が指摘するさらなる調査の方向性の一つである。",
    "imta": "International Mountain Tourism Alliance（IMTA）はVillepinが会長を務める中国の機関だ。この会長職は、Villepinが2008年以来中国で積み上げてきた公式・半公式の役割ネットワークの一部を成す：中国法人としての協会の会長職、投資ファンドの執行委員会への参加。IMTAはVillepinの中国における制度的な基盤—フランス語・中国語で管理される構造を通じるPhilippeのFCFルートとは異なり、中央権力から直接、上から得られた正統性—を示している。",
    "alain-merieux": "アラン・メリューはbioMérieux（体外診断の世界的リーダー）の創業者であるリヨンの実業家だ。彼はシラク大統領在任中に始まった仏中協力プロジェクトである武漢の高度安全P4研究所の設計者で、2018年に開設された。MérieuxはRaffarinとFabiusとともにFCF戦略評議会に名を連ねる。FCFの装置の中核にいる彼の存在は、仏中間の衛生外交（武漢P4研究所）とPhilippeが参加する影響力ネットワークの間にリンクを確立する。P4研究所の問題は、2020年のCovid-19パンデミック以降、地政学的に敏感な問題となっている。",
    "laurent-fabius": "ローラン・ファビウスは元首相（1984-1986年）で2016年以来憲法院院長を務め、RaffarinとともにFrance China Foundationの共同後援者だ。オランド政権下の元外相（2012-2016年）として、仏中外交の構造化に貢献した。MérieuxやRaffarinとともにFCF戦略評議会に名を連ねる彼の存在は、左右の対立を超え、北京との接近を巡るフランスエリートの合意を示している。Fabiusは法律の合憲性を審査する—Philippe政権の法律を含む。",
    "hubert-vedrine": "ユベール・ヴェドリンはミッテラン時代のエリゼ宮事務総長、次いで外相（1997-2002年）を務め、FCF戦略評議会のメンバーである。フランス外交政策の理論家であり、アメリカの「超大国」という概念の考案者として、米国からの独立というフランス外交の伝統の継続性を代表する—シラクの後継者たちを中国へと向かわせたのも同じ伝統だ。",
    "jacques-chirac": "ジャック・シラク（1932-2019年）、共和国大統領（1995-2007年）は、エコシステム全体の共通の源泉である。米国からの独立政策と北京との特別な対話は、PhilippeとVillepinが異なるルートで継承している仏中関係の伝統を生み出した。2019年のJDD/Ifop世論調査はJuppéをシラクの最有力後継者（62%）と位置づけ、Villepinを3位としながら、「シラク主義の最後の砦はマティニョンのÉdouard Philippeのもとにあるのではないか」と問いかけた。Villepinはシラクの「お気に入りの息子たち」の一人であった（La Libre）。Chirac → Juppé → PhilippeとChirac → Villepinはこの政治家系図の二本の枝だ。",
    "cpifa": "CPIFA（Chinese People's Institute of Foreign Affairs）はFrance China Foundationの公式中国パートナーだ。中国外交部と連携し、PhilippeとRaffarinの中仏ネットワークの制度的な対話相手を担う。CPIFAはフランスのソフトパワー（FCF）と中国の外交装置の間のインターフェースだ。この結びつきは、Philippe/Raffarinネットワーク（制度的・規制された）をVillepinネットワーク（私的、習近平を通じた中央権力への直接アクセス）から区別する。",
    "charles-hufnagel": "シャルル・フフナゲルは2000年代にAreva時代に知り合ったJuppéのコミュニケーション顧問だ。マティニョンでのPhilippeの広報官を務めた。政治記者から「エリゼ宮の同僚よりはるかに信頼できる」と評されている（Le Temps）。彼はJuppéieのコミュニケーション的継続性を体現する：JuppéのキャンペーンとPhilippeのマティニョン在任を特徴づけたのと同じ分別と節度ある対メディア姿勢の教義だ。Juppéieの第1サークル。",
    "benoist-apparu": "ベノワ・アパルは、サルコジ政権下の元住宅担当国務長官で、Philippeとともに2016年のJuppé選挙運動の共同広報官を務めた。予備選挙でのJuppéの敗北後、Fillon選挙チームに加わった。彼の軌跡は2016年11月以降のJuppé派の拡散を示している—一部はMacron（Boyer、Philippe）に合流し、他はLRの軌道に留まった。Juppéieの第1サークル。",
    "anne-clerc": "アンヌ・クレルはPhilippe政権下のマティニョン官房長だ。マティニョンでのRaffarin元チームのメンバーであり、2つのシラク主義首相官邸を繋ぐ人的橋渡し役だ。Philippe内閣における彼女の存在は、国家装置内でのJuppéieの継続性を示している：同じネットワークがマティニョンからマティニョンへと受け継がれていく。",
    "xavier-chinaud": "ザビエル・シノーはフィリップ政権下でマティニョン府の議員関係顧問を務める。ラッファラン政権下のマティニョン府では「政治研究」を担当した。アンヌ・クレルクと同様に、ラッファランとフィリップの両内閣を結ぶ橋渡し役を果たし、二つのシラク主義的マティニョン間での慣行とネットワークの継承を担っている。",
    "christophe-bechu": "クリストフ・ベシュはHorizons党の事務局長であり、元生態移行大臣（2022-2024年）、アンジェ市長を務める。Horizons内での彼の役割は組織的に重要で、党の地域組織を確保しつつ、フィリップ派の機構と地方選出議員を繋ぎ合わせている。フィリップ（ノルマンディー）/ベシュ（ロワール）/エストロジ（プロバンス=アルプ=コート・ダジュール）という軸が2027年に向けてHorizonsに多地域的な基盤を与える。ジュペイ第3サークル — 制度的同盟者。",
    "nathalie-loiseau": "ナタリー・ロワゾーはRenaissanceの欧州議会議員であり、元欧州担当大臣（2017-2019年）で、ジュペ派の諸サークルに近い。元ENA校長として、彼女はジュペイの欧州的な繋がりを体現する。ジュペが予備選で敗北した後、彼女はマクロンに合流した「行進派」 — マクロン支持に転じたジュペ派 — の一員となった。ジュペイ第3サークル。",
    "virginie-calmels": "ヴィルジニー・カルメルは、ボルドー市庁でのジュペの元第一副市長として、ジュペイの「新右派」支流を代表する — DroiteLib運動を通じてフィリップから離れ、ロラン・ヴォキエ陣営に合流した支流である。彼女の軌跡は2016年敗北後のジュペイの断片化を示す：ジュペ派の大多数はマクロンに合流したが、少数派はLRの右傾化を選んだ。元Endemol Franceのトップとして、ジュペが重視した政治家マネージャーのプロフィールを体現している。",
    "julien-miro": "ジュリアン・ミロは「bébés Juppé」ネットワークの主催者の一人である — 2016年予備選キャンペーンの退役者である30代の約30名が、敗北後に非公式ネットワークを形成した。ギヨーム・プフィスターとともに、友人関係にある有名人（Boyer、Gaymard、Keller、Bournazel）と共に隔月夕食会を開く。示唆的なのは、ミロが「アラン・ジュペは負けたが、ジュペ派が勝った：彼らは大臣官房の至るところにいる」と述べたことだ。マティニョン、外務省、経済省、生態移行省、文化省の顧問として — bébés Juppéはマクロン改革の実務を担っていた。ジュペイ第2サークル。",
    "guillaume-pfister": "ギヨーム・プフィスターは、ジュリアン・ミロとともに非公式の「bébés Juppé」ネットワークの共同主催者である。彼らが掲げる目標：「ジュペ派の炎を維持すること」と「ポスト・ジュペを準備すること」。夕食会にはジュペに近い著名人（Boyer、Gaymard、Keller、Bournazel）と大臣官房に散らばる若い顧問たちが集う。このネットワークはHorizonsの幹部の苗床を形成する。ジュペイ第2サークル。",
    "fpi-raffarin": "FPIはラッファランの財団であり、仏中関係のための手段として再構成された。予算350万ユーロは、約30の企業（Carrefour、Kering、L'Oréal、LVMH）がそれぞれ年15,000ユーロを拠出して賄われる。財団は中国の著名人からの寄付も受け、元大使ウー・ジャンミンからの85,000ユーロも含まれる。FPIはシンクタンクと影響力ネットワークの交差点に位置し、ラッファランに中国活動のための制度的インフラを提供する。FCFと並行するチャンネルであり — 一方（FPI）はラッファランの個人的な手段、他方（FCF）は集合的な構造である。",
    "groupe-bugshan": "Bugshan Groupはサウジアラビアのコングロマリットで、2008年から2010年にかけてアレクサンドル・ジュフリに関連するパナマの会社を通じて、年間80万ユーロをヴィルパンに支払った。Radio Franceの調査によって明らかになったこれらの資金の流れは、ヴィルパンのビジネス・ネットワークの不透明さを示す。資金はオフショア構造を経由しており、受益者の追跡を困難にする。Bugshan-Djouhri-Villepinの繋がりはネットワーク内で最も不透明なノードの一つである。",
    "sebastien-lecornu": "現職首相のセバスチャン・ルコルニュは、フィリップと競争と協力の関係を維持している。2016年予備選後、ジュペ派とともにフィヨン・チームに参加した元ルメール派。彼の軌跡はジュペイの軌跡と交わるが、完全に融合はしていない。フィリップと同じノルマン人（エブルー）として、多数派内で穏健右派への影響力をめぐる潜在的なライバルを代表する。",
    "plastic-omnium": "Plastic Omniumはフランスの自動車部品メーカーで、ラッファランが取締役会のメンバーを務めた。同グループは中国で売上の相当な割合を上げており、ラッファランが促進した仏中ネットワークの直接的な受益者となっている。ラッファランのエコシステムへの参加は、人脈活用のメカニズムを示す：中国に利益を持つ企業はFPI（年15,000ユーロ）に資金を提供し、その見返りとしてフランス政治の「中国担当大臣」によって促進された中国市場へのアクセス恩恵を受ける。",
    "laurent-marcangeli": "ロラン・マルカンジェリは国民議会の「Horizons et indépendants」会派を率いる。フィリップの立法上の代理人として、会派の法律案に対する立場を調整し、フィリップ派の議員の結束を確保する。2024年の解散後、会派は30議員から6議員へと激減 — これはHorizonsの議会基盤の脆弱さを示す崩壊である。",
    "jacques-attali": "ジャック・アタリ（1943年生）はエコール・ポリテクニーク卒でénarque（ロベスピエール組、1970年）。国家院元審計官、フランソワ・ミッテランの10年間の特別顧問（1981-1991）、BERS（BERD）の創設者初代総裁（1991-1993）、フランス成長開放委員会委員長（2007-2010）。仲介エージェントとして、アタリはマクロン＝フィリップの二人組を設計した：2007年に彼は自身の委員会の副調査報告者に若いマクロンを選んだ。2011年にはマクロンをオランドに紹介した。2017年3月にはマクロンにフィリップを首相として選ぶよう提言し、二人の会合を設定した。このAttali → Macron → Philippeという連鎖がフィリップ政権（2017-2020）の基礎的メカニズムである。アタリはFrance China Foundation（2013年）の戦略評議会の共同創設者で、Philippe、Raffarin、Fabius、Mérieux、de Castriesとともに座る——5つの権力レベルが交わるユニークな収束点。彼は2020年3月、パンデミック到来の時期にFCFを去った。マルチエージェントシステムでは、アタリは自身の中心点を持たず、各中心点を互いに結びつけることで間接的影響力を最大化する接続ノードとして機能する。その価値はネットワークにあり、正式な権力にはない——それゆえ政権交代を傷つかずに乗り越えられる。大統領が変わっても、首相が倒れても、アタリは残る。",
    "alain-minc": "アラン・マンク（1954年生）はénarque（レオン・ブルム組、1975年、首席）、財政総合視察官。元ルモンド監督委員会議長、AMコンセイユ社長、Sanef取締役会長、Fondation Saint-Simon会計係、Le Siècle会員。CAC40の大企業トップの3分の1が彼の役務に報酬を支払った（Bolloré、Bouygues、Vinci、Club Med、Suez）。仲介エージェントとして、マンクはフランス右派（Balladur、Sarkozy、Juppé）から活動し、補完役のアタリは左派（Mitterrand、Hollande）から活動する——これにより政治スペクトル全体をカバーできる対称性を持つ。マンクは2016年の予備選でJuppéを支持し、2017年にはマクロンに鞍替えした（ジュペー支持者自身と同様の移行）。JDDが源泉徴収（2018年）に関連して記録したGilles Boyer（マティニョン顧問）を通じ、フィリップとの間接的チャンネルを維持する。マクロンはENA卒業後、MincとAttaliという2人のメンターを持ちこれはタンデム仲介モデルを裏付ける。マンクはFAFの元Young Leaderであり、4十年に及ぶ連鎖を形成する：Minc（YL）→ Juppé（YL 1982）→ Philippe（YL 2011）→ Macron（YL 2012）。アタリと同様、マンクは一般には見えないところに身を置くことで間接的影響力を最大化する。選挙上の責任なし、正式な権力なし、しかし類稀な接続能力を持つ。",
    "commission-attali": "サルコジの依頼で設置され、アッタリが議長を務め、マクロンが副総報告担当者を担った。316項目の措置のうち：VTCの自由化があり、これがノヴェリ法（2009年）、そして「Uber-Macron deal」（2014-2016年）へと繋がった。規制緩和の連鎖の出発点：Commission → Uber → Macron → Philippe。",
    "msc-aponte": "アレクシス・コレルの母方の従兄弟にあたるアポンテ一族が創設。世界第2位の海運会社で、ル・アーヴル港でコンテナターミナルを運営する。コレルはGPMHでの任期中、MSCとの家族関係を一切申告しなかった。コレルの違法な利益相反による起訴の核心にある問題。",
    "rodolphe-saade-cma-cgm": "CMA CGM（世界第3位の海運会社）の最高経営責任者で、2023年のAltice Mediaの買収以来BFM TVとRMCのオーナー。CMA CGMはフィリップの拠点であるル・アーヴル港でターミナルを運営する。2024年にBolloré Transport & Logisticsを買収。三重ノード：経済的（海上輸送）、メディア的（BFM/RMC）、政治的（ル・アーヴル市長の港湾パートナー）。",
    "gpmh": "フランスの主要港であり、ネットワークの収束ノード。コレルとフィリップは共に監査役会に在籍した（2010-2012年）。CMA CGMのハブでありMSCの顧客でもある。大連（中国）と姉妹都市協定を結ぶ。COSCO Shipping（中国最大の海運会社）と連携。政治的、財政的、メディア的、地政学的権力が収束する地理的拠点。",
    "uber-files": "ICIJに流出した12万4,000件のUberの内部文書。Uberとマクロン内閣間の17回のやりとり、マクロン＝カラニック会合4回、隠された合意（UberはUberPopを放棄、国はVTC研修を250時間から7時間に削減）、Uberが起草して議員に伝えられた修正案が明らかになった。議会調査委員会（2023年）：利益相反なし、ただし「特権的な関係」は確認された。",
    "henri-de-castries": "システムにおける唯一無二のノード：2012年以来ビルダーバーグの運営委員会を率い、FCFのConseil stratégiqueではアッタリ、ラッファラン、フィリップと並んで在籍し、ENA（ヴォルテール組、1980年）でのヴィルパンの同期生でもある。元AXA CEO（2000-2016年）、Institut Montaigne会長、トリプルYoung Leader FAF（1994、1995、1998年）。大西洋横断ネットワーク（ビルダーバーグ、FAF）と仏中ネットワーク（FCF）を繋ぐ唯一の橋。",
    "gabriel-attal": "首相（2024年1月～9月）、第五共和制最年少の首相。2023年にリスボンのビルダーバーグに予算担当大臣として招待され、7ヶ月後に首相に任命された。2025年にはフィリップと並んでストックホルムに出席 — マクロン派の元首相二人が初めて共同参加。繰り返されるパターン：マクロン（ビルダーバーグ2014年 → 2ヶ月後に大臣）、フィリップ（2016年 → 11ヶ月後に首相）、アタル（2023年 → 7ヶ月後に首相）。",
    "patricia-barbizet": "ビルダーバーグの常任運営委員会のメンバー — ド・カストリに次ぐフランスの2番目の常任代表。元Siècle会長、元Artémis（ピノー）持株会社ゼネラルマネジャー。2023年のリスボン・ビルダーバーグに出席。ビルダーバーグをSiècleに繋ぎ、そこではアッタリとミンクも在籍する。",
    "institut-montaigne": "アンリ・ド・カストリが率いるリベラル系シンクタンクで、AXA、Engie、BNP Paribas、LVMH、TotalEnergiesが資金を提供する。マクロン2017年選挙キャンペーンの知的参照先：ディレクターのロラン・ビゴルニュがLREMのキャンペーン用住所を提供した。Horizons 2027プログラムの教義的生産のための手段。",
    "blackrock": "ラリー・フィンクが創設した世界最大の資産運用会社。AXA（ド・カストリ）、BNP（ルミエール、ビルダーバーグ2025）、TotalEnergies（プイヤネ、ビルダーバーグ）、Société Générale（コレル2025）などを含むCAC 40企業少なくとも18社に出資。2025年には220億ドルで世界43の港を買収するMSCの同盟者。フィリップは2027年に年金積立率15%を提案 — まさにBlackRockがフランスで目指す目標。",
    "jean-francois-cirelli": "ENA卒（レオナルド・ダ・ヴィンチ組、1985年）、元シラク顧問、ラッファラン内閣の副官房長（2002-2004年）、2003年フィヨン年金改革の立案者。Gaz de Franceの最高経営責任者、Engie第2位の幹部。2015年以来BlackRockフランスの会長。2018年にフィリップよりComité Action Publique 2022へ招待された。2019年12月31日、歴史的な年金スト最中に、フィリップによりLégion d'honneur将校に昇進させられた。",
    "marc-ferracci": "経済学者、HEC卒業、経済科学博士。Sciences Poで22歳のときにマクロンと出会う。マクロンの結婚の証人。父ピエール・フェラッチはAttali委員会（2007年）に参加し、そこでマクロンは調査報告者を務めた。Renaissanceの国会議員、元産業大臣。申告資産：2300万ユーロ。トリビューン「Pour la France, construisons l'union !」（2026年3月29日）の署名者。マクロン・エコシステムとフィリップ連合をつなぐ橋渡しエージェント。",
    "philippe-tabarot": "2024年12月以来運輸大臣。GPMH（Philippe/Kohler/MSC/CMA CGMのノード）を含むフランスの海港を監督。Estrosi（Horizons）の隣でのPACA地域副議長。LR上院議員。公金横領と不正利益取得でPNFの捜査対象。運輸大臣ポストは繰り返し登場するノード：Djebbari（YL FCF 2020）はHATV PからCMA CGM入りを禁じられた。",
    "maud-bregeon": "Lecornu政府報道官、委任大臣。トリビューン「Pour la France, construisons l'union !」（2026年3月29日）の署名者。LCIでフィリップが「真剣な選択肢を取り、この戦いを率いるのに最良の立場にいる可能性がある」と発言。現政権とフィリップの2027年候補者指名を明示的に結びつける。",
    "jean-paul-delevoye": "フィリップ政権下の年金担当高等弁務官。普遍的ポイント制度を担当。任命から3ヶ月後の2018年3月にはすでにBlackRockと面会。2019年12月16日、HATPVに未申告の13のマンデートを理由に辞任。彼が準備していた改革はBlackRock有利の積立方式への道を開くものとして疑われた。2020年2月の49.3条の適用、その後のパンデミックが改革を無期限に凍結した。",
    "elabe-bfmtv": "2026年3月28日のBFMTV（CMA CGM/Saadé所有）向けElabeの世論調査で、フィリップを第1回投票で20.5〜25.5%としている。moipresident.onlineの独立ベイズ集計は17%を示しており、3.5〜8.5ポイント低い。第2回投票でのBardellaとの51.5%という数字は誤差範囲内。依頼者（BFMTV/CMA CGM）は候補者（ル・アーヴル港）と利害を共有する。",
    "patrick-pouyanné": "TotalEnergiesのCEO。フィリップとともにBilderberg（2023年、2025年）の常連参加者。TotalEnergiesはInstitut Montaigne（de Castries）の株主であり、BlackRockにより相当程度保有されている。フィリップ、Attal、de Castriesとともにリスボンとストックホルムに出席。BilderbergサークルとビジネスサークルBlackRockを結ぶノード。",
    "jean-lemierre": "BNP Paribas会長。フィリップとAttalとともにストックホルムのBilderberg 2025に出席。BNPはBlackRockに一部保有されており、Institut Montaigneを支援。Kohlerは2025年にエリゼ宮を去りSociété Généraleへ移った——同じ銀行エコシステム。Bilderbergサークルはフランスのシステム上重要な銀行を大統領候補と直接結びつける。",
    "bernard-emie": "対外安全保障総局（DGSE、2017-2024）長官。フィリップ、Attal、de CastriesとともにリスボンのBilderberg 2023に出席。フランス対外情報機関トップの私的な大西洋横断フォーラムへの出席は注目すべき事実であり、Regards.frが取り上げた。2025年には2ヶ月前に任命されたNicolas Roche（SGDSN）がBilderbergで後任となった。",
    "laurent-nunez": "Laurent Nuñez-Belda（1964年ブルージュ生）はénarque（シラノ・ド・ベルジュラック組、1997-1999、内部試験）。DGSI長官（2017年6月〜2018年10月）、フィリップII政権内務省国務長官（2018年10月〜2020年7月）、エリゼ宮国家情報調整官（2020年7月〜2022年7月）、パリ警視総監（2022年7月〜2025年10月）、その後Lecornu II政権内務大臣（2025年10月〜現在）。彼はカスタネルとともに「黄色いベスト」弾圧の実行面の責任者であり、フィリップは政治的責任を担う。Nuñezは公にLBDを擁護し、2019年3月にDelpuech知事解任に加わり、第5共和政で最も厳しい治安維持ドクトリンを明確に採用した。MASの観点では、彼は国家執行エージェントであり、その忠誠心はマクロン（各ポストに個人的に任命）に直接向かい、名目上の上司であるフィリップにはない。HorizonsメンバーとともにLecornu II内閣にいることで、フィリップ派の圏との追加的な間接的繋がりが生まれる。Nuñez–Bompard–Caubelの三角形は調査報告書の構造的発見である：Bompard（Carrefour CEO）のENA同期であり、その妻Charlotte Caubelはフィリップ内閣で司法部門の責任者（2017-2020）を務めHorizonsの党員でもある。",
    "alexandre-bompard": "Alexandre Joubert-Bompard（1972年生）はCarrefourグループCEO（2024年売上高：860億ユーロ）で、ENA Cyrano de Bergerac組（1997-1999）で4位に卒業。彼は同組のLaurent Nuñezの同期（1999年4月19日付令、Légifrance、JORFTEXT000000211140）。妻のCharlotte CaubelはÉdouard PhilippeのマティニョンでMatignon内閣の司法部門長（2017-2020）を務めた。Bompardはフィリップとの直接の文書化された繋がりを持たないが、家族ネットワーク（Caubel経由）と職業ネットワーク（Nuñez経由）が大型小売業の世界と行政権力の中枢を結びつける。Carrefourは中国に重要な利害を持ち、パリ2024オリンピックの公式パートナーだった。",
    "charlotte-caubel": "Charlotte Caubel（裁判官、Sciences Po）は2017年5月にÉdouard PhilippeのマティニョンでMatignon内閣の司法顧問に任命された。3年間（2017-2020）在任し、司法部門の責任者となった。マティニョン後は保護司法青少年局長（2020-2022）を務め、その後Borne内閣（2022-2024）で児童担当国務長官に任命された。Horizons党の党員。2025年8月にはパリ副検察官に任命された。夫はAlexandre Bompard（Carrefour CEO）で、Laurent NuñezのENA同期。このNuñez–Bompard–Caubelの三角形は、NuñezのENA同期をフィリップ内閣の中核とHorizons党に直接結びつける。",
  },
  zh: {
    "emmanuel-macron": "埃马纽埃尔·马克龙于2012届「青年领袖」项目中入选，比爱德华·菲利普晚一年。两人共同的导师阿兰·朱佩属于1982年创始届——三代青年领袖被同一位政治教父联结在一起。2017年5月15日，马克龙任命菲利普为总理，尽管后者此前曾批评过他（称其为「前罗斯柴尔德银行家」，并讽刺其具有「老滑头的犬儒主义」）。这种批评之后的和解充分说明了网络纽带相较公开立场的力量。马克龙的职业轨迹是：财务总监察院，再到罗斯柴尔德银行，此后在奥朗德（本人为1996届青年领袖）手下被任命为爱丽舍宫副秘书长。「奥朗德（YL 1996）→马克龙（YL 2012）→菲利普（YL 2011）」这条位于国家权力之巅的锁链，在FAF历史上是绝无仅有的。两人关系自2020年以来持续趋于紧张：菲利普批评马克龙2024年解散议会是「一个灾难性和荒谬的决定」，并于2025年底要求其辞职。马克龙2012届的同期生中还有弗勒尔·佩勒兰和塞德里克·维拉尼，两人后来均成为政治人物。一位总统与其总理来自同一跨大西洋项目的连续届次，这在历史上前所未有，引发了外界对美国影响力渗透法国精英阶层形成过程的质疑。",
    "alain-juppe": "阿兰·朱佩是整个生态系统的教父。希拉克政府总理（1995—1997年），2004年被定罪（RPR虚设职位案），FAF创始届（1982年）青年领袖，波尔多市长（2006—2019年），自2019年3月起担任宪法委员会委员（任期至2028年），自2025年2月起担任乔治·蓬皮杜研究所所长。正是朱佩将菲利普引入政坛（2002年出任人民运动联盟秘书长），维尔潘早在「J组」（1979年）便与他相识，后被朱佩任命为外交部（Quai d'Orsay）办公室主任（1993年）。「朱佩（YL 1982）→菲利普（YL 2011）→马克龙（YL 2012）」这一三角形，是FAF内部权力传递最为引人注目的案例。如今，他因宪法委员会的诸多限制（谨慎义务、禁止任何党派职责、与一切职务不相容）而被束之高阁，既不能支持菲利普，也不能就政治问题表态，更无法在地平线党（Horizons）中发挥作用。但其剩余影响力三重叠加：制度层面（参与宪法裁决，与理查·费朗 YL 2005共同任职），象征层面（其政治遗产渗透入Horizons：实用主义、欧洲主义、温和自由主义），以及网络层面（「朱佩派」——其非正式的忠实追随者网络——构成Horizons的骨干）。出版《抉择之时》（Tallandier，2025年），探讨欧洲独立性。「阿兰·朱佩败了，但朱佩主义者赢了：他们遍布各部委的顾问班子」（朱利安·米罗）。",
    "cma-cgm": "达飞轮船（CMA CGM）是法国最大的航运公司，也是全球第三大航运公司，1978年由雅克·萨德在马赛创立。集团拥有600余艘船舶，服务全球420个港口。CMA CGM地区安全主管扬·勒戈夫与爱德华·菲利普共同入选2011届青年领袖。勒阿弗尔港是菲利普自2010年以来的政治大本营，也是CMA CGM在欧洲的主要枢纽之一——该集团船舶承担着勒阿弗尔相当大比例的集装箱运输。据欧洲刑警组织（Europol）数据，勒阿弗尔是可卡因进入欧洲的主要入境点，2023年查获量达18吨。港口安全问题——CMA CGM（通过勒戈夫）、市长的职责（菲利普）与跨大西洋网络（FAF）交汇的领域——是一个关键节点。CMA CGM自2017年起由罗多尔夫·萨德掌舵，集团已多元化布局媒体（收购《La Tribune》《La Provence》）和物流领域。法中基金会（FCF）——其成员包括菲利普的幕僚长里博多-迪马——嵌入同一套中法海事影响圈。CMA CGM通往亚洲的商业航线大量经由勒阿弗尔，使该港口成为商业、外交与政治利益的汇聚点。",
    "yann-le-goff": "扬·勒戈夫在2011年与爱德华·菲利普共同入选青年领袖时，担任法国最大航运公司达飞轮船（CMA CGM）的地区安全主管。其在CMA CGM的职位使他处于航运安全问题的核心——这一领域涵盖港口毒品走私打击工作。据欧洲刑警组织数据，菲利普的政治大本营勒阿弗尔港是可卡因进入欧洲的主要入境点。CMA CGM船舶占勒阿弗尔集装箱吞吐量的大部分，这意味着CMA CGM的安全保障与勒阿弗尔港安全密不可分。勒戈夫与菲利普在2011—2012年间的两次为期五天的研讨会上共处，在非正式而保密的氛围中建立了私人联系。同一届青年领袖中既有未来的市长/总理，又有在其港口运营的主要航运公司安全主管，这创造了一个直接的影响渠道。这种关联尤为重要，因为港口毒品走私已成为法国一大政治议题，勒阿弗尔的查获量屡创纪录（2023年查获可卡因18吨）。勒戈夫代表菲利普青年领袖网络中的CMA CGM节点。其职位（海事安全）、菲利普的属地（勒阿弗尔）与结构性问题（毒品走私）的交汇，值得深入审视。",
    "atos": "阿托斯（Atos）是一家专注于数字化转型、网络安全和云计算的法国IT集团。爱德华·菲利普于2020年离开马提尼翁（Matignon，即法国总理府）后随即被任命为独立董事，年薪约7万欧元。阿托斯在处理交通违法行为计算机数据——尤其是测速摄像头——方面处于领先地位，这一市场直接受益于菲利普2018年推行的每小时80公里限速措施。《伏尔泰大道》和《爆炸》媒体指出了这一潜在利益冲突：推出一项极不受欢迎道路措施的总理，随后加入了处理该措施所产生数据的公司董事会。菲利普与阿托斯的渊源可追溯至2006年，远在其就任总理之前。该公司自2022年起遭遇严重财务困难，股价暴跌，大规模重组。阿托斯还管理着法国国家战略业务（超级计算机、国防、2024年巴黎奥运会），使其成为一个敏感主体——而其董事恰好也是总统候选人。时间线——2018年推行时速80公里限制、2020年离开总理府、2020年加入阿托斯——引发了外界对公共决策与私人利益之间界限模糊的质疑。菲利普从未公开回应过这一潜在利益冲突。",
    "areva": "阿海珐（Areva，2018年更名为Orano）是法国核工业跨国企业，覆盖完整核燃料循环。爱德华·菲利普于2007年10月至2010年10月担任公共事务总监——从事游说与政界关系工作，使其始终处于决策圈核心。这一时期恰与其2011年入选青年领袖重叠，彼时他被介绍为「勒阿弗尔市长兼阿海珐公共事务总监」。核游说在法国是最强大的力量之一，该行业约占法国电力产量的70%。作为公共事务总监，菲利普的职责是代表阿海珐向议员和政府——即他后来作为总理所领导的同一批机构——进行游说。其职业轨迹：国务院→Debevoise & Plimpton（商业律师）→阿海珐（游说）→勒阿弗尔市长→总理府，呈现了公私之间「旋转门」的经典路径。阿海珐因2007年灾难性收购UraMin（损失36亿欧元）而爆发重大丑闻，此案于菲利普任职期间曝光。2017年，集团被迫在菲利普政府任期内由国家注资50亿欧元进行重组和资本补充。曾为其服务过的公司的游说者后来成为挽救该公司的总理——这是潜在利益冲突的教科书式案例。",
    "debevoise-plimpton": "Debevoise & Plimpton LLP是一家1931年在纽约成立的美国律师事务所，专攻国际商事法、并购、私募股权和国际仲裁。该所拥有约800名律师，在纽约、华盛顿、伦敦、巴黎、法兰克福、香港和上海设有办公室。爱德华·菲利普在卸任人民运动联盟秘书长并申请国务院留职停薪后，于2004年至2007年在巴黎分所担任律师。在这家顶级英美律所的经历，展示了典型的「旋转门」职业轨迹：高级公务员生涯（ENA、国务院）→政党领导（UMP）→国际私营部门→重返政坛。Debevoise代理《财富》500强企业和投资基金，这使菲利普在国际商界建立了广泛人脉。该所在香港和上海设有分支机构——亚洲贸易的神经中枢——结合菲利普圈子后来与中法关系的深度交织，此细节颇为值得关注。离开Debevoise后，菲利普进入阿海珐担任公共事务总监（游说职能），确认了其在经济影响圈中的嵌入程度。「国务院→UMP→Debevoise→阿海珐→市长→总理府」这一序列勾勒出一条每个阶段都为下一阶段丰富人脉的路径。Debevoise的经历是这段本质上属于法国的职业生涯中的英美角落。他在Debevoise处理的报酬和委托事项从未被公开。",
    "antoine-rufenacht": "安托万·吕费纳克特1995年至2010年任勒阿弗尔市长，是诺曼底右翼的代表人物，曾就读于国家行政学院。正是他发现了爱德华·菲利普作为潜在接班人的价值，并于2001年将其纳入市政候选名单，担任法律事务副市长，从而将他引入政界。此后，吕费纳克特于2002年向阿兰·朱佩推荐菲利普担任人民运动联盟秘书长，由此开启了后者的全国政治生涯。2010年吕费纳克特辞去市长职务后，市议会选举菲利普接替他——一次完美编排的地方权力交接。律师克里斯蒂娜·波瓦耶-吕费纳克特与菲利普同届入选2011年FAF青年领袖——这一巧合从未得到公开解释，她的姓氏与前市长相同。吕费纳克特执掌勒阿弗尔长达十五年，塑造了菲利普继承的地方政治与经济网络。吕费纳克特任内，勒阿弗尔围绕港口和被列入联合国教科文组织遗产名录的佩雷建筑群推进了城市转型。吕费纳克特与菲利普的关系是地方政治传承的教科书案例：导师识别、培养并将自己的门生安置在城市顶端。菲利普在勒阿弗尔的根基——市政府、港口、城市社区——均直接继承自吕费纳克特的网络。地方导师与跨大西洋网络（FAF）汇聚于同一姓氏周围这一事实，令人不禁对法国精英阶层的共选机制产生疑问。",
    "french-american-foundation": "法美基金会（FAF）是1976年在杰拉尔德·福特总统和瓦莱里·吉斯卡尔·德斯坦总统的倡议下成立的组织。其「青年领袖」项目创设于1981年，每年从高级公务员、企业界、媒体、军队和科研机构中分别遴选10名30至40岁的法国人和美国人。入选者在连续两年内参加两次为期五天的研讨会，地点在法国和美国之间交替。研讨会内容不对外公开——FAF不披露历届活动的议程。完成项目后，参与者加入一个拥有600余名成员的校友网络。该项目常被描述为美国「软实力」的工具，尽管FAF自我标榜为「既非智库，也非游说机构，更非议员联谊会」。青年领袖在法国政府中的存在引人注目，且跨越政党轮替。爱德华·菲利普属于2011届，埃马纽埃尔·马克龙属于2012届，阿兰·朱佩属于1982年创始届，弗朗索瓦·奥朗德属于1996届。菲利普政府大臣理查·费朗是2005届青年领袖。自1981年以来，已有400余位领导人受益于该项目，而总统与其总理均来自连续届次这一事实在FAF历史上是前所未有的。项目赞助商包括空客、摩根大通和索迪斯。",
    "david-barroux": "大卫·巴鲁是法国主要财经日报《回声报》（Les Échos）的记者兼主编，与爱德华·菲利普同属法美基金会2011届青年领袖。执掌这份权威经济媒体，使他在法国经济政策报道方面具有相当大的影响力。《回声报》属于贝纳尔·阿尔诺的LVMH集团，将巴鲁置于一个与法国巨额财富相互关联的媒体生态系统中。作为青年领袖，他与菲利普共同参加了2011—2012年间两次为期五天的研讨会，建立了持久的私人与职业联系。一位未来总理与一家大型日报主编汇聚于同一跨大西洋网络，值得关注。《回声报》总体上对菲利普政府的改革给予正面报道，尤其是劳动法典改革和PACTE法案。这种亲近性折射出法国政界与媒体精英在同一影响力网络中的深度交融。巴鲁代表2011届的媒体支柱。FAF不公开这些未来领导人在研讨会上的交流内容。",
    "yohann-benard": "约汉·贝纳尔在2011年入选青年领袖时担任亚马逊法国公司公共事务总监。他与爱德华·菲利普共同组成FAF这届成员——彼时菲利普是勒阿弗尔市长兼阿海珐公共事务总监。两人担任类似职能——游说与机构关系——一个服务于核工业巨头，另一个服务于美国电商巨头。亚马逊因其劳工和税务实践以及对本地商业的冲击，在法国颇具争议。贝纳尔负责在法国当选官员和行政机构面前维护亚马逊的利益。与未来的总理共享一个精英跨大西洋网络，使他获得了进入决策圈的特权渠道。菲利普政府在马提尼翁的三年里，尽管有所承诺，并未特别加重对GAFA的税收。一位亚马逊游说人士与一位后来成为总理的阿海珐游说人士同届，清楚地呈现了企业利益与政治权力之间的多孔性。FAF研讨会为这些联系的建立提供了非正式场所。贝纳尔代表这届的美国企业支柱。",
    "stephane-israel": "斯特凡·以色列（Stéphane Israël）与爱德华·菲利普同年入选2011届青年领袖。他后来成为ArianeGroup（空客/赛峰合资企业）子公司、全球航天发射服务领导者阿里亚纳空间（Arianespace）的执行总裁。加入阿里亚纳空间之前，以色列曾在奥朗德总统任内担任高等教育与研究部长日内维耶夫·菲奥拉佐的办公室主任（2012—2014年）。他体现了高级公务员体系与战略性产业之间典型的「旋转门」模式。其轨迹——部长办公室，再到公共企业领导层——与菲利普（国务院、阿海珐、政坛）相近。阿里亚纳空间是欧洲航天主权的关键参与者，其总裁与法国行政当局保持密切关系。以色列与菲利普同届，在核工业、航天工业与政治权力之间建立了横向联系。ArianeGroup母公司空客也是FAF青年领袖项目的赞助商之一。项目赞助商与入选成员之间的这种交织，引发了对遴选过程独立性的质疑。以色列代表2011届的战略工业支柱。",
    "christine-poyer-rufenacht": "克里斯蒂娜·波瓦耶-吕费纳克特是合伙律师，与爱德华·菲利普共同入选2011年FAF青年领袖。她的姓氏不可避免地令人联想起安托万·吕费纳克特——2001年将菲利普引入政坛的勒阿弗尔市长——这一官方传记从未加以说明的令人不安的同名现象。安托万·吕费纳克特是菲利普的地方导师，为其在市政候选名单上谋得第一个位置，继而向阿兰·朱佩推荐他出任人民运动联盟秘书长。同一届青年领袖中，既有吕费纳克特的门生，又有一位与他同姓之人，这引发了外界对这些网络内部共选机制的疑问。FAF不公布详细的评选标准，申请流程部分依赖赞助推荐。如果克里斯蒂娜·波瓦耶-吕费纳克特与安托万·吕费纳克特存在亲属关系，这将构成一个家族与政治网络在跨大西洋机构中自我延续的案例。至少，姓氏上的巧合说明了FAF所选法国精英活动圈子的狭窄。勒阿弗尔在这些网络中作为反复出现的节点浮现出来：菲利普、吕费纳克特、达飞轮船。这一联系值得深入调查。FAF在其流程方面的不透明使核实工作困难重重。",
    "estelle-youssouffa": "埃斯特尔·尤苏法如今是马约特岛第一选区的国民议会议员，于2022年当选。她与爱德华·菲利普同届入选2011年青年领袖。从政前，尤苏法曾是记者，尤其在法国24小时电视频道（France 24）和半岛电视台（Al Jazeera）工作，因此属于该项目的媒体支柱。从国际新闻业到议会代表的轨迹，呈现了青年领袖走向权力职位的典型路径。作为议员，她在国民议会任职，而爱德华·菲利普的地平线党（Horizons）在议会同样设有代表，为同一届成员之间缔结议会联盟提供了可能。马约特面临重大挑战（移民、安全、发展），这些议题定期出现在全国性辩论中。尤苏法与菲利普同届FAF，将海外领地问题与菲利普系网络联系了起来。青年领袖项目历史上在成员之间产生了持久纽带，成员们此后各自在不同领域担任要职。这种同届动态是网络最有效的机制之一。尤苏法代表2011届的海外领地与媒体支柱。",
    "richard-ferrand": "理查·费朗是法国政治人物，曾任国民议会议长（2018—2022年），并在爱德华·菲利普第一届内阁中担任领土凝聚力部长（2017年5—6月）。他是2005届青年领袖，比菲利普早六年。费朗是埃马纽埃尔·马克龙最早的支持者之一，2016年共同创立了「前进！」运动（En Marche）。作为菲利普的部长、后来的议会议长，他是菲利普所活跃的马克龙主义体制中的重要齿轮。他2005届青年领袖的身份，将他纳入与菲利普（2011）、马克龙（2012）、朱佩（1982）相同的跨大西洋网络。领土凝聚力部长与总理均为前青年领袖这一事实，说明该网络在政府内部的高密度渗透。费朗于2019年因一宗房产纠纷——布列塔尼互助会案——被正式立案调查，涉嫌非法利益冲突，于2023年获得不予起诉裁定。其司法经历表明，青年领袖网络的成员身份未必能免于检察追诉。尽管如此，行政与立法两院顶端青年领袖的汇聚仍值得批判性审视。",
    "francois-hollande": "弗朗索瓦·奥朗德2012年至2017年担任法兰西共和国总统，是FAF 1996届青年领袖，与皮埃尔·莫斯科维奇同届。他比菲利普早十五年参加该项目，说明了网络跨越政治世代与政党更替的延续性。奥朗德先后任命马纽埃尔·瓦尔斯和贝尔纳·卡泽纳夫为总理，但正是其继任者马克龙（YL 2012）任命了菲利普（YL 2011）。奥朗德—马克龙的总统继承链，因此是青年领袖网络内部的一条内部传承链。奥朗德担任社会党第一书记长达十一年（1997—2008年），此后方才登上总统宝座，这使他得以构建起密集的政治网络。其1996届成员包括皮埃尔·莫斯科维奇——日后的欧盟委员，继而担任审计法院院长——展示了前青年领袖所任职位的多样性。FAF项目因此孕育了两位共和国总统（奥朗德和马克龙）、至少四位总理（朱佩、菲利普及间接意义上的其他人），以及众多部长。来自同一遴选项目的权力如此集中，就法国统治精英的形成而言引发了民主层面的质疑。奥朗德2017年以来多次批评菲利普，但两人共享同一结构性网络。",
    "laurent-wauquiez": "洛朗·沃基耶是奥弗涅-罗讷-阿尔卑斯大区主席，共和党（LR）前主席（2017—2019年），2006届青年领袖。他代表着与爱德华·菲利普相同的跨大西洋网络的右翼。2017年菲利普加入马克龙阵营之前，两人曾在LR党内相互角力。沃基耶强烈批评菲利普出任总理府，称其为对右派的背叛。尽管政治立场对立，两人共享同样的精英教育轨迹——都是国家行政学院毕业生，都是青年领袖。沃基耶被视为2027年总统大选的潜在候选人，这将使他成为来自同一网络的菲利普的直接竞争对手。两位潜在总统候选人均为前青年领袖这一事实，说明该项目无论左右皆能培养国家未来领导人的能力。沃基耶2006届将其置于网络年表中费朗（2005）与菲利普（2011）两代之间。其政治轨迹——从萨科齐政府国务秘书到大区主席——呈现出与菲利普相似但更为偏右的路径。FAF研讨会有可能在两人公开政治对抗之前，便通过校友网络提供了沃基耶与菲利普相交的机会。",
    "fleur-pellerin": "弗勒尔·佩勒兰与埃马纽埃尔·马克龙同年入选2012届青年领袖。彼时她担任奥朗德政府中小企业、创新与数字经济部副部长，后成为文化部长（2014—2016年）。2012届紧接菲利普2011届之后，意味着两届的研讨会可能存在重叠——菲利普2012年的第二次研讨会可能与佩勒兰和马克龙的第一次研讨会重合。佩勒兰毕业于国家行政学院（圣歌尔届，2000年），这所学校在青年领袖的简历中反复出现。卸任部长后，她创立了专注于亚洲投资的风险投资公司Korelya Capital，在跨大西洋（FAF）与亚洲（法中基金会）网络之间架起了一座桥梁。佩勒兰出生于韩国，由法国家庭收养，由此具备FAF所重视的双文化背景。其离任后转向亚洲风险投资的轨迹，说明了在精英网络中建立的联系如何转化为经济机遇。包含马克龙和塞德里克·维拉尼在内的2012届，是该项目历史上政治影响力最为深远的届次之一。",
    "laphonza-butler": "拉丰扎·巴特勒是美国政治人物，2023年10月由加州州长盖文·纽森任命为加州参议员，接替已故参议员黛安·范斯坦。她与法国一侧的爱德华·菲利普同属2011届美国方面的青年领袖。进入参议院之前，巴特勒曾任加州最大医疗行业工会SEIU Local 2015的主席（拥有40万会员），此后又领导了支持女性候选人的民主党组织EMILYs List。她进入参议院的轨迹，展示了美国青年领袖走向最高职位的路径。一位美国参议员与一位前法国总理曾在同一跨大西洋项目中受训，这在美国参议院与法国政治之间创造了一个直接的影响渠道。巴特勒在2011—2012年间的两次为期五天的研讨会上与菲利普相处，建立了持久的个人联系。青年领袖项目恰恰是为了在两国未来领导人之间构建这种桥梁而设计的。巴特勒代表2011届的美国进步政治支柱。她的存在说明了FAF在候选人尚未登上最高职位之前便能识别未来领导人的能力。",
    "horizons": "地平线党（Horizons）是爱德华·菲利普2021年10月9日在其大本营勒阿弗尔举行的公开集会上创立的政党。该党定位于中间偏右，体现马克龙主义总统多数派的右翼。四大核心主题为人口、环境、地缘政治与技术，口号是「高瞻远瞩，行之有道」。埃马纽埃尔·马克龙对这位自称「忠诚但自由」的前总理创立地平线党颇为不悦。2022年1月，该党加入「共同公民」（Ensemble Citoyens）联盟。尼斯市长克里斯蒂安·埃斯特罗西成为二号人物，为这个扎根诺曼底的政党带来了地中海色彩的依托。在2022年立法选举中，地平线党在联盟内获得58个候选人认可，并组建了由洛朗·马尔坎杰利主持的约30名议员的「地平线党与独立人士」议会团。2024年议会解散后，该党仅保住6席。2026年3月，地平线党宣称在全国拥有465名登记注册的市长——这一地方网络构成菲利普2027年总统竞选的骨干。该党作为个人选举工具运作：其唯一战略目标就是将菲利普送入爱丽舍宫。党内骨干大多来自菲利普在勒阿弗尔和朱佩派的人脉网络。",
    "christian-estrosi": "克里斯蒂安·埃斯特罗西自2008年起担任尼斯市长（2014—2017年曾任普罗旺斯-阿尔卑斯-蔚蓝海岸大区主席，中间有所中断），是爱德华·菲利普地平线党（Horizons）的二号人物。作为萨科齐政府工业部长（2009—2010年）和普罗旺斯右派的代表人物，埃斯特罗西为地平线党带来了南法依托，与菲利普的诺曼底根基互补。2021年他加入地平线党是一次重大政治冲击：他离开LR转投一个中右政党，带动了部分尼斯及蔚蓝海岸右派人士追随。尼斯是法国第五大城市，也是主要的旅游和经济枢纽，这使埃斯特罗西在党内具有相当的政治份量。2016年7月14日的尼斯恐袭（86人遇难）在埃斯特罗西身上留下了深刻烙印，他作为都市圈主席应对了这场危机——这一事件塑造了他的危机管理者形象。他与记者劳拉·特努吉结婚，这为其带来额外的媒体曝光度。在地平线党内，埃斯特罗西扮演招募者角色，吸引那些被中右路线所打动的LR议员。其轨迹说明了菲利普的策略：吸纳对LR向强硬右翼演变感到失望的右派干部。「菲利普（诺曼底）/埃斯特罗西（普罗旺斯-阿尔卑斯-蔚蓝海岸）」这对搭档将赋予地平线党在2027年总统选举中的双区域基础。埃斯特罗西还担任法国市镇间合作联盟（Intercommunalités de France）副主席，拥有与菲利普互为补充的地区性网络。",
    "gilles-boyer": "吉尔·博瓦耶是爱德华·菲利普二十余年来的最亲密顾问，在朱佩的轨道中锻造成型。曾任朱佩波尔多市政厅办公室主任（2002—2004年、2006—2010年），继而担任朱佩2016年初选的竞选总监（菲利普为联合发言人）。与菲利普共同创作了两部政治小说（《真相之时》2007年，《阴影中》2011年）及《印象与清晰脉络》（2021年）。任菲利普在马提尼翁的特别顾问（2017—2019年）。现为文艺复兴党（Renaissance）欧洲议会议员。一位萨科齐主义者曾给他们起绰号「普里克和普洛克」（博瓦耶和菲利普），两人的搭档关系形影不离。博瓦耶架起了朱佩遗产与Horizons机器之间的桥梁：他是菲利普主义教义的守护者，也是那种影响每一政策走向的幕后顾问的原型。「朱佩派」的核心圈。",
    "christophe-castaner": "克里斯托夫·卡斯塔内尔于2018年10月由爱德华·菲利普任命为内政部长，此前波伏广场经历了第五共和国史上最漫长的代理期——源于热拉尔·科洛姆的辞职。其任命恰在黄背心运动爆发前一个月，使他成为1968年五月以来最具争议的维稳政策的直接责任人。卡斯塔内尔将示威者称为「前来杀人的叛乱分子」，为过度的安全响应进行背书。在他的主导下，防卫弹发射器（LBD40）的使用量比上年猛增逾200%。人员伤亡前所未有：25人失明，5人断手，432人重伤。联合国、欧洲委员会和国际特赦组织要求禁止这些武器。卡斯塔内尔系统性地无视警察暴力的举报，拒绝暂停LBD的使用。作为菲利普的部长，其政策直接关联到总理的政治责任。警察总局内部调查局（IGPN）受理了313项涉嫌警察暴力的司法调查，创历史纪录。卡斯塔内尔此前曾担任LREM总代理，这说明菲利普政府期间马克龙主义机器与安全机器之间的深度融合。",
    "benoit-ribadeau-dumas": "伯努瓦·里博多-迪马，国家行政学院马克·布洛克届（1997年）榜首，菲利普的同届同学。马提尼翁办公室主任（2017—2020年）——违背马克龙意愿而被选用，后者原欲推入尼古拉·雷韦尔。因作风强硬被称为「梵蒂冈」。法中基金会（FCF）成员（2013年与菲利普、马克龙同届创始班）。马提尼翁前：萨科齐驻爱丽舍宫副官房长（2011—2012年），奥朗德任内副秘书长——一段跨越政党轮替的职业生涯。菲利普政府所有决策的操盘手：劳动法令、时速80公里限制、黄背心运动、养老金改革、新冠疫情应对。力主2020年3月15日地方选举第一轮按时举行。马提尼翁后加入Exor（埃尔坎/阿涅利家族理财室），担任Stellantis和Iveco董事。「朱佩派」核心圈——连接国家行政学院网络、法中基金会与行政权力的节点。",
    "france-china-foundation": "法中基金会（FCF）是2012年为拉近法中两国统治精英而成立的组织。其战略委员会包括让-皮埃尔·拉法兰、洛朗·法比尤斯和阿兰·梅里厄（武汉P4实验室的缔造者）。其官方中方合作伙伴是中国人民外交学会（CPIFA），该学会隶属于中国外交部。2013年创始届汇集了菲利普、马克龙和里博多-迪马。2015年，菲利普在勒阿弗尔接待FCF代表团参观港口。2018年5月，他以总理兼前青年领袖身份出席凡尔赛宫年度晚宴。FCF的不透明程度与FAF相当：不公布会议议程，无公开报告。FAF（大西洋横断）和FCF（中法）两大网络围绕同一核心——菲利普、里博多-迪马、勒内——共存，在马提尼翁制造了前所未有的双极影响力体系。维尔潘在任何FCF场合均未出现——其中国网络属于个人与私密性质，并非机构化的。",
    "emmanuel-lenain": "埃马纽埃尔·勒内是职业外交官，2012年法中基金会的共同创始人，2017年至2020年担任爱德华·菲利普在马提尼翁的外交顾问。这一双重角色——中法网络的架构师与总理顾问——使他成为行政权力核心中连接跨大西洋（FAF）与亚洲（FCF）两大网络的人形桥梁。在马提尼翁任职之前，勒内曾担任多个战略性外交职务，尤其是在法国常驻联合国代表团。离开马提尼翁后，他被任命为法国驻印度大使（2019—2022年）——这一职位将他置于法中印战略三角之中。他在菲利普入选FAF青年领袖一年后的2012年创立FCF，暗示着一种有意构建互补性双边影响力网络的战略。作为菲利普的外交顾问，勒内可接触政府所有国际谈判，包括涉及中国及海上贸易路线的谈判。法国最大港口、菲利普政治大本营勒阿弗尔，与中法贸易及「一带一路」倡议（新丝绸之路）问题直接相关。勒内处于FCF、马提尼翁与亚洲外交的交汇处，说明了一个人如何能够充当外交、经济与政治利益之间的传动皮带。其马提尼翁后的轨迹——驻印度大使馆，继而在外交部任职——确认了他在面向亚洲的法国外交机构中的路径。勒内是连接菲利普青年领袖网络与中法网络的缺失一环。",
    "port-du-havre": "勒阿弗尔港是法国最大的集装箱港口，也是欧洲第五大港口。自2021年起，它已并入HAROPA港口集群（勒阿弗尔、鲁昂、巴黎），这是法国最大的港口综合体。Édouard Philippe自2010年起担任该市市长，从而对港口战略方向和勒阿弗尔-塞纳大都市区产生直接影响。法国最大的航运公司CMA CGM在此处理了大量集装箱运输，开设了直达上海、宁波、深圳及主要亚洲港口的航线。经勒阿弗尔转运的中法海洋贸易每年数十亿欧元。该港口也受到中国\"一带一路\"倡议的影响，该倡议旨在将欧洲港口基础设施与中国物流网络连接起来。根据欧洲刑警组织的数据，勒阿弗尔是欧洲最大的可卡因入境口岸。毒品缉获量呈爆炸式增长：2023年法国海关查获可卡因18吨，创历史纪录。港口安全由国家、海关和港口当局共同负责——这一领域中，CMA CGM（通过Yann Le Goff，负责安全）、市政府（Philippe）和影响力网络（FAF、FCF）的利益交织在一起。港口扩建和集装箱码头投资是该地区的重大经济议题，Philippe在此享有长达十五年无可争辩的政治根基。港口治理问题——谁决定投资、特许权、检查——是Philippe-CMA CGM-FCF关系网络的核心所在。",
    "jean-pierre-raffarin": "让-皮埃尔·拉法兰，希拉克政府总理（2002-2005年），是Philippe和Villepin中国网络之间的枢纽人物。他累积了无可匹敌数量的中国职位：博鳌亚洲论坛（亚洲版达沃斯）顾问委员会成员、\"一带一路\"论坛成员、上海中欧国际工商学院理事、中国-国际企业家联合会联合主席、CGTN（中国公共电视）节目主持人、法国政府对华特别代表（2018年以来）、FCF联合赞助人及中法委员会主席。2019年9月29日，习近平向他颁发友谊勋章——中国给予外国人的最高荣誉，与普京和卡斯特罗共享。DGSI于2018年夏天因其与被视为党的代理人的中国商人的往来，召集他进行了\"意识增强谈话\"。他的前瞻与创新基金会（FPI）拥有350万欧元预算，由约三十家企业（家乐福、开云、欧莱雅、LVMH）资助，并收到了前中国大使吴建民85,000欧元的捐款。2022年，拉法兰加入Horizons党——他的双重角色（对华官方代表和Philippe党成员）堪称绝无仅有。Causeur指出，拉法兰和Villepin在离开马提尼翁后的对华转型中走了\"镜像轨迹\"。",
    "rodolphe-saade": "罗多尔夫·萨阿德自2017年担任CMA CGM集团董事长兼首席执行官，接替其父雅克·萨阿德——集团创始人（1978年）。在他领导下，CMA CGM已成为全球第三大航运公司，2022年营收超700亿欧元。萨阿德将集团多元化扩展至海上运输之外：收购CEVA Logistics（物流）、购入《论坛报》和《普罗旺斯报》（媒体）、技术领域投资。萨阿德集团源自黎巴嫩，总部位于马赛，与中国保持重要商业联系——亚欧航线是CMA CGM业务的核心。Édouard Philippe的根据地勒阿弗尔港是CMA CGM的主要欧洲枢纽之一。CMA CGM安全主管、与Philippe同为Young Leader 2011的Yann Le Goff直接在萨阿德管理层的授权下工作。罗多尔夫·萨阿德的资产估计超过400亿欧元，是法国最大的财富之一。其媒体扩张（《论坛报》、《普罗旺斯报》、BFM Marseille）赋予他经济影响力之外的媒体影响力。CMA CGM是中国\"一带一路\"倡议的核心参与者，在地中海、非洲和东南亚拥有港口合作关系。萨阿德帝国、Philippe的勒阿弗尔港与Ribadeau-Dumas的FCF网络的汇聚，构成了一个规模相当可观的经济与政治利益节点。",
    "belt-and-road": "习近平于2013年发起的\"一带一路\"倡议（BRI）是历史上最大的基础设施计划，在亚洲、非洲和欧洲的预计投资超过1万亿美元。BRI的海上部分——\"21世纪海上丝绸之路\"——旨在通过投资码头、物流和港口特许权，将中国港口与欧洲港口相连。在欧洲，中国已投资比雷埃夫斯港（希腊，经由COSCO）、汉堡、安特卫普和瓦伦西亚。法国最大集装箱港口、Édouard Philippe根据地的勒阿弗尔港，直接受到这一战略的影响。以亚欧航线为核心业务的CMA CGM，既是COSCO和东方海外货柜航运（OOCL）等中国船公司的竞争对手，又是潜在的合作伙伴。曾任Philippe马提尼翁幕僚长的FCF成员Ribadeau-Dumas，正是在这一空间中运作——中国经济外交在此寻求在欧洲决策者中建立影响支点。BRI因被视为\"债务外交\"和中国地缘政治影响力工具而受到批评。法国总理被FCF网络人员环绕于马提尼翁，同时担任中国海上航线上法国第一大港的市长，由此形成了前所未有的利益汇聚。意大利于2019年签署了BRI备忘录，后于2023年退出——Philippe领导下的法国从未签署，但维持了模糊立场。面对中国投资的港口主权问题，是一个直接涉及勒阿弗尔的战略议题。",
    "cosco-shipping": "中远海运是中国第一、全球第四大航运公司，通过国务院国资委（SASAC）由中国国家持有。中远运营1,300余艘船舶，服务于全球300余个港口。在欧洲，中远2016年收购了希腊比雷埃夫斯港67%的股权，体现了中国掌控战略港口基础设施的战略。中远和CMA CGM既是竞争对手，也是Ocean Alliance（涵盖亚欧航线，即经由勒阿弗尔的同一航线）内的合作伙伴。该联盟意味着CMA CGM和中远的集装箱共用相同船舶和码头，包括在勒阿弗尔。中远在欧洲港口的存在引发了国家安全和主权方面的担忧。德国2022年阻止中远持有汉堡码头股份超过24.9%。对勒阿弗尔来说，同样的问题摆在眼前：中国在竞争性港口的投资，在多大程度上影响法国第一大港的战略？Philippe在马提尼翁周围那些FCF成员，恰恰活跃在这个中欧港口外交空间。Ocean Alliance（中远 + CMA CGM）、FCF网络与Philippe担任勒阿弗尔市长这三者的交织，构成一张值得深入审视的利益之网。中远是中国\"一带一路\"政策在海洋领域的执行工具。",
    "comite-france-chine": "中法委员会隶属于法国企业运动国际（MEDEF International），是法国商界面向中国的主要游说机构。由让-皮埃尔·拉法兰担任主席，与法中基金会协同运作：委员会在企业层面运作，FCF在个人层面运作。拉法兰既主持委员会又担任FCF赞助人，架起了官方经济外交与非正式影响力网络之间的桥梁。成员包括在中国活跃的CAC 40成分股企业：空客、道达尔、欧莱雅、赛诺菲，以及港口和物流领域的参与者。Ribadeau-Dumas（Philippe的幕僚长，FCF 2013届）和Lenain（FCF联合创始人，外交顾问）均在这一生态系统中活跃。",
    "alexis-kohler": "Alexis Kohler（1972年生于斯特拉斯堡）是énarque，曾任马克龙领导下经济部办公室主任（2014年），后任爱丽舍宫秘书长（2017-2025）——八年间担任埃马纽埃尔·马克龙的左膀右臂。2022年3月，他因与MSC（地中海航运公司）的利益冲突——该公司由Aponte家族创立，而Aponte家族是其母亲的堂亲——被以非法牟利、贩卖影响力和被动腐败正式起诉。2010年至2012年，Kohler作为国家资产参与局代表，在勒阿弗尔大海事港（GPMH）监事会任职，与Édouard Philippe（2010年10月起任市长）并肩。据Mediapart报道，Kohler从未申报与MSC的家族关系，在涉及MSC的投票中也未回避，而菲利普则严格遵守了回避规则。Kohler作为枢纽代理人运作：财政稽查院 → APE/GPMH（与菲利普并肩）→ 马克龙内阁（Bercy）→ MSC（旋转门）→ 爱丽舍宫（SG）→ 法国兴业银行（2025年）。这一回路阐明了通讯录递增收益的机制。Kohler与Philippe共同活动的勒阿弗尔港是地缘战略节点：CMA CGM（全球第三大航运公司）枢纽，MSC（第二大，Kohler家族）客户，与COSCO Shipping（第一大中国航运，大连结对城市）相连，处于菲利普的政治治理之下。2025年，Kohler离开爱丽舍宫加入法国兴业银行，继续国家与金融之间的旋转门回路。",
    "sibyle-veil": "西比尔·韦尔自2018年4月起担任Radio France总裁，由受行政权力影响的CSA（现更名为Arcom）任命。她毕业于ENA（国家行政学院）莱奥波尔德·塞达尔·桑戈尔届（2004年），与埃马纽埃尔·马克龙同届。这种同届情谊——法国高级公务员体系中最牢固的联系之一——将法国最重要公共广播机构的总裁与共和国总统直接相连。在她的领导下，France Inter凭借其政治早间节目，始终保持法国收听率最高的广播电台地位。Philippe在France Inter的访谈以友好基调为特点，系统性地缺乏对敏感档案的追问：CMA CGM关联、法中基金会、阿托斯案。韦尔2022年获得连任，确认了马克龙政府的信任。在Radio France之前，她曾是最高行政法院的行政官员，并在审计法院工作过。ENA → 最高行政法院 → 公共媒体负责人的职业路径，是同一届毕业生掌控行政权力和媒体权力的法国体制的典型缩影。Macron（总统）→ Arcom（任命）→ Veil（管理）→ France Inter（编辑方针）这一链条，说明公共广播受到间接控制。Radio France每日覆盖约1500万听众。",
    "bernard-arnault": "贝尔纳·阿尔诺是LVMH集团董事长兼首席执行官，以逾2000亿欧元的资产总额位居全球首富。他是Les Échos–Le Parisien集团的所有者，该集团旗下包括经济日报《回声报》，其总编辑David Barroux与Édouard Philippe同为Young Leader 2011届。阿尔诺被视为埃马纽埃尔·马克龙最亲密的寡头级盟友，两人之间有文献记录的私人关系。LVMH是法国最大的广告主，从而对法国所有媒体拥有间接影响力。《回声报》的报道对Philippe推动的经济改革（劳动法令、PACTE法）系统性地持正面立场。法兰西岛地区读者最多的大众日报《巴黎人报》进一步扩大了媒体受众面。阿尔诺与马克龙和Philippe共同出席了多个建筑项目的落成典礼。世界首富、任命Philippe的总统以及同届Young Leader总编辑形成一个权力-金钱-媒体三角关系。LVMH在中国拥有重大商业利益，这使阿尔诺通过不同于FCF的渠道与中法网络相连。法国最大经济媒体的所有者同时也是任命Philippe的总统的主要财务支持者，这一事实造成了结构性的媒体利益冲突。",
    "vincent-bollore": "文森特·博洛雷是一位布列塔尼实业家，通过Vivendi构建了一个媒体帝国：Canal+、CNews、C8、Europe 1、《巴黎竞赛画报》、《星期日日报》。自2015年起逐步收购这些媒体的过程伴随着向右翼和极右翼的编辑路线转变，以埃里克·泽穆尔、帕斯卡尔·普罗、洛朗斯·法拉利等人物为代表。CNews成了\"法国福克斯新闻\"。在政治博弈中，博洛雷是一个\"造王者\"：他的频道帮助泽穆尔在2022年作为总统候选人崛起。对Philippe而言，CNews扮演着矛盾的角色：该频道将他呈现为对抗国民联盟的\"理性\"替代选项，为马克龙派的共和主义防线叙事服务。经由拉加代尔受博洛雷控制的Europe 1，已重新定位为与Philippe中右路线相容的编辑方针。博洛雷在非洲（博洛雷非洲物流、港口）和亚洲也有大量利益，将其与海上运输问题和中非网络联系起来。他的非洲物流帝国2022年出售给了CMA CGM（MSC），在博洛雷与萨阿德集团之间建立了直接联系。阿尔诺（《回声报》、《巴黎人报》）、博洛雷（CNews、Europe 1）和萨阿德/CMA CGM（BFM TV）之间的媒体集中意味着，法国三大新闻媒体均为与马克龙权力圈亲近的寡头所有。",
    "patrick-drahi": "帕特里克·德拉希是法裔以色列商人，Altice创始人，曾拥有BFM TV、RMC和《解放报》，直至2024年将媒体资产出售给CMA CGM（罗多尔夫·萨阿德）。这笔交易在利益冲突链条中至关重要：BFM TV（法国最大的24小时新闻频道）从一个深陷财务丑闻（Altice巨额负债）的所有者手中，转让给了在Édouard Philippe根据地港口运营的领先航运公司CMA CGM。德拉希此前已因对BFM编辑路线的影响而受到批评。移交给CMA CGM加剧了冲突：勒阿弗尔的港口运营商如今拥有了报道勒阿弗尔市长候选人的媒体。德拉希还拥有以色列HOT和苏富比拍卖行。他的帝国建立在巨额债务（高峰时超过600亿欧元）之上，这一金融模式在多个国家引发了税务调查。出售给萨阿德说明了法国正在进行的媒体集中：新闻媒体从债台高筑的亿万富翁手中，转移到与中国贸易航线相关联的亿万富翁船东手中。Drahi → BFM → CMA CGM → Le Havre → Philippe这一链条，是通过逐步收购构建起来的利益冲突轨迹。",
    "pierre-moscovici": "皮埃尔·莫斯科维奇自2020年6月起担任审计法院院长。Young Leader 1996届（与奥朗德同届）。前经济部长，后任欧盟委员。国家最高公共审计官与前总理均出自同一Young Leaders网络，这一事实引发了对监督独立性的质疑。",
    "dominique-de-villepin": "多米尼克·德维尔潘，希拉克政府总理（2005-2007年），经营着一个私人的、多极的、不透明的网络。没有任何有文献记录的直接关系将他与Philippe联系起来——两人的网络通过Juppé和中国关联汇聚。Villepin于1979年加入\"J团体\"（Juppé的忠诚者），后于1993年由Juppé任命为外交部幕僚长。2008年以来：在中国约50场有偿演讲（据Radio France透露两场收费94,000欧元）、担任IMTA（中国机构）主席、在香港设立公司（2015年以来未申报账目）、与习近平关系密切。超出中国的多极网络：与阿勒萨尼家族（卡塔尔）为友、在卡塔尔博物馆局任职、与普京在瓦尔代论坛（2014年）共同登台、通过与Djouhri有关联的巴拿马公司每年从沙特集团Bugshan获得80万欧元（2008-2010年）、通过Proglio的17年Veolia合同、在伊朗、委内瑞拉、亚美尼亚、阿塞拜疆的业务活动。协助中国企业在非洲和欧洲开展业务，有时与法国企业形成竞争。2025年5月民调：Villepin 51%、Philippe 50%。吸引左翼（LFI 65%），Philippe吸引中右翼。2027年的直接竞争对手。",
    "villepin-international": "Villepin International是多米尼克·德维尔潘离开马提尼翁后设立的咨询公司。其账目自2015年起不再申报——同年在香港设立两家公司，随后又设立第三家（Villepin Group Limited），有可观的资金流动。Radio France调查部门的报道（2025年12月）揭示了经由这些结构流动的中国业务规模。资金流的去向和受益方仍是重大灰色地带。这种财务不透明与Philippe通过FCF构建的制度化、相对透明的网络形成鲜明对比。",
    "alexandre-djouhri": "亚历山大·朱里是一名中间人，于2025年9月在利比亚资金案中被判处六年监禁。Radio France的调查显示，Villepin曾多次与他同行出境。在圣彼得堡论坛上，两人将自己注册为Veolia的\"副总裁\"——这一注册遭到集团管理层否认。Philippe方面没有类似联系的记录。Djouhri是专属于Villepin网络的暗节点，将这位前总理与最具争议性的商业圈（俄罗斯、海湾、利比亚）联系起来。",
    "henri-proglio": "亨利·普罗里奥是Veolia Environnement前首席执行官（2003-2009年），随后担任法国电力公司（EDF）首席执行官（2009-2014年）。据调查显示，Villepin通过Proglio与Veolia保持合同关系已达17年。这一联系解释了圣彼得堡论坛上Villepin和Djouhri将自己注册为Veolia\"副总裁\"的事件。Proglio是法国资本主义界在公共和私人部门之间穿梭的代表性人物。他作为Villepin与商界联络点的角色，是报告所指出的深入调查方向之一。",
    "imta": "国际山地旅游联盟（IMTA）是一个中国机构，Villepin担任其主席。这一主席职位是Villepin自2008年以来在中国积累的官方和半官方职能网络的一部分：担任中国法律框架下协会的主席、进入投资基金执行委员会。IMTA体现了Villepin在中国的制度性根基——这种合法性是从顶层直接从中央权力获得的，不同于Philippe的FCF路径（通过受规范的中法联合结构运作）。",
    "alain-merieux": "阿兰·梅里厄是里昂实业家，bioMérieux创始人，bioMérieux是体外诊断领域的全球领导者。他是武汉高级别P4生物安全实验室的设计者，该实验室于2018年落成——这是希拉克总统任期内启动的中法合作项目。梅里厄与拉法兰和法比尤斯同坐FCF战略委员会。他在FCF装置核心的存在，在中法卫生外交（武汉P4实验室）与Philippe所参与的影响力网络之间建立了联系。自2020年新冠疫情暴发以来，P4实验室问题已具有地缘政治敏感性。",
    "laurent-fabius": "洛朗·法比尤斯，前总理（1984-1986年），2016年起担任宪法委员会主席，与拉法兰共同担任法中基金会的联合赞助人。作为奥朗德政府的前外长（2012-2016年），他参与了中法外交的结构化。他与拉法兰和梅里厄共同坐入FCF战略委员会，超越了左右分野，体现了法国精英围绕向北京靠拢的共识。法比尤斯负责验证法律的合宪性——包括Philippe政府的法律。",
    "hubert-vedrine": "于贝尔·韦德里纳，密特朗时代的爱丽舍宫秘书长，随后担任外交部长（1997-2002年），是FCF战略委员会成员。作为法国外交政策理论家和美国\"超级大国\"概念的创造者，他代表着法国外交独立于美国这一传统的延续——正是这一传统推动了希拉克的继承者们转向中国。",
    "jacques-chirac": "雅克·希拉克（1932-2019年），共和国总统（1995-2007年），是整个生态系统的共同源头。他的对美独立政策和与北京的特殊对话，孕育了中法关系的传统，Philippe和Villepin分别通过不同渠道继承了这一传统。2019年JDD/Ifop民调将Juppé列为希拉克最主要的继承人（62%），Villepin居第三，同时提问\"希拉克主义的最后堡垒是否就在马提尼翁，由Édouard Philippe把守\"。Villepin是希拉克的\"最爱的儿子\"之一（La Libre）。Chirac → Juppé → Philippe和Chirac → Villepin是这棵政治家谱树的两个分支。",
    "cpifa": "CPIFA（中国人民对外友好协会）是法中基金会的官方中国合作伙伴。与中国外交部相关联，它是Philippe和拉法兰中法网络的机构性对话方。CPIFA是法国软实力（FCF）与中国外交机构之间的接口。这一连接将Philippe/Raffarin网络（制度化、受规范）与Villepin网络（私人的、通过习近平直接获取中央权力）区分开来。",
    "charles-hufnagel": "夏尔·胡夫纳格尔是Juppé的传播顾问，两人在2000年代的Areva相识。担任Philippe在马提尼翁的发言人。政治记者认为他\"比爱丽舍宫的同行可靠得多\"（Le Temps）。他体现了Juppéie的传播连续性：同一套谨慎低调、克制对媒曝光的教条，贯穿了Juppé的选举运动和Philippe在马提尼翁的岁月。Juppéie第一圈。",
    "benoist-apparu": "贝努瓦·阿帕吕，萨科齐政府前住房国务秘书，与Philippe共同担任2016年Juppé竞选活动的联合发言人。Juppé在初选中落败后，他加入了菲永的竞选团队。他的轨迹说明了2016年11月后Juppé派的分散——一部分加入了马克龙（博耶、Philippe），另一部分仍留在共和党轨道。Juppéie第一圈。",
    "anne-clerc": "安娜·克莱尔是Philippe政府下马提尼翁的官房长。她曾是马提尼翁拉法兰团队的成员——这使她成为两任希拉克主义总理幕僚之间的人际桥梁。她在Philippe内阁中的存在，说明了Juppéie在国家机器内部的延续性：同一张网络从一个马提尼翁传递到下一个马提尼翁。",
    "xavier-chinaud": "夏维尔·希诺在菲利普执政期间担任马蒂尼翁府的议员关系顾问。曾任拉法兰政府马蒂尼翁府「政治研究」负责人。与安娜·克莱克一样，他是拉法兰与菲利普两届内阁之间的纽带，确保两届希拉克主义马蒂尼翁之间惯例与人脉的传承。",
    "christophe-bechu": "克里斯托夫·贝希是地平线党秘书长、前生态转型部长（2022-2024年）兼昂热市长。他在地平线党内部发挥着结构性作用：负责党的地方组织，并在菲利普派别机器与地方民选官员之间架起桥梁。菲利普（诺曼底）/贝希（卢瓦尔）/埃斯特罗西（普罗旺斯-阿尔卑斯-蓝色海岸）这一轴线赋予地平线党面向2027年大选的多地区基础。朱贝网络第三圈——制度性盟友。",
    "nathalie-loiseau": "纳塔莉·卢瓦佐是复兴党欧洲议会议员、前欧洲事务部长（2017-2019年），与朱贝派圈子关系密切。作为前ENA校长，她代表着朱贝网络的欧洲纽带。朱贝在初选中失败后，她成为「行进者」群体的一员——倒向马克龙的朱贝派。朱贝网络第三圈。",
    "virginie-calmels": "维尔吉妮·卡尔梅尔曾任波尔多市政府朱贝的第一副市长，代表朱贝网络的「新右翼」分支——该分支通过DroiteLib运动远离菲利普、转向洛朗·沃基。她的轨迹揭示了2016年失败后朱贝网络的分裂：朱贝派大多数人加入马克龙，少数人选择了LR的右转。作为前Endemol France负责人，她体现了朱贝所看重的政治家-管理者型人才。",
    "julien-miro": "朱利安·米罗是「bébés Juppé」网络的组织者之一——约三十名三十多岁人士、2016年初选战役的老将，在败选后组成非正式网络。他与纪尧姆·普菲斯特一起，每两个月举办一次与友人（Boyer、Gaymard、Keller、Bournazel）共进的晚宴。耐人寻味的是，米罗宣称：「阿兰·朱贝输了，但朱贝派赢了：他们遍布各大臣内阁。」马蒂尼翁、外交部、经济部、生态转型部、文化部的顾问——bébés Juppé主导了马克龙主义的各项改革。朱贝网络第二圈。",
    "guillaume-pfister": "纪尧姆·普菲斯特与朱利安·米罗共同担任「bébés Juppé」非正式网络的联合组织者。他们的公开目标：「延续朱贝派的火焰」并「为后朱贝时代做准备」。晚宴汇聚与朱贝亲近的知名人士（Boyer、Gaymard、Keller、Bournazel）以及散落在各大臣内阁中的年轻顾问。这一网络是地平线党干部的培育基地。朱贝网络第二圈。",
    "fpi-raffarin": "FPI是拉法兰的基金会，被重组为推进法中关系的工具。预算350万欧元，由约三十家企业（家乐福、开云、欧莱雅、LVMH）每年各出资1.5万欧元资助。基金会还收到中国知名人士的捐款，包括前大使吴建民捐赠的8.5万欧元。FPI运作于智库与影响力网络的交叉地带，为拉法兰的中国活动提供制度性基础设施。这是与FCF并行的渠道——一个（FPI）是拉法兰的个人工具，另一个（FCF）是集体结构。",
    "groupe-bugshan": "布格尚集团是一家沙特综合企业，2008年至2010年间通过一家与亚历山大·久里相关联的巴拿马公司，每年向维尔潘支付80万欧元。这些资金流动由Radio France的调查披露，揭示了维尔潘商业网络的不透明性。资金流经离岸结构，使受益方难以追溯。布格尚-久里-维尔潘的关联是网络中最不透明的节点之一。",
    "sebastien-lecornu": "现任总理塞巴斯蒂安·勒科尔尼与菲利普保持着竞争合作关系。他是前勒梅尔追随者，2016年初选后随朱贝派一同加入菲永团队。他的轨迹与朱贝网络交汇，但并未融入其中。他与菲利普同是诺曼底人（埃夫勒），代表着多数派内争夺温和右翼影响力的潜在竞争对手。",
    "plastic-omnium": "全耐塑料（Plastic Omnium）是一家法国汽车零部件制造商，拉法兰曾是其董事会成员。该集团在中国实现了相当大比例的营业额，使其成为拉法兰促成的法中网络的直接受益者。其在拉法兰生态圈中的存在揭示了人脉变现的机制：拥有中国利益的企业向FPI出资（每年1.5万欧元），换取法国政界「中国先生」便利的中国市场准入。",
    "laurent-marcangeli": "洛朗·马尔卡恩哲利担任国民议会「地平线与无党派」议会团团长。他是菲利普的立法代理人：协调该党团在法律文本上的立场，并确保菲利普派议员的凝聚力。2024年解散后，该党团从三十名议员锐减至六名——这一崩溃揭示了地平线党议会基础的脆弱性。",
    "jacques-attali": "雅克·阿塔利（1943年生）毕业于综合理工学院，为énarque（罗伯斯庇尔班，1970年）。曾任国务院审计官、弗朗索瓦·密特朗十年特别顾问（1981-1991）、欧洲复兴开发银行（BERD）创始人及首任行长（1991-1993）、法国增长解放委员会主席（2007-2010）。作为中介代理人，阿塔利设计了马克龙-菲利普组合：2007年，他选择年轻的马克龙担任其委员会副调查报告员；2011年，他将马克龙介绍给奥朗德；2017年3月，他建议马克龙选择菲利普出任总理，并安排了二人的会面。这条Attali → Macron → Philippe的链条是菲利普政府（2017-2020）的奠基机制。阿塔利是France China Foundation战略委员会（2013年）联合创始人，与Philippe、Raffarin、Fabius、Mérieux和de Castries同席——五个权力层次的独特汇聚。他于2020年3月离开FCF，正值疫情到来之际。在多智能体系统中，阿塔利没有自己的质心，而是作为连接节点运作，通过将各质心相互连接来最大化间接影响力。他的价值在于网络，而非正式权力，这使他能够在政权更迭中全身而退——总统可以换，总理可以下台，阿塔利依然存在。",
    "alain-minc": "阿兰·芒克（1954年生）是énarque（莱昂·布鲁姆班，1975年，届第一名），财政总稽查员。曾任《世界报》监事会主席、AM Conseil总裁、Sanef董事会主席、Fondation Saint-Simon司库、Le Siècle会员。CAC 40大企业三分之一的领导层曾支付其服务报酬（Bolloré、Bouygues、Vinci、Club Med、Suez）。作为中介代理人，芒克从法国右翼（巴拉迪尔、萨科齐、朱佩）出发开展工作，而其互补者阿塔利则从左翼（密特朗、奥朗德）出发——这种对称使他们能够覆盖整个政治谱系。芒克在2016年初选中支持朱佩，随后于2017年转向马克龙（与朱佩派人士本身的转向如出一辙）。他通过Gilles Boyer（马提尼翁顾问）与菲利普保持间接渠道，这一关系被JDD记录于扣缴税款事件（2018年）。马克龙离开ENA时拥有两位导师：芒克和阿塔利，印证了双人中介模式。芒克是FAF的前Young Leader，由此形成跨越四个十年的链条：Minc（YL）→ Juppé（YL 1982）→ Philippe（YL 2011）→ Macron（YL 2012）。与阿塔利一样，芒克通过对公众保持隐形来最大化间接影响力。无选举责任、无正式权力，但拥有无与伦比的连接能力。",
    "commission-attali": "由萨科齐委托设立，阿塔利主持，马克龙担任副总报告员。316项措施中包括：VTC（网约车）的自由化，导致诺韦利法案（2009年），继而是「Uber-Macron交易」（2014-2016年）。放松管制链条的起点：委员会 → Uber → 马克龙 → 菲利普。",
    "msc-aponte": "由阿彭特家族——阿列克西·科勒母亲的表亲——创立。全球第二大航运公司，在勒阿弗尔港运营集装箱码头。科勒在GPMH任职期间从未申报其与MSC的家族关联。位于科勒违法利益冲突起诉案的核心。",
    "rodolphe-saade-cma-cgm": "达飞集团（全球第三大航运公司）CEO，2023年收购Altice Media后成为BFM TV和RMC的拥有者。达飞集团在菲利普的根据地勒阿弗尔港运营码头。2024年收购博洛雷运输物流公司。三重节点：经济（海上运输）、媒体（BFM/RMC）和政治（勒阿弗尔市长的港口伙伴）。",
    "gpmh": "法国最大港口，网络的汇聚节点。科勒与菲利普共同在监事会任职（2010-2012年）。达飞集团的枢纽港和MSC的客户港。与大连（中国）结为友好城市。与中远海运（中国第一大航运公司）有所关联。政治、金融、媒体与地缘战略权力在此汇聚的地理节点。",
    "uber-files": "泄露给ICIJ的12.4万份Uber内部文件。揭露了Uber与马克龙内阁之间的17次联络、马克龙与卡兰尼克的4次会面、一项隐藏的交易（Uber放弃UberPop，国家将网约车培训从250小时削减至7小时），以及Uber起草后转交给议员的修正案。议会调查委员会（2023年）：无利益冲突，但「特权关系」得到确认。",
    "henri-de-castries": "系统中的唯一节点：自2012年起主持毕德堡指导委员会，与阿塔利、拉法兰、菲利普共同参与FCF战略委员会，并与维尔潘同届ENA（伏尔泰届，1980年）。前安盛CEO（2000-2016年），Institut Montaigne会长，三次Young Leader FAF（1994、1995、1998年）。跨大西洋网络（毕德堡、FAF）与法中网络（FCF）之间的唯一桥梁。",
    "gabriel-attal": "总理（2024年1月至9月），第五共和国最年轻的总理。2023年以公共账目部长身份受邀参加里斯本毕德堡会议，七个月后被任命为总理。2025年与菲利普一同出席斯德哥尔摩会议——首次两位马克龙派前总理同时与会。规律性模式：马克龙（毕德堡2014年 → 2个月后任部长）、菲利普（2016年 → 11个月后任总理）、阿塔尔（2023年 → 7个月后任总理）。",
    "patricia-barbizet": "毕德堡常设指导委员会成员——继德卡斯特里之后的第二位法国常任代表。前Siècle会长，前Artémis（皮诺）控股公司总经理。出席了2023年里斯本毕德堡会议。将毕德堡与Siècle连通，阿塔利和明克也是后者的成员。",
    "institut-montaigne": "由亨利·德卡斯特里主持的自由主义智库，由AXA、Engie、BNP Paribas、LVMH和道达尔能源资助。马克龙2017年竞选的智识参照来源：智库主任洛朗·比戈尼曾提供LREM竞选地址。2027年地平线党纲领的教义生产工具。",
    "blackrock": "拉里·芬克创立的全球最大资产管理公司。持有CAC 40指数至少18家企业的股份，包括安盛（德卡斯特里）、法国巴黎银行（勒米尔，毕德堡2025）、道达尔能源（普扬内，毕德堡）、法国兴业银行（科勒2025）。2025年与MSC联合收购全球43个港口，总价228亿美元。菲利普提议2027年将养老金资本化比例设为15%——正是贝莱德在法国的目标。",
    "jean-francois-cirelli": "ENA毕业（列奥纳多·达·芬奇届，1985年），前希拉克顾问，拉法兰内阁副秘书长（2002-2004年），2003年菲永养老金改革的设计者。法国天然气公司CEO，安迪（Engie）第二号人物。自2015年起担任贝莱德法国总裁。2018年受菲利普邀请加入公共行动2022委员会。2019年12月31日，在历史性养老金大罢工期间，由菲利普晋升为荣誉军团军官。",
    "marc-ferracci": "经济学家，HEC毕业，经济学博士。22岁在Sciences Po认识马克龙。马克龙婚礼见证人。其父皮埃尔·费拉奇曾任Attali委员会委员（2007年），马克龙时任调查报告员。Renaissance议员，前工业部长。申报资产：2300万欧元。2026年宣言《Pour la France, construisons l'union !》（2026年3月29日）签署人。马克龙生态圈与菲利普联盟之间的桥梁代理人。",
    "philippe-tabarot": "2024年12月起任交通部长。监督法国海港，包括GPMH（Philippe/Kohler/MSC/CMA CGM节点）。曾任PACA大区副主席，与Estrosi（Horizons）共事。LR参议员。因挪用公款和非法牟利受到PNF调查。交通部长职位是反复出现的节点：Djebbari（YL FCF 2020）被HATVP禁止加入CMA CGM。",
    "maud-bregeon": "Lecornu政府发言人，委任部长。2026年宣言《Pour la France, construisons l'union !》（2026年3月29日）签署人。曾在LCI上表示菲利普\"做出了严肃的选择，很可能是领导这场战役最合适的人选\"。明确将现任政府与菲利普2027年候选资格相联系。",
    "jean-paul-delevoye": "菲利普政府退休金高级专员，负责普遍积分制度。2018年3月，即任命后三个月便与BlackRock会面。2019年12月16日因13项未向HATVP申报的任务而辞职。他所准备的改革被怀疑是为有利于BlackRock的积累制铺路。2020年2月援引49.3条款，随后的疫情将改革无限期冻结。",
    "elabe-bfmtv": "2026年3月28日Elabe为BFMTV（CMA CGM/Saadé所有）所做民调，显示菲利普第一轮得票率为20.5%至25.5%。moipresident.online独立贝叶斯聚合数据显示为17%，即低3.5至8.5个百分点。第二轮对阵Bardella的51.5%在误差范围内。委托方（BFMTV/CMA CGM）与候选人（勒阿弗尔港）存在共同利益。",
    "patrick-pouyanné": "TotalEnergies首席执行官，是菲利普在Bilderberg（2023年、2025年）的常客伙伴。TotalEnergies是Institut Montaigne（de Castries）股东，并被BlackRock持有相当比例股份。与菲利普、Attal和de Castries同时出席里斯本和斯德哥尔摩会议。连接Bilderberg圈与商业/BlackRock圈的节点。",
    "jean-lemierre": "BNP Paribas主席，出席了斯德哥尔摩Bilderberg 2025，与菲利普和Attal同场。BNP部分被BlackRock持有，并为Institut Montaigne提供资助。Kohler于2025年离开爱丽舍宫，加入法国兴业银行——同一银行生态系统。Bilderberg圈将法国系统性重要银行与总统候选人直接联系起来。",
    "bernard-emie": "对外安全总局（DGSE，2017-2024）局长，出席了里斯本Bilderberg 2023，与菲利普、Attal和de Castries同场。法国对外情报机构负责人出席私人跨大西洋论坛是值得关注的事实，被Regards.fr所提及。2025年，两个月前刚被任命的Nicolas Roche（SGDSN）在Bilderberg取代了他。",
    "laurent-nunez": "Laurent Nuñez-Belda（1964年生于布尔日）是énarque（西哈诺·德·贝尔热拉克班，1997-1999，内部考试）。DGSI局长（2017年6月至2018年10月），菲利普II政府内政部国务秘书（2018年10月至2020年7月），爱丽舍宫国家情报协调员（2020年7月至2022年7月），巴黎警察总监（2022年7月至2025年10月），随后出任Lecornu II政府内政部长（自2025年10月）。他是与卡斯塔纳并肩镇压\"黄背心\"的实际执行者，而菲利普承担政治责任。Nuñez公开为LBD辩护，参与撤换Delpuech警察总督（2019年3月），并毫不含糊地执行了第五共和国最为强硬的维持秩序原则。用MAS术语来说，他是国家执行代理人：其忠诚直接指向马克龙（亲自任命他担任每个职位），而非其名义上司菲利普。他在Lecornu II政府中的存在，与Horizons成员并肩，为与菲利普派圈子的间接联系增加了额外纽带。Nuñez–Bompard–Caubel三角是调查报告的结构性发现：Bompard（Carrefour CEO）的ENA同届同学，而其妻Charlotte Caubel曾任菲利普内阁司法部门主任（2017-2020），并是Horizons党员。",
    "alexandre-bompard": "Alexandre Joubert-Bompard（1972年生）是Carrefour集团首席执行官（2024年营业额：860亿欧元），以ENA Cyrano de Bergerac班（1997-1999）第4名毕业。他是该班Laurent Nuñez的同学（1999年4月19日法令，Légifrance，JORFTEXT000000211140）。其妻Charlotte Caubel曾任Édouard Philippe在马提尼翁内阁的司法部门主任（2017-2020）。Bompard与菲利普没有已记录的直接联系，但其家族网络（经Caubel）和职业网络（经Nuñez）将大型零售业与行政权力核心圈联系起来。Carrefour在中国拥有重要利益，并曾是巴黎2024年奥运会的官方合作伙伴。",
    "charlotte-caubel": "Charlotte Caubel（法官，Sciences Po）于2017年5月被任命为Édouard Philippe在马提尼翁内阁的司法顾问。她在那里工作了三年（2017-2020），成为司法部门主任。离开马提尼翁后，她执掌司法青少年保护局（2020-2022），随后被任命为博尔内政府（2022-2024）儿童问题国务秘书。她是Horizons党党员。2025年8月被任命为巴黎副检察官。其夫是Alexandre Bompard（Carrefour CEO），与Laurent Nuñez同为ENA同届同学。Nuñez–Bompard–Caubel三角将Nuñez的ENA班级直接联系到菲利普内阁的核心和Horizons党。",
  },
};
